window.EXPL = {"390": {"A": "Sticky sessions keep user on same EC2 instance but session lost if instance fails — not durable storage.", "B": "DynamoDB is durable, highly available, and purpose-built for distributed session storage. Correct.", "C": "Cognito user pools handle authentication/identity, not transactional session data storage.", "D": "ElastiCache for Redis provides sub-millisecond durable session storage with persistence options. Correct.", "E": "Systems Manager Application Manager is for operational visibility/runbooks, not session data storage.", "_summary": "Durable session storage requires external data store (DynamoDB or ElastiCache Redis), not ALB affinity"}, "364": {"A": "Uses AWS managed default key for SQS — default key policy cannot be fully customized; no TLS condition; weaker control than customer managed key.", "B": "Customer managed KMS key for SNS with key policy controls who can use the key (at-rest + authorization). Correct.", "C": "'Update the default key policy' implies AWS managed key — cannot be fully restricted; customer managed key required for fine-grained control.", "D": "Customer managed KMS key for SQS + key policy for authorization + queue policy TLS condition covers at-rest and in-transit for SQS. Correct.", "E": "IAM policy alone cannot grant KMS key access — key policy is required as primary control mechanism; D is correct form of this.", "_summary": "Customer managed KMS keys (not AWS managed) required for policy-level access control; B+D together cover SNS at-rest and SQS at-rest+in-transit"}, "202": {"A": "SSE-S3 rotates keys automatically but rotation schedule is AWS-controlled, not guaranteed annual, and customer has no control or audit trail.", "B": "KMS customer managed key with automatic rotation enabled rotates exactly every 365 days automatically; S3 default encryption ties it all together. Correct, least overhead with full control.", "C": "Same as B but manual rotation — adds operational overhead each year. Wrong.", "D": "Imported key material in KMS does NOT support automatic rotation — must rotate manually. Wrong.", "_summary": "KMS customer managed key + automatic rotation = annual rotation with zero operational overhead; SSE-S3 rotation is uncontrolled"}, "201": {"A": "Amazon Connect is a contact center service for voice/chat — not designed for outbound SMS marketing campaigns.", "B": "Amazon Pinpoint is purpose-built for marketing SMS including two-way messaging; Kinesis stream enables durable archival for 1-year analysis requirement. Correct.", "C": "SQS is a queue, not an SMS sending service — cannot send or receive SMS messages.", "D": "SNS FIFO topics do not support SMS subscriptions; also SNS lacks native two-way SMS reply handling.", "_summary": "Pinpoint handles two-way SMS marketing natively; Kinesis covers durable 1-year storage requirement"}, "959": {"A": "CloudWatch alarms trigger on metric thresholds, not time schedules — wrong tool for business-hours scheduling.", "B": "Trusted Advisor provides cost/security recommendations, not a scheduling engine for starting/stopping resources.", "C": "Systems Manager State Manager maintains configuration state on EC2 instances — cannot start/stop RDS instances directly.", "D": "EventBridge cron expressions schedule Lambda at exact times; Lambda calls RDS StartDBInstance/StopDBInstance APIs. Native, low-overhead scheduling. Correct.", "_summary": "EventBridge cron + Lambda is standard low-overhead pattern for scheduled RDS start/stop"}, "174": {"A": "Auto Scaling groups are regional, not cross-region — cross-region HA requires Route 53 + separate stacks, not a simple ASG change.", "B": "Modifying ASG to span two AZs with 3 instances each is the standard HA pattern; ALB natively routes across AZs, zero app changes needed. Correct.", "C": "A launch template alone does not deploy instances — passive artifact, provides no active HA.", "D": "ALB already performs round-robin by default; changing this setting adds no redundancy or HA.", "_summary": "Multi-AZ ASG is the minimal-change path to HA; ALB handles cross-AZ routing automatically"}, "21": {"A": "S3 can host static content but cannot process orders or store relational transactional data — incomplete architecture.", "B": "EC2 + ALB + RDS works but requires managing instances, patching, scaling policies — high operational overhead.", "C": "EKS is highest operational overhead option — cluster management, node groups, Kubernetes expertise required.", "D": "S3 static + CloudFront CDN + API Gateway + Lambda + DynamoDB is fully serverless; auto-scales to millions of requests, DynamoDB delivers millisecond latency, zero infrastructure management. Correct.", "_summary": "Serverless stack (S3+CloudFront+APIGW+Lambda+DynamoDB) minimizes overhead while handling massive scale with ms latency"}, "108": {"A": "Lambda cannot be directly triggered by RDS data changes (no native RDS→Lambda trigger); single SQS queue also doesn't fan out to multiple independent targets.", "B": "Same trigger problem as A; FIFO adds ordering but doesn't solve the fundamental RDS→Lambda trigger issue or multi-target fan-out.", "C": "Inverted pattern — SQS cannot fan out to SNS; message flow direction is wrong.", "D": "RDS event notifications natively publish to SNS; SNS fans out to multiple SQS queues; each Lambda independently processes its target system. Correct fan-out pattern.", "_summary": "SNS→SQS fan-out is the correct pattern; RDS event notifications send to SNS, not SQS"}, "515": {"A": "Wrong. Data API access for containerized/event-driven apps describes Aurora Serverless Data API or AppSync, not Redshift. Redshift is OLAP, not transactional API backend.", "B": "Correct. Redshift supports both server-side encryption (SSE-KMS) and client-side encryption before upload.", "C": "Correct. Redshift pause/resume lets you schedule analytics workloads during off-peak hours, paying only when running.", "D": "Wrong. Caching to reduce backend pressure is ElastiCache (Redis/Memcached). Redshift is a data warehouse, not a cache.", "E": "Correct. Redshift RA3 scales to petabytes via Redshift Spectrum and managed storage; designed for massive analytical scale.", "F": "Wrong. Redshift does not create secondary replicas via Console like RDS Multi-AZ. It uses snapshots and cross-region snapshot copy instead.", "_summary": "Redshift = OLAP warehouse with scheduled analytics, encryption, petabyte scale"}, "28": {"A": "Correct. AWS SSO (IAM Identity Center) + AWS Managed Microsoft AD with one-way trust to on-prem AD lets on-prem users authenticate via existing AD while AWS side manages access. One-way trust is sufficient for this flow.", "B": "Wrong. Two-way trust is unnecessary here; it grants on-prem AD access to AWS Managed AD resources, adding risk without benefit for SSO-only use case.", "C": "Wrong. AWS Directory Service alone with a trust doesn't provide SSO across all org accounts; missing the IAM Identity Center layer.", "D": "Wrong. Deploying an on-prem IdP adds operational overhead and doesn't leverage the existing AD directly through AWS-native integration.", "_summary": "IAM Identity Center + Managed AD one-way trust = SSO across org accounts using on-prem AD"}, "12": {"A": "Correct. Single CloudFront distribution with two origins (S3 for static, ALB for dynamic) + cache behaviors handles both content types with minimum latency. Route 53 points to CloudFront.", "B": "Wrong. Global Accelerator improves TCP/UDP network path but doesn't cache content. Using GA for S3 static files misses the CDN caching benefit.", "C": "Wrong. GA with both ALB and CloudFront as endpoints is architecturally redundant and introduces unnecessary complexity.", "D": "Wrong. Two separate domain names for static/dynamic content breaks unified user experience and adds operational overhead without benefit over multi-origin CloudFront.", "_summary": "Multi-origin CloudFront (S3 + ALB) = single solution for static and dynamic latency reduction"}, "3": {"A": "Correct. aws:PrincipalOrgID condition on the S3 bucket policy restricts access to all principals in the org with one policy statement — zero per-account maintenance.", "B": "Wrong. aws:PrincipalOrgPaths requires specifying OU paths; managing paths per department adds overhead and breaks when org structure changes.", "C": "Wrong. CloudTrail-based monitoring + manual policy updates is reactive and extremely high operational overhead.", "D": "Wrong. Tagging every user who needs access requires per-user maintenance — scales poorly and is high overhead.", "_summary": "aws:PrincipalOrgID = single condition restricts S3 to entire org with zero per-account overhead"}, "193": {"A": "Wrong. Read replicas reduce primary read load but don't eliminate repeat queries — same data fetched repeatedly still hits the replica. Also replicas don't satisfy 'high availability' requirement as well as Redis.", "B": "Correct. ElastiCache for Redis caches query results in memory, dramatically reducing DB reads. Redis supports Multi-AZ with automatic failover for high availability.", "C": "Wrong. Route 53 DNS caching is for DNS resolution TTLs, completely unrelated to database read reduction.", "D": "Wrong. ElastiCache for Memcached does not support replication or Multi-AZ failover, so it fails the high availability requirement.", "_summary": "Redis = in-memory caching + HA via replication; Memcached lacks HA"}, "278": {"A": "Wrong. Redshift is columnar/analytical, not optimized for hierarchical nested data or low-latency high-throughput transactional queries.", "B": "Correct. DynamoDB stores hierarchical/nested data natively, delivers single-digit millisecond latency at any scale, and supports scheduled export to S3.", "C": "Wrong. Macie + EventBridge + Lambda doesn't send email — Lambda would need additional code. SNS is the correct email delivery mechanism.", "D": "Wrong. Athena + QuickSight provides dashboards but doesn't detect sensitive financial data or trigger email notifications.", "E": "Correct. Macie detects sensitive financial data in S3, EventBridge schedules monthly triggers, SNS sends email to subscribers — fully managed, no code.", "_summary": "DynamoDB for low-latency hierarchical data; Macie+EventBridge+SNS for monthly financial data email alerts"}, "134": {"A": "Correct. New S3 bucket with CRR + SSE-KMS multi-region keys (designed specifically for cross-region use without re-encryption overhead) + Athena (serverless SQL on S3) = fully serverless, encrypted, replicated, least overhead.", "B": "Wrong. RDS is not serverless and cannot query S3 data directly with SQL like Athena. Requires data loading and managed instances.", "C": "Wrong. SSE-S3 keys are region-specific; CRR with SSE-S3 forces S3 to decrypt and re-encrypt at destination, adding complexity. Also loads into existing bucket which may have conflicting configs.", "D": "Wrong. Both flaws from C apply, plus RDS is not serverless — highest operational overhead of all options.", "_summary": "Athena = serverless SQL on S3; KMS multi-region keys purpose-built for CRR encryption"}, "131": {"A": "Wrong. Individual per-bucket policies granting CloudFront read access don't block direct S3 URL access from other principals.", "B": "Wrong. CloudFront does not authenticate using IAM users. This mechanism doesn't exist for CloudFront-to-S3 authorization.", "C": "Wrong. S3 bucket policy Principal must reference the OAI ARN (arn:aws:iam::cloudfront:user/...), not the distribution ID. Distribution ID alone is not a valid IAM principal.", "D": "Correct. OAI is a special CloudFront identity; assigning it to the distribution and granting only OAI read permission on S3 blocks all direct S3 URL access while allowing CloudFront to serve files.", "_summary": "OAI on S3 bucket policy = CloudFront-only access, direct S3 URL blocked"}, "128": {"A": "Spot Instances tolerate interruptions by design — stateless apps fit perfectly; ASG handles replacement automatically; cheapest compute option.", "B": "EKS adds $0.10/hr cluster fee plus operational complexity managing control plane; Spot is correct but EKS overhead fails 'minimize operational overhead.'", "C": "On-Demand costs 3-5x more than Spot; stateless + disruption-tolerant apps should use Spot to minimize cost.", "D": "On-Demand on EKS is most expensive option; fails both cost and operational overhead requirements.", "_summary": "Stateless+disruption-tolerant = Spot; EC2 ASG simpler than EKS"}, "113": {"A": "DataSync requires available network bandwidth — explicitly ruled out by the constraint.", "B": "Snowcone max usable capacity ~8TB; cannot hold 50TB dataset.", "C": "Snowball Edge works for transfer; Glue is serverless managed ETL but requires rewriting custom app logic in Glue format — higher migration effort.", "D": "Snowball Edge handles 50TB transfer without network; EC2 lets company run existing custom application with zero code changes — least migration effort even if EC2 requires some instance management.", "_summary": "No bandwidth = Snowball Edge; existing custom app lifts to EC2 easier than rewriting for Glue"}, "22": {"A": "Multi-AZ resilient but charges full Standard pricing regardless of access frequency — overpays for rarely-accessed files.", "B": "Multi-AZ resilient; automatically moves objects between frequent/infrequent tiers based on actual access — optimal for unpredictable patterns with no retrieval penalty surprise.", "C": "Multi-AZ resilient but charges per-retrieval fee; unpredictable access patterns cause unpredictable costs.", "D": "Single AZ only — fails the resilience requirement explicitly.", "_summary": "Unpredictable access + AZ resilience = S3 Intelligent-Tiering"}, "110": {"A": "S3 Glacier is archival storage with hours-long retrieval; wrong tier for active upload workflow.", "B": "Still routes upload traffic through EC2 web server — doesn't reduce coupling or offload compute from EC2.", "C": "Presigned URL lets browser upload directly to S3, bypassing EC2 entirely — removes EC2 from upload critical path, reduces coupling and latency.", "D": "S3 Event Notification triggers Lambda asynchronously after upload — decouples resize from upload request, EC2 no longer blocks on image processing.", "E": "Scheduled EventBridge polling adds latency and wastes cycles; not event-driven — inferior to S3 Event Notifications.", "_summary": "Presigned URL offloads upload; S3 Event + Lambda decouples resize processing"}, "109": {"A": "S3 Glacier vaults use vault lock for WORM but Glacier is separate from S3; vault lock doesn't support 'specific IAM users can delete' granularity.", "B": "Governance mode with 100-year retention is arbitrary — requirement specifies nonspecific/indefinite duration; fixed retention period doesn't fit.", "C": "CloudTrail is audit-only; reactive restoration doesn't prevent modification in the first place.", "D": "Legal hold has no retention period — stays until explicitly removed; s3:PutObjectLegalHold permission gates who can add/remove holds, giving specific users delete capability.", "_summary": "Indefinite immutability without fixed date = S3 Object Lock legal hold"}, "1": {"A": "S3 Transfer Acceleration routes uploads through nearest CloudFront edge location over AWS backbone — maximizes speed globally; multipart handles 500GB efficiently; operationally trivial.", "B": "Requires creating regional buckets, configuring CRR rules, managing replication IAM, and cleaning up source — more operational complexity.", "C": "Daily Snowball jobs require physical shipment logistics — not 'as quickly as possible'; latency is days not hours.", "D": "Requires managing EC2 instances, EBS volumes, snapshot schedules, cross-region copy jobs, and restoration — maximum complexity.", "_summary": "High-speed internet + global fast aggregation = S3 Transfer Acceleration"}, "258": {"A": "Lambda 15-min timeout and ephemeral storage limits make 1GB file CSV→Parquet conversion risky at scale; not designed for heavy ETL workloads.", "B": "Self-managed Spark cluster (EMR) is highest operational overhead — requires cluster provisioning, scaling, maintenance.", "C": "Uses Athena (query engine) for transformation instead of ETL purpose-built tooling; scheduled Lambda adds polling inefficiency; overly complex chain.", "D": "Glue ETL is fully managed serverless transformation service purpose-built for CSV→Parquet at scale; Lambda per PUT ensures immediate event-driven invocation; AWS manages all infrastructure.", "_summary": "Managed ETL at scale = Glue job triggered by S3 PUT Lambda"}, "242": {"A": "Simple routing returns all values but performs no health checks — unhealthy instances included in response.", "B": "Latency routing returns single best endpoint per query based on lowest latency — not all healthy IPs.", "C": "Multivalue routing returns up to 8 healthy records per query with health check integration — designed exactly for returning multiple healthy endpoint IPs.", "D": "Geolocation routing directs users based on geographic location to a single endpoint — not designed to return all IPs.", "_summary": "Return all healthy IPs in DNS = Route 53 Multivalue routing policy"}, "46": {"A": "Inspector scans EC2 for vulnerabilities, not S3 objects for PII. S3 Lifecycle removes by age/rules, not by content — wrong services.", "B": "Macie purpose-built for PII detection in S3. SNS handles admin alerts. Native integration, zero custom code — least development effort. Correct.", "C": "Custom scanning algorithms = high dev effort. Violates least-effort constraint.", "D": "Custom Lambda + SES + Lifecycle = high dev effort. Also Lifecycle can't target objects by content.", "_summary": "Macie=managed PII detection in S3; avoid custom scanning when managed service exists"}, "239": {"A": "REST API + Lambda + IAM auth works but adds API Gateway operational overhead vs direct URL approach.", "B": "Lambda Function URL with AWS_IAM auth type = direct HTTPS endpoint, no extra service layer, least operational complexity. Correct.", "C": "Lambda@Edge doesn't support Go 1.x runtime — hard constraint violation. Also overkill for a simple microservice.", "D": "CloudFront Functions run JS only — Go 1.x not supported. No AWS_IAM auth type option exists for CF Functions.", "_summary": "Lambda Function URLs provide HTTPS+IAM natively without API Gateway overhead"}, "687": {"A": "SageMaker requires ML expertise to configure algorithms, training jobs, hyperparameters — violates no-ML-experience requirement.", "B": "SageMaker training still requires ML expertise to set up — wrong service for no-ML users.", "C": "Lambda+SageMaker endpoints still requires ML expertise to build/train the model upstream.", "D": "Forecast is managed time-series service requiring no ML expertise. Lambda+Forecast predictor for inference. Correct (pair with E).", "E": "Amazon Forecast trains on historical S3 data with no ML expertise needed — managed AutoML for time-series. Correct (pair with D).", "_summary": "Amazon Forecast=managed no-ML-required forecasting; SageMaker requires ML expertise"}, "11": {"A": "Secrets Manager purpose-built for credentials. Supports native Aurora rotation via built-in Lambda rotation function — minimal operational overhead. Correct.", "B": "Parameter Store SecureString stores secrets but has NO built-in automatic rotation — requires custom Lambda. More effort than Secrets Manager.", "C": "S3 bucket is object storage, not credential management. No rotation capability. Operational overhead increases.", "D": "EBS volume = same manual credential file problem with extra disk management overhead. No improvement.", "_summary": "Secrets Manager=built-in automatic rotation for Aurora; Parameter Store lacks native rotation"}, "16": {"A": "QuickSight doesn't share dashboards via IAM roles — QuickSight uses its own internal user/group identity system, not IAM roles directly.", "B": "QuickSight natively connects to S3 and RDS, creates datasets, publishes dashboards, shares with QuickSight users/groups with granular access control. Correct.", "C": "Glue ETL produces static files to S3 — no interactive visualization. Doesn't meet visualization requirement.", "D": "Athena+Glue generates static reports — no data visualization capability. Doesn't meet visualization requirement.", "_summary": "QuickSight=native visualization+multi-source+user/group sharing; not IAM roles"}, "14": {"A": "Redshift is OLAP data warehouse, not OLTP replacement. Single node has no HA. Wrong service category entirely.", "B": "Single-AZ has no high availability. RDS MySQL read replicas exist but Single-AZ primary is SPOF — fails HA requirement.", "C": "Aurora Multi-AZ + Aurora Auto Scaling adds/removes read replicas dynamically for unpredictable read workloads. Correct.", "D": "Memcached has no persistence and Spot instances can terminate anytime — both violate high availability requirement.", "_summary": "Aurora+Aurora Auto Scaling=auto-scaling read replicas with HA for unpredictable reads"}, "275": {"A": "Scheduled action sets desired capacity proactively before office opens — prevents reactive lag during morning ramp-up. Correct.", "B": "Step scaling at lower threshold still reactive — scaling lags behind sudden morning traffic surge regardless of cooldown.", "C": "Target tracking still reactive — waits for CPU to rise before adding instances, doesn't solve morning startup problem.", "D": "Setting both min AND max to 20 locks ASG at 20 all day/night — eliminates overnight scale-down, kills cost minimization.", "_summary": "Scheduled action=proactive pre-scaling; reactive policies can't prevent known predictable traffic spikes"}, "270": {"A": "Client-side encryption encrypts data before it leaves the client — satisfies 'encrypted before upload' AND encrypted in transit. Correct.", "B": "Server-side encryption encrypts data at rest IN S3 after upload — data travels unencrypted to S3 then gets encrypted. Fails 'before upload' requirement.", "C": "Bucket policy enforcing SSE-S3 is server-side — encryption happens after S3 receives the data, not before upload.", "D": "Default KMS key is server-side encryption — same issue as B/C, encrypts after S3 receives data not before upload.", "_summary": "Client-side=only option that encrypts BEFORE upload; server-side encrypts after receipt"}, "225": {"A": "Kinesis Data Stream→S3 lands data but provides no SQL analytics layer; requires additional service wiring, more ops overhead.", "B": "Firehose is fully managed ingestion (high availability built-in), delivers directly to Redshift which supports petabyte-scale SQL analytics; least operational overhead.", "C": "S3+Lambda enables event-driven processing but Lambda is not a SQL analytics engine; does not satisfy SQL analytics requirement.", "D": "Self-managed EC2 ingestion fleet requires patching/scaling ops; RDS does not scale to petabytes and has high operational burden.", "_summary": "Firehose (managed ingestion) + Redshift (managed petabyte SQL)"}, "167": {"A": "Spot-only risks interruption; SQS messages survive but processing gaps violate 'no downtime' continuous requirement.", "B": "Reserved for max capacity pays peak price 24/7; extremely wasteful for intermittent traffic.", "C": "Reserved covers stable baseline (continuous processing guaranteed), Spot handles burst cheaply; SQS retains messages if Spot reclaimed so no data loss.", "D": "Reserved baseline + On-Demand burst is reliable but On-Demand costs more than Spot for identical result; not MOST cost-effective.", "_summary": "Reserved baseline ensures continuity; Spot absorbs unpredictable burst cheaply with SQS durability as safety net"}, "952": {"A": "SSE-KMS multi-Region keys + new bucket + Athena works but creating new bucket and migrating existing data adds unnecessary overhead vs using existing bucket.", "B": "RDS is not serverless and cannot natively query S3; violates serverless requirement.", "C": "CRR on existing bucket avoids data migration, SSE-S3 satisfies encryption at rest, Athena is fully serverless SQL on S3; least overhead, all requirements met.", "D": "RDS is not serverless and cannot directly query S3 data; disqualified on serverless requirement.", "_summary": "Athena (serverless SQL on S3) + CRR + SSE-S3 on existing bucket = zero migration overhead"}, "878": {"A": "Single shared email for all root accounts is insecure; multiple people accessing one root mailbox increases blast radius of compromise.", "B": "Distribution lists for root user email expose root notifications to broader group; less controlled than centralized mailbox.", "C": "Individual employee email as root contact risks notification loss if employee leaves; no team-based routing for functional categories.", "D": "Email aliases→centralized mailbox limits root notification exposure to a controlled team; alternate contacts with per-function distribution lists route billing/ops/security to correct teams. Most secure + correct routing.", "_summary": "Centralized mailbox for root aliases + per-function alternate contact distribution lists = least exposure with correct routing"}, "30": {"A": "RDS stopped instances auto-restart after 7 days maximum; cannot remain stopped for weeks between monthly tests.", "B": "RDS has no Auto Scaling policy for compute/memory; this feature does not exist for RDS instances.", "C": "Snapshot preserves data, terminated instance incurs zero compute cost, restore on-demand; only snapshot storage billed between tests — most cost-effective.", "D": "Downgrading instance still incurs hourly compute charges; also requires two disruptive modify operations adding risk and time.", "_summary": "Snapshot+terminate eliminates compute cost; RDS stop has 7-day auto-restart limit making it unsuitable"}, "29": {"A": "NLB supports UDP (required for VoIP); Global Accelerator provides anycast routing to lowest-latency Region plus automated failover — exactly matches both requirements.", "B": "ALB is HTTP/HTTPS only; does not support UDP connections needed for VoIP; disqualified.", "C": "NLB handles UDP correctly but CloudFront does not support UDP; Route 53 latency failover is slower than Global Accelerator's network-layer failover.", "D": "ALB does not support UDP; CloudFront does not support UDP; both disqualifiers.", "_summary": "NLB (UDP support) + Global Accelerator (latency routing + automated failover) is the only UDP-capable low-latency failover combo"}, "27": {"A": "CloudWatch native dashboard sharing generates a shareable link with no AWS account required; access scoped to only that dashboard — satisfies least privilege exactly.", "B": "IAM user grants access to all CloudWatch data via CloudWatchReadOnlyAccess, not just one dashboard; over-provisioned, requires AWS account for external person.", "C": "ViewOnlyAccess is far broader than needed; sharing credentials with external party violates least privilege and security best practice.", "D": "Bastion RDP with cached AWS credentials is operationally complex, expensive, and grants far more access than a single dashboard; not least privilege.", "_summary": "CloudWatch dashboard sharing = no AWS account needed, scope-limited to single dashboard"}, "26": {"A": "AWS Config continuously records S3 bucket configuration state and evaluates rules (e.g., s3-bucket-public-read-prohibited); alerts on unauthorized changes.", "B": "Trusted Advisor provides periodic best-practice checks but does not continuously track or alert on individual resource configuration changes.", "C": "Amazon Inspector assesses EC2/container/Lambda workloads for software vulnerabilities; has no S3 bucket configuration change detection capability.", "D": "S3 server access logging records object-level requests, not configuration changes; EventBridge can react to some API events but Config is the dedicated configuration compliance service.", "_summary": "AWS Config is the dedicated service for continuous configuration recording and compliance rule evaluation"}, "25": {"A": "Refactoring to EC2/Tomcat increases complexity and operational burden; contradicts minimize-configuration requirement.", "B": "DynamoDB platform change is drastic; DAX accelerates reads not write ingestion; doesn't address Lambda concurrency problem.", "C": "SNS is pub/sub with no message retention or backpressure; cannot buffer high-volume DB writes to throttle the consumer Lambda.", "D": "SQS decouples ingestion from DB writes, buffers load, and Lambda SQS event source naturally throttles concurrency — minimal config, scales automatically.", "_summary": "SQS queue between two Lambdas buffers write load and controls DB concurrency"}, "24": {"A": "Budgets tracks spend vs budget thresholds; lacks granular instance-type breakdown or cost visualization.", "B": "Cost Explorer natively filters by instance type, renders 2-month graphs, zero infrastructure setup — lowest operational overhead.", "C": "Billing dashboard shows high-level totals; no per-instance-type drill-down capability.", "D": "CUR + S3 + QuickSight pipeline works but requires provisioning, data-source wiring, and ongoing maintenance — high operational overhead.", "_summary": "Cost Explorer granular filtering = least-effort instance-type cost analysis"}, "23": {"A": "Intelligent-Tiering charges per-object monitoring fees; cost-inefficient for predictable one-month-then-never access pattern.", "B": "Glacier Deep Archive is cheapest S3 storage class (~$0.00099/GB-month); ideal for indefinite retention with no access after 1 month.", "C": "Standard-IA costs more than Glacier Deep Archive; acceptable for infrequent access but not cheapest for long-term archival.", "D": "One Zone-IA saves vs Standard-IA but still far more expensive than Glacier Deep Archive and sacrifices multi-AZ durability.", "_summary": "Glacier Deep Archive = cheapest indefinite storage after predictable access window ends"}, "20": {"A": "EBS snapshots cannot restore to EC2 instance store; instance store is ephemeral and unrelated to EBS snapshot restore path.", "B": "Multi-Attach shares the live production volume with test — test modifications directly affect production data, violating isolation requirement.", "C": "Manually initializing new EBS volumes then restoring still requires full initialization warm-up; high I/O blocked until blocks are read from S3.", "D": "Fast Snapshot Restore pre-warms snapshot blocks so restored volumes deliver full I/O immediately with no initialization penalty — minimizes clone time.", "_summary": "EBS Fast Snapshot Restore eliminates I/O warm-up on restored volumes"}, "540": {"A": "Multi-Region DMS replication is operationally complex, expensive, and overkill for a single-region HA + reporting requirement.", "B": "Single-AZ RDS has no HA; read replica in same AZ provides no failover protection and doesn't meet higher-availability goal.", "C": "RDS Multi-AZ cluster deployment supports only MySQL and PostgreSQL — not Oracle; option is invalid for this engine.", "D": "Aurora Multi-AZ instance deployment provides automatic failover (HA) and native reader instances for reporting offload; most operationally efficient managed solution even though it requires migrating off Oracle.", "_summary": "Aurora Multi-AZ with reader instances = HA + reporting offload, most operationally efficient"}, "539": {"A": "SQL Server Enterprise Always On active/active is very expensive (Enterprise licensing) and operationally complex; violates minimize-costs requirement.", "B": "RDS warm standby + DMS CDC meets RTO but costs more than pilot light; DMS CDC setup adds operational overhead.", "C": "AWS Elastic Disaster Recovery replicates disk changes continuously (RPO seconds, meets ≤30s), launches pilot-light recovery within 60 min RTO, and is lower cost than warm standby or active/active.", "D": "Nightly backups yield RPO of up to 24 hours — far exceeds the 30-second RPO requirement; disqualified immediately.", "_summary": "AWS Elastic Disaster Recovery pilot light meets 30s RPO + 60min RTO at lowest cost"}, "18": {"A": "S3 event notification to SQS creates durable, stateless trigger; messages persist if Lambda is throttled or fails.", "B": "Lambda SQS event source mapping processes messages stateless; deleting on success prevents reprocessing — correct durable pattern.", "C": "Lambda monitoring S3 directly and tracking state in memory is stateful and not durable; memory resets on cold start.", "D": "EC2 instance polling SQS with a text file log is stateful, not serverless, and adds unnecessary infrastructure.", "E": "EventBridge to SNS email notifies a human; does not trigger automated image processing.", "_summary": "S3→SQS→Lambda is the durable stateless image-processing pattern"}, "17": {"A": "IAM role attached via instance profile gives EC2 temporary credentials automatically — correct AWS pattern for service-to-service access.", "B": "IAM policies cannot be attached directly to EC2 instances; they must attach to an IAM identity (role, user, group).", "C": "IAM groups organize IAM users only; groups cannot be attached to EC2 instances.", "D": "IAM users embed long-term access keys; attaching a user to EC2 is not a supported construct and is a security anti-pattern.", "_summary": "IAM role via instance profile = correct, secure way to grant EC2 access to S3"}, "15": {"A": "GuardDuty detects threats via log analysis — no inline traffic inspection or packet filtering capability.", "B": "Traffic Mirroring copies packets to analysis tools but cannot block/filter traffic inline.", "C": "Network Firewall provides stateful/stateless inspection, IPS, and filtering inline at VPC boundary — direct replacement for on-prem inspection server.", "D": "Firewall Manager is a management plane to deploy/centralize rules across accounts — not the inspection engine itself.", "_summary": "Network Firewall = inline VPC traffic inspection/filtering; Firewall Manager = rule management only"}, "702": {"A": "Storage Gateway file gateway adds NFS/SMB latency layer — cannot deliver sub-millisecond HPC performance.", "B": "FSx for Lustre natively integrates with S3 as data repository, delivers sub-millisecond parallel throughput for HPC — correct path after Snowball imports to S3.", "C": "EFS is NFS-based general-purpose storage — not designed for HPC sub-millisecond latency; extra S3→EFS copy step wasteful.", "D": "Snowball data lands in S3 first (after device return) — cannot import directly into FSx for Lustre bypassing S3.", "_summary": "HPC + sub-ms latency = FSx for Lustre; Snowball data path always goes S3 first"}, "49": {"A": "Glacier Instant Retrieval has no tag-based query engine for fast retrieval; also wrong tier for files accessed randomly within 1 year.", "B": "Intelligent-Tiering auto-optimizes costs for variable access within 1 year; lifecycle to Glacier Flexible after 1 year (delay acceptable); Athena queries S3, Glacier Select queries Glacier — cost-effective and complete.", "C": "Storing metadata in S3 Standard + Glacier Instant Retrieval is more expensive than Glacier Flexible; adds complexity without cost benefit.", "D": "Glacier Deep Archive has 12-hour retrieval — acceptable per requirements, but RDS for metadata adds unnecessary cost/complexity vs Glacier Select.", "_summary": "Intelligent-Tiering for active + Glacier Flexible for archived; Athena+Glacier Select for querying each tier"}, "737": {"A": "One-way replication from us-east-2 to both regional buckets ensures data is available locally for streaming — minimal app change.", "B": "Chained replication (us-east-2→eu-west-2→ap-southeast-1) adds extra replication lag to ap-southeast-1; worse latency.", "C": "Bidirectional replication among all 3 is unnecessary — developers only upload to us-east-2; adds complexity with no benefit.", "D": "MRAP ARN for streaming auto-routes students to nearest bucket replica — one ARN change in app, no upload logic change needed.", "E": "MRAP for uploads too would route developer uploads to nearest bucket, but A+D already solves both use cases with fewer changes; E requires more application modification.", "_summary": "A replicates data to all regions; D routes streaming to nearest replica via MRAP — fewest app changes"}, "184": {"A": "Lambda deployed inside VPC gets an ENI and uses VPC routing tables — Direct Connect path to on-premises database becomes reachable. Correct.", "B": "Direct Connect already exists; adding VPN is redundant and Lambda still needs VPC placement to use any VPN/DX route.", "C": "Route tables only help if Lambda is VPC-attached; Lambda created via console runs outside VPC by default — route table change alone insufficient.", "D": "Elastic IP attaches to ENIs, not to non-VPC Lambda functions; no ENI = no network path to on-premises.", "_summary": "Lambda must be VPC-attached to use Direct Connect routing to on-premises resources"}, "159": {"A": "API key usage plan blocks requests without valid key at API Gateway edge before Lambda invocation — effective, low cost.", "B": "Lambda still invokes and incurs cost for every botnet request; filtering inside Lambda is reactive, not preventive.", "C": "WAF rules block malicious traffic at edge (rate limiting, IP reputation, bot control) before reaching API Gateway/Lambda. Correct.", "D": "Private API blocks all external users including legitimate ones — not viable for publicly accessible application.", "E": "IAM role per user is unscalable for public API; botnets won't have valid IAM credentials anyway.", "_summary": "WAF blocks at edge; API keys restrict access to known users — both prevent unauthorized traffic"}, "302": {"A": "CloudFront caches video content at edge locations worldwide — reduces buffering by serving from nearest PoP. Correct.", "B": "DataSync replicates files cross-region but doesn't solve codec/format or CDN delivery — no buffering improvement.", "C": "Elastic Transcoder converts raw video to mobile-optimized formats (smaller bitrate, H.264/HLS) — directly solves large raw file buffering. Correct.", "D": "EC2 Auto Scaling in Local Zones for CDN is high operational overhead — CloudFront already does this managed.", "E": "EC2 Auto Scaling for transcoding is high operational overhead — Elastic Transcoder is managed equivalent.", "_summary": "Transcode to mobile format (Elastic Transcoder) + CDN edge caching (CloudFront) = solve buffering at minimal overhead"}, "308": {"A": "Trusted Advisor resource-level checks (RDS instances) are visible in the account where resources run — finance team must check there. Correct.", "B": "Consolidated billing account Trusted Advisor shows some cost checks but not per-resource RDS instance details from member accounts.", "C": "RDS Reserved Instance Optimization check identifies On-Demand instances running long enough to benefit from RI purchase — exactly the 90-day active instance scenario. Correct.", "D": "RDS Idle DB Instances checks for low-activity instances — question states instances are active, so this check won't flag them.", "E": "Redshift Reserved Node check is for Redshift clusters — wrong service entirely.", "_summary": "Check RI Optimization (not idle) from member account where RDS runs — consolidated account lacks instance-level detail"}, "759": {"A": "Lifecycle policies react to age/rules, not demand patterns; also doesn't define the split by movie age as required—imprecise fit.", "B": "S3 Standard-IA gives immediate synchronous retrieval (no delay), meets 5-min window; older lower-demand movies cost less in IA; standard retrieval from IA is instant.", "C": "Glacier Flexible expedited retrieval takes 1–5 min—borderline for 5-min SLA and expensive; Intelligent-Tiering adds unnecessary management overhead for newer movies.", "D": "Glacier Flexible bulk retrieval takes 5–12 hours—violates 5-minute streaming requirement entirely.", "_summary": "S3 Standard-IA has immediate retrieval; Glacier Flexible bulk breaks latency SLA"}, "1017": {"A": "Attaching both policies to EC2 instance profile gives ALL pods access to both services; no pod-level isolation possible this way.", "B": "IAM policies cannot be attached directly to Kubernetes Pods; Pods have no IAM identity of their own.", "C": "Correct—separate K8s service accounts use IRSA to assume IAM roles; S3FullAccess on data-services account, DynamoDBFullAccess on UI account matches requirements exactly.", "D": "Mapping is swapped: assigns S3 to UI pods and DynamoDB to data-services pods—opposite of requirements.", "_summary": "IRSA grants per-pod IAM roles via K8s service accounts; answer C has correct policy-to-account mapping"}, "918": {"A": "Correct—archiving 10 KB files into large objects avoids 128 KB minimum-size charges in Glacier Instant; Glacier Instant gives immediate access for 1–2 reads/year; Deep Archive is cheapest for 7-year retention.", "B": "Starts in Standard-IA (more expensive per-GB than Glacier Instant for infrequent access) then moves to Glacier Instant—backwards cost ordering; still archives files which is good but suboptimal tier choice.", "C": "Sends raw 10 KB files to Glacier Instant—each billed at 128 KB minimum, multiplied by millions of files is extremely expensive; no archiving step.", "D": "No archiving step; 10 KB files in S3 Standard-IA each billed at 128 KB minimum—same cost trap as C.", "_summary": "10 KB files need pre-archiving to avoid S3 minimum-size per-object charges; Glacier Instant cheapest for occasional immediate access"}, "757": {"A": "Termination protection only blocks accidental API/console termination; does nothing for hardware/OS failures that actually need recovery.", "B": "EC2 instances are AZ-scoped resources; there is no native Multi-AZ deployment mode for a single EC2 instance like there is for RDS.", "C": "Correct—CloudWatch EC2 recovery action automatically restarts the instance on new hardware in the same AZ, preserving instance ID, EIP, and EBS volumes; reduces manual recovery time.", "D": "RAID on EBS provides storage redundancy against disk failure only; does not recover the compute instance if it fails, so recovery time is unchanged.", "_summary": "CloudWatch recover action automates EC2 instance restart without manual intervention"}, "835": {"A": "Correct—Direct Connect public VIF is purpose-built for accessing AWS public endpoints (S3, DynamoDB) from on-premises without internet; no extra components, lowest cost.", "B": "NAT gateway incurs hourly + per-GB charges and requires an internet gateway in the VPC; more expensive and architecturally heavier than a public VIF.", "C": "S3 interface endpoint (PrivateLink) charges per AZ per hour plus per-GB data processing; more expensive than public VIF for this use case.", "D": "VPC peering is between two VPCs, not between on-premises and a VPC; Direct Connect uses VIFs, not peering—architecturally invalid.", "_summary": "Direct Connect public VIF is the native, zero-extra-cost path to AWS public services from on-premises"}, "378": {"A": "Route 53 is DNS-based routing, not a real-time UDP load balancer; cannot distribute game session traffic the way a load balancer can.", "B": "Correct—NLB operates at Layer 4 and natively supports UDP; DynamoDB on-demand scales capacity automatically with no manual intervention.", "C": "NLB is correct for UDP, but Aurora Global Database is a cross-region replication feature, not an auto-scaling non-relational store; still requires capacity planning.", "D": "ALB is Layer 7 (HTTP/HTTPS only); it cannot handle UDP game traffic—eliminated immediately.", "_summary": "NLB handles UDP; DynamoDB on-demand scales non-relational data without intervention"}, "361": {"A": "RDS latency is milliseconds, not sub-millisecond; custom export scripts add operational overhead.", "B": "S3 object retrieval latency is in the tens of milliseconds range—far above sub-millisecond threshold.", "C": "Correct—DAX provides sub-millisecond in-memory caching for DynamoDB reads; built-in DynamoDB S3 export is managed with no pipeline to operate; Athena queries S3 for one-time historical analysis.", "D": "Kinesis Data Streams + Firehose pipeline requires provisioning, monitoring, and scaling—significant operational overhead versus the built-in DynamoDB export.", "_summary": "DAX = sub-ms reads; DynamoDB S3 export + Athena = serverless historical queries with minimal ops"}, "935": {"A": "Route 53 failover to a second single EC2 in another Region doesn't provide auto scaling and introduces cross-region complexity without addressing read latency.", "B": "Correct—ASG across multiple AZs with ALB provides horizontal scaling and HA for the web tier; private subnets improve security.", "C": "Correct—Aurora MySQL with reader instances in separate AZs reduces read latency via read replicas and provides DB-level HA.", "D": "ALB is regional and cannot span multiple AWS Regions; this architecture is invalid.", "E": "Cross-region Aurora read replicas solve a global latency problem not stated here; intra-region reader instances (option C) are sufficient and cheaper.", "_summary": "Multi-AZ ASG+ALB for compute HA/scale; Aurora multi-AZ with reader replicas for DB HA and read latency"}, "928": {"A": "WAF cannot attach to NLB — WAF integrates only with ALB, CloudFront, API GW, AppSync; NLB is Layer 4 TCP only.", "B": "NLBs now support security groups, but option says 'recreate' — implies architectural change; contradicts minimal-change requirement.", "C": "Second NLB in parallel is significant architectural change — directly contradicts minimal-change requirement.", "D": "Shield Advanced enables on existing NLB with zero architectural changes; provides enhanced Layer 3/4 DDoS protection and unauthorized access mitigation without touching topology.", "_summary": "Shield Advanced = protection on NLB with no architecture change"}, "922": {"A": "Sharing IAM user credentials violates least privilege and individual accountability — one compromise exposes all resources for all team members.", "B": "IAM roles with least-privilege per developer is AWS best practice — no shared secrets, scoped permissions, revocable per user, auditable via CloudTrail.", "C": "Access keys are long-lived static credentials with higher breach risk; programmatic-only restriction also does not prevent access to sensitive data within that scope.", "D": "Cognito User Pools handle app-user authentication, not AWS resource access — Identity Pool needed to vend temporary AWS credentials; User Pool alone cannot grant AWS resource permissions.", "_summary": "IAM roles + least privilege = correct per-developer access control"}, "507": {"A": "DynamoDB Global Tables provides active-active multi-region replication typically under 1 second; single logical table accessed via Regional endpoints satisfies global consistency requirement.", "B": "Aurora cross-region read replicas are read-only — writes must hit primary Region; cross-region replication lag routinely exceeds 1 second for reservation writes.", "C": "RDS cross-region read replicas have same problem as B — read-only, asynchronous lag, no globally consistent writes under 1 second.", "D": "Aurora Serverless has no native multi-region replication; Lambda event-stream sync is custom, complex, and cannot guarantee sub-second consistency.", "_summary": "DynamoDB Global Tables = only AWS option with sub-second multi-region write consistency"}, "9": {"A": "DataSync is a migration/sync tool — does not replace the file server, provides no local cache for low-latency access to recent files.", "B": "S3 File Gateway caches frequently accessed files on-premises for low-latency SMB access; S3 Lifecycle to Glacier Deep Archive automatically tiers aging data — solves all three requirements.", "C": "FSx for Windows File Server is cloud-only storage — does not extend on-prem seamlessly or provide automated lifecycle to archival tiers.", "D": "Per-user S3 client installation is high operational overhead; no local cache means no low-latency guarantee; Glacier Flexible Retrieval has minute-to-hour retrieval times.", "_summary": "S3 File Gateway = local cache + SMB protocol + S3 Lifecycle = complete solution"}, "8": {"A": "Scheduled scaling is time-based — cannot react to actual queue depth or variable workload spikes; jobs can queue indefinitely between schedule windows.", "B": "SQS decouples job submission from processing; scaling ASG on ApproximateNumberOfMessagesVisible responds directly to actual demand — canonical pattern for variable distributed workloads.", "C": "CloudTrail is an audit logging service, not a job queue or message broker — architecturally wrong service for job coordination.", "D": "EventBridge routes events but lacks durable queuing semantics; scaling on compute-node load is reactive after overload, not proactive; not a job destination.", "_summary": "SQS + queue-depth ASG scaling = decoupled variable-workload architecture"}, "238": {"A": "Cost Explorer has no native SES alert trigger on threshold breach — requires manual report review, not automated notification.", "B": "Same limitation as A — Cost Explorer monthly reports lack built-in threshold-based alert delivery; SES integration is not natively supported.", "C": "AWS Budgets natively supports per-account, per-service (EC2) monthly cost budgets with SNS alert on threshold — purpose-built for exactly this use case, lowest cost and operational overhead.", "D": "CUR + Athena + EventBridge + SNS is technically functional but architecturally complex and expensive for what is a simple threshold alert.", "_summary": "AWS Budgets = purpose-built per-account service-scoped cost alerting"}, "107": {"A": "Athena+S3 suits ad-hoc analytics on stored data — not a real-time REST API for writing and retrieving live location points.", "B": "API Gateway exposes REST endpoints; Lambda handles read/write to a backing store — standard pattern for REST API with real-time data access and analytics platform integration.", "C": "QuickSight+Redshift is BI visualization stack — cannot serve as a REST API for location data ingestion or retrieval.", "D": "Kinesis Data Analytics is a stream-processing SQL engine — not a REST-accessible location store; architecture incomplete for data retrieval requirement.", "_summary": "API Gateway + Lambda = standard REST API pattern for location data CRUD"}, "482": {"A": "s3 sync uses HTTPS by default satisfying encryption-in-transit, but requires manual retry logic, error handling, and progress monitoring — more operational burden.", "B": "DataSync is fully managed — handles TLS encryption in transit, data integrity verification, bandwidth throttling, automatic retries; least operational overhead for on-prem-to-S3 migration.", "C": "Snowball targets petabyte-scale or no-internet scenarios — 100GB over 100Mbps internet transfers in ~2 hours; physical device adds days of shipping lead time unnecessarily.", "D": "Setting up IPsec VPN for a one-time 100GB transfer is significant infrastructure overhead — excessive complexity relative to task.", "_summary": "DataSync = managed TLS migration with least operational overhead for 100GB on-prem to S3"}, "391": {"A": "EBS snapshots of stateless EC2 instances waste resources — no app data lives on those volumes; AMI captures OS+software state which is all that's needed.", "B": "EBS snapshot lifecycle still snapshots stateless instance volumes unnecessarily; also lacks PITR precision for RPO.", "C": "Stateless tier loses nothing on termination — AMI covers OS/config. RDS automated backups + PITR recovers to any point within retention window, easily satisfying 2h RPO. No wasted snapshot overhead.", "D": "EBS snapshots of stateless EC2 instances add cost and complexity with zero benefit; PITR part is correct but the EC2 piece is wrong.", "_summary": "Stateless EC2 = AMI only; RDS PITR handles sub-2h RPO without manual snapshot scheduling"}, "176": {"A": "VPC gateway endpoint for DynamoDB routes traffic entirely within AWS backbone — no internet, no NAT, most secure and free.", "B": "NAT gateway sends traffic through public subnet then internet; traffic leaves AWS-direct path; not the most secure.", "C": "NAT instance in private subnet is a DIY NAT — still routes to internet, adds management overhead, less secure than endpoint.", "D": "Internet gateway sends traffic to public internet — worst option for security.", "_summary": "VPC gateway endpoints keep DynamoDB traffic on AWS backbone, no internet exposure"}, "371": {"A": "Third-party Kubernetes plugin adds operational overhead vs native AWS encryption path.", "B": "Cannot enable encryption on existing EBS volumes in-place; would require snapshot+copy+restore — high overhead and error-prone.", "C": "Enabling EBS encryption by default in the region with the CMK auto-encrypts all new EBS volumes at creation, zero per-cluster config needed.", "D": "EKS node group IAM role must have kms:Decrypt/kms:GenerateDataKey permissions on the CMK; without this, EBS can't use the key. Associating the role grants this.", "E": "KMS CMK belongs in KMS, not as a Kubernetes secret — wrong pattern, adds security risk.", "_summary": "Region-level EBS default encryption (C) + IAM role KMS permissions (D) = least-overhead CMK encryption for EKS EBS volumes"}, "797": {"A": "Backup admin account helps with account access but doesn't restore root MFA access — root credentials are separate.", "B": "AWS supports multiple MFA devices per user including root. Adding a backup MFA device (hardware key, second authenticator) directly prevents lockout if one device is lost.", "C": "Cannot create new accounts when locked out of root — root is needed for certain operations and this doesn't restore root access.", "D": "IAM admin user with AdministratorAccess policy can do most things but cannot replace root for root-only actions (e.g., closing account, changing support plan).", "_summary": "Multiple MFA devices on root user = simplest disaster recovery for MFA loss"}, "342": {"A": "Dynamic scaling reacts after CPU already hits threshold — doesn't provision 30 min early, too late for batch jobs.", "B": "Scheduled scaling works but requires manual capacity estimation and doesn't adapt to variable transaction volumes.", "C": "Predictive scaling uses ML on historical CloudWatch metrics to forecast load, pre-launches instances up to 30 min before predicted spike. Handles variable transactions automatically — zero manual capacity analysis.", "D": "EventBridge+Lambda triggers when CPU already at 60% — reactive, no 30-min advance provisioning, and adds Lambda operational overhead.", "_summary": "Predictive scaling = ML-based proactive capacity with configurable pre-launch buffer, least overhead for repeating patterns"}, "127": {"A": "EBS (io1/io2) provides persistent high IOPS for active video processing (up to 256K IOPS). S3 gives 11-nines durability for 300TB media. Glacier delivers lowest-cost archival at petabyte scale.", "B": "EFS adds unnecessary latency and cost vs S3 for 300TB blob/media storage; S3 outperforms EFS for large media files.", "C": "EC2 instance store is ephemeral — data lost on stop/terminate — wrong for persistent 10TB video processing storage. S3 not Glacier-tier pricing.", "D": "Instance store offers max raw I/O but is ephemeral; unsuitable for persistent 10TB working set without data loss risk.", "_summary": "EBS=persistent high-IOPS processing, S3=durable media store, Glacier=cheap archival — three tiers matched to three storage needs"}, "926": {"A": "All Fargate steady state with rightsizing only — pays Fargate price for burst traffic, not cost-optimized.", "B": "Fargate for 24/7 base guarantees availability (cannot be interrupted). Fargate Spot for bursts saves up to 70% — burst interruptions acceptable since steady Fargate absorbs fallback. Cost-optimal split.", "C": "Fargate Spot for steady state risks interruption on the always-on baseline — violates 24/7 availability requirement.", "D": "All Fargate with Compute Optimizer rightsizing reduces waste but doesn't apply Spot pricing to burst traffic — less cost-effective than B.", "_summary": "Fargate=reliable base, Fargate Spot=cheap burst; never use Spot for steady-state availability requirements"}, "394": {"A": "Magnetic (HDD) volumes deliver far fewer IOPS than gp3 — would make performance significantly worse.", "B": "gp3 max provisioned IOPS is 16,000 — cannot reach 20,000+ IOPS needed to avoid degradation; ceiling is the problem.", "C": "io2 (Block Express) supports up to 256,000 IOPS — can provision well above the 20,000 IOPS threshold where degradation occurs. Correct fix.", "D": "RDS is a managed service; you cannot RAID-stripe multiple EBS volumes at the OS level as you would on self-managed EC2. Two volumes don't add IOPS in RDS.", "_summary": "gp3 caps at 16K IOPS; io2 Block Express supports 256K — right tool when workload exceeds gp3 ceiling"}, "277": {"A": "Storage Gateway for files adds latency and cost over direct S3; not cheaper than EFS for video scale.", "B": "Storage Gateway volumes give block storage via iSCSI; no cost advantage here, adds complexity.", "C": "Moves from expensive EFS to EBS, but EBS is per-instance block storage—not shared, and still costlier than S3 for bulk video.", "D": "S3 stores video at lowest cost (~$0.023/GB vs EFS ~$0.30/GB); EBS attached to EC2 handles processing temporarily. Cheapest architecture.", "_summary": "EFS expensive for bulk storage; S3+EBS is cost-optimal for store-then-process pattern"}, "208": {"A": "Interface VPC endpoint for S3 works but costs ~$0.01/hr per AZ; gateway endpoint is free and purpose-built for S3.", "B": "Gateway VPC endpoint routes S3 traffic over AWS backbone (no internet); bucket resource policy scoped to EC2 IAM role enforces access restriction. Note: gateway endpoints use endpoint policies not security groups—option text is imprecise but architecture is correct.", "C": "nslookup returns public S3 IPs, not private; S3 has no fixed private IPs, so static route would break.", "D": "ip-ranges.json lists public IPs; same flaw as C—S3 endpoints are not reachable via private IPs from VPC without a VPC endpoint.", "_summary": "Gateway VPC endpoint = free, private S3 access; bucket policy restricts to specific IAM role"}, "139": {"A": "S3 event notifications can target Lambda/SNS/SQS but NOT SageMaker Pipelines directly; also uses Lambda to copy instead of native replication.", "B": "Uses Lambda to copy (operational overhead) instead of native S3 replication; EventBridge targeting is correct but copy mechanism is wrong.", "C": "S3 replication handles copy automatically (good), but S3 event notification destinations don't include SageMaker Pipelines natively.", "D": "S3 replication = zero-code auto-copy. EventBridge receives S3 events and can fan-out to both Lambda and SageMaker Pipelines as targets. Least overhead.", "_summary": "S3 replication + EventBridge = least-overhead fan-out to Lambda and SageMaker Pipelines"}, "102": {"A": "EFS is regional, accessible from any AZ; same-AZ placement not required and not the automation step.", "B": "DataSync agent installed on-prem reads the NFS/SFTP source and securely transfers to AWS. Required for on-prem-to-AWS DataSync tasks.", "C": "EBS secondary volume is irrelevant; destination is EFS on the EC2 instance.", "D": "Manual OS copy is not automated; violates the requirement.", "E": "DataSync supports SFTP as a source location type; creating this location config tells DataSync where to pull data from.", "_summary": "DataSync agent (on-prem) + SFTP location config automates NFS/SFTP-to-EFS transfer"}, "98": {"A": "Long polling reduces empty receives but doesn't prevent redelivery when visibility timeout expires during processing.", "B": "FIFO queue deduplication works but requires queue type change and dedup ID management—more operational overhead.", "C": "Visibility timeout < processing time causes message to become visible again while Lambda still runs, triggering duplicate invocations. Setting timeout > function timeout + batch window fixes this.", "D": "Deleting before processing risks data loss on Lambda failure; not safe.", "_summary": "Visibility timeout too short → message reappears → duplicate Lambda invocations; increase it to fix"}, "416": {"A": "Redshift is OLAP/data warehousing; doesn't help with OLTP web app page load latency.", "B": "CloudFront CDN caches static and dynamic content at edge locations, directly reducing page load times for global users.", "C": "S3 cannot serve dynamic content; inappropriate for OLTP-backed pages.", "D": "Read replica offloads read-heavy queries from primary RDS instance, reducing DB latency under load.", "E": "Multi-AZ improves availability/failover, not read performance or page load speed.", "_summary": "CloudFront reduces latency at edge; RDS read replica reduces DB read contention"}, "536": {"A": "Scaling production instance makes data scientists share resources with OLTP workload; complex queries degrade production.", "B": "Multi-AZ instance standby is a hot-standby for failover only—NOT readable; data scientists cannot query it.", "C": "Multi-AZ instance + 2 read replicas = 3 extra instances running; more expensive than option D.", "D": "RDS Multi-AZ cluster (3-node: 1 writer + 2 readable standbys) provides HA and readable endpoints for data scientists. Fewer instances than C, lower cost.", "_summary": "Multi-AZ cluster has readable standbys; cheaper HA+read-offload than Multi-AZ instance + separate read replicas"}, "1009": {"A": "SSE-S3 eliminates KMS calls entirely but abandons KMS—may not satisfy strict KMS-based encryption requirements.", "B": "S3 Bucket Key generates one KMS data key per bucket, reuses it for many objects, reducing KMS API calls by ~99% while still using KMS SSE-KMS. Correct.", "C": "Client-side KMS encryption still makes KMS API calls per operation; doesn't reduce calls, adds client complexity.", "D": "SSE-C means customer provides raw key per request; KMS does not store SSE-C keys—this option conflates two different mechanisms and is invalid.", "_summary": "S3 Bucket Key caches KMS data key at bucket level, slashing KMS API call costs while keeping SSE-KMS"}, "1008": {"A": "Two fixed On-Demand instances behind ALB adds capacity but no auto-scaling; overpays during low traffic periods.", "B": "Route 53 weighted routing splits traffic manually but provides zero auto-scaling; not seamless.", "C": "Stopping instance to resize causes downtime, violating seamless scaling requirement.", "D": "Auto Scaling group + Spot Fleet + ALB auto-scales on demand using Spot pricing; stateless app tolerates Spot interruptions, minimizing cost.", "_summary": "Stateless workload + Auto Scaling + Spot Fleet = seamless scale at lowest cost"}, "971": {"A": "CachingDisabled policy on CloudFront disables caching entirely — no latency improvement at all.", "B": "Cross-region S3 replication + dual-origin CloudFront works but adds replication config overhead with minimal benefit over single-origin CloudFront.", "C": "S3 Transfer Acceleration optimizes upload throughput to S3, not download distribution from S3 to remote clients.", "D": "CloudFront caches 100 files at global edge PoPs; Outposts servers download from nearest edge instead of ap-northeast-1 every time — least overhead.", "_summary": "CloudFront global edge caching eliminates origin-region latency for distributed downloaders"}, "956": {"A": "Spot Instances can be interrupted mid-job — directly violates 'cannot be disrupted' requirement.", "B": "On-Demand is correct for compute, but starting data in Glacier Instant Retrieval costs more than S3 Standard for actively accessed data in the first 30 days.", "C": "Spot Instances again violate the non-interruptible batch job constraint.", "D": "On-Demand guarantees no interruption; S3 Standard serves active 30-day access cheaply; Glacier Deep Archive at ~$0.00099/GB-mo is cheapest tier for 23-month cold retention before expiration.", "_summary": "Non-interruptible jobs need On-Demand; Deep Archive is cheapest long-term cold storage"}, "929": {"A": "SNS topic resource policy must explicitly allow the Lambda role to call sns:Publish — required step.", "B": "Switching from CMK to AWS-managed SSE-KMS contradicts the stated requirement to use customer managed keys.", "C": "KMS key policy must grant the Lambda execution role kms:GenerateDataKey and kms:Decrypt — SNS cannot encrypt messages without this.", "D": "Specifying Lambda ARN in the SNS policy is part of implementing option A, not an additional separate step.", "E": "API Gateway HTTP API is unrelated to Lambda-to-SNS publish access control — unnecessary complexity.", "F": "Lambda execution role needs IAM permissions for both sns:Publish and KMS key operations — without this the role has no rights regardless of resource policies.", "_summary": "Encrypted SNS publish requires: SNS topic policy (A) + KMS key policy (C) + Lambda execution role IAM permissions (F)"}, "883": {"A": "Requires consistent manual tagging by developers plus Lambda maintenance and Config rule upkeep — high operational overhead.", "B": "AWS Budgets actions natively apply a DenyAll IAM policy when budget threshold is breached — zero custom code, fully automated enforcement.", "C": "Cost Explorer and Anomaly Detection only alert after spending occurs; no enforcement or hard caps on resource creation.", "D": "Service Catalog restricts launch catalog but Lambda stop/start scheduling requires per-account Lambda maintenance — high overhead.", "_summary": "AWS Budgets actions automate cost enforcement with no custom infrastructure"}, "881": {"A": "CloudFront TTL of 2 minutes bounds maximum staleness at edge; content refreshes from origin every 2 minutes at most.", "B": "S3 buckets have no native TTL property; caching behavior is controlled by Cache-Control headers set on individual objects.", "C": "Cache-Control: private instructs all caches not to store the response — disables caching, opposite of the goal.", "D": "Lambda@Edge on viewer response fires after CloudFront already decided to serve from cache; cannot retroactively change edge TTL behavior.", "E": "Cache-Control: max-age=86400 on S3 objects maximizes cache hit ratio; CloudFront invalidations at deploy time purge changed files within seconds.", "_summary": "Short CloudFront TTL (A) caps staleness; long S3 max-age + invalidation on deploy (E) maximizes performance"}, "841": {"A": "EBS snapshots cannot be directly copied to S3 Glacier Deep Archive — requires custom data extraction pipeline, adding significant operational overhead.", "B": "EBS Snapshots Archive tier costs ~75% less than standard snapshot storage and supports up to 90-day retention policies natively with no workflow changes.", "C": "Retaining 7 years of monthly snapshots in standard EBS snapshot tier is far more expensive than Archive tier — not cost-effective.", "D": "EBS direct APIs read raw block data from snapshots; piping that to S3 IA requires custom tooling and ongoing maintenance.", "_summary": "EBS Snapshots Archive is the native cheap long-term tier; no pipeline changes needed"}, "764": {"A": "Web tier in private subnets blocks inbound internet traffic — breaks the public-facing web tier requirement.", "B": "Aurora MySQL is MySQL-compatible and supports PITR, but Aurora is technically a different engine from on-prem MySQL, representing slightly more architectural change.", "C": "RDS for MySQL is a direct managed lift of on-prem MySQL — same engine, same SQL dialect, native PITR support, fewest changes; web public / app private / DB private is correct 3-tier placement.", "D": "App and DB tiers in public subnets is an insecure anti-pattern; never correct for production.", "_summary": "RDS MySQL = fewest changes from on-prem MySQL + native PITR; note community prefers B (Aurora) for lower operational overhead but C is more literally 'fewest changes'"}, "721": {"A": "Spot Fleet manages EC2 VMs — not serverless, not minimal infra, violates core requirement.", "B": "Elastic Beanstalk runs on EC2 under hood — not serverless, still requires platform management.", "C": "EKS with self-managed EC2 Auto Scaling groups carries heavy operational burden — opposite of minimal infra.", "D": "Lambda is natively serverless, supports Python, auto-scales to thousands of concurrent requests, zero infra management needed — exact fit.", "_summary": "Serverless + Python + auto-scale + minimal ops = Lambda"}, "560": {"A": "Control Tower drift notifications detect when accounts/OUs deviate from Control Tower-managed config and sends SNS alerts — built-in, no extra wiring needed; strong candidate for least overhead.", "B": "AWS Config aggregated rules detect resource config compliance, not OU hierarchy structural changes — wrong tool for this problem.", "C": "CloudTrail org trail captures Organizations API calls (CreateOU, MoveAccount, etc.), but notifying ops team requires additional EventBridge rule + SNS setup — more wiring than Control Tower's built-in drift alerts; community favors this but A has lower overhead.", "D": "CloudFormation drift detection checks stack resource drift, not Organizations OU changes — completely wrong scope.", "_summary": "OU change detection: CloudTrail records the calls but needs extra notification plumbing; Control Tower drift does it built-in"}, "543": {"A": "Management account billing preferences has 'discount sharing' toggle — only the payer/management account can enable org-wide discount sharing. Correct step.", "B": "Member account that bought Savings Plan cannot control discount sharing — that authority belongs solely to management account. Wrong.", "C": "AWS RAM cannot share Savings Plans — RAM shares resources like subnets and Transit Gateways, not billing constructs. Wrong.", "D": "Creating a new payer account leaves the existing Savings Plan in a different account (now a member) where it cannot be applied as payer — breaks the sharing model. Wrong.", "E": "Creating org in the account that already owns the Savings Plan makes it the management/payer account — Savings Plan stays with the payer, enabling cross-account sharing after A enables the setting. Correct.", "_summary": "Savings Plan sharing requires: account with plan = management account (E), then enable discount sharing from mgmt account (A)"}, "510": {"A": "Security group rule referencing another region's SG CIDR range placed on the wrong resource (eu-west-1 app inbound, not ap-southeast-2 DB inbound) — wrong direction, wrong resource.", "B": "Cross-region VPC peering does NOT support security group ID references across regions — you cannot reference eu-west-1 SG ID in an ap-southeast-2 security group rule. Invalid.", "C": "VPC peering with updated route tables works cross-region; security group rule using IP CIDR of eu-west-1 app servers on ap-southeast-2 DB SG is the correct approach since cross-region SG ID references are unsupported. Correct.", "D": "Transit gateway inter-region peering is valid networking, but security group rules still cannot reference SG IDs from another region — same fatal flaw as B. Wrong.", "_summary": "Cross-region VPC peering requires IP CIDR in SG rules; cross-region SG ID references are not supported"}, "501": {"A": "KDS + Lambda can analyze in real-time but requires custom code to then push to S3 — two separate moving parts, more operational effort.", "B": "AWS Glue is batch ETL, not a streaming ingestion tool — wrong service for continuous per-minute data ingestion.", "C": "Firehose natively delivers streaming data to S3 (data lake); Kinesis Data Analytics (Managed Flink) reads from Firehose/KDS for real-time analysis — fully managed, no servers, single integrated pipeline. Correct.", "D": "API Gateway is request-response, not designed for high-throughput streaming ingestion — operationally inefficient for this pattern.", "_summary": "Firehose → S3 (ingest) + KDA (real-time analysis) = fully managed streaming pipeline, least ops overhead"}, "491": {"A": "SQS standard satisfies 'at least once' delivery; SSE-KMS encrypts credit card data with customer-managed key control; kms:Decrypt is the correct IAM permission for Lambda to decrypt messages. Most cost-effective combination. Correct.", "B": "FIFO queue costs more than standard and provides exactly-once (overkill for 'at least once' requirement); SSE-SQS is fine but 'encryption key invocation permission' is not a real IAM permission name — wrong terminology. Wrong.", "C": "FIFO costs more than standard — unnecessary expense for 'at least once' requirement; SSE-KMS correct but FIFO premium kills cost-effectiveness. Wrong.", "D": "Standard queue correct; SSE-KMS correct; but 'encryption key invocation permission' is wrong IAM permission name — actual required permission is kms:Decrypt. Wrong.", "_summary": "At-least-once = standard SQS (cheaper than FIFO); correct Lambda KMS permission = kms:Decrypt"}, "119": {"A": "WAF in each region/account works but requires duplicating rule management everywhere — not centralized, higher admin effort across multiple accounts.", "B": "Firewall Manager centrally manages WAF rules across all accounts in an AWS Organization and all regions from one place — purpose-built for multi-account WAF governance with least administrative effort. Correct.", "C": "AWS Shield protects against DDoS/volumetric attacks, not SQL injection or XSS — completely wrong service for application-layer attack protection.", "D": "Same Shield problem as C, plus 'one region' for a global setup makes no sense. Wrong on two counts.", "_summary": "Multi-account WAF governance = Firewall Manager; Shield is DDoS, not SQLi/XSS"}, "117": {"A": "CloudWatch Logs subscriptions natively stream log data directly to OpenSearch Service — built-in integration, zero code, minimal configuration. Correct.", "B": "Lambda function triggered by log group works but requires writing, deploying, and maintaining custom function code — more operational overhead than native subscription.", "C": "Firehose can deliver to OpenSearch but adds an extra service hop between CloudWatch Logs and OpenSearch — more components, more overhead than direct subscription.", "D": "Installing Kinesis Agent on every application server is significant operational burden — agent lifecycle management, monitoring, updates on each host. Worst option for low overhead.", "_summary": "CloudWatch Logs → OpenSearch via native subscription filter = direct, managed, zero-code integration"}, "88": {"A": "Requester Pays shifts S3 data transfer costs to the requester (marketing firm), so company pays nothing for outbound transfers.", "B": "Cross-Region Replication copies data to marketing firm's bucket but company pays replication transfer costs — opposite of goal.", "C": "Cross-account access lets marketing firm read company's bucket, but egress costs still billed to bucket owner (company) by default.", "D": "Intelligent-Tiering adds per-object monitoring fees and syncing duplicates data with full replication transfer costs.", "_summary": "Requester Pays moves egress cost to the downloader"}, "82": {"A": "ACM has no native rule system to publish to SNS — this feature doesn't exist in ACM.", "B": "Config rule acm-certificate-expiration-check works, but detecting non-compliance via EventBridge then SNS adds indirection; valid but not the simplest path.", "C": "Trusted Advisor does flag expiring certs but requires Business/Enterprise support and CloudWatch metric integration is imprecise for 30-day targeting.", "D": "ACM publishes native EventBridge events at exactly 45/30/15/7/3/1 days before expiry — EventBridge catches the 30-day event, Lambda sends SNS. Direct and event-driven.", "_summary": "ACM emits native EventBridge expiry events at fixed intervals including 30 days"}, "101": {"A": "NAT gateways in public subnets (one per AZ) with per-AZ private route tables is AWS best practice — HA, managed, no SPOF.", "B": "NAT instances belong in public subnets not private subnets; this description places them wrong and NAT instances are legacy.", "C": "A VPC can only have one internet gateway; you cannot attach a second IGW, and IGW on private subnet provides no isolation.", "D": "Egress-only internet gateway handles IPv6 only — question explicitly states IPv4 CIDR blocks.", "_summary": "NAT gateway per AZ in public subnet is the HA IPv4 egress pattern for private subnets"}, "806": {"A": "Volume Gateway presents iSCSI block storage, not NFS — wrong protocol for NFS replacement, higher cost for this use case.", "B": "S3 File Gateway exposes NFS/SMB interface backed by S3 — drop-in NFS replacement; Lifecycle policies move cold data to Glacier for lowest cost.", "C": "EFS Standard-IA charges per GB stored and per-access, more expensive than S3 at scale for large datasets migrated from NFS.", "D": "EFS One Zone-IA is cheaper than Standard-IA but single-AZ reduces durability and is still more expensive than S3 for large cold data.", "_summary": "S3 File Gateway replaces NFS protocol with S3 backend; Lifecycle policies drive cost to near-Glacier pricing"}, "803": {"A": "Cognito user pools support risk-based adaptive authentication that analyzes IP, device, and location to trigger MFA on anomalous logins — scales to millions natively.", "B": "Cognito identity pools federate external identities to AWS credentials; they don't provide user-pool-style adaptive auth or MFA risk scoring.", "C": "IAM users have hard service limits and are designed for operators not application end-users — cannot scale to millions.", "D": "IAM Identity Center targets workforce/employee SSO scenarios, not customer-facing apps requiring millions of user accounts.", "_summary": "Cognito user pools adaptive auth triggers MFA based on risk signals (location/IP/device)"}, "1012": {"A": "Scheduled scaling requires knowing peak times in advance — question explicitly states peaks are variable and unpredictable.", "B": "ElastiCache addresses DynamoDB read latency, not CPU saturation on processing EC2 instances or queue depth — wrong bottleneck.", "C": "CloudFront caches web tier responses but processing tier CPU and SQS depth are the stated bottleneck, not web tier latency.", "D": "Target tracking on SQS ApproximateNumberOfMessages scales processing EC2s reactively as queue depth grows — AWS recommended pattern for SQS-driven workers.", "_summary": "SQS queue depth (ApproximateNumberOfMessages) as Auto Scaling target tracks demand without predefined schedules"}, "761": {"A": "IAM Identity Center integrates via SAML 2.0 or AD Connector — it cannot directly federate arbitrary non-SAML LDAP directories.", "B": "Embedding AWS credentials into LDAP is not an authentication integration — it creates static long-lived credentials with no LDAP validation.", "C": "Rotating IAM credentials on LDAP password change creates static keys, not identity-brokered sessions, and doesn't enforce LDAP auth for console login.", "D": "Custom identity broker authenticates users against LDAP directly, then calls STS AssumeRole to issue temporary console credentials — AWS documented pattern for non-SAML IdPs.", "_summary": "Custom identity broker is the AWS pattern when IdP cannot speak SAML — broker validates identity then calls STS"}, "976": {"A": "Geolocation routing maps user geographic regions (country/continent) to endpoints — routes by configured region mapping, not by network proximity distance.", "B": "Geoproximity routing routes traffic based on geographic distance between user and resource locations, optimizing for nearest resource — exactly the stated requirement; NLB handles multi-AZ TCP distribution.", "C": "Multivalue answer returns multiple healthy IPs like round-robin DNS — no proximity logic, no closest-resource selection.", "D": "Weighted routing distributes by configured percentage weights — no proximity or location awareness.", "_summary": "Geoproximity routing minimizes user-to-resource geographic distance; geolocation only maps regions to fixed endpoints"}, "973": {"A": "Correct. ALB must accept public HTTPS traffic; inbound 0.0.0.0/0:443 is required.", "B": "Incorrect. Too broad — ALB only needs outbound to EC2 instances, not all internet.", "C": "Correct. ALB forwards HTTPS to EC2 targets on port 443; outbound to instances required.", "D": "Incorrect. EC2 instances don't initiate inbound connections to ALB on 443.", "E": "Correct. ALB initiates health checks outbound to EC2 on port 8443.", "F": "Incorrect. EC2 doesn't push health check responses inbound to ALB.", "_summary": "ALB SG: inbound from internet, outbound to targets (data + health check)"}, "659": {"A": "Incorrect. DataSync over VPC endpoint still uses existing Site-to-Site VPN, which is already 90% saturated — insufficient bandwidth.", "B": "Incorrect. Direct Connect requires weeks of provisioning for physical circuit; can't meet 2-week deadline.", "C": "Correct. Snowball Edge ships physical device — 50 TB offline transfer, no dependency on saturated VPN, fits 2-week window.", "D": "Incorrect. Storage Gateway is for ongoing hybrid storage integration, not bulk one-time migration.", "_summary": "Saturated VPN + tight deadline = offline physical transfer via Snowball"}, "651": {"A": "Incorrect. One Zone-IA stores data in single AZ; images 'cannot be lost' rules it out.", "B": "Incorrect. One Zone-IA violates durability requirement; Glacier Flexible Retrieval is not instant (minutes to hours).", "C": "Correct. Standard-IA = multi-AZ durable; Glacier Instant Retrieval = immediate access post-360d; Deep Archive = ≤12h retrieval for auditors at lowest cost.", "D": "Incorrect. Glacier Flexible Retrieval at 360 days fails 'instantly upon request' requirement.", "_summary": "Durability rules out One Zone-IA; instant post-360d access requires Glacier Instant, not Flexible"}, "955": {"A": "Correct. Pilot light: minimal ASG capacity in second region + Aurora global DB (sub-minute promotion) + Route 53 active-passive meets ≤30 min RTO without serving traffic when primary is healthy.", "B": "Incorrect. Active-active serves traffic from both regions — violates 'does not need to support customer usage when primary healthy.'", "C": "Incorrect. Restoring Aurora from AWS Backup across regions exceeds 30-minute RTO for meaningful data volumes; also active-active mismatches requirement.", "D": "Incorrect. Rebuilding infrastructure from AWS Backup configuration far exceeds 30-minute RTO.", "_summary": "Passive DR with pilot light ASG + Aurora global DB = RTO <30 min without active-active cost"}, "564": {"A": "Incorrect. EBS encryption protects physical storage; DBA with OS/instance access can still read decrypted data.", "B": "Correct. Client-side encryption means data encrypted before reaching RDS — even DBAs with full DB access see only ciphertext.", "C": "Incorrect. Server-side KMS encryption is transparent at rest; S3 decrypts on authorized read, so privileged users can access plaintext. Also S3 not suited for transactional ecommerce.", "D": "Incorrect. FSx Windows permissions protect from unauthorized users but not from admins — doesn't protect from DBAs.", "_summary": "Client-side encryption is only method where DBA sees only ciphertext"}, "562": {"A": "Correct. Gateway endpoints route traffic via route table entries — must add route pointing DynamoDB prefix to the gateway endpoint.", "B": "Correct. DynamoDB supports only gateway VPC endpoints (not interface); creating it keeps traffic on AWS private network.", "C": "Incorrect. EC2 uses interface endpoints for EC2 API; irrelevant to DynamoDB traffic routing.", "D": "Incorrect. ENI creation is for interface endpoints; gateway endpoints use route tables, not ENIs.", "E": "Incorrect. Gateway endpoints have no security group — security group rules apply only to interface endpoints.", "_summary": "DynamoDB = gateway endpoint only; enforced via route table, no ENI or SG needed"}, "593": {"A": "Correct. Multi-AZ replication groups = AZ-level (region-level) HA; multiple nodes per shard = node-level HA. Covers both failure domains.", "B": "Incorrect. AOF provides persistence/durability on single node but no cross-AZ replication — doesn't address AZ failure.", "C": "Incorrect. Multi-AZ cluster with read replicas helps reads but doesn't explicitly add node-level shard redundancy beyond single primary.", "D": "Incorrect. Auto Scaling adjusts capacity for load; doesn't provide HA for node or AZ failures.", "_summary": "Multi-AZ = AZ-level HA; multiple nodes per shard = node-level HA — both required simultaneously"}, "942": {"A": "Incorrect. SSE-C uses keys provided per-request outside KMS; no CloudTrail key rotation tracking, manual rotation burden.", "B": "Incorrect. SSE-S3 uses S3-managed keys; rotation is opaque to CloudTrail — key rotation events not visible.", "C": "Incorrect. AWS managed KMS keys auto-rotate but rotation schedule is AWS-controlled (not explicitly configurable to annual); less auditability control than customer managed.", "D": "Correct. Customer managed KMS keys: enable annual rotation explicitly, every rotation event logged to CloudTrail, meets all requirements. Slightly higher cost than SSE-S3 but only option satisfying all three constraints (auto-rotate annually + CloudTrail tracking + minimize cost vs SSE-C overhead).", "_summary": "Customer managed KMS key = configurable annual rotation + full CloudTrail audit trail"}, "944": {"A": "Wrong — single AZ EC2+RDS has no fault tolerance; S3 versioning aids recovery not availability", "B": "Correct — ASG across multi-AZ + Multi-AZ RDS + CloudFront covers all three resilience layers (compute, database, static assets)", "C": "Wrong — EC2 in single AZ remains SPOF; serving static assets from EC2 bypasses S3 scalability and durability", "D": "Wrong — EFS One Zone-IA is single-AZ and not resilient; Lambda+Aurora Serverless doesn't match the stated EC2+RDS architecture requirement", "_summary": "Multi-AZ ASG + Multi-AZ RDS + CloudFront = canonical resilient three-tier web app"}, "767": {"A": "Wrong — DataSync migrates data to S3 on schedule but provides no local cache; subset won't be immediately available with minimal lag", "B": "Wrong — file gateway caches recently accessed files locally, but volume gateway cached mode is purpose-built for primary storage in S3 with a hot-data cache on-premises", "C": "Correct — cached volume gateway stores full dataset in S3 (no daily access needed) and caches frequently accessed blocks locally for low-latency reads; eliminates on-prem storage capex", "D": "Wrong — EFS is cloud-based NFS; all reads traverse VPN with latency; no local cache satisfying the minimal-lag requirement", "_summary": "Volume gateway cached volumes = S3 primary storage + local hot-data cache for low-latency subset access"}, "675": {"A": "Wrong — creates a controlled deletion path via IAM role; does not prevent accidental deletion by the admin", "B": "Wrong — attaching a deny policy to the storage admin user modifies their permissions, violating the no-admin-rights-change constraint", "C": "Correct — Recycle Bin tag-based retention rules intercept deletions and route snapshots to a recoverable bin; admin rights unchanged; tags applied once protect all future snapshots automatically", "D": "Wrong — EBS snapshot lock prevents all deletion including legitimate cleanup; must be applied per-snapshot; more administrative effort than a single tag-based Recycle Bin rule", "_summary": "Recycle Bin retention rules = accidental-deletion recovery window without touching IAM"}, "663": {"A": "Correct — customer managed KMS key policy grants kms:Encrypt/Decrypt only to ECS task execution role; S3 GetObject fails without kms:Decrypt; RDS storage unreadable without key access; one policy controls both services", "B": "Wrong — AWS managed keys have policies controlled by AWS; you cannot restrict them to a specific IAM role", "C": "Wrong — S3 bucket policy restricting to ECS role is valid, but no VPC Interface endpoint exists for Amazon RDS for MySQL as an AWS service", "D": "Wrong — VPC endpoint for RDS MySQL does not exist as an AWS service endpoint; same invalid premise as C", "_summary": "KMS CMK key policy = data-layer access control enforced at encryption for both S3 and RDS simultaneously"}, "638": {"A": "Wrong — presigned URLs are per-object and time-limited; regenerating and distributing them to global employees has ongoing overhead", "B": "Wrong — creating and managing individual IAM users for every global employee is high-overhead and does not scale", "C": "Correct — S3 File Gateway exposes S3 as SMB/NFS shares; employees mount using OS-native protocols with no special client software; single gateway deployment covers all employees", "D": "Wrong (relatively) — Transfer Family SFTP is fully managed but requires SFTP client software per machine and custom identity provider configuration in Secrets Manager; more moving parts than a simple share mount", "_summary": "S3 File Gateway = S3 exposed as familiar network drive requiring zero per-user client configuration"}, "978": {"A": "Wrong — RDS automated backup maximum retention is 35 days; 90-day retention is not configurable here", "B": "Wrong — manual daily snapshots with manual or scripted deletion after 90 days require significant operational effort", "C": "Wrong — Aurora Clone is Aurora-specific; the feature does not exist for RDS for Oracle", "D": "Correct — AWS Backup for RDS supports retention periods well beyond 35 days; continuous backup mode provides PITR up to 14 days; backup plan creation is the only operational step", "_summary": "AWS Backup = managed RDS backup lifecycle exceeding the 35-day automated backup cap"}, "355": {"A": "Wrong — Lambda max is 10 GB memory and 6 vCPU; cannot satisfy 64 vCPU / 512 GiB requirement", "B": "Wrong — Fargate max is 16 vCPU and 120 GiB; insufficient for 64 vCPU / 512 GiB workload", "C": "Wrong — Lightsail has no native Auto Scaling and is not designed for high-compute batch workloads", "D": "Correct — AWS Batch provisions EC2 instances of any size including 64+ vCPU / 512+ GiB; manages job queue and instance lifecycle; purpose-built for periodic large-compute batch jobs with least operational overhead", "_summary": "AWS Batch on EC2 = managed job scheduling for workloads that exceed Lambda and Fargate resource limits"}, "36": {"A": "Wrong — SSE-S3 uses Amazon-managed keys; does not satisfy the customer managed KMS key requirement at all", "B": "Partially correct key type — multi-Region KMS key IS the right feature for same-key-material in both regions, but client-side encryption requires application-level code to call KMS and is more operationally complex than SSE-KMS", "C": "Wrong — creating a CMK then configuring SSE-S3 is contradictory; SSE-S3 ignores the CMK entirely", "D": "Correct — customer managed KMS keys with SSE-KMS on both buckets plus S3 CRR uses server-side encryption (least overhead); using a multi-Region KMS key pair satisfies same-key-material and key-stored-in-each-region; replication re-encrypts with destination replica key automatically", "_summary": "SSE-KMS + CRR + multi-Region CMK = cross-region S3 encryption with same key material and minimal operational overhead"}, "679": {"A": "Object Lock must be enabled at bucket level first — prerequisite for any retention enforcement.", "B": "Versioning alone adds version history but neither enforces retention nor auto-deletes; wrong tool for this job.", "C": "Default retention period on Object Lock ensures every ingested object is WORM-protected for exactly 30 days.", "D": "Lifecycle policies cannot 'protect' objects; they only transition or expire — no such Lifecycle action exists for protection.", "E": "Lifecycle expiration rule auto-deletes objects after 30 days, satisfying the mandatory deletion requirement.", "F": "Tags are metadata only; backup solution tagging does not enforce any retention at the S3 service level.", "_summary": "Object Lock (A+C) enforces immutability; Lifecycle expiration (E) handles auto-delete."}, "879": {"A": "RDS Proxy helps connection pooling but 'retry until complete' auto-scaling pattern adds EC2 cost without fixing the root bottleneck.", "B": "ElastiCache caches frequent reads (product catalog, session data) reducing Aurora read pressure so it handles peak write load better — cost-effective.", "C": "SQS decouples purchase intake from processing; Auto Scaling workers scale with queue depth, absorbing spikes without timeouts.", "D": "Lambda retry loops add invocation cost and don't address capacity scaling under sustained peak load.", "E": "API Gateway usage plans throttle clients — reduces load but degrades customer experience, doesn't scale capacity.", "_summary": "SQS decoupling (C) absorbs bursts; ElastiCache (B) offloads DB reads — together cost-effective peak scaling."}, "141": {"A": "CloudFront edge network serves static content cached and routes dynamic requests over AWS backbone to ALB, minimizing latency globally for both content types.", "B": "Route 53 latency routing picks fastest regional DNS endpoint but users still traverse public internet to reach ALB — no edge acceleration.", "C": "Dynamic content bypasses CloudFront entirely, traveling public internet to ALB; loses CloudFront's TCP optimization and PoP proximity for dynamic traffic.", "D": "Geolocation routing assigns region by geography not actual latency; users may route to farther region and still traverse public internet to ALB.", "_summary": "CloudFront with ALB origin accelerates both static (cached at edge) and dynamic (AWS backbone) content globally."}, "859": {"A": "Trusted Advisor in management account aggregates checks across all org member accounts — finance team gets org-wide visibility from one place.", "B": "Member account Trusted Advisor shows only that account's resources; finance team would need to log into each account separately — inefficient.", "C": "RI Optimization check identifies high-utilization On-Demand instances and recommends Reserved Instance purchases — directly targets cost reduction.", "D": "Idle DB Instance check flags underutilized instances; high-utilization RDS instances are the opposite of idle, so this check yields no findings.", "E": "Compute Optimizer analyzes EC2/Lambda compute; it does not cover RDS Reserved Instance recommendations.", "_summary": "Management account Trusted Advisor (A) gives org-wide view; RI Optimization check (C) targets high-utilization On-Demand RDS cost."}, "807": {"A": "Reserved concurrency caps parallelism (can cause throttling) and less memory means less vCPU — CPU-intensive tasks run slower and cost more in duration.", "B": "Reserved concurrency still risks throttle-induced latency spikes; doesn't eliminate cold starts that hurt latency.", "C": "Provisioned concurrency eliminates cold starts but decreasing memory cuts vCPU allocation — CPU-intensive tasks run slower, increasing duration cost.", "D": "Provisioned concurrency pre-warms instances eliminating cold-start latency; more memory per Compute Optimizer gives more vCPU, CPU-intensive code finishes faster, reducing GB-second billing.", "_summary": "Provisioned concurrency kills latency; higher memory boosts vCPU, cutting duration for CPU-bound Lambda."}, "775": {"A": "Transit Gateway + inspection VPC + Network Firewall works but requires multi-step routing config and firewall rule management — high overhead.", "B": "VPC Lattice is purpose-built for cross-account service-to-service communication with native HTTPS listeners, built-in service registry, and minimal per-service config.", "C": "PrivateLink requires a separate endpoint service and VPC interface endpoint per microservice per consumer VPC — combinatorial admin overhead at scale.", "D": "VPC peering with prefix lists and route tables requires managing O(n²) peering connections and route entries — does not scale, high overhead.", "_summary": "VPC Lattice provides cross-account HTTPS service mesh with native service registry at lowest operational overhead."}, "1019": {"A": "Private integration controls backend connectivity (VPC resources), not who can call the API from the internet — wrong control plane.", "B": "API Gateway resource policies support aws:SourceIp conditions; deny-all except trusted CIDRs enforces IP-based access restriction at the API level.", "C": "API Gateway is a fully managed regional/edge service — it cannot be placed inside a private subnet; NACLs cannot be applied to it directly.", "D": "API Gateway does not attach security groups to itself; security groups apply to VPC resources like EC2 or VPC endpoints, not the API Gateway service endpoint.", "_summary": "API Gateway resource policy with IP condition (aws:SourceIp) is the correct mechanism for IP-based access restriction."}, "892": {"A": "Auto Scaling min=max=1 means only one instance runs at a time; failover requires launching a replacement, causing downtime — not truly fault tolerant.", "B": "Hourly backup + restore has significant RTO (restore time) and RPO (up to 1 hour of data loss) — backup is not fault tolerance.", "C": "Two EC2 instances from same AMI in separate AZs behind NLB provides active-active fault tolerance; AZ failure leaves one instance still serving traffic — no app changes required.", "D": "Refactor Spaces and ECS Fargate require redesigning the application into containers/microservices — explicitly prohibited by the 'no design changes' constraint.", "_summary": "Multi-AZ active-active EC2 behind NLB (C) is the simplest fault-tolerant lift-and-shift with no application changes."}, "348": {"A": "Provisioned+Standard-IA+reserved: Standard-IA lowers storage cost but not throughput cost; constant high-frequency analytics workload makes IA table class cost MORE per operation, not less.", "B": "Provisioned mode with explicit RCU/WCU: predictable workload maps to fixed provisioned capacity, keeping spend constant and at/below budget—cheapest option for steady traffic.", "C": "On-demand mode cannot cap spend via RCU/WCU settings; auto-scaling pricing is 6-7× provisioned per request at steady throughput, blowing the budget.", "D": "On-demand mode is incompatible with reserved capacity—reserved capacity only applies to provisioned mode, making this option invalid.", "_summary": "Provisioned mode = fixed cost for predictable workloads; reserved capacity requires provisioned mode; on-demand is expensive at scale"}, "13": {"A": "Secrets Manager natively integrates with RDS for automatic rotation, supports multi-Region secret replication, and requires zero custom code—lowest operational overhead.", "B": "SSM Parameter Store has no built-in automatic rotation for RDS credentials and no native multi-Region replication feature; requires custom Lambda—more overhead than Secrets Manager.", "C": "S3+EventBridge+Lambda is a fully custom DIY rotation pipeline with high build/maintain overhead and no native RDS integration.", "D": "KMS+DynamoDB global table+Lambda is maximally complex with no native RDS rotation support; highest operational overhead of all options.", "_summary": "Secrets Manager = native RDS rotation + multi-Region replication; everything else requires custom code"}, "851": {"A": "Separate Aurora instances with manual start/stop: start/stop adds operational overhead; no size governance enforcement; storage charges persist while stopped.", "B": "Service Catalog product with size restrictions enforces governance, developers self-service launch/terminate when needed, each dev gets separate isolated instance—cost controlled by size caps and on-demand usage.", "C": "Single Aurora Serverless cluster with multiple databases shares cluster resources; developers lack true isolation; default capacity settings may not auto-pause per-database.", "D": "Trusted Advisor detects idle RDS reactively, not proactively; terminating vs pausing loses dev data; high manual overhead with no governance.", "_summary": "Service Catalog enforces size governance + self-service launch/terminate = cost control without ops overhead"}, "143": {"A": "Lambda requires decomposing app into discrete functions; 'keep as much code as possible' conflicts with Lambda's stateless per-function execution model—significant refactoring needed.", "B": "Amplify suits frontend hosting but still depends on Lambda for backend, incurring same refactoring issues as option A.", "C": "EC2+ALB+Auto Scaling requires OS-level management, patching, capacity planning—higher operational overhead vs container or serverless options.", "D": "ECS lets you containerize existing code with minimal changes; ALB routes to separate services per team; Fargate removes server management; scales well with minimal ops overhead.", "_summary": "ECS/Fargate = containerize existing code minimal-refactor + low ops overhead; EC2 = too much management"}, "120": {"A": "CloudFront is for HTTP/HTTPS caching; DNS traffic runs UDP/TCP port 53 and cannot be proxied through CloudFront—fundamentally wrong service for DNS workloads.", "B": "Global Accelerator standard accelerator routes any TCP/UDP traffic over AWS global backbone, supports NLB endpoints in multiple regions with health-check failover—correct for DNS performance and availability.", "C": "Same CloudFront-for-DNS flaw as option A; attaching EIPs to EC2 instances does not fix the fundamental incompatibility.", "D": "ALBs only support HTTP/HTTPS/gRPC; DNS is TCP/UDP so ALB replacement is wrong; CloudFront still cannot handle DNS traffic.", "_summary": "Global Accelerator handles any TCP/UDP including DNS across regions; CloudFront only handles HTTP/HTTPS"}, "845": {"A": "EC2 cron job introduces server management, patching, and availability concerns—operationally inefficient for a simple daily scan of 15 records.", "B": "SQS queues messages but does not send emails; a consumer must still process the queue and call another service—extra moving parts, wrong tool for direct email delivery.", "C": "Lambda scheduled via EventBridge runs daily with no servers to manage; SNS email subscriptions deliver directly to employees—fully serverless, minimal operational overhead.", "D": "SQS cannot deliver emails directly; Lambda writes to queue but nothing sends email without additional infrastructure—incomplete solution.", "_summary": "Lambda+EventBridge schedule+SNS = serverless anniversary emails; EC2 cron adds ops overhead; SQS cannot send emails"}, "804": {"A": "EMR requires cluster provisioning and management—not serverless; standard Redshift also requires cluster management; fails 'serverless where possible' requirement.", "B": "EMR is not serverless; Aurora Serverless is an OLTP database lacking MPP analytics capabilities—wrong data warehouse choice.", "C": "AWS Glue is fully serverless ETL; Redshift Serverless provides MPP with zero cluster management; Redshift ML enables SQL-based model creation and training—all requirements met.", "D": "Athena queries data in-place on S3 and is not a data warehouse with MPP; no 'Athena ML' product equivalent to Redshift ML for creating and training models.", "_summary": "Glue(serverless ETL)+Redshift Serverless(MPP)+Redshift ML(SQL models) = fully serverless MPP analytics pipeline"}, "83": {"A": "EC2 in us-east-1 is still in the US; provides no performance benefit for European users and requires full migration.", "B": "S3 hosts only static content; a dynamic website with backend logic cannot run on S3—wrong service.", "C": "CloudFront with custom on-premises origin caches content at European edge locations, reducing latency for EU users while keeping the backend in the US; deployable immediately with no migration.", "D": "Route 53 geoproximity routing only changes DNS resolution target; it does not cache or accelerate content—European users still retrieve content from US servers with full round-trip latency.", "_summary": "CloudFront custom origin = CDN caching at EU edge + on-prem backend unchanged; Route 53 alone cannot accelerate content delivery"}, "252": {"A": "EFS = shared NFS file system. Multiple EC2 instances mount simultaneously, data replicated across multiple AZs. Meets both requirements.", "B": "EBS = block storage attached to one EC2 at a time (io1/io2 multi-attach limited and cluster-aware only). No cross-instance simultaneous access.", "C": "S3 Glacier Deep Archive = cold archival. Retrieval takes hours. Not for active concurrent access.", "D": "AWS Backup = backup orchestration service, not a storage target. Doesn't provide file access.", "_summary": "Shared concurrent file access from multiple EC2 = EFS"}, "247": {"A": "RDS manages binlog automatically when automated backups are enabled. No manual action needed; enabling backups (E) implicitly enables binlog.", "B": "Failover priority = Multi-AZ setting, unrelated to read replica creation.", "C": "Long-running transactions on source block replica creation cleanly. Must let them finish to avoid replication lag or inconsistency.", "D": "Global tables = DynamoDB feature. Irrelevant to RDS MySQL.", "E": "Automated backups must be enabled (retention > 0) for RDS to allow read replica creation. Hard prerequisite.", "_summary": "Read replica prereqs: complete long transactions + enable automated backups"}, "754": {"A": "WAF cannot attach to NLB. WAF supports ALB, CloudFront, API Gateway, AppSync, Cognito only. Invalid.", "B": "WAF on ALB filters web exploits at HTTP layer. Global Accelerator provides two static anycast IPs and routes to ALBs in each Region for performance and availability. Correct.", "C": "WAF still can't attach to NLB. CloudFront IPs are not static. Two failures.", "D": "CloudFront does not provide static IPs. Global Accelerator is needed for static IPs. WAF on CloudFront is valid but static IP requirement fails.", "_summary": "Static IP = Global Accelerator; WAF needs ALB or CloudFront; B combines both correctly"}, "773": {"A": "ASGs don't use pre-stopped instances to scale out; that's not ASG behavior. Stopped instances still incur EBS costs.", "B": "Sizing min capacity for peak means paying for peak 24/7 regardless of traffic. Expensive.", "C": "Dynamic ecommerce content cannot be meaningfully pre-cached. Logic is flawed; scaling in after cache population defeats the purpose of handling surge.", "D": "ASG scales out on demand using preconfigured AMI via launch template. Pay only for instances running, fast launch from baked AMI. Most cost-effective for seasonal spikes.", "_summary": "Seasonal traffic = ASG with preconfigured AMI launch template, pay per use"}, "728": {"A": "Glacier expedited retrieval has per-GB retrieval cost. Fails 'no additional cost' requirement.", "B": "Cached volumes: primary data lives in S3 (migrates storage to AWS), frequently accessed data cached on-prem. Immediate retrieval of cached data at no extra cost. Minimizes bandwidth by caching hot data locally.", "C": "Stored volumes: primary data remains on-prem, S3 gets snapshots only. Doesn't migrate storage to AWS; just adds backup.", "D": "Direct Connect is expensive to provision and doesn't minimize bandwidth costs. Stored volumes still keep primary data on-prem.", "_summary": "Cached volumes = S3 primary + local cache for immediate retrieval, minimizes bandwidth"}, "692": {"A": "Latency routing policy measures actual network latency to each Region and routes users to lowest-latency endpoint. Best for performance. A record (Alias) correct for ALB.", "B": "Geolocation routes by geographic origin of DNS query, not actual latency. Could route to a closer-in-miles but higher-latency Region.", "C": "Failover policy = active-passive HA pattern, not performance optimization. CNAME also adds extra DNS hop vs Alias A record.", "D": "Geoproximity routes by distance/bias, not measured latency. Performance is suboptimal. CNAME has same alias disadvantage.", "_summary": "Best performance across Regions = Route 53 latency routing policy with Alias A record"}, "677": {"A": "Spot-only managed node group cheapest but risks total capacity loss if Spot market is interrupted, undermining resiliency testing goals.", "B": "Mixed managed node groups: On-Demand provides stable baseline for cluster control plane workloads; Spot handles burst/test workloads cheaply. Enables resiliency testing while keeping costs low. EKS manages both.", "C": "ASG with launch configuration = self-managed nodes. Violates 'EKS must manage all nodes' requirement (need managed node groups).", "D": "On-Demand only managed node group = no cost savings for infrequent dev use. Most expensive option.", "_summary": "Dev EKS resiliency testing = mixed managed node groups On-Demand + Spot"}, "653": {"A": "SCPs can deny actions but cannot dynamically look up cost center from RDS or auto-apply tags. They enforce permissions, not attribute-based auto-tagging.", "B": "CloudTrail logs every API call with caller identity. EventBridge triggers Lambda on resource-creation events. Lambda queries RDS for caller's cost center and applies tag. Correct end-to-end.", "C": "Scheduled EventBridge rule fires periodically, not on resource creation. Tags resources late. Less accurate and efficient than event-driven approach.", "D": "Tags with a default value, not the actual cost center from RDS. Doesn't meet 'cost center ID of the user who created the resource' requirement.", "_summary": "Dynamic user-to-cost-center tagging = CloudTrail → EventBridge → Lambda → RDS lookup → tag"}, "640": {"A": "Lambda resource policy controls who invokes Lambda, not what Lambda can access — wrong direction for KMS permissions.", "B": "KMS key policy must explicitly grant the Lambda execution role decrypt permission; KMS is resource-based and identity-based policies both required.", "C": "Lambda resource policy ≠ Lambda IAM role — resource policy governs invocations only, not KMS access.", "D": "IAM policies attach to roles/users, not to Lambda functions directly — this action as stated is incorrect/misleading.", "E": "Lambda execution role must carry kms:decrypt — correct mechanism for giving Lambda identity-based KMS access.", "_summary": "KMS decrypt needs both: key policy grant (B) + execution role with permission (E)"}, "639": {"A": "Sticky sessions pin clients to one target, causing imbalance — disabling restores even round-robin distribution. Correct fix.", "B": "NLB operates at L4 and doesn't solve sticky-session-induced imbalance; changes protocol handling unnecessarily.", "C": "More instances don't fix uneven distribution — overloaded instance still gets same sticky traffic.", "D": "Health check frequency affects failover detection, not traffic distribution algorithm.", "_summary": "Sticky sessions cause traffic skew — disable to restore even ALB distribution"}, "634": {"A": "S3 global tables doesn't exist — that's a DynamoDB concept. Invalid option.", "B": "Public bucket violates security requirement — any unauthorized party can access data.", "C": "Cross-account S3 bucket policy grants each agency's AWS account read access — IAM-controlled, no per-user management, scales cleanly. Correct.", "D": "Creating IAM users per analyst in source account is operationally inefficient, doesn't scale across multiple agencies with many analysts.", "_summary": "Cross-account S3 bucket policy = secure + operationally efficient multi-agency sharing"}, "622": {"A": "DynamoDB on-demand handles unpredictable spiky load (millions→thousands) instantly; NoSQL schema is flexible. Correct.", "B": "Aurora Serverless scales but is relational — schema evolution requires migrations, contradicts 'rapidly evolve schema' requirement.", "C": "DynamoDB auto scaling is reactive with warm-up lag — on-demand (A) is strictly better for sudden 1000x traffic spikes.", "D": "S3+CloudFront is the canonical solution for static single-page apps — globally distributed, infinitely scalable, no servers. Correct.", "E": "EC2 fleet with EFS adds operational complexity and doesn't match 'most scalable' for static content.", "_summary": "On-demand DynamoDB + S3/CloudFront = scalable schema-flexible serverless stack"}, "523": {"A": "AppSync pipeline resolvers natively chain multiple data sources (DynamoDB tables) in sequence/parallel — built exactly for this pattern, zero added latency overhead. Correct.", "B": "Lambda@Edge handles edge routing/caching, not multi-table DynamoDB aggregation — wrong tool.", "C": "API Gateway + Lambda can do this but requires custom orchestration code — less operationally efficient than AppSync's native pipeline.", "D": "Athena Federated Query is analytics-oriented with high latency — incompatible with 'no impact on baseline performance'.", "_summary": "AppSync pipeline resolvers natively aggregate multiple DynamoDB tables with minimal operational overhead"}, "402": {"A": "Default Kinesis retention is 24 hours; consuming every other day (48h) means data expires before consumption. Extending retention to ≥48h fixes data loss. Correct.", "B": "KPL improves write throughput/batching — doesn't help with data expiring before it's read.", "C": "More shards increases throughput capacity — doesn't affect retention period or prevent data expiry.", "D": "S3 Versioning preserves S3 object history — irrelevant to data never reaching S3 from Kinesis.", "_summary": "Kinesis default 24h retention expires data before every-other-day consumer reads it — extend retention"}, "123": {"A": "ACM certificates are non-exportable managed certs — cannot install on EC2 for termination; doesn't offload SSL compute.", "B": "S3 cannot perform SSL termination for application traffic — invalid architecture.", "C": "EC2 proxy works but adds operational burden and is not AWS-managed; less efficient than ALB.", "D": "ALB with ACM HTTPS listener offloads SSL termination entirely from EC2 — compute freed, AWS manages cert lifecycle. Correct.", "_summary": "ALB + ACM offloads SSL termination from EC2, eliminating CPU bottleneck"}, "1004": {"A": "Direct Connect requires physical circuits per customer location — extremely expensive, weeks to provision, not cost-effective for international API consumers.", "B": "CloudFront CachingOptimized helps cacheable content; ERP API responses are dynamic/personalized — cache hit rate near zero, limited benefit.", "C": "Global Accelerator uses AWS Anycast edge + private backbone to route international traffic — reduces internet hops, improves TCP latency for dynamic APIs without caching. Most cost-effective. Correct.", "D": "Site-to-Site VPN still traverses public internet backbone — doesn't meaningfully reduce latency vs direct HTTPS.", "_summary": "Global Accelerator routes dynamic API traffic via AWS backbone, cutting international latency cost-effectively"}, "1007": {"A": "SSE-S3 uses AWS-managed keys, not customer-specific keys. Fails both encryption-during-processing and per-customer key requirements.", "B": "EMR CSE-Custom satisfies client-side encryption with customer keys, but one EMR cluster per customer means heavy operational overhead vs Glue.", "C": "Glue security configurations support CSE-KMS: data encrypted client-side before writing anywhere. One KMS CMK per customer satisfies customer-specific key requirement. Glue is serverless = least operational effort. Correct.", "D": "EMR SSE-KMS encrypts data at rest on disk/S3, not during in-memory processing. Fails 'encrypted where it is processed' requirement. EMR also higher operational overhead than Glue.", "_summary": "CSE (client-side) required for 'encrypted where processed'; Glue beats EMR on operational effort"}, "524": {"A": "Glue + custom scripts queries CloudTrail data but requires writing and maintaining ETL code. Not least effort.", "B": "Batch + custom scripts is batch compute for custom code. More effort than native query tools.", "C": "Athena queries CloudTrail logs stored in S3 directly via SQL. No infrastructure to manage, no custom code. Native CloudTrail+Athena integration even auto-creates table. Least effort. Correct.", "D": "QuickSight is BI visualization tool. Requires Athena or other datasource configured first, then dashboard build. More setup steps than just running Athena queries.", "_summary": "Athena on S3-backed CloudTrail logs = least-effort ad-hoc IAM error analysis"}, "490": {"A": "EMR Hive job reads DynamoDB directly, consuming RCUs. Requires cluster management and custom job code. Violates RCU and coding constraints.", "B": "DynamoDB native Export to S3 feature reads from PITR snapshots, not the live table — zero RCU consumption, no availability impact. PITR provides continuous backup. Built-in feature, minimal code. Correct.", "C": "DynamoDB Streams + Lambda consumes additional read capacity (stream reads use RCUs). More coding needed. Fails RCU constraint.", "D": "Lambda polling export consumes RCUs on every invocation. PITR is on but Lambda export itself is not continuous — it's periodic. Fails RCU and continuity constraints.", "_summary": "DynamoDB Export to S3 via PITR snapshots = zero RCU impact, no code, truly continuous"}, "958": {"A": "RDS Proxy maintains persistent connection pool and re-routes connections to new primary during failover without dropping app connections. Cuts failover impact from minutes to seconds. Correct.", "B": "Read replica handles read traffic only. Doesn't participate in Multi-AZ failover path. Doesn't reduce failover time.", "C": "Performance Insights is monitoring/diagnostics. Doesn't alter failover behavior or reduce timeout duration.", "D": "Cross-region snapshot copies are DR strategy. Don't affect intra-region Multi-AZ failover time at all.", "_summary": "RDS Proxy absorbs connection failover, shielding app from Multi-AZ switchover disruption"}, "930": {"A": "EC2 On-Demand ASG guarantees 100% uptime. Lambda for infrequent extraction is serverless, cost-effective, scales to zero. Trigger on S3 upload event requires no portal code changes. Correct.", "B": "Spot Instances can be interrupted. Violates 100% uptime requirement for web portal.", "C": "Savings Plan is a billing commitment, not an architecture. Running extraction program in ASG continuously wastes cost for infrequent workload. Doesn't address on-demand invocation.", "D": "Migrating portal to S3 static site + API Gateway rewrites the entire existing portal. Directly violates 'no code changes' requirement.", "_summary": "On-Demand ASG for uptime + Lambda for infrequent extraction = no portal code changes needed"}, "465": {"A": "gp3 volumes do not support EBS Multi-Attach. Multi-Attach is limited to Provisioned IOPS SSD volumes only.", "B": "st1 (HDD-based) volumes do not support EBS Multi-Attach. Only io1/io2 SSD volumes support it.", "C": "io2 Provisioned IOPS SSD volumes support EBS Multi-Attach on Nitro-based instances within same AZ. Only volume type that satisfies simultaneous multi-instance write requirement. Correct.", "D": "gp2 volumes do not support EBS Multi-Attach. Same restriction as gp3 — only io1/io2 qualify.", "_summary": "EBS Multi-Attach exclusive to io1/io2 Provisioned IOPS SSD on Nitro instances same AZ"}, "1003": {"A": "Mountpoint for S3 mounts S3 as POSIX filesystem but has no local cache. Every read hits S3 over network. Latency for on-premises rendering is unacceptable for performance-sensitive workloads.", "B": "S3 File Gateway caches frequently accessed data on-premises via local cache disk. NFS/SMB interface requires no app changes. Low-latency reads from local cache, transparent S3 backend. Cost-effective. Correct.", "C": "Copying data to FSx for Windows then using FSx File Gateway is expensive double-storage: FSx costs plus S3 costs. Unnecessary complexity.", "D": "Custom on-premises file server with S3 API requires building and maintaining sync/cache logic. High implementation effort, no built-in caching intelligence.", "_summary": "S3 File Gateway local cache solves on-premises latency while keeping S3 as source of truth"}, "373": {"A": "S3 Intelligent-Tiering charges per-object monitoring fee (~$0.0025/1000 objects). Trillions of objects = enormous monitoring cost. Access pattern is predictable, so Intelligent-Tiering adds cost without benefit.", "B": "S3 Intelligent-Tiering cannot automatically transition to Deep Archive based on time elapsed — it tiers by access frequency only. Lifecycle policy needed regardless. Still carries per-object monitoring fee problem.", "C": "S3 Standard-IA has retrieval fees and 30-day minimum storage. Data used daily in first 30 days incurs heavy retrieval charges. Wrong tier for frequently accessed recent data.", "D": "S3 Standard for first 30 days (daily access, no retrieval fees), transition to Standard-IA after 30 days (quarterly access, minimal delay, low retrieval cost), Deep Archive after 1 year. Matches access pattern exactly, no per-object monitoring overhead. Correct.", "_summary": "Match lifecycle tiers to access pattern: Standard→Standard-IA→Glacier Deep Archive beats Intelligent-Tiering for predictable trillions-of-objects workload"}, "338": {"A": "Binary log replication works but is manual/custom setup with higher operational overhead than native Aurora Global Database; keeping one instance is required but approach is suboptimal.", "B": "Aurora Global Database requires at least one DB instance in secondary Region to store replicated data; removing it makes the secondary Region useless — invalid.", "C": "DMS continuous replication is viable but removing the DB instance from secondary Region is impossible — data has nowhere to land — invalid.", "D": "Aurora Global Database uses storage-level replication (low latency, managed), minimum one DB instance in secondary Region is the correct and cost-effective DR setup.", "_summary": "Aurora Global Database requires ≥1 instance in secondary Region; native replication beats DMS or binlog for cost+ops"}, "544": {"A": "API Gateway canary deployments natively split traffic by percentage, allow live verification, then promote to prod — zero DNS changes, minimal blast radius, correct.", "B": "Import merge mode adds new resources without removing existing ones but deploys directly to production with no gradual rollout — risky for availability.", "C": "Import overwrite mode replaces entire API definition atomically on production — highest disruption, fails the 'minimal effects' requirement.", "D": "New endpoint + new custom domain + Route 53 cutover introduces DNS propagation delay and full traffic switch — not gradual, more data-loss risk than canary.", "_summary": "API Gateway canary release = built-in gradual traffic shifting without DNS changes"}, "157": {"A": "Manual snapshots have no automated expiry lifecycle; requires manual deletion after 5 years — not a scalable automated solution.", "B": "Aurora automated backup retention max is 35 days — cannot be configured for 5-year retention, option is factually invalid.", "C": "Same issue as B — Aurora automated backups cap at 35 days, 5-year retention is not possible with this setting.", "D": "Exporting DB logs (PostgreSQL audit logs) to CloudWatch Logs supports indefinite retention — satisfies the 'keep audit logs forever' requirement.", "E": "AWS Backup supports multi-year retention with lifecycle rules to delete after exactly 5 years — satisfies data retention and deletion requirements.", "_summary": "AWS Backup for long-term data retention; CloudWatch Logs export for indefinite audit log retention"}, "151": {"A": "AWS Control Tower provides data residency guardrails that preventively deny internet access and restrict all activity to specified Regions — proactive control, correct.", "B": "AWS WAF filters HTTP/S web traffic, not VPC-level network internet access — wrong tool for blocking internet gateway attachment.", "C": "AWS Organizations SCPs can deny ec2:CreateInternetGateway and restrict all Regions except ap-northeast-3 at account level — preventive, scalable, correct.", "D": "NACLs block traffic but don't prevent internet gateways from being attached; per-user IAM policies don't prevent VPC-level internet access and are high operational overhead.", "E": "AWS Config rules detect and alert (reactive) — they do not prevent internet gateway creation or region usage; fails compliance requirement.", "_summary": "SCPs and Control Tower guardrails prevent actions; Config/WAF/NACLs are reactive or wrong layer"}, "19": {"A": "NLB in application VPC can't transparently intercept and redirect all inbound traffic to an inspection VPC appliance in a scalable way — wrong architecture.", "B": "ALB operates at Layer 7 and cannot transparently forward raw IP packets to a third-party firewall appliance — wrong layer for packet inspection.", "C": "Transit Gateway connects VPCs but requires complex route table manipulation across multiple VPCs and attachments — higher operational overhead.", "D": "Gateway Load Balancer is purpose-built for transparent third-party appliance insertion; GWLB endpoint in application VPC intercepts traffic, GWLB load-balances to appliance — least operational overhead, correct.", "_summary": "GWLB + GWLB endpoint = purpose-built transparent network appliance insertion with minimal ops"}, "70": {"A": "NLB operates at Layer 4 (TCP/UDP); while it can do HTTP health checks on targets, it cannot detect application-layer HTTP error responses from the app — root problem unsolved.", "B": "Cron job is a custom script — explicitly prohibited by requirements.", "C": "ALB operates at Layer 7, natively performs HTTP health checks, marks instances returning errors as unhealthy, and triggers ASG replacement — solves root cause without custom code, correct.", "D": "CloudWatch alarm on UnhealthyHostCount still relies on NLB health detection which can't see HTTP errors — alarm fires only when NLB already marks instance unhealthy via TCP check.", "_summary": "NLB can't detect HTTP errors; ALB HTTP health checks + ASG replacement = correct layer 7 solution"}, "69": {"A": "Multi-Region deployment with Route 53 + Cross-Region Replication is over-engineered and high operational effort for AZ-level HA requirements.", "B": "Multi-AZ ASG covers compute HA; Aurora Multi-AZ covers DB HA; RDS Proxy manages connection pooling and reduces failover connection storm — comprehensive HA with least operational effort, correct.", "C": "Single AZ ASG is not highly available; hourly snapshots mean up to 1 hour data loss — fails both HA and minimal data loss requirements.", "D": "Multi-Region + S3 + Lambda is extremely complex, not a standard DB pattern, and has high operational overhead — incorrect.", "_summary": "Multi-AZ ASG + Aurora Multi-AZ + RDS Proxy = HA with minimal ops and failover connection management"}, "529": {"A": "EC2 requires full OS patching, DB engine management, backups — increases operational overhead, opposite of requirement.", "B": "RDS is fully managed (patching, backups, failover handled by AWS); encryption at rest via KMS satisfies security requirement — reduces ops overhead and increases security, correct.", "C": "S3 is object storage, unsuitable for transactional relational databases — wrong service class entirely.", "D": "RDS is correct service but CloudWatch Logs provides monitoring/logging, not encryption or primary data security — incomplete security posture.", "_summary": "RDS managed service cuts ops overhead; encryption at rest addresses security; S3/EC2 wrong for transactional DBs"}, "939": {"A": "Deletes read replica entirely — removes reporting capacity and provides no buffer for future growth, despite replica being undersized not useless.", "B": "Correct. Replica at 25% CPU is oversized; downsize it. Primary at 60% is healthy headroom — no change needed. Meets growth requirement.", "C": "Replica doesn't need to grow; primary at 60% is fine. Resizing primary smaller risks headroom for growth.", "D": "Deleting replica forces all reads back to primary which is already at 60%, reducing growth headroom. Making primary larger adds cost unnecessarily.", "_summary": "Rightsize underutilized replica; leave healthy primary alone"}, "502": {"A": "S3 has no native POSIX mount. Third-party tools like s3fs are unsupported workarounds — not a valid resilient architecture.", "B": "NFS from primary EC2 creates single point of failure; defeats purpose of adding instances.", "C": "Correct. EFS is a managed NFS share mountable on multiple EC2 instances simultaneously — shared images survive any single instance failure.", "D": "Global Accelerator routes traffic across regions/edge; overkill and expensive for single-region website resilience. CloudFront is the right CDN choice here.", "E": "Correct. ASG+ALB provides horizontal scaling and availability; CloudFront caches content at edge, reducing origin load and improving latency.", "_summary": "EFS for shared storage + ASG/ALB/CloudFront for scale and resilience"}, "469": {"A": "S3 Replication copies objects between buckets — it does not transition storage classes based on access frequency.", "B": "Lifecycle to Standard-IA forces objects into IA regardless of access pattern; unpredictable access risks frequent retrieval surcharges.", "C": "Correct. Intelligent-Tiering monitors access and auto-moves objects between tiers with no retrieval fees. Only monitoring charge per object. Perfect for unpredictable patterns.", "D": "S3 Inventory generates reports; it does not automate transitions based on access. Extra operational step with no access-pattern awareness.", "_summary": "Unpredictable access → S3 Intelligent-Tiering auto-tiers with zero retrieval penalty"}, "446": {"A": "Versioning + Lifecycle can still delete objects. MFA delete adds friction but is manual overhead and doesn't satisfy immutable legal retention.", "B": "Governance mode allows privileged users (and root) to override retention — does not meet strict legal requirements. Also 'recopy' is manual overhead.", "C": "Compliance mode is correctly immutable — even root cannot delete. But manually recopying all existing objects is high operational overhead.", "D": "Correct. Compliance mode = legally immutable, no override possible. S3 Batch Operations applies Object Lock to all existing objects automatically — least operational overhead.", "_summary": "Compliance mode for immutability + Batch Operations to retrofit existing objects"}, "975": {"A": "Correct. Athena is serverless, pay-per-query, natively reads Parquet (columnar — efficient scans), and supports CSE-KMS decryption. Cheapest for occasional queries.", "B": "S3 Select queries a single object at a time. Cannot aggregate across multiple files/prefixes for moving averages.", "C": "Redshift requires a running cluster — billed continuously even when idle. Excessive cost for occasional queries.", "D": "EMR Serverless has higher startup overhead and complexity than Athena for simple SQL on S3. Less cost-effective for occasional use.", "_summary": "Occasional SQL on S3 Parquet → Athena serverless pay-per-query is cheapest"}, "923": {"A": "Correct. Compute Optimizer analyzes CloudWatch metrics and recommends right-sized instance type — vertical rightsizing reduces waste and CPU pressure.", "B": "Creating AMI + launch template is a prerequisite step but alone adds no scaling or availability — incomplete without an ASG.", "C": "ASG scales horizontally (adds instances), not vertically. Cannot use ASG to change instance size dynamically.", "D": "Compute Optimizer recommends instance types (vertical sizing), not horizontal scaling strategies. Misleading framing.", "E": "Correct. ASG + ALB adds horizontal scaling for CPU spikes and improves availability with multiple instances — directly addresses 100% CPU and single-instance risk.", "_summary": "Vertical rightsize via Compute Optimizer + horizontal scale via ASG/ALB"}, "885": {"A": "EC2 Instance Savings Plan covers only EC2 in a specific family/region — does not cover SageMaker.", "B": "Compute Savings Plan covers EC2, Lambda, Fargate — but NOT SageMaker. Wrong claim.", "C": "Correct. SageMaker Savings Plan covers SageMaker. Required as separate plan since no other SP covers it.", "D": "Correct. Compute Savings Plan covers EC2 + Lambda + Fargate — three services with one plan, most flexible SP available.", "E": "EC2 Instance Savings Plan covers only EC2 in specific instance family — does not cover Fargate.", "_summary": "Compute SP covers EC2/Lambda/Fargate; SageMaker SP covers SageMaker — 2 plans, 4 services"}, "463": {"A": "Glue minimum billing unit is 1 DPU-minute with a 10-minute minimum per job — expensive for a 30-second workload.", "B": "EMR spins up a cluster; heavy overhead and cost for 2 MB of data processed in 30 seconds.", "C": "Correct. Lambda supports up to 10 GB memory and 15-minute timeout. 1 GB / 30 seconds fits perfectly. Pay only per invocation — most cost-effective for small, short, per-mattress jobs.", "D": "Same billing problem as Glue Scala — PySpark on Glue has 10-minute minimum, overkill for this workload.", "_summary": "Lambda ideal: fits 1 GB/30s constraints, pay-per-invocation cheapest for small nightly per-device jobs"}, "458": {"A": "EC2 meets compute needs but requires OS patching, scaling config, high admin effort — eliminated.", "B": "Lambda integrates natively with API Gateway, supports up to 10GB memory, fully serverless — least admin effort for compute.", "C": "RDS is managed relational DB, covers 2GB storage, multi-AZ handled by AWS — least admin effort for relational data.", "D": "DynamoDB is NoSQL key-value store — explicitly disqualified by 'relational format' requirement.", "E": "EKS requires cluster provisioning, node management, k8s expertise — high admin effort, overkill here.", "_summary": "API Gateway + Lambda (compute) + RDS (relational managed DB) = serverless + managed = min overhead"}, "68": {"A": "Direct Connect gives consistent low latency; VPN backup is cheap and accepts degraded performance on failover — matches all requirements exactly.", "B": "Both VPN tunnels traverse public internet — cannot guarantee consistent low latency, fails primary requirement.", "C": "Dual Direct Connect provides redundancy but doubles cost — violates minimize-costs requirement.", "D": "No 'failover attribute' exists in AWS CLI for Direct Connect — this option is fabricated.", "_summary": "DX primary for low latency + VPN backup for cost-effective failover = canonical hybrid HA pattern"}, "67": {"A": "CreateQueue creates new queue — unrelated to duplicate processing problem.", "B": "AddPermission manages IAM/SQS permissions — unrelated to visibility or deduplication.", "C": "ReceiveMessage wait time controls long polling — reduces empty receives but does not prevent duplicate processing.", "D": "Visibility timeout expiring before processing+delete completes causes another consumer to pick up same message; ChangeMessageVisibility extends it, giving worker enough time to finish and delete — eliminates duplicate writes.", "_summary": "Duplicate RDS records = visibility timeout too short; extend it so message stays invisible until deleted"}, "66": {"A": "S3 Glacier retrieval takes minutes to hours — violates 'immediate accessibility always required'.", "B": "S3 One Zone-IA stores in single AZ — critical data at risk if AZ fails; also immediate access fine but durability concern disqualifies it.", "C": "S3 Standard-IA provides immediate access, multi-AZ durability, lower cost for infrequent access after 30 days, deletion at 4 years — meets every constraint.", "D": "Moving to Glacier at 4 years contradicts policy to DELETE at 4 years, and Glacier lacks immediate accessibility.", "_summary": "Standard → Standard-IA at 30d + delete at 4yr = cost-effective with immediate access and correct retention"}, "65": {"A": "Custom Python libraries require coding, testing, maintenance — higher operational overhead than managed services.", "B": "SageMaker requires custom model training and MLOps pipeline for PHI — significant operational overhead.", "C": "Textract extracts text from PDFs and JPEGs accurately; Comprehend Medical is purpose-built for PHI detection in medical text — both fully managed, zero model training needed.", "D": "Rekognition analyzes images for objects/faces/labels — not designed for document text extraction; Textract is the correct service for that.", "_summary": "Textract (document OCR) + Comprehend Medical (PHI NLP) = fully managed PHI pipeline with least overhead"}, "64": {"A": "Reconfiguring all on-premises workloads to hit FSx over VPN adds latency and changes access patterns — violates requirements.", "B": "S3 File Gateway uses NFS/SMB to S3 but lacks Windows ACL semantics and DFS namespace support needed for Windows workloads.", "C": "S3 doesn't natively support Windows file access patterns; splitting workloads between S3 direct and gateway changes access patterns.", "D": "FSx File Gateway caches frequently accessed files locally for low latency on-premises access; FSx for Windows File Server on AWS serves cloud workloads natively; no access pattern changes required for either side.", "_summary": "FSx File Gateway on-prem (local cache) + FSx for Windows on AWS = low latency both sides, no pattern changes"}, "63": {"A": "S3 PUT event triggers Lambda on upload — fully serverless, auto-scaling, pay-per-invocation, cheapest for spiky/growing demand.", "B": "DynamoDB has 400KB item size limit — cannot store 5MB PDFs; fundamentally wrong service for file storage.", "C": "Elastic Beanstalk with EC2+EBS runs 24/7 — expensive for workload that only needs compute during conversions; EBS not shared across instances.", "D": "Contradicts itself (mentions EFS then says save in EBS); EC2-based solution still requires always-on instances — not cost-effective.", "_summary": "S3 event → Lambda is canonical serverless file-processing pattern: scales to zero, pays per conversion"}, "62": {"A": "ACM managed renewal only works for ACM-issued certificates — external CA certs imported into ACM are not auto-renewed.", "B": "Importing key material doesn't change renewal behavior; ACM still cannot auto-renew imported external certs.", "C": "ACM Private CA issues certificates from a private internal CA — question requires external CA certificate, not private CA.", "D": "Import external CA cert into ACM (valid path), attach to ALB, use EventBridge rule on ACM expiry event to trigger notification for manual rotation — correct because ACM cannot auto-renew imported certs.", "_summary": "External CA certs imported to ACM require manual rotation; EventBridge expiry alarm is the AWS-native reminder mechanism"}, "61": {"A": "Instance metadata not designed for secrets; Lambda-based rotation of both metadata and RDS credentials simultaneously = high operational overhead.", "B": "S3 config file + scheduled Lambda rotation works but requires custom rotation logic and versioning management — high overhead vs managed solution.", "C": "Secrets Manager natively supports automatic RDS credential rotation with zero custom code; EC2 IAM role grants least-privilege access — lowest operational overhead.", "D": "Parameter Store SecureString lacks built-in automatic rotation for RDS unlike Secrets Manager; rotation must be implemented manually via Lambda.", "_summary": "Secrets Manager = managed RDS rotation, no custom Lambda needed"}, "60": {"A": "NACLs block traffic at subnet level — blocking HTTP port 80 denies traffic entirely rather than redirecting it to HTTPS.", "B": "ALB listener rules have no URL string-replace action; redirect action exists but operates at protocol level, not string substitution.", "C": "ALB listener rules support a native 'redirect' action that sends HTTP requests to HTTPS with correct status code (301/302) — built-in feature, no custom logic.", "D": "NLB operates at Layer 4 (TCP) and cannot inspect or redirect HTTP/HTTPS; SNI is for TLS cert selection, not protocol redirection.", "_summary": "ALB redirect listener rule: HTTP→HTTPS is native built-in action"}, "54": {"A": "S3 uses APIs/URLs, not SMB/UNC paths — breaks how users currently access files; requires application changes.", "B": "S3 File Gateway provides SMB but adds gateway layer complexity and doesn't deliver native Windows file share HA/durability as cleanly as FSx.", "C": "FSx for Windows File Server natively supports SMB protocol (preserving existing access patterns) and Multi-AZ provides HA + durability without workflow changes.", "D": "EFS uses NFS protocol; Windows workloads do not natively use NFS — breaks existing Windows file share access patterns.", "_summary": "FSx for Windows = SMB-native, Multi-AZ HA, zero client reconfiguration"}, "53": {"A": "S3 Glacier has retrieval latency (minutes to hours) — violates 'immediately accessible for 1 year'; access control policies can be modified by root users.", "B": "IAM policies can always be modified by root user — cannot prevent deletion by all users including root; requirement explicitly forbids root deletion.", "C": "S3 Standard satisfies immediate access; Lifecycle to Glacier Deep Archive after 1 year; Object Lock compliance mode prevents deletion by ALL users including root/admins for full 10 years; S3 Standard is multi-AZ (maximum resiliency).", "D": "S3 One Zone-IA stores data in single AZ — fails 'maximum resiliency' requirement; Object Lock governance mode allows users with special IAM permissions to delete, violating no-deletion requirement.", "_summary": "Object Lock compliance mode = legally immutable, even root cannot delete"}, "276": {"A": "RDS Storage Auto Scaling is a native feature that automatically increases allocated storage when free space drops below threshold — directly solves RDS storage exhaustion with zero custom work.", "B": "Oracle-specific PL/SQL functions are incompatible with Aurora (Aurora supports MySQL/PostgreSQL only) — migration not feasible without rewriting application logic.", "C": "CloudWatch alarm for low storage only notifies; it does not trigger automatic storage scaling — still requires manual intervention.", "D": "CPU utilization is a native CloudWatch metric for EC2; configuring it as Auto Scaling group scaling metric directly addresses EC2 overload from increasing traffic.", "E": "Free memory is not a default EC2 CloudWatch metric — requires CloudWatch agent installation and custom metric configuration; adds operational overhead and complexity.", "_summary": "A+D: RDS Storage Auto Scaling + CPU-based ASG scaling = both layers auto-scale"}, "50": {"A": "Lambda has 15-min timeout and no native mechanism to execute commands inside EC2 instances at scale — wrong tool for OS/software patching.", "B": "Patch Manager uses patch baselines designed for OS patches (Windows Update, yum/apt); third-party software patching requires custom Run Command documents, not Patch Manager baselines.", "C": "Maintenance windows introduce scheduling delay ('as quickly as possible' violated) — designed for change-control windows, not emergency remediation.", "D": "Run Command executes immediately across all 1,000 instances in parallel using a custom document/script — fastest path for emergency third-party patch deployment.", "_summary": "Run Command = immediate parallel execution across fleet, no scheduling delay"}, "48": {"A": "ElastiCache Redis is in-memory only; data lost on restart — not durable for catalog storage.", "B": "Larger instance store is still ephemeral — data lost when instance stops/terminates; does not solve durability problem.", "C": "S3 Glacier Deep Archive requires hours for retrieval — not suitable for a catalog requiring immediate access.", "D": "EFS is a managed network file system with multi-AZ redundancy and persistence independent of EC2 lifecycle — provides both high availability and durability.", "_summary": "Instance store = ephemeral; EFS = persistent, HA, durable network storage"}, "47": {"A": "Reserved Instances are a billing discount construct, not a capacity reservation — do not guarantee physical capacity; also require 1-3 year commitment vs 1-week need.", "B": "On-Demand Capacity Reservations require AZ specification — Region-level reservation is not a valid option for this resource type.", "C": "Reserved Instances guarantee billing rates, not physical capacity in specific AZs — capacity is not reserved even with AZ-scoped RIs.", "D": "On-Demand Capacity Reservations specified at AZ level guarantee physical EC2 capacity immediately with no term commitment — correct for short-term, AZ-specific capacity guarantee.", "_summary": "Capacity Reservation ≠ Reserved Instance; only ODCR guarantees physical capacity"}, "45": {"A": "Lambda already spans AZs by default; adding AZs doesn't prevent message loss from transient network failures.", "B": "SQS queue subscribed to SNS buffers messages durably; if Lambda fails, messages wait in queue for retry. Correct.", "C": "CPU/memory irrelevant to network failures causing missed invocations.", "D": "Lambda has no 'provisioned throughput' knob; this option doesn't exist as described.", "E": "Lambda polling SQS uses visibility timeout + retry logic; unprocessed messages stay in queue until success. Correct.", "_summary": "SNS→SQS→Lambda pattern adds durable buffer, eliminates message loss on transient failures"}, "44": {"A": "Versioning preserves all object versions; accidental delete creates a delete marker, original recoverable. Correct.", "B": "MFA Delete requires MFA token to permanently delete versions or disable versioning; strong guard against accidental permanent loss. Correct.", "C": "Bucket policy restricts access but doesn't protect authorized users from accidentally deleting.", "D": "Default encryption protects data at rest, has no bearing on deletion.", "E": "Lifecycle policies automate deletion; adds risk, doesn't prevent it.", "_summary": "Versioning+MFA Delete = layered protection: recovery path + hard barrier to permanent deletion"}, "43": {"A": "VPN still traverses internet; doesn't free up internet bandwidth for internal users.", "B": "Direct Connect = dedicated private circuit, completely separate from internet link; backups don't consume internet bandwidth. Correct.", "C": "Snowball is for bulk offline transfer, not suitable for time-sensitive recurring backups.", "D": "S3 has no bandwidth-related service limits; removing them solves nothing.", "_summary": "Direct Connect offloads backup traffic off internet entirely—long-term, timely, no bandwidth contention"}, "42": {"A": "AZ-local NAT gateways reduce cross-AZ transfer cost but still incur NAT→S3 data transfer charges.", "B": "NAT instance cheaper than NAT gateway but still routes S3 traffic over internet, incurring transfer charges.", "C": "Gateway VPC endpoint routes S3 traffic over AWS private network; no NAT gateway needed, no regional data transfer charges. Correct.", "D": "Dedicated Host affects compute tenancy, not data transfer costs.", "_summary": "Gateway VPC endpoint for S3 eliminates NAT gateway data-processing and regional transfer charges"}, "341": {"A": "EMR to SPICE is heavy ETL and SPICE bypasses Lake Formation column-level controls entirely.", "B": "IAM policies on QuickSight users for column-level control are complex and don't integrate cleanly with Lake Formation governance.", "C": "Glue Elastic Views was deprecated; S3 bucket policies cannot enforce column-level access control.", "D": "Lake Formation blueprint ingests Aurora to S3 natively; Lake Formation column-level grants apply to Athena queries; QuickSight+Athena honors LF permissions. Least overhead. Correct.", "_summary": "Lake Formation native column-level security + Athena = governed join with minimal ops overhead"}, "965": {"A": "Client-side encryption with CMK encrypts data before it ever leaves the client—satisfies 'before storing in S3'. Correct.", "B": "SSE-KMS encrypts at the S3 service layer, not before the data is transmitted to S3; fails the 'before storing' requirement.", "C": "SSE-C also server-side; customer provides key but encryption still happens at S3, not before upload.", "D": "S3 managed keys only exist for server-side encryption (SSE-S3); client-side encryption with S3-managed keys is not a real AWS feature.", "_summary": "'Before storing' = client-side encryption; only option A encrypts prior to transmission to S3"}, "268": {"A": "ElastiCache (Redis/Memcached) caches frequent DB reads in memory; dramatically reduces RDS load with minimal app code changes. Correct.", "B": "RDS Proxy manages connection pooling to reduce connection overhead, not read throughput; doesn't solve read performance.", "C": "Moving to Lambda is a major architectural change, not minimal.", "D": "Migrating to DynamoDB requires data model redesign and significant app changes.", "_summary": "ElastiCache as read cache in front of RDS = fastest path to read performance improvement with least architectural change"}, "291": {"A": "Signed cookies grant access without changing URLs—covers users with hardcoded URLs who support cookies. Correct.", "B": "Signed URLs work per-request without cookies—covers users whose HTTP clients don't support cookies. Correct.", "C": "AppSync is a GraphQL API service; unrelated to CloudFront content access control.", "D": "CloudFront doesn't natively validate JWTs for access control; requires Lambda@Edge custom logic.", "E": "Secrets Manager stores credentials; doesn't provide CloudFront access control mechanisms.", "_summary": "Signed URLs for no-cookie clients + Signed cookies for hardcoded-URL clients = covers both user segments without forcing changes"}, "200": {"A": "Lambda authorizer works but requires writing/maintaining custom auth code — adds development overhead.", "B": "API keys + Lambda validation requires key management and custom code — not least overhead.", "C": "Email header + Lambda is insecure (spoofable) and requires custom validation logic.", "D": "Cognito user pool authorizer is a native API Gateway feature — no custom code needed, fully managed, zero Lambda required.", "_summary": "Cognito user pool authorizer = built-in API Gateway auth, zero Lambda overhead"}, "199": {"A": "Rekognition handles image/video analysis, not audio speaker recognition — wrong service entirely.", "B": "Transcribe supports speaker diarization (multi-speaker). Athena queries S3 transcript files via SQL. S3 handles 7-year retention natively.", "C": "Translate does language translation, not speaker recognition — wrong service. Redshift overkill for file querying.", "D": "Rekognition wrong for audio. Textract extracts text from documents/images, not for transcript business analysis.", "_summary": "Transcribe=speaker diarization; Athena=serverless SQL on S3"}, "925": {"A": "Governance mode allows users with s3:BypassGovernanceRetention permission to override or delete — not fully protected.", "B": "Compliance mode: no one (including root) can shorten retention or delete objects during period — satisfies regulatory immutability.", "C": "Versioning + lifecycle only archives old versions; objects still deletable before retention period ends.", "D": "Glacier transition is storage tiering only — provides no deletion/modification protection.", "_summary": "Compliance mode = immutable, no override, even by root — use for regulatory retention"}, "296": {"A": "10.0.1.0/32 prefix length invalid for VPC CIDR — AWS requires /16 to /28 minimum.", "B": "192.168.0.0/24 overlaps with development VPC — peering requires non-overlapping CIDRs, invalid.", "C": "192.168.1.0/32 prefix length invalid for VPC CIDR — same reason as A.", "D": "10.0.1.0/24 non-overlapping + valid prefix length. Only valid option; /24=smallest valid choice from these answers.", "_summary": "VPC peering needs non-overlapping CIDRs; VPC prefix must be /16–/28"}, "194": {"A": "Two EC2 across AZs in cluster with replication provides HA and automatic failover — meets both requirements.", "B": "AMI backup + CloudFormation requires manual intervention to recover — not automatic failover.", "C": "Multi-region replication is expensive and cross-region failover is not automatic without additional tooling.", "D": "EC2 automatic recovery restores the same instance in same AZ — does not handle DB failover logic.", "_summary": "Multi-AZ EC2 cluster with replication = HA + auto failover"}, "125": {"A": "Auto Scaling in private subnets + RDS Multi-AZ in private subnets — EC2/RDS not internet-exposed, highly available. Correct.", "B": "ALB in private subnets cannot receive inbound internet traffic — ALB must sit in public subnets.", "C": "EC2 in public subnets violates requirement that EC2 not be exposed to public internet.", "D": "Two public subnets + two private subnets + two NAT gateways + ALB in public subnets — provides HA, NAT enables private EC2 to reach third-party payment service. Correct.", "_summary": "Private EC2+RDS with public ALB and NAT gateways = HA + internet-isolated backend"}, "551": {"A": "Standard for week-1 access, then Glacier (3–5hr retrieval, within 6hr SLA) for years — cheapest long-term option. Correct.", "B": "Standard-IA bills 128KB minimum per object; 50KB files incur size penalty — more expensive than Glacier for long storage.", "C": "Intelligent-Tiering charges per-object monitoring fee; 50KB small objects make this uneconomical.", "D": "Glacier Deep Archive minimum retrieval is 12 hours — violates the 6-hour requirement.", "_summary": "Glacier Standard retrieval ≤5hr satisfies 6hr SLA at lowest long-term cost"}, "409": {"A": "RDS is a relational database service — cannot replace an SMB/NFS file share for IIS.", "B": "Storage Gateway designed for hybrid on-premises connectivity — adds operational complexity vs native cloud option.", "C": "FSx for Windows File Server is fully managed Windows-native SMB file system — purpose-built for Windows workloads, Multi-AZ, durable. Correct.", "D": "EFS uses NFS protocol — Windows IIS servers cannot mount EFS natively without additional tooling.", "_summary": "FSx for Windows File Server = managed SMB, native Windows compatibility, Multi-AZ durable"}, "33": {"A": "DynamoDB has no native 'remove sensitive data on write' rule — would require custom Lambda trigger; DynamoDB Streams works for sharing but this option misrepresents write-time transformation.", "B": "Kinesis Firehose has no native DynamoDB delivery destination; Firehose delivers to S3/Redshift/OpenSearch. Architecture is invalid.", "C": "Kinesis Data Streams supports near-real-time multi-consumer fan-out; Lambda integration processes each record (strips sensitive data) before DynamoDB write; other apps consume same stream concurrently. Fits all requirements.", "D": "Batching files in S3 then processing with Lambda is batch architecture, not near-real-time. Violates explicit near-real-time requirement.", "_summary": "Kinesis Data Streams = near-real-time fan-out + Lambda transformation before DynamoDB write"}, "32": {"A": "Fargate runs containers — operational overhead and cost far exceed requirements for static HTML/CSS/JS/images.", "B": "S3 static website hosting natively serves HTML/CSS/JS/images with no server, no management, pay-per-GB — lowest cost option for static content.", "C": "EC2 requires instance management, patching, and baseline cost even at zero traffic — overkill for static files.", "D": "ALB + Lambda + Express.js adds unnecessary runtime complexity and cost for content that needs no server-side logic.", "_summary": "S3 static hosting = cheapest, zero-ops solution for purely static websites"}, "31": {"A": "AWS Config managed rule `required-tags` automatically detects non-compliant resources across EC2, RDS, Redshift with no custom code — minimal operational overhead by design.", "B": "Cost Explorer is for cost analysis, not compliance enforcement. Manual tagging = high ongoing effort.", "C": "Custom API code on EC2 requires maintaining the instance, code, and execution schedule — high operational overhead.", "D": "Lambda + CloudWatch Events improves on C but still requires writing and maintaining custom compliance code vs. using Config's built-in managed rules.", "_summary": "AWS Config managed rules = purpose-built, no-code tagging compliance with minimal ops overhead"}, "434": {"A": "Pre-deployed Auto Scaling group + LB in DR region (warm standby) means near-zero spin-up time; DynamoDB global tables replicate data continuously; Route 53 DNS health check failover is native and fast. Minimizes downtime.", "B": "CloudFormation 'launched when needed' = cold standby — stack creation takes minutes, increasing RTO. DynamoDB not addressed.", "C": "CloudFormation for compute still requires launch time during failover; DynamoDB global tables correct but compute readiness lags vs. A.", "D": "Pre-deployed compute + global tables is correct, but routing failover via CloudWatch alarm → Lambda → Route 53 API adds latency and failure points vs. native Route 53 health-check-based failover.", "_summary": "Warm standby (pre-deployed) + DynamoDB global tables + Route 53 DNS failover = minimum RTO"}, "140": {"A": "Spot Instances ideal for sporadic, interruptible, unpredictable workloads — up to 90% cheaper than On-Demand with correct use case.", "B": "On-Demand for interruptible sporadic workloads works but wastes money vs. Spot — not cost-optimized.", "C": "Compute Savings Plan covers EC2 + Fargate + Lambda — single commitment covers both predictable front-end (Fargate) and API (Lambda) workloads for 1 year.", "D": "Reserved Instances require steady-state predictable usage; data ingestion layer is sporadic/unpredictable — RI commitment would be wasted.", "E": "EC2 Instance Savings Plan covers only EC2 (specific instance family/region) — does NOT cover Fargate or Lambda, so it misses the front-end and API layer entirely.", "_summary": "Spot for interruptible compute; Compute Savings Plan (not EC2 Savings Plan) covers Fargate+Lambda"}, "914": {"A": "CloudFront+Amplify can host static sites but adds Amplify operational overhead; keeping MySQL on EC2 Reserved Instance maintains DB management burden — not least overhead.", "B": "CloudFront+S3 = standard globally-distributed static hosting; Lambda+API Gateway = serverless microservices with zero server management; RDS for MySQL = managed DB removing EC2 DB ops. Least overhead overall.", "C": "NLB does not support Lambda as targets for HTTP workloads — Lambda targets are supported by ALB only. Architecturally invalid.", "D": "S3 without CloudFront lacks global edge distribution; EC2 Reserved Instance for MySQL keeps operational overhead of managing OS/DB engine — fails both requirements.", "_summary": "CloudFront+S3 + Lambda+API Gateway + RDS = globally available, fully managed, zero server ops"}, "1002": {"A": "On-demand capacity mode with global tables works but on-demand pricing is 2-3x provisioned at steady load — less cost-effective at gaming scale.", "B": "DAX improves read performance but manual Cross-Region Replication via custom code adds operational overhead; not least cost-effective due to DAX instance cost + manual CRR complexity.", "C": "Using DynamoDB Streams for manual cross-region replication is complex custom code — global tables exist precisely to replace this pattern; on-demand mode adds extra cost vs. provisioned+auto scaling.", "D": "Global tables handle automatic multi-region replication natively; provisioned capacity + auto scaling is significantly cheaper than on-demand for predictable/scalable gaming loads. Best cost-availability balance.", "_summary": "Global tables (native replication) + provisioned+auto scaling = most cost-effective resilient DynamoDB"}, "177": {"A": "ElastiCache for Redis requires application-layer changes to route reads through cache — violates 'without reconfiguring the application.'", "B": "DAX is API-compatible with DynamoDB SDK — drop-in replacement, no application code changes; in-memory cache purpose-built for DynamoDB read acceleration.", "C": "Global tables replicate data across regions for availability, not for read latency improvement within a region — wrong tool for this problem.", "D": "ElastiCache for Memcached requires application reconfiguration to use Memcached endpoints — violates the no-reconfiguration constraint.", "_summary": "DAX = DynamoDB-native in-memory cache, zero app code changes required"}, "676": {"A": "KDS lacks native OpenSearch delivery — needs custom Lambda consumer to write records; Firehose is the correct streaming tool for direct OpenSearch ingestion.", "B": "Firehose has first-class OpenSearch delivery stream support; CloudWatch Logs → Firehose → OpenSearch is the canonical near-real-time pipeline. Correct.", "C": "VPC Flow Logs cannot publish to CloudTrail; CloudTrail captures API calls, not network traffic. Premise wrong.", "D": "Same fatal flaw as C: VPC Flow Logs have no CloudTrail integration regardless of which streaming service follows it.", "_summary": "VPC Flow Logs → CloudWatch Logs → Firehose → OpenSearch; Firehose not KDS for direct OpenSearch delivery"}, "478": {"A": "No Object Lock means any actor (or even IAM policy change) could delete or overwrite files before designated date; not the most secure.", "B": "Versioning enables Object Lock; retention period enforces WORM protection until designated date; bucket policy (not IAM user grants) enables public read without requiring AWS principals. Correct.", "C": "Reactive — Lambda replaces deleted objects after the fact; deletion window exists; not preventative and not 'most secure'.", "D": "Object Lock cannot be applied at folder level; it must be enabled at bucket creation and applied per-object or via default retention. Selecting a folder is not a valid method.", "_summary": "S3 Object Lock + Versioning + bucket policy = WORM public hosting; Lock must be bucket-level at creation"}, "322": {"A": "Lambda invoked synchronously by S3 event — user waits up to 60 s for Lambda to return before getting confirmation. Does not meet faster response requirement.", "B": "Step Functions orchestrates but still ties user response to workflow completion; no mechanism for immediate acknowledgment before thumbnail done.", "C": "SQS decouples upload receipt from processing — app immediately tells user image received, thumbnail generation happens asynchronously off the queue. Correct.", "D": "SNS fan-out still processes thumbnail before sending push notification; user waits up to 60 s for first notification.", "_summary": "SQS decouples ingestion ACK from processing; user gets immediate 'received' confirmation, thumbnail generated async"}, "158": {"A": "CloudFront edge caches both live HLS/DASH streams and on-demand VOD segments globally, reducing latency for all viewers. Correct.", "B": "Global Accelerator routes TCP/UDP over AWS backbone but does not cache content; no benefit for media segment delivery at scale.", "C": "Route 53 is DNS — improves routing decisions but does not cache or accelerate content delivery itself.", "D": "S3 Transfer Acceleration speeds uploads to S3 over AWS edge network; does not help with download/streaming performance.", "_summary": "CloudFront is the only option with edge caching for both live streaming and on-demand video delivery"}, "667": {"A": "Gateway endpoints are VPC route-table entries — they work only within the VPC; on-premises traffic over Direct Connect cannot use them.", "B": "Transit Gateway moves traffic between networks but does not create a private endpoint for S3; S3 traffic would still egress to internet without an endpoint.", "C": "Interface endpoints (PrivateLink) create ENIs with private IPs in the VPC; private DNS resolution works from on-premises over Direct Connect, keeping traffic off internet. Correct.", "D": "KMS manages encryption keys — does nothing to control network routing or prevent internet traversal.", "_summary": "Interface endpoints (PrivateLink) for S3 are reachable from on-premises over Direct Connect; gateway endpoints are VPC-only"}, "744": {"A": "NLB supports one Elastic IP per AZ at creation; clients whitelist those static IPs on their firewalls. Correct.", "B": "ALB does not support Elastic IP assignment — it uses DNS names that resolve to changing IPs; cannot be whitelisted by IP on client firewalls.", "C": "A Route 53 record pointing to a single EIP bypasses load balancing entirely; single point of failure and not a managed LB solution.", "D": "EC2 proxy is manually managed, single point of failure, and adds operational burden; not a recommended scalable pattern.", "_summary": "Only NLB supports Elastic IP assignment, giving clients static IPs to whitelist; ALB uses dynamic DNS"}, "717": {"A": "Internet-facing server is wrong — company has Direct Connect to on-premises so internal server is correct and more secure; S3 events work but managed workflow is better.", "B": "Single AZ is not resilient; violates multi-AZ resilience requirement.", "C": "EventBridge Scheduler with periodic polling contradicts 'process immediately' requirement; introduces up to 1-hour latency.", "D": "Internal server (uses existing Direct Connect), two AZs (resilient), S3 (scalable storage), managed workflow triggers Lambda immediately on file arrival. Correct.", "_summary": "Internal Transfer Family SFTP + two AZs + S3 + managed workflow = secure, resilient, event-driven immediate processing"}, "153": {"A": "Putting all files in Standard-IA from day 1 incurs retrieval fees during the first 90 days when files are frequently accessed — more expensive than Standard.", "B": "Intelligent-Tiering charges a per-object monitoring fee (~$0.0025/1000 objects/month); wasteful when access pattern is already known (drops after 90 days).", "C": "S3 Inventory is a reporting/auditing tool; it does not trigger object transitions. Lifecycle policies do.", "D": "Lifecycle policy keeps files in Standard (cheap retrieval) for first 90 days then auto-transitions to Standard-IA; matches known access pattern with no monitoring overhead. Correct.", "_summary": "Lifecycle policy to Standard-IA after 90 days is optimal when access pattern is known; avoids Intelligent-Tiering monitoring fee"}, "920": {"A": "SQS = point-to-point queue, not pub/sub. REST API also costs more than HTTP API — wrong pattern, wrong API tier.", "B": "SNS = correct pub/sub, but REST API is ~70% more expensive than HTTP API with same Lambda invoke capability — not MOST cost-effective.", "C": "Kinesis enhanced fan-out adds streaming complexity and cost for simple pub/sub; WebSocket API unnecessary here.", "D": "HTTP API cheapest API Gateway tier (~70% less than REST); SNS is native pub/sub. Correct pattern + lowest cost.", "_summary": "HTTP API < REST API cost; SNS = pub/sub; SQS = queue (not pub/sub)"}, "421": {"A": "Transfer Family does not support EBS as backend storage — only S3 or EFS. Invalid option.", "B": "EFS supports POSIX permissions (user permission control), high IOPS, attaches to Transfer Family. VPC endpoint with internet-facing access + elastic IPs + security group restricts trusted IPs. Meets all requirements.", "C": "S3 is object storage — not high IOPS, no POSIX user-level permissions. Fails high IOPS and permission control requirements.", "D": "Internal VPC endpoint in private subnet blocks internet-facing access — contradicts requirement to accept traffic from trusted internet IPs.", "_summary": "Transfer Family supports EFS (POSIX+IOPS) or S3; VPC endpoint + SG controls trusted IPs"}, "709": {"A": "Attaches SCP to root OU — affects ALL accounts including production. Overly broad, breaks production.", "B": "Attaching SCP directly to each of the 3 nonproduction member accounts works. SCPs can target individual accounts.", "C": "SCPs attached to management account do not apply to the management account itself; this doesn't restrict nonproduction member accounts.", "D": "Creates OU for production then attaches SCP there — restricts production instead of nonproduction. Backwards.", "E": "Creates dedicated OU, moves nonproduction accounts in, attaches SCP to that OU. Clean organizational approach, correct scope.", "_summary": "SCP can target individual accounts (B) or an OU containing those accounts (E); root OU and mgmt account are wrong targets here"}, "614": {"A": "PrivateLink exposes services across VPC/account boundaries — wrong tool for internal tier-to-tier EC2 communication. NACLs are stateless/IP-based, not SG-reference capable.", "B": "VPC endpoints are for AWS managed services (S3, DynamoDB) — not for routing between EC2 tiers in same VPC.", "C": "NLB works for load balancing but NACLs can't reference security groups — IP-based only, fragile with Auto Scaling changing IPs.", "D": "ALB fronts app servers; app server security group references web server security group as source — dynamic, scalable, correct multi-tier pattern.", "_summary": "Security groups reference other SGs; NACLs are IP-only and stateless — SG is right tool for tier isolation"}, "1014": {"A": "ECS with EC2 Spot requires managing EC2 infrastructure. SQS orchestrates queues, not workflows — Step Functions better. Higher ops overhead than B.", "B": "AWS Batch fully managed (no infra to manage), Step Functions orchestrates workflow serverlessly, S3 is durable and managed. All serverless/managed — least operational overhead.", "C": "EC2 Spot Instances require infrastructure management. FSx also requires provisioning. Violates no-infrastructure-management requirement.", "D": "EC2 instances require full infrastructure management. EBS not shareable across instances for distributed processing. Highest ops overhead.", "_summary": "AWS Batch + Step Functions + S3 = fully managed stack with zero infra management"}, "933": {"A": "Single API call (or console toggle) to enable Multi-AZ on existing instance. AWS handles standby replica, failover, replication. Minimal effort.", "B": "Heterogeneous migration (MySQL→DynamoDB) requires schema redesign, DMS setup, application code changes. Massive effort.", "C": "Creating new Multi-AZ instance and restoring snapshot is manual, error-prone, causes downtime — more effort than modifying existing instance.", "D": "RDS is managed service — cannot be put in EC2 Auto Scaling group. Architecturally invalid and databases don't scale horizontally like stateless apps.", "_summary": "Multi-AZ on existing RDS = single setting change; lowest effort HA solution"}, "87": {"A": "RDS Proxy pools/manages connections but cannot buffer writes when DB is completely offline during upgrade — data still lost.", "B": "Lambda max timeout is 15 minutes; DB upgrades can exceed that. Retry loop doesn't persist data durably across invocations.", "C": "Lambda /tmp storage is ephemeral per-invocation, not shared, not durable — data lost when function ends.", "D": "SQS FIFO queue durably stores events during DB unavailability. Separate Lambda polls queue and writes to DB post-upgrade. Fully decoupled, no data loss.", "_summary": "SQS decouples ingestion from storage; data persists in queue until DB is available again"}, "801": {"A": "KMS customer managed key — key material lives in AWS KMS inside AWS Cloud. Does not meet 'keys outside AWS' requirement.", "B": "KMS AWS managed key — entirely AWS-controlled. Keys never leave AWS. Fails requirement.", "C": "SSE-S3 (default) — keys managed by S3/AWS internally. Fails requirement.", "D": "Client-side encryption at company data center — keys never leave company premises, data encrypted before upload. Encrypted in transit (TLS to S3) and at rest (pre-encrypted). Only option satisfying 'manage keys outside AWS Cloud'.", "_summary": "'Keys outside AWS' = client-side encryption only; KMS variants (CMK or AWS-managed) keep keys inside AWS"}, "982": {"A": "IP-based bucket policy grants no temporary credentials and IPs can be spoofed or change — not secure.", "B": "IAM Roles Anywhere lets on-premises VMs use X.509 certs to assume IAM roles and get STS temporary credentials — correct fit for Identity Center + no long-term keys.", "C": "Long-term access keys in CLI config violate 'temporary access' requirement and are a credential leak risk.", "D": "Secrets Manager stores the secret but the underlying IAM user keys are still long-term, not temporary.", "_summary": "IAM Roles Anywhere = temporary creds for on-prem workloads via PKI"}, "96": {"A": "Policy restricts TO us-east-1 via StringEquals condition on RequestedRegion, not except it.", "B": "aws:SourceIp checks the caller's IP (user), not the EC2 instance's IP.", "C": "Correct — Allow on ec2:TerminateInstances fires only when region=us-east-1 AND caller IP=10.100.100.254/32.", "D": "Policy Effect is Allow, not Deny; the conditions restrict when the Allow applies, not block it.", "_summary": "Allow + condition = grant only when all conditions match"}, "320": {"A": "Kinesis Data Streams buffers in-flight data durably (reboot-safe), Kinesis Data Analytics queries stream in near-real-time — correct.", "B": "Firehose buffers 60–900 s before delivery to Redshift, violates near-real-time; also Firehose lacks real-time query capability itself.", "C": "Instance store is ephemeral and lost on reboot — contradicts the data-loss requirement stated in the problem.", "D": "ElastiCache Redis is a cache/pub-sub, not a queryable analytical store for JSON at scale.", "_summary": "Kinesis Streams = durable in-flight buffer; KDA = real-time SQL on stream"}, "146": {"A": "Spot can be interrupted mid-day at peak load, risking availability for a production app.", "B": "Reserved covers predictable overnight/weekend baseline cheaply; Spot handles bursty daytime peaks — minimizes cost without availability risk.", "C": "On-Demand for baseline costs more than Reserved for the same predictable load; Reserved always wins for steady usage.", "D": "Dedicated Instances are most expensive and add no benefit for a stateless web app.", "_summary": "Reserved = cheapest for steady baseline; Spot = cheapest for variable burst"}, "949": {"A": "Site-to-Site VPN connects on-prem to AWS over IPsec — not designed for app-to-SaaS connectivity inside AWS.", "B": "Transit Gateway routes between VPCs/accounts; third-party SaaS typically isn't a peer VPC in your Transit Gateway.", "C": "PrivateLink is bidirectional for service consumption; description of 'only outbound without enabling provider to establish' misrepresents how it works.", "D": "AWS PrivateLink lets the SaaS provider expose an endpoint service; app connects via VPC Endpoint — fully private, no public internet traversal.", "_summary": "PrivateLink = private Layer-4 connectivity to SaaS endpoint services"}, "392": {"A": "Port 443 open to 0.0.0.0/0 serves global dynamic IPs; DB port 3306 locked to web-server SG keeps DB off public internet — correct layered design.", "B": "Allowlisting specific customer IPs breaks for dynamic IPs and requires constant updates.", "C": "Dynamic IPs can't be enumerated in SG rules; exposing DB to customer IPs is also a security violation.", "D": "DB SG allowing 3306 from 0.0.0.0/0 exposes the database to the entire internet.", "_summary": "Web tier open to all on 443; DB tier allows only web-server SG on 3306"}, "936": {"A": "Lambda@Edge is for CDN-edge HTTP manipulation, not a secrets retrieval pattern.", "B": "Lambda layer provides shared retrieval logic once — all functions reuse it, zero per-function duplication — reduces operational overhead.", "C": "Secrets Manager stores secrets with built-in automatic rotation via managed Lambda rotators — least-overhead rotation solution.", "D": "Parameter Store SecureString lacks built-in auto-rotation; rotation requires custom Lambda setup, more overhead than Secrets Manager.", "E": "Dedicated Lambda consumer for env-var injection is complex, high overhead, not a standard pattern.", "_summary": "Secrets Manager (auto-rotation) + Lambda layer (shared retrieval) = least overhead"}, "230": {"A": "Two NAT gateways in same AZ = single AZ is still SPOF; not fault tolerant.", "B": "NAT instances with ASG/NLB add complexity and management burden; NAT Gateway is the managed replacement.", "C": "NAT Gateway auto-scales within AZ and is fully managed; one per AZ across two AZs = HA, fault tolerant, scalable — correct.", "D": "Spot Instances can be reclaimed at any time; NAT on Spot risks losing all egress traffic.", "_summary": "Managed NAT Gateway per AZ = auto-scale + HA with zero instance management"}, "218": {"A": "CORRECT. SGs stateful — inbound allow-443 automatically permits return traffic. Default SG has no inbound 443 rule, so new SG needed.", "B": "INCORRECT. Outbound rule to dest 0.0.0.0/0 port 443 does nothing for inbound client connections to web server.", "C": "INCORRECT. NACLs stateless — inbound-only rule blocks return traffic; missing outbound ephemeral-port rule.", "D": "INCORRECT. NACLs stateless — outbound 443 is wrong direction for return traffic; clients get responses on ephemeral ports 32768-65535, not 443.", "E": "CORRECT. NACLs stateless require explicit inbound (443) + outbound (ephemeral 32768-65535) rules for full TCP handshake.", "_summary": "NACL stateless = need both inbound 443 and outbound ephemeral; SG stateful = inbound only"}, "217": {"A": "CORRECT. Active-passive = only primary serves traffic (matches 'no need to handle load when primary healthy'). Aurora cross-region replica provides replication; 30-min RTO/RPO achievable.", "B": "INCORRECT. Active-active = both regions serve traffic simultaneously, overshoots requirement and costs more.", "C": "INCORRECT. Active-active wrong again; restoring from snapshot during failover likely exceeds 30-min RTO.", "D": "INCORRECT. Rebuilding infrastructure from AWS Backup during a live failover far exceeds 30-min RTO; Aurora has no 'second primary' concept in standard clusters.", "_summary": "Pilot-light/warm-standby with active-passive Route 53 + Aurora cross-region replica = meets 30-min RTO/RPO at lowest cost"}, "888": {"A": "CORRECT. Kinesis Data Streams on-demand auto-scales shards to traffic spikes; Lambda consumes stream for true real-time processing.", "B": "INCORRECT. Firehose is near-real-time delivery to storage targets, not real-time analytics; Glue is batch ETL, not streaming.", "C": "INCORRECT. Kinesis Video Streams is for video/audio media, not clickstream events; Glue is batch, not real-time.", "D": "INCORRECT. Managed Flink is an analytics processor, not an ingestion layer — cannot capture data directly from website.", "_summary": "Kinesis Data Streams on-demand = auto-scaling ingestion; Lambda = real-time processing"}, "785": {"A": "INCORRECT. S3 event notifications deliver at-least-once; no deduplication, so duplicate payment processing possible.", "B": "INCORRECT. SQS standard queue guarantees at-least-once delivery — duplicate messages possible, causing duplicate payments.", "C": "CORRECT. SQS FIFO provides exactly-once processing via message deduplication IDs within 5-minute window, preventing duplicate payments.", "D": "INCORRECT. DynamoDB Streams invoke Lambda at-least-once on failures; no built-in deduplication for payment idempotency.", "_summary": "SQS FIFO exactly-once processing is the only option that structurally prevents duplicate payment execution"}, "581": {"A": "INCORRECT. One instance per AZ with min=2 — if one AZ fails, only 1 instance survives, violating 'at least two always running'.", "B": "CORRECT. Two On-Demand per AZ, min=4 — AZ failure leaves 2 On-Demand instances running in surviving AZ; requirement met.", "C": "INCORRECT. All instances in one AZ — single AZ failure kills everything; Spot instances add interruption risk for stateful app.", "D": "INCORRECT. Spot instances can be reclaimed by AWS at any time — 'always running' guarantee impossible with Spot for stateful production.", "_summary": "Fault tolerance needs N+N across AZs; On-Demand only for stateful; min capacity must survive full AZ loss"}, "526": {"A": "INCORRECT. More read replicas distribute read load but don't reduce writer failover downtime; DNS propagation still causes 3-min gap.", "B": "INCORRECT. Secondary cluster requires application reconfiguration + manual endpoint switch during failover — high operational overhead.", "C": "INCORRECT. ElastiCache Memcached is a read cache; irrelevant to write-path failover latency.", "D": "CORRECT. RDS Proxy maintains persistent connection pool; during Aurora failover it transparently reconnects to new writer, reducing downtime from minutes to seconds with zero app changes.", "_summary": "RDS Proxy absorbs Aurora failover by pooling connections and auto-reconnecting — lowest overhead, biggest downtime reduction"}, "514": {"A": "INCORRECT. IAM role permissions may be valid; the failure is network connectivity — nodes in private subnets can't reach private-only EKS API endpoint without VPC endpoints.", "B": "CORRECT. Interface VPC endpoints (com.amazonaws.region.eks + STS + EC2) let private-subnet nodes reach the private EKS control plane without internet access.", "C": "INCORRECT. Moving nodes to public subnet violates stated security compliance requirement of private data plane.", "D": "INCORRECT. Outbound SG rules won't help if there's no routable network path to the private-only control plane; VPC endpoints are the missing piece.", "_summary": "Private EKS endpoint requires interface VPC endpoints so private-subnet nodes can resolve and reach the control plane"}, "483": {"A": "INCORRECT. AWS Lambda does not support Windows containers — only Linux container images supported.", "B": "INCORRECT. AWS Batch adds scheduling/compute-environment overhead unnecessary for a simple periodic 1-3 min job; ECS scheduled task is simpler and cheaper.", "C": "CORRECT. ECS Fargate supports Windows containers; EventBridge scheduled task triggers every 10 min, pay only for 1-3 min of Fargate runtime per run — minimal cost and overhead.", "D": "INCORRECT. Windows Task Scheduler runs on Windows OS instances, not in cloud; cannot natively trigger ECS Fargate tasks — operationally broken solution.", "_summary": "ECS Fargate Windows scheduled task = only viable Windows-container option with pay-per-use pricing for short periodic jobs"}, "440": {"A": "RDS MySQL snapshots restore directly into Aurora MySQL — supported natively via AWS console or CLI without intermediate steps. Correct.", "B": "RDS snapshots live in AWS-managed storage; users cannot download and re-upload them to S3 for import. Incorrect.", "C": "mysqldump produces a SQL dump file; Aurora supports importing such files from S3 via the aws_s3 extension or console wizard. Correct.", "D": "DMS requires live database endpoints, not snapshot files as a source. Incorrect.", "E": "DMS can use S3 as a source but adds unnecessary complexity vs. direct Aurora S3 import; not the simplest path. Incorrect.", "_summary": "RDS snapshot → Aurora direct restore (A); mysqldump → S3 → Aurora import (C)"}, "405": {"A": "ALB capacity is managed automatically by AWS; Auto Scaling groups target EC2 instances, not the ALB itself. Incorrect.", "B": "Internet gateways are AWS-managed and scale automatically; no API to control their capacity. Incorrect.", "C": "ALB operates within one Region; cross-Region distribution requires Route 53 and separate stacks, overkill here. Incorrect.", "D": "Target tracking on CPU lets the ASG scale out under load and scale in when idle — handles traffic spikes during working hours. Correct.", "E": "Scheduled scaling can set min/max/desired to 0 on weekends and restore defaults Monday, eliminating weekend costs. Correct.", "_summary": "Target tracking handles traffic spikes (D); scheduled scaling eliminates weekend capacity (E)"}, "739": {"A": "SNS→SQS→Lambda polling works but requires provisioning and managing SQS queues plus Lambda event source mappings — higher operational overhead. Incorrect.", "B": "EventBridge event rules with event patterns provide native message filtering and invoke Lambda directly — fully managed, no queues to maintain, least overhead. Correct.", "C": "MSK is a managed Kafka cluster; provisioning brokers for a simple fan-out use case is excessive operational overhead. Incorrect.", "D": "Multiple SQS queues with no filtering logic means all messages go everywhere; no built-in content-based routing. Incorrect.", "_summary": "EventBridge event patterns = serverless filtering + direct Lambda invocation, zero infra to manage"}, "10": {"A": "SNS delivers to subscribers without ordering guarantees; parallel Lambda invocations can process out of sequence. Incorrect.", "B": "SQS FIFO queues guarantee exactly-once, first-in-first-out delivery; triggers Lambda in order received. Correct.", "C": "Blocking all requests while one processes is not ordering — it serializes at the gateway and breaks throughput. Incorrect.", "D": "SQS standard queues provide best-effort ordering only; messages can arrive out of sequence. Incorrect.", "_summary": "FIFO queue = guaranteed order; standard queue = best-effort only"}, "5": {"A": "Manually syncing both EBS volumes doesn't persist: new uploads still go to only one instance, problem recurs immediately. Incorrect.", "B": "ALB sticky sessions bind a user to one instance but don't merge data across instances; other users still see split data. Incorrect.", "C": "EFS is a shared NFS-backed file system mounted by all EC2 instances simultaneously; all reads/writes hit one location. Correct.", "D": "Returning documents from two servers in one response requires custom application logic and doesn't solve root cause. Incorrect.", "_summary": "EFS = shared storage across AZs; EBS = instance-local, causes data split"}, "7": {"A": "Kinesis Data Analytics is a stream-processing/analytics service, not a pub/sub fanout broker for many consumers. Incorrect.", "B": "Scaling the ingestion tier with ASG doesn't decouple it from dozens of consumers; tight coupling remains. Incorrect.", "C": "A single Kinesis shard handles only 1,000 records/s write; a 100,000/s burst blows past this limit instantly. Incorrect.", "D": "SNS fans out to one SQS queue per consumer; each consumer reads independently at its own pace — decoupled and massively scalable. Correct.", "_summary": "SNS+SQS fan-out = decoupled, per-consumer queues, handles burst traffic"}, "2": {"A": "Redshift requires provisioning a cluster and loading data via COPY; high operational overhead for simple on-demand queries. Incorrect.", "B": "CloudWatch Logs requires moving data out of S3, changing existing architecture — violates minimal-change constraint. Incorrect.", "C": "Athena queries JSON files in S3 directly with SQL; no ETL, no infrastructure, zero architecture changes. Correct.", "D": "Glue catalog plus transient EMR cluster adds cataloging jobs and cluster management overhead — not minimal. Incorrect.", "_summary": "Athena = serverless SQL on S3 in place, zero infra to manage"}, "6": {"A": "CLI over internet consumes full network bandwidth for 70 TB — slow and expensive in bandwidth. Incorrect.", "B": "Snowball Edge is an 80 TB physical appliance; data transfers offline, consuming zero internet bandwidth; fastest path for 70 TB. Correct.", "C": "S3 File Gateway streams data over the internet — uses network bandwidth, does not minimize it. Incorrect.", "D": "Direct Connect provisioning takes weeks and still sends data over a network link — doesn't minimize bandwidth and isn't fast to set up. Incorrect.", "_summary": "Snowball Edge = physical transfer, zero internet bandwidth, fastest for large offline datasets"}, "670": {"A": "Correct. On-demand bills per request with zero idle cost; 4 hrs/week means ~97% idle — provisioned capacity billed 24/7 would be far more expensive. Note: the 'update capacity units' clause is misleading since on-demand requires no capacity unit config.", "B": "Wrong. Provisioned mode charges for reserved throughput around the clock; paying 168 hrs/week of capacity for 4 hrs/week of use wastes ~97% of spend.", "C": "Wrong. Reserved capacity discounts provisioned throughput but provisioned still bills 24/7; 1-year commitment on a sporadic workload has poor ROI.", "D": "Wrong. 3-year commitment amplifies the waste — longest idle-billing period, worst cost outcome for a 4-hr/week workload.", "_summary": "On-demand DynamoDB optimal for sporadic short-duration workloads; provisioned/reserved waste money on idle capacity."}, "132": {"A": "Correct. S3 stores static files with no server management; CloudFront serves them from 400+ edge locations globally — low latency, auto-scaling, minimal infra provisioning, lowest cost for static downloads.", "B": "Wrong. Lambda+DynamoDB suits dynamic compute/data, not binary file downloads; DynamoDB is not a file store, and there is no CDN layer for global speed.", "C": "Wrong. ALB+EC2 Auto Scaling requires provisioning and managing compute; no global edge caching, higher cost, more operational overhead.", "D": "Wrong. Internal ALBs are private-facing; Route 53 alone provides DNS routing but no CDN edge caching, still requires servers behind the ALBs.", "_summary": "S3+CloudFront is the canonical serverless global static delivery pattern — zero infra, edge caching, lowest cost."}, "129": {"A": "Correct. Aurora is fully managed and PostgreSQL-compatible; eliminates patching, backups, and DB capacity planning while retaining full app compatibility.", "B": "Wrong. EC2 still requires OS patching, capacity planning, and infra management — same operational overhead problem, just cloud-hosted.", "C": "Wrong. CloudFront is a CDN for cacheable content; does not address infra management overhead for the containerized app stack.", "D": "Wrong. ElastiCache reduces DB query load but adds another infra component to manage; does not eliminate capacity planning or infra overhead.", "E": "Correct. Fargate removes all EC2 node management for containers — no cluster provisioning, patching, or capacity planning; ECS+Fargate is the direct serverless lift for containerized workloads.", "_summary": "Aurora (managed DB) + Fargate (serverless containers) eliminate both primary infra management burdens from the on-prem setup."}, "328": {"A": "Wrong. CloudFront caching is ineffective for dynamic personalized API responses; manually pre-adding EC2 instances does not auto-scale for sudden unpredictable spikes.", "B": "Wrong. CloudFront helps for static but ASG scale-out on network metrics has a multi-minute lag; during a sudden spike instances launch too slowly and requests drop before capacity arrives.", "C": "Wrong. ElastiCache in front of an ALB is not a valid architecture; ElastiCache caches application data, not HTTP requests at the load balancer layer; does not protect async workers from overload.", "D": "Correct. CloudFront offloads static S3 content; SQS decouples request intake from processing — during a sudden spike SQS absorbs all incoming requests immediately with no loss, and EC2 workers drain the queue at capacity, guaranteeing zero dropped requests.", "_summary": "SQS as request buffer decouples intake from processing, ensuring no requests are lost during sudden spikes regardless of worker capacity."}, "189": {"A": "Wrong. S3 Object Lock governance mode allows IAM users with s3:BypassGovernanceRetention to override the lock — privileged users can still delete or overwrite objects before retention expires.", "B": "Correct. S3 Object Lock compliance mode: no user including root can delete or overwrite locked objects before the retention period ends — satisfies the strict 5-year immutability requirement.", "C": "Wrong. SSE-S3 encrypts data but AWS controls the key rotation schedule with no customer-configurable annual rotation period; also less auditable than KMS.", "D": "Correct. KMS customer managed keys support enabling automatic annual key rotation (every 365 days) with a single toggle — least operational overhead for customer-controlled yearly rotation, fully auditable.", "E": "Wrong. KMS imported key material explicitly does NOT support automatic rotation — AWS disables auto-rotation for imported keys; manual rotation required, higher overhead.", "_summary": "Compliance mode Object Lock for immutability + KMS CMK with auto-rotation covers both requirements with minimal ops overhead."}, "290": {"A": "Wrong. Dedicated Instances are the most expensive EC2 option; dedicated hardware per account adds cost with no benefit for a standard variable-load web app.", "B": "Wrong. On-Demand only is reliable but does not optimize costs; no discount mechanism applied during scaling periods.", "C": "Correct. On-Demand provides an interruption-resistant baseline; Spot fills burst capacity at up to 90% discount with no commitment; Auto Scaling mixed instance policies support this natively out of the box.", "D": "Wrong. Reserved Instances require 1-year or 3-year contracts — explicitly violates the no-long-term-commitment requirement.", "_summary": "On-Demand baseline + Spot burst = maximum cost savings with zero commitment; Auto Scaling supports mixed fleets natively."}, "74": {"A": "Correct. Web tier must accept inbound HTTPS (port 443) from 0.0.0.0/0 — standard rule for a public-facing HTTPS web server.", "B": "Wrong. Outbound rules define destination, not source; 'allow outbound 443 from 0.0.0.0/0' is logically invalid. Outbound from web to internet may be needed for external API calls but is not related to DB connectivity.", "C": "Correct. DB tier (SQL Server) should only accept inbound on port 1433 sourced from the web tier security group — least-privilege, no direct internet access to the database.", "D": "Wrong. DB tier does not initiate connections to the web tier on 443 or 1433; stateful connection tracking handles response traffic, no explicit outbound rules needed for this.", "E": "Wrong. Port 443 is HTTPS, not SQL Server; DB tier only needs inbound 1433 from the web tier SG — adding 443 violates least-privilege and serves no database purpose.", "_summary": "Web SG: inbound 443 from internet; DB SG: inbound 1433 from web SG only — classic two-tier least-privilege security group pattern."}, "419": {"A": "Wrong. EC2 EBS encryption default is an account-level setting applied only to the account where it is configured; must be set manually in each member account — does not scale org-wide without per-account effort.", "B": "Wrong. IAM permission boundaries constrain IAM entity permissions, not OUs; permission boundaries cannot be attached to an OU — SCPs serve that role in Organizations.", "C": "Correct. SCP with deny on ec2:CreateVolume when ec2:Encrypted is false applies org-wide to all accounts under the target OU; enforces encryption at the policy layer, cannot be bypassed by account-level IAM.", "D": "Wrong. Updating IAM policies per account requires manual changes in every member account — high operational overhead, not scalable; SCP is the correct org-wide enforcement mechanism.", "E": "Correct. Setting Default EBS volume encryption from the Organizations management account propagates the auto-encrypt default to all member accounts; new volumes are encrypted transparently without requiring employee action — minimal employee impact.", "_summary": "SCP (C) blocks unencrypted volume creation org-wide; Organizations management account EBS default (E) auto-encrypts silently, minimizing employee disruption."}, "450": {"A": "Keeps existing monolithic architecture per AZ instead of refactoring into separate tiers — violates Well-Architected design principle of loose coupling and tier isolation.", "B": "Single RDS in one AZ has no Multi-AZ resiliency — fails durability pillar; also NACLs alone insufficient without proper tier segmentation.", "C": "Correct. Refactors monolith into three proper tiers across two AZs with Auto Scaling for web and app tiers — aligns with Well-Architected reliability and security pillars.", "D": "Single RDS with no Multi-AZ is a single point of failure — not resilient; incomplete answer even with correct security group access control.", "E": "Correct. ELB in front of web tier with security groups referencing each layer's SG enables layered defense (security groups as firewall chains) and distributes traffic.", "F": "Correct. RDS Multi-AZ cluster in private subnets with app-tier SG access only provides failover capability and least-privilege DB access — required for resiliency.", "_summary": "CEF: proper tier separation + Multi-AZ + ELB + RDS Multi-AZ = Well-Architected compliant migration"}, "714": {"A": "Round robin distributes requests evenly regardless of current instance load — overloaded instances still receive new requests at the same rate as healthy ones.", "B": "Correct. Least Outstanding Requests (LOR) algorithm on ALB routes each new request to the instance with fewest in-flight requests; RequestCountPerTarget and ActiveConnectionCount are the metrics LOR uses — naturally avoids overloaded instances.", "C": "Round robin doesn't solve the overload problem; RequestCount and TargetResponseTime are CloudWatch metrics for monitoring, not inputs to the routing algorithm decision.", "D": "LOR algorithm is right but RequestCount and TargetResponseTime are not the metrics driving LOR routing decisions — ALB's LOR uses RequestCountPerTarget and ActiveConnectionCount internally.", "_summary": "ALB Least Outstanding Requests algorithm prevents routing to overloaded targets"}, "400": {"A": "DynamoDB transactions are for ACID multi-item writes — they have no notification mechanism; cannot alert teams.", "B": "Modifying existing application to publish to 4 SNS topics changes current app behavior (affecting performance risk) and requires maintaining 4 separate topics.", "C": "Correct. DynamoDB Streams captures item-level changes without touching the existing app; Lambda trigger reads stream and publishes to one SNS topic; all four teams subscribe — zero app modification, least overhead.", "D": "Polling DynamoDB every minute with a cron job adds latency, wastes RCUs, and SQS is not a subscription model teams can easily consume — high operational overhead.", "_summary": "DynamoDB Streams + Lambda trigger + SNS = event-driven alerts with zero impact on existing app"}, "395": {"A": "GuardDuty performs threat detection (malware, compromised credentials, unusual behavior) — not an audit trail of specific API calls by specific users.", "B": "Inspector scans EC2 instances and container images for software vulnerabilities — not for tracking who performed configuration changes.", "C": "Correct. CloudTrail records every AWS API call with the IAM identity (user/role), timestamp, source IP, and request parameters — directly answers who changed what security group rules.", "D": "Config tracks resource configuration state over time and detects drift — shows what changed but does not reliably surface the IAM identity that made the change; CloudTrail is authoritative for attribution.", "_summary": "CloudTrail = API audit log with IAM identity; Config = config state history without clear actor attribution"}, "386": {"A": "SNS is a pub/sub notification service — no caching capability; does not prevent repeated DB queries.", "B": "Correct. ElastiCache (Redis or Memcached) stores query results in memory; identical repeated queries hit cache instead of RDS — eliminates redundant DB round-trips and improves response time.", "C": "Read replica offloads read traffic but every identical query still executes a full DB query on the replica — no caching of results; helps with scale but not with identical-dataset redundancy.", "D": "Kinesis Data Firehose is a data ingestion/delivery pipeline to S3/Redshift — no relevance to DB query caching or performance.", "_summary": "ElastiCache caches repeated identical query results in memory, eliminating redundant RDS round-trips"}, "369": {"A": "Correct. AWS Batch is language-agnostic (runs any containerized workload), managed by AWS, auto-scales compute, and EventBridge schedules jobs natively — minimal operational overhead, supports 1-hour+ runtimes.", "B": "App Runner targets long-running web services/APIs — not designed for scheduled batch jobs; requires containerization effort and lacks native batch scheduling.", "C": "Lambda max execution time is 15 minutes — 1-hour tasks cannot run on Lambda; would require rearchitecting each task to work within that constraint.", "D": "Launching full EC2 instances via Auto Scaling for batch tasks is expensive and heavyweight — high operational overhead managing AMIs, instances, and scaling policies.", "_summary": "AWS Batch + EventBridge = managed, language-agnostic, scheduled batch execution with no runtime limit"}, "362": {"A": "DynamoDB partition key routes items to same shard for storage — DynamoDB is a database, not a message queue; no ordering guarantee for reads and no consumer sequencing.", "B": "Correct. Kinesis data stream with same partition key routes all messages for that payment ID to the same shard — shard preserves strict insertion order for consumers.", "C": "ElastiCache Memcached is a key-value cache — no message queue semantics, no ordering, no consumer groups.", "D": "Standard SQS provides best-effort ordering only — message attributes do not enforce FIFO delivery; same payment ID messages can arrive out of order.", "E": "Correct. SQS FIFO queue with message group ID set to payment ID guarantees exactly-once, in-order processing within each group — all messages for a payment ID processed sequentially in send order.", "_summary": "Kinesis partition key and SQS FIFO message group both guarantee per-key ordering"}, "987": {"A": "Correct. Network Load Balancer operates at Layer 4 (TCP/UDP) — matches the TCP requirement, highly available across AZs, low latency, cost-effective for non-HTTP workloads.", "B": "Correct. Auto Scaling group automatically launches/terminates EC2 instances based on demand — meets the auto-scale requirement with no manual intervention.", "C": "Application Load Balancer operates at Layer 7 (HTTP/HTTPS) — adds unnecessary overhead for a TCP application and costs more than NLB for this use case; NLB is the right tool.", "D": "Manually adding instances does not meet the automatic scaling requirement — defeats the purpose and introduces operational overhead.", "E": "Gateway Load Balancer is for inserting third-party virtual network appliances (firewalls, IDS) into traffic path — wrong use case here.", "_summary": "NLB (Layer 4 TCP) + Auto Scaling group = cost-effective HA with automatic scaling for TCP workloads"}, "145": {"A": "RDS MySQL + 2 On-Demand + ALB scales but uses pricier On-Demand instances with no auto-scaling — not most cost-effective.", "B": "Route 53 weighted routing is static split, not dynamic scaling; On-Demand instances add cost without elasticity.", "C": "Reactive instance-type change via Lambda requires stopping EC2 = downtime; not seamless scaling.", "D": "Aurora (more scalable than RDS MySQL) + Auto Scaling group + Spot Fleet = seamless scale at lowest cost; ALB distributes load across fleet.", "_summary": "Auto Scaling + Spot Fleet = seamless + cheapest; Aurora handles DB growth"}, "245": {"A": "One target in target group removes redundancy but ALB still runs full cost; saves little, breaks HA.", "B": "Least-outstanding-requests changes routing algorithm only — zero cost impact.", "C": "Reduces size in BOTH environments; risks degrading prod performance, not scoped to dev cost.", "D": "Capping Auto Scaling max in dev means fewer instances launch under load; dev doesn't need prod-level capacity, so lower max = direct cost reduction.", "_summary": "Dev ASG max cap = cheapest lever; prod untouched"}, "882": {"A": "EC2 Instance Savings Plan covers EC2 only — Lambda costs unoptimized; private subnet connection is correct but plan choice wrong.", "B": "EC2 Instance Savings Plan still misses Lambda; public subnets for Lambda unnecessary and less secure.", "C": "Compute Savings Plan covers EC2 + Lambda + Fargate; VPC-connected Lambda in private subnets gets direct network path to EC2 — both savings and connectivity correct.", "D": "Compute Savings Plan is right but Lambda in its own service VPC cannot directly reach EC2 in customer private subnets — breaks network requirement.", "_summary": "Compute Savings Plan covers Lambda+EC2; VPC-attach Lambda to reach private EC2"}, "716": {"A": "Adding public subnets to existing VPC and deploying MSK there enables broker public endpoints; mTLS encrypts in transit and authenticates — operationally simplest reuse of existing VPC.", "B": "New VPC works but duplicates networking setup with no benefit — more operational overhead than reusing existing VPC.", "C": "ALB is HTTP/HTTPS-only; Kafka uses TCP protocol — ALB cannot proxy Kafka traffic; private subnets also don't expose to internet.", "D": "NLB in private subnets without internet-facing flag is not reachable from internet; MSK handles its own TLS, NLB passthrough doesn't solve Kafka encryption natively.", "_summary": "MSK public access via public subnets + mTLS = simplest internet-accessible encrypted Kafka"}, "214": {"A": "EMR + Spark works but requires cluster provisioning, job code, and cluster management — high dev effort.", "B": "Glue crawler auto-detects schema; Glue ETL natively writes Parquet with minimal code; fully managed — least development effort.", "C": "AWS Batch requires writing transformation scripts and container images — more dev effort than Glue.", "D": "Lambda has 15-min timeout and limited memory; 5 GB file transformations are risky; requires custom code — higher dev effort and reliability risk.", "_summary": "Glue crawler+ETL = managed CSV→Parquet with near-zero code"}, "213": {"A": "AWS WAF has managed rule groups for SQLi and XSS; attaches directly to ALB; no servers to manage — satisfies all requirements.", "B": "S3 static hosting irrelevant to protecting a dynamic ALB-backed app.", "C": "Shield Advanced defends DDoS (L3/L4), not application-layer attacks like XSS/SQLi — wrong threat model.", "D": "Third-party firewall on EC2 increases server management burden — directly contradicts the minimal-ops requirement.", "_summary": "WAF managed rules on ALB = app-layer protection with zero server ops"}, "212": {"A": "Intelligent-Tiering auto-moves objects between access tiers based on actual usage; variable/rapidly-changing patterns are its exact use case; immediate access, no retrieval fees — most cost-effective.", "B": "Glacier Instant Retrieval targets quarterly-accessed data with 90-day minimum storage; variable frequent access would incur high retrieval costs.", "C": "Standard guarantees immediate access and no retrieval fees but charges full storage rate always — not cost-optimized when access is sometimes infrequent.", "D": "Standard-IA has per-GB retrieval fees; rapidly changing access patterns can make retrieval costs exceed Standard pricing, violating cost-effective constraint.", "_summary": "Intelligent-Tiering auto-optimizes cost for unpredictable access without retrieval penalties"}, "211": {"A": "CloudTrail records API activity, not a tag-based resource inventory — wrong tool.", "B": "CLI queries per-service per-region is manual, slow, and not 'quickest' at scale.", "C": "CloudWatch Logs Insights searches log data, not resource metadata or tags.", "D": "Resource Groups Tag Editor queries all AWS resource types across all regions by tag in one console action — purpose-built for this exact need.", "_summary": "Tag Editor = single query for tagged resources globally across all services"}, "623": {"A": "Shield protects DDoS only — no SQL injection/XSS rules.", "B": "WAF attaches directly to API Gateway with managed rule groups for SQLi and XSS — no extra infra needed.", "C": "Shield on CloudFront still does nothing for SQLi/XSS; adds unnecessary CloudFront layer.", "D": "WAF on CloudFront works but redundant — WAF can attach to API Gateway directly, fewer moving parts.", "_summary": "WAF native to API Gateway = least ops overhead for SQLi/XSS protection"}, "418": {"A": "Admin Access violates least privilege — grants far more than S3 access.", "B": "Dev account as principal in prod role trust policy enables STS AssumeRole cross-account — correct minimal pattern.", "C": "Disabling Block Public Access exposes bucket publicly — security violation.", "D": "New prod IAM users per member creates credential sprawl and ignores existing group structure.", "_summary": "Cross-account access via role trust policy + AssumeRole = least-privilege standard"}, "231": {"A": "Allowing all traffic from public IP is insecure; Elastic IPs can also be reassigned.", "B": "VPC peering uses private IPs, traffic stays on AWS backbone — no internet exposure, most secure.", "C": "Publicly accessible DB is a critical security risk — eliminates private network benefit.", "D": "Proxy EC2 adds cost and complexity with no security improvement over peering.", "_summary": "VPC peering = private cross-VPC connectivity without public exposure"}, "295": {"A": "DynamoDB + proxy intercept layer adds significant dev and ops overhead.", "B": "S3 Object Lambda strips PII dynamically at read time per caller — one storage location, no duplication, zero ETL pipeline.", "C": "Three S3 copies require sync logic and triple storage cost.", "D": "Three DynamoDB copies same problem as C, plus higher cost than S3.", "_summary": "S3 Object Lambda transforms data on-the-fly — eliminates ETL and duplicate storage"}, "282": {"A": "Route table entries don't filter traffic — this changes routing, not access control.", "B": "Security group rule referencing ALB's security group ID blocks all non-ALB sources, including other subnet resources — correct.", "C": "Moving EC2 to public subnet increases attack surface, doesn't restrict to ALB.", "D": "Opening all TCP on ALB SG has no effect on EC2 inbound rules.", "_summary": "SG-to-SG reference enforces ALB-only inbound without IP-based rules"}, "281": {"A": "Multi-AZ uses synchronous replication — standby always in sync, RPO effectively zero, meets <1s requirement.", "B": "Auto scaling adds capacity but does nothing for data replication or RPO.", "C": "Read replicas are asynchronous — replication lag can exceed 1 second under load, RPO not guaranteed.", "D": "DMS CDC is a migration tool, not an HA mechanism; latency not sub-second guaranteed.", "_summary": "Multi-AZ synchronous replication = near-zero RPO, the only RDS option meeting <1s"}, "414": {"A": "Scheduled DataSync at end of day violates near-real-time requirement.", "B": "S3 File Gateway presents S3 as SMB/NFS share — business system writes unchanged, data lands in S3 immediately, zero code change.", "C": "DataSync with custom API automation adds development and maintenance overhead.", "D": "SFTP requires polling script and credential management — more admin overhead than File Gateway.", "_summary": "S3 File Gateway = drop-in network share replacement, near-real-time S3 ingestion, zero app changes"}, "995": {"A": "Lambda max timeout is 15 minutes — 20-minute video processing impossible.", "B": "Fargate removes EC2 management, no timeout limit, scales on demand, Aurora handles metadata, S3 Intelligent-Tiering cuts storage cost — all requirements met.", "C": "EC2 Auto Scaling works functionally but adds infra management overhead vs Fargate; S3 Standard costs more than Intelligent-Tiering.", "D": "EKS on EC2 adds Kubernetes ops burden; Glacier Deep Archive is archival-only, not for active video serving; single-AZ RDS is an availability risk.", "_summary": "Fargate = serverless containers, no 15-min cap, scales automatically, cost-efficient"}, "998": {"A": "Gateway VPC endpoint routes EC2-to-S3 traffic over AWS private network, bypassing public internet. Subnet route table entry directs S3-bound traffic to endpoint. Correct.", "B": "S3 is global AWS service; cannot be placed inside VPC. Concept invalid.", "C": "S3 access points control namespace/permissions, not traffic routing path. Traffic still exits via public endpoint.", "D": "Direct Connect links on-premises to AWS, not EC2-to-S3 within AWS. Wrong tool, massive overhead.", "_summary": "Gateway VPC endpoint keeps S3 traffic on AWS private network"}, "437": {"A": "Inspector scans EC2/containers for vulnerabilities; not a traffic-filtering or rate-limiting tool.", "B": "WAF rate-limiting rule on ALB counts requests per IP and blocks excess. Handles rotating IPs dynamically. Correct.", "C": "NACLs are IP-based and stateless; attacker rotating IPs requires constant manual updates, impractical.", "D": "GuardDuty detects threats via logs/telemetry; no mechanism to actively block traffic or rate-limit requests.", "_summary": "WAF rate-based rules block high-frequency attackers without manual IP management"}, "432": {"A": "Glue ML transforms only do FindMatches (deduplication/record linkage), not general model training. OpenSearch is search/analytics, not a BI dashboard.", "B": "SageMaker handles full ML lifecycle (build/train/deploy). QuickSight integrates natively for BI dashboards. Both managed, minimal ops overhead. Correct.", "C": "Marketplace AMI requires managing EC2 instances. OpenSearch not suited for business intelligence reporting.", "D": "QuickSight calculated fields do simple math, not ML model training. Incorrect service for the ML requirement.", "_summary": "SageMaker + QuickSight = managed ML-to-BI pipeline with zero infrastructure"}, "1015": {"A": "CloudFront caches content at edge for fast downloads. Transfer Acceleration routes uploads through CloudFront edge locations to S3 over optimized paths. Both configs take minutes. Correct.", "B": "Migrating static S3 site to EC2+ALB+Global Accelerator is massive operational lift; defeats serverless S3 advantage.", "C": "Multi-region S3 replication plus redirect logic adds significant complexity and ongoing management burden vs. option A.", "D": "Global Accelerator targets EC2/ALB/NLB/Elastic IP endpoints, not S3 natively. Does not accelerate S3 uploads like Transfer Acceleration.", "_summary": "CloudFront + S3 Transfer Acceleration solves both download and upload latency with one-time config"}, "1011": {"A": "Cognito identity pool exchanges user pool ID tokens for temporary STS credentials (IAM role) scoped to S3 access. Correct.", "B": "User pools authenticate users and issue JWTs; they cannot generate AWS IAM credentials or STS tokens for S3. Only identity pools do this.", "C": "VPC endpoint for S3 lets private-subnet app reach S3 without traversing public internet or needing NAT. Correct.", "D": "NAT gateway adds cost and complexity; S3 bucket policies cannot condition on 'originated from Cognito' as a meaningful filter.", "E": "Mobile users have dynamic IPs. IP-allowlist on S3 bucket is impractical and bypasses Cognito integration entirely.", "_summary": "Identity pool for IAM creds + VPC endpoint for private routing = secure Cognito-S3 integration"}, "1000": {"A": "File Gateway uses NFS/SMB file protocol, not block (iSCSI). Requirement is block storage replacement.", "B": "Cached volumes store primary data in S3, cache hot data locally as iSCSI block targets. Expands effective capacity while keeping low latency for frequent access. Correct.", "C": "Stored volumes keep full dataset on-premises and async-backup to S3. Does not solve the space limitation problem since all data still lives locally.", "D": "Tape Gateway targets archival/backup to S3/Glacier; no low-latency retrieval capability for active workloads.", "_summary": "Volume Gateway cached mode = iSCSI block storage with S3 backend, local cache for hot data"}, "996": {"A": "Self-managed nodes require company to patch, scale, and maintain EC2 instances. Highest operational overhead.", "B": "Managed node groups handle EC2 lifecycle but company still provisions and manages node capacity. Moderate overhead.", "C": "Fargate for EKS is serverless compute; no EC2 to manage, patch, or scale. Matches 'no manage underlying compute'. Correct.", "D": "Karpenter reduces node provisioning effort but is still EC2-based; company still owns the compute infrastructure.", "_summary": "EKS on Fargate = zero EC2 management, fully serverless compute for Kubernetes"}, "219": {"A": "T3 is burstable general-purpose; worse than M5 for sustained in-memory workloads. Manual console change also bypasses IaC.", "B": "M5 is not memory-optimized; Auto Scaling with manual adjustment doesn't fix the root memory constraint.", "C": "R5 memory-optimized is correct instance type. But CloudWatch built-in EC2 metrics exclude memory utilization; custom metrics need the CloudWatch agent. Future capacity planning would be blind.", "D": "R5 (memory-optimized) addresses in-memory performance. CloudWatch agent publishes custom application latency and memory metrics unavailable via built-in metrics. Correct.", "_summary": "R5 for memory-intensive workloads + CloudWatch agent for custom metrics not available natively"}, "861": {"A": "Provisioned IOPS SSD gives consistent low-latency throughput for write-heavy workloads; CloudWatch lets you tune IOPS as load changes. Correct.", "B": "ElastiCache caches reads, not writes. Write traffic still hammers RDS directly — no improvement for write performance bottleneck.", "C": "DocumentDB uses MongoDB API, not MySQL. Migration requires schema rewrite; doesn't address write throughput concern.", "D": "EFS is a file system, not a database. Cannot replace RDS for structured relational data or IOPS-bound DB workloads.", "_summary": "High-write RDS workload → Provisioned IOPS SSD + CloudWatch tuning"}, "196": {"A": "Redeploying CloudFormation stack every 30 days deletes everything and recreates — destroys data, not just old records. Wrong.", "B": "Requires a running EC2 instance 24/7 to poll Streams and run deletion scripts — high cost and dev effort.", "C": "Lambda on Streams works but requires querying and deleting old items — more dev effort than native TTL.", "D": "DynamoDB TTL is a native zero-cost feature. Set attribute = now + 30 days; DynamoDB deletes expired items automatically. Zero extra infrastructure.", "_summary": "Auto-expire DynamoDB items → TTL attribute is least effort and zero cost"}, "195": {"A": "EventBridge to ECS task doesn't create a durable message buffer — orders in-flight during outage are still lost.", "B": "ALB is synchronous. If EC2 instances fail mid-request, the order is dropped; ALB has no message persistence.", "C": "SQS durably persists messages. If EC2 instances go down, messages stay in queue until instances recover and process them. Correct.", "D": "SNS is pub/sub without durability guarantees; Run Command adds operational complexity without solving message persistence.", "_summary": "Resilient order processing → SQS decouples producers from consumers, survives EC2 outages"}, "192": {"A": "EC2 + MySQL is self-managed, low scalability, high operational overhead. Wrong.", "B": "S3 stores documents durably and cheaply; Athena runs serverless SQL queries directly on S3 data. Scalable, no infrastructure. Correct.", "C": "Auto Scaling EC2 for custom OCR processing requires code maintenance and scaling management vs. serverless Lambda.", "D": "Rekognition detects objects/faces in images — not OCR. Transcribe Medical converts audio to text — wrong input type for scanned documents.", "E": "Textract does OCR on scanned documents (PDFs, images). Comprehend Medical extracts entities like diagnoses and medications from text. Correct combination.", "_summary": "Scanned medical documents → Textract (OCR) + Comprehend Medical (entity extraction) + S3 + Athena (SQL)"}, "681": {"A": "Customer managed key gives full control: enable/disable automatic rotation, manual rotation on demand. Least overhead that still satisfies control requirement. Correct.", "B": "AWS managed keys rotate automatically every year but you cannot control the schedule, disable rotation, or trigger manual rotation. Fails 'control' requirement.", "C": "Imported key material requires manual re-import to rotate — highest operational overhead of all options.", "D": "AWS owned keys are fully opaque; you have zero visibility or control over them.", "_summary": "KMS with rotation control → customer managed key (CMK)"}, "293": {"A": "Snowball is a one-time physical migration appliance, not an ongoing backup solution. No persistent S3 mount for local access.", "B": "Snowball Edge suits edge compute and migration but is not designed as a persistent on-premises backup gateway.", "C": "Cached volume gateway keeps only frequently accessed data local — does not guarantee local access to ALL data as required.", "D": "Stored volume gateway keeps ALL primary data on-premises and asynchronously backs up to S3 as EBS snapshots. Local access preserved for all data. Correct.", "_summary": "Local access to ALL data + backup to AWS → Storage Gateway stored volume gateway"}, "808": {"A": "ECR is the native registry for ECS. Basic scan (Clair-based) checks CVEs. Scan-on-push filter triggers scan for every new image automatically. Fewest workload changes. Correct.", "B": "Macie detects PII and sensitive data — not CVEs in container images. Wrong service entirely.", "C": "Migrating ECS workloads to EKS is a major architectural change, violating 'fewest changes'. Enhanced scan adds Inspector v2 but EKS migration is the blocker.", "D": "S3 is not a container registry; Inspector integration via Lambda adds complexity. More changes than ECR native scanning.", "_summary": "Container image CVE scanning on ECS → ECR with scan-on-push (basic scan)"}, "796": {"A": "SageMaker Autopilot trains a custom ML model — explicitly prohibited by requirements.", "B": "Rekognition Image is a pre-trained AWS managed service with a content moderation API. No model training needed. Lambda + function URL integrates cleanly with web app. Correct.", "C": "Comprehend analyzes text sentiment/entities — cannot analyze image content. Wrong service for photo moderation.", "D": "Rekognition Video processes video streams/stored video — overkill and wrong API for individual photo uploads.", "_summary": "Photo content moderation without training → Rekognition Image moderation labels via Lambda"}, "792": {"A": "Cognito user pool handles user authentication (sign-up/sign-in). API Gateway REST APIs natively support Cognito authorizer — fully managed, zero custom auth code. Most operationally efficient.", "B": "Identity pools grant temporary AWS credentials for accessing AWS resources — wrong tool for user authentication. HTTP APIs use JWT authorizer (not named 'Cognito authorizer') — minor but identity pool choice makes this wrong.", "C": "Lambda authorizer works but requires writing/maintaining custom auth logic. More operational overhead than managed Cognito.", "D": "IAM users don't scale to millions of external users — designed for internal AWS principals, not public app users.", "_summary": "Cognito user pool = user auth; identity pool = AWS resource access; user pool + REST API Cognito authorizer = least overhead"}, "905": {"A": "Global Accelerator supports TCP and UDP over AWS backbone with static Anycast IPs. Accepts NLB endpoints (EC2) and on-premises IP endpoints. Solves both workloads. Correct.", "B": "CloudFront is HTTP/HTTPS only — cannot handle raw TCP or UDP traffic. Wrong for these workloads.", "C": "ALB is Layer 7 HTTP only — cannot handle TCP or UDP traffic. Wrong.", "D": "NLB operates Layer 4, supports both TCP and UDP. Can route to EC2 and on-premises (via Direct Connect/VPN). Correct.", "E": "ALB for on-premises UDP workload fails — ALB doesn't support UDP. Wrong.", "_summary": "Global Accelerator + NLBs covers TCP/UDP; ALB/CloudFront can't handle non-HTTP traffic"}, "813": {"A": "Route 53 A record → ALB (stable endpoint). ALB listener rule routes dev hostname to dev target group. When instance replaced, new instance registers in target group automatically — no DNS change needed. Correct.", "B": "Public IPs change on instance replacement — Route 53 record becomes stale. Fails auto-routing requirement.", "C": "ALB listener redirect sends HTTP 3xx with target IP to client — IP changes on replacement, breaks routing. Also redirect != forward.", "D": "All instances in one target group means dev requests load-balance across all instances including prod — dev traffic not isolated to dev instance.", "_summary": "Route 53 → ALB → target group survives instance replacement; direct IP records don't"}, "250": {"A": "CloudWatch with 90-day expiration deletes logs — doesn't retain for intermittent access afterward. Wrong.", "B": "VPC Flow Logs cannot target Kinesis directly (only CloudWatch Logs or S3). Also Kinesis is a stream, not archival storage.", "C": "VPC Flow Logs cannot be sent to CloudTrail — CloudTrail captures API calls, not network flow data.", "D": "VPC Flow Logs support S3 as destination. S3 Standard for 90 days (frequent access), Lifecycle transitions to S3 Standard-IA (intermittent access). Cost-optimized and meets both access patterns. Correct.", "_summary": "VPC Flow Logs → S3 + Lifecycle to Standard-IA satisfies frequent-then-intermittent access pattern"}, "181": {"A": "SQS decouples producers from consumers, buffers messages durably, each message processed once. Ideal for sequential work distribution across microservices where order of results doesn't matter. Correct.", "B": "SNS fan-out pushes every message to all subscribers — every consumer gets every message. Wrong for distributing work items that should be processed exactly once.", "C": "Lambda as message intermediary adds latency and cost; no buffering — if consumers unavailable, messages lost. Less efficient than SQS.", "D": "DynamoDB + Streams adds database overhead for a messaging problem. Streams have 24h retention, complex consumer logic, not designed for work queue pattern.", "_summary": "SQS = durable work queue for microservice decoupling; SNS = fan-out broadcast, wrong pattern here"}, "210": {"A": "Setting min capacity to peak values means always running at peak — wastes resources during off-peak. Doesn't optimize utilization.", "B": "SNS cannot create Auto Scaling groups dynamically. Architecturally incorrect — ASGs are provisioned, not created on demand via SNS.", "C": "SQS doesn't push notifications to trigger scaling. Scaling based on 'notifications the queues send' is inaccurate — SQS exposes CloudWatch metrics, not push notifications.", "D": "SQS decouples collection from fulfillment, preventing data loss on scaling events. Backlog-per-instance metric (ApproximateNumberOfMessages ÷ running instances) is AWS-recommended target tracking metric for queue-based ASG scaling. Correct.", "_summary": "SQS backlog-per-instance is the correct scaling metric for queue-driven ASGs; prevents data loss and optimizes utilization"}, "236": {"A": "Requires rewriting app to use Lambda + DynamoDB instead of MySQL — major code changes. Violates 'least change' requirement.", "B": "RDS read replicas add read capacity but don't provide write HA. Also no mention of S3 for images — storing images in RDS is impractical.", "C": "Single DB instance has no HA. Storing images on a memory-optimized EC2 DB instance is wrong.", "D": "Elastic Beanstalk Multi-AZ requires minimal app changes. RDS Multi-AZ provides HA with automatic failover. S3 stores images durably and scalably. All three tiers are HA with least refactoring. Correct.", "_summary": "Elastic Beanstalk + RDS Multi-AZ + S3 = scalable HA with minimal app changes"}, "100": {"A": "Secrets Manager stores and rotates secrets — not designed for encrypting/decrypting arbitrary certificate data in near real time. Wrong use case.", "B": "Custom Python cryptography in Lambda adds key management overhead, security risk, and operational complexity. 'Store Lambda in S3' is also confused — S3 stores deployment package, not a runtime storage solution.", "C": "KMS performs encryption/decryption operations in near real time via API. EC2 IAM role grants least-privilege access. S3 is highly available (multi-AZ by design). Fully managed — least operational overhead. Correct.", "D": "EBS volumes are AZ-scoped — not highly available across AZs. S3 is more durable and available for this requirement.", "_summary": "KMS + S3 = managed encryption with near-real-time ops and HA storage; EBS is AZ-local, not HA"}, "753": {"A": "AWS Transfer for SFTP is managed/HA SFTP; EFS is multi-AZ shared storage; ASG with scheduled scaling handles nightly batch — no self-managed SFTP, minimal ops. CORRECT.", "B": "Self-managed EC2 SFTP adds ops burden; EBS is single-AZ, not resilient; ASG min/desired=1 is just one instance with no redundancy. WRONG.", "C": "EFS is HA but self-managed SFTP on EC2 still adds operational overhead vs Transfer Family; ASG min/desired=1 still single instance. WRONG.", "D": "Transfer for SFTP + S3 is valid architecture but requires modifying the application to pull from S3 instead of filesystem — adds migration effort. WRONG.", "_summary": "Transfer Family = managed HA SFTP; EFS = multi-AZ shared FS for batch EC2 access"}, "736": {"A": "S3 Lifecycle policies transition or expire objects within the same bucket — cannot copy objects to a different bucket. Fundamentally wrong service feature. WRONG.", "B": "S3 Same-Region Replication supports cross-account replication within the same region (us-west-2→us-west-2), keeps logs in-region, fully managed by AWS, minimal ops. CORRECT.", "C": "Custom PutObject script needs compute scheduling, error handling, and maintenance — higher operational overhead than a managed replication rule. WRONG.", "D": "Lambda per account triggered on ObjectCreated works but requires deploying and maintaining Lambda functions in each account — more overhead than SRR. WRONG.", "_summary": "S3 SRR handles cross-account same-region replication with zero custom code"}, "799": {"A": "Amazon Comprehend is a managed NLP service that detects entities (including ingredients as noun phrases/custom entities) from text — no ML expertise needed, pay-per-use. CORRECT.", "B": "Amazon Forecast is time-series forecasting, not text/NLP — cannot extract ingredient names from recipe text. Completely wrong service. WRONG.", "C": "Polly converts text to speech; routing audio to human employees defeats automation, introduces latency, and is not cost-effective. WRONG.", "D": "SageMaker requires ML knowledge to build, train, and deploy models — violates the no-ML-expertise constraint and is expensive for this task. WRONG.", "_summary": "Comprehend NLP entity extraction = managed, no-ML-knowledge, cost-effective text analysis"}, "921": {"A": "Resize EC2 addresses CPU bottleneck; ASG min=max=1 respects single-instance constraint; RDS read replica offloads read traffic from primary. Both problems solved. CORRECT.", "B": "Read replicas are read-only — routing ALL read/write traffic to replica is architecturally invalid; writes to a replica cause errors. WRONG.", "C": "ASG max=2 is useless because app only runs on one instance; resizing RDS alone doesn't fix EC2 CPU utilization. Neither problem fully solved. WRONG.", "D": "Resizing both EC2 and RDS increases capacity but doesn't separate read workload — read performance improvement is less targeted than a read replica. WRONG.", "_summary": "Vertical scale EC2 + RDS read replica = two targeted fixes for two distinct bottlenecks"}, "722": {"A": "Transit gateway attaches all 30 VPCs and connects to Direct Connect via transit VIF — single hub enables full mesh VPC-to-VPC and VPC-to-on-prem routing, least overhead. CORRECT.", "B": "Direct Connect gateway + VGWs connects on-prem to VPCs but cannot route traffic between VPCs — VPC-to-VPC communication requirement unmet. WRONG.", "C": "Transit VPC (old EC2-based pattern) + manual VPC peering for 30 VPCs = 30×29/2=435 peering connections — massive operational overhead. WRONG.", "D": "Site-to-Site VPN per VPC ignores existing Direct Connect, adds 30 VPN connections, doesn't address VPC-to-VPC routing, higher cost. WRONG.", "_summary": "Transit gateway + transit VIF = single hub for 30-VPC mesh + on-prem via existing DX"}, "931": {"A": "Lambda resource-based policy must explicitly allow cross-account SNS service principal to invoke it — this is required for cross-account SNS→Lambda. CORRECT.", "B": "Adding SQS as intermediary adds unnecessary complexity; the requirement is direct SNS→Lambda invocation, not buffering. WRONG.", "C": "SNS topic access policy must allow the Lambda function (from the admin account) to subscribe cross-account — both the topic policy and Lambda policy are needed. CORRECT.", "D": "EventBridge cross-account forwarding adds an extra service and complexity when SNS can directly invoke Lambda with correct policies. WRONG.", "E": "S3+Athena is a completely different architecture for analytics, not for triggering Lambda on significant metrics. WRONG.", "_summary": "Cross-account SNS→Lambda needs: SNS topic policy (C) + Lambda resource policy (A)"}, "190": {"A": "Java and PHP cannot trivially run on Lambda without significant refactoring — this solution requires major application rewrite. WRONG.", "B": "Elastic Beanstalk natively supports Java and PHP, handles HA/scaling automatically; URL swapping enables zero-downtime blue/green feature testing. CORRECT.", "C": "Self-managed EC2+ASG+ALB requires patching, scaling config, OS management — more operational overhead than Beanstalk. WRONG.", "D": "Containerizing Java/PHP adds migration complexity; EC2 container management via LBC adds more ops overhead than Beanstalk. WRONG.", "_summary": "Beanstalk = managed PaaS for Java/PHP; URL swapping = built-in feature-testing mechanism"}, "188": {"A": "AWS Transfer Family is a fully managed SFTP service with built-in HA; native S3 integration means files land directly in the data lake — zero operational overhead. CORRECT.", "B": "S3 File Gateway provides SMB/NFS access to S3, not SFTP — wrong protocol entirely. WRONG.", "C": "Private EC2 + VPN requires partner VPN setup, cron job maintenance, single-instance risk — high operational overhead, not HA. WRONG.", "D": "Self-managed SFTP on EC2 behind NLB requires patching EC2 instances and cron jobs — more overhead than Transfer Family. WRONG.", "_summary": "Transfer Family = managed HA SFTP with direct S3 backend; no EC2 to maintain"}, "448": {"A": "VPN between peering VPCs doesn't fix SPOF — Management VPC's single customer gateway device is the failure point, not inter-VPC path.", "B": "Management VPC uses VPN/customer gateway, not VGW; adding VGW there is wrong service and doesn't address customer gateway SPOF.", "C": "Second customer gateway device gives redundant VPN tunnels to data center — eliminates single device SPOF in Management VPC. Correct.", "D": "VPC peering connections are already HA by design; two peering connections between same VPC pair are not allowed and don't fix the gateway SPOF.", "_summary": "Eliminate SPOF by adding redundant customer gateway device for Management VPC VPN"}, "548": {"A": "Systems Manager templates provision/configure resources — they do not restrict which services an account can call.", "B": "SCPs attached to OUs in AWS Organizations deny/allow API actions org-wide — single policy controls all accounts in OU with zero per-account overhead. Correct.", "C": "CloudFormation provisions approved stacks but cannot prevent users from calling service APIs directly.", "D": "Service Catalog controls approved product launches but doesn't block direct API access to restricted services.", "_summary": "SCPs on OUs = centralized service restriction with minimal ongoing overhead"}, "537": {"A": "RDS Multi-AZ cluster covers DB HA; ElastiCache Redis supports replication groups across AZs (survives node failure); ASG across 3 AZs covers web tier. All three tiers HA. Correct.", "B": "Memcached does NOT support replication — node failure loses all session data; fails HA requirement for session store.", "C": "DAX caches DynamoDB reads but is not designed for web session state; switching from MySQL to DynamoDB adds migration complexity and DAX doesn't help session storage use case.", "D": "RDS in single AZ is explicit single point of failure — violates high availability across 3 AZs requirement.", "_summary": "Redis (replicated) vs Memcached (no replication) is the key differentiator for session HA"}, "170": {"A": "Security groups filter by IP/port only — no geographic/country awareness.", "B": "ALB security groups also IP/port only — same limitation, no geo-filtering capability.", "C": "AWS WAF geographic match condition blocks/allows traffic by country code, attached directly to ALB. Correct.", "D": "Network ACLs filter by CIDR ranges only — no country-based filtering; maintaining country IP ranges manually has huge overhead.", "_summary": "WAF geographic match is the only AWS mechanism for country-based access control"}, "156": {"A": "Athena queries S3 directly (serverless, no infra) — perfect for one-time queries on staged S3 data; QuickSight connects to Athena for KPI dashboards. Correct.", "B": "Kinesis Data Analytics runs continuous streaming SQL — not designed for ad-hoc one-time queries on staged S3 data.", "C": "Custom Lambda to move individual records to Redshift — high operational overhead, managing Lambda invocations per record is fragile and complex.", "D": "OpenSearch is for search/log analytics — not a BI/KPI dashboard tool; Glue to OpenSearch doesn't address one-time queries on S3.", "E": "Lake Formation blueprints automate data lake ingestion; Glue crawler+ETL loads data to S3 in Parquet (columnar, Athena-optimized) — serverless pipeline with minimal ops overhead. Correct.", "_summary": "E builds serverless S3 data lake pipeline; A queries it with Athena + visualizes with QuickSight"}, "149": {"A": "SQS FIFO guarantees exactly-once, in-order delivery per message group; Lambda integration is serverless = minimal overhead. Correct.", "B": "SNS has no ordering guarantee — fan-out pub/sub pattern, order not preserved across subscribers.", "C": "SQS Standard uses best-effort ordering — does NOT guarantee message order, violates the ordering requirement.", "D": "SNS→SQS fan-out pattern still loses ordering — SNS delivery to SQS does not preserve send order.", "_summary": "SQS FIFO is the only managed queue that guarantees strict message ordering"}, "144": {"A": "Redshift migration requires ETL pipeline setup and schema redesign — higher cost and operational overhead than needed for read offload.", "B": "Aurora Replica receives replicated data from primary in near-real-time; direct reporting queries to replica endpoint — zero primary load, pay only for replica instance. Correct.", "C": "Larger instance costs more and doesn't separate reporting load from OLTP traffic — root cause unaddressed.", "D": "Aurora uses shared distributed storage (not provisioned IOPS per instance) — this setting doesn't apply to Aurora the same way; also not cost-effective.", "_summary": "Aurora Replica offloads read-heavy reporting from primary at minimal additional cost"}, "142": {"A": "Route 53 does latency/geo routing but no static IPs; ALB doesn't support UDP traffic.", "B": "CloudFront is HTTP/HTTPS only — cannot proxy UDP traffic at all; wrong service for UDP gaming.", "C": "Global Accelerator provides two static anycast IPs, routes users to nearest AWS edge PoP, then AWS backbone to NLB; NLB supports UDP. Correct.", "D": "API Gateway is HTTP/HTTPS/WebSocket only — no UDP support; ALB also doesn't support UDP.", "_summary": "Global Accelerator = static IPs + edge routing; NLB = UDP support — both required for UDP gaming front-end"}, "509": {"A": "Security groups are stateful and support only allow rules — no deny rules exist. Cannot block specific IPs.", "B": "NACLs are stateless, support explicit deny rules, and apply to entire subnets. Blocking IPs at public subnet level stops traffic before it hits any instance — correct and fastest mitigation.", "C": "Wrong tier (application, not web) and SGs still lack deny rules — double fail.", "D": "Wrong tier. Attacker traffic never reaches application subnets because ALB sits in public subnets. NACL there blocks nothing.", "_summary": "NACLs support deny rules; SGs do not. Block at the correct (web) tier subnet."}, "513": {"A": "S3 static hosting + Lambda = fully serverless, auto-scales to zero or millions, no infra to manage, highly available by default. Correct.", "B": "CloudFront is a CDN not a web host; Step Functions is an orchestrator not an image processor; RDS is wrong storage for images — three wrong choices.", "C": "Single EC2 is neither highly available nor auto-scaling. Fails both requirements.", "D": "ECS + SQS + EC2 is overcomplicated and EC2 workers don't scale as elastically as Lambda for unpredictable traffic.", "_summary": "Serverless (S3+Lambda) maximizes scalability and availability with zero infra management."}, "80": {"A": "Making AMI publicly available violates least-privilege. 'Most secure' disqualifies this immediately.", "B": "launchPermission scoped to MSP account only (private share) + KMS key policy grants MSP account decrypt access. Standard, minimal-exposure pattern. Correct.", "C": "Key policy cannot point to a different KMS key for re-encryption of existing snapshots. Snapshots remain encrypted under source key; MSP must have access to that key, not a new one.", "D": "AMI export to another account's S3 is not a standard EC2 AMI sharing workflow and adds unnecessary complexity and exposure.", "_summary": "Share AMI via launchPermission to specific account + grant KMS key policy access to that account."}, "78": {"A": "PITR retains only 35 days of continuous backups — cannot meet 7-year retention requirement.", "B": "AWS Backup supports DynamoDB, allows custom schedules and retention up to years, fully managed, zero custom code. Correct.", "C": "Manual on-demand backup is not automated — violates 'operationally efficient'; also requires manual S3 Lifecycle setup.", "D": "EventBridge + Lambda custom pipeline has high ongoing operational overhead (code maintenance, error handling, monitoring).", "_summary": "AWS Backup is the managed, policy-driven solution for DynamoDB long-term retention."}, "86": {"A": "Secrets Manager has native RDS rotation integration, IAM-based access control, and automatic scheduled rotation. Built exactly for this. Correct.", "B": "OpsCenter is for incident/operational item management, not secret storage. Wrong service entirely.", "C": "S3 has no built-in secret rotation mechanism; requires custom code and is less access-controlled than Secrets Manager.", "D": "Static encrypted files on disk have no rotation mechanism — credentials are effectively static unless manually replaced.", "_summary": "Secrets Manager provides managed credential storage with automatic RDS rotation."}, "445": {"A": "DataSync agent on-prem uses Direct Connect, performs continuous incremental sync, allows data to remain accessible and updatable throughout migration. 700 TB over 10 Gbps completes well within 90 days. Correct.", "B": "Snowball Edge: once data is on device and shipped, that copy can't be updated. Violates 'access and update during transfer' requirement.", "C": "rsync has no change-tracking database, no managed retry, and no incremental sync visibility — operationally fragile for 700 TB.", "D": "Tape: slowest option, no way to update data on shipped tapes, fails both efficiency and update-during-transfer requirements.", "_summary": "DataSync over Direct Connect enables managed, incremental, concurrent-access migration."}, "1018": {"A": "Managed Microsoft AD requires provisioning and managing a full directory in AWS — more overhead than AD Connector for a proxy-only need.", "B": "Manual IAM users per developer is maximum operational overhead with zero AD integration. Wrong on both counts.", "C": "AD Connector proxies auth requests to on-prem AD with no data sync needed. IAM Identity Center integrates natively with Organizations for multi-account permission sets. Least overhead. Correct.", "D": "Cognito is designed for customer/app identity (CIAM), not enterprise workforce SSO — wrong service category.", "_summary": "AD Connector + IAM Identity Center = least-overhead federation of on-prem AD into multi-account AWS."}, "318": {"A": "CloudTrail records all API calls — captures who launched oversized EC2, who modified security groups, with timestamps and identity. Correct.", "B": "Data lifecycle policies manage EBS snapshot schedules — unrelated to change auditing.", "C": "Trusted Advisor gives best-practice recommendations, not a change audit trail.", "D": "AWS Config records configuration state history and evaluates compliance rules (e.g., flag non-approved instance types, detect open security groups). Correct.", "E": "CloudFormation restores infrastructure state but does not track or audit changes made outside CloudFormation.", "_summary": "CloudTrail = API audit log; AWS Config = resource configuration history and compliance rules."}, "787": {"A": "Control Tower deploys in management account, auto-enrolls accounts via Account Factory (audits new accounts), enables CloudTrail org-wide (API/login audit), and integrates Security Hub with FSBP — fully managed, minimal overhead. Correct.", "B": "Control Tower must deploy in management account, not a member account. Architecture is invalid.", "C": "AMS Accelerate + GuardDuty: GuardDuty detects threats, does not audit API calls/logins or check FSBP compliance. Wrong service, higher overhead.", "D": "AMS Accelerate adds operational overhead via RFC workflow; Security Hub alone doesn't provide the CloudTrail-based API/login audit requirement. Inferior to Control Tower.", "_summary": "Control Tower in mgmt account = org-wide CloudTrail + Security Hub FSBP + Account Factory auto-enrollment"}, "300": {"A": "Spot Instances can be interrupted; 24/7 app requires stable compute. S3 is object storage, unsuitable as legacy DB storage layer.", "B": "EC2 Reserved is correct for 24/7 compute, but RDS On-Demand for a 24/7 growing DB is significantly more expensive than Reserved pricing.", "C": "Both workloads run 24/7, so Reserved pricing (up to 72% savings) on both EC2 and Aurora is most cost-effective. Aurora auto-scales storage, handling growth. Correct.", "D": "EC2 On-Demand for 24/7 workload wastes money vs Reserved. RDS Reserved is correct but app layer choice negates savings.", "_summary": "24/7 workloads → Reserved pricing on both layers; Aurora handles auto-growing storage"}, "648": {"A": "FSx for Lustre scratch provides no HA and no data replication — data lost on failure. Fails HA requirement.", "B": "Persistent FSx for Lustre is HA, replicates data, delivers sub-millisecond latency, sustains high throughput, and supports thousands of concurrent compute instances for HPC. Correct.", "C": "EFS Bursting Throughput scales throughput based on stored data size — unsuitable for large sustained throughput spikes. EFS latency is single-digit milliseconds, not sub-millisecond.", "D": "EFS Provisioned Throughput can sustain throughput but NFS-based latency is too high for sub-millisecond HPC requirement.", "_summary": "HPC sub-ms latency + HA + sustained throughput → FSx Lustre persistent"}, "961": {"A": "WAF can attach to Global Accelerator, but attaching to ALB (option C) is equally valid and more straightforward — however GA+WAF is a less common pattern and adds complexity upstream.", "B": "Custom Lambda reading ALB metrics to update NACLs is manual, fragile, and high implementation effort. Opposite of least effort.", "C": "WAF natively integrates with ALB; rate-based rules auto-block IPs exceeding thresholds with no custom code. Standard DDoS mitigation pattern, least implementation effort. Correct.", "D": "Placing CloudFront in front of Global Accelerator is redundant architecture (both are global entry-point services), adds cost and complexity without clear benefit.", "_summary": "WAF rate-based rules on ALB = native DDoS mitigation, zero custom code"}, "962": {"A": "Athena DynamoDB connector queries DynamoDB directly, consuming provisioned read capacity units. Violates minimal-impact requirement.", "B": "Glue DynamoDB export connector uses DynamoDB's export-to-S3 feature, which runs off backup capacity and does NOT consume provisioned RCUs. Processing happens on exported S3 data. Correct.", "C": "Redshift COPY from DynamoDB reads the table directly, consuming RCUs proportional to data scanned. Impacts provisioned capacity.", "D": "EMR Hive external table on DynamoDB issues Scan/Query operations consuming RCUs on each job run. Impacts provisioned capacity.", "_summary": "Glue export connector → DynamoDB export-to-S3 bypasses RCU consumption"}, "980": {"A": "Gateway endpoint routes S3 traffic over AWS network (free, no internet), and IAM instance profile restricts EC2 to specific company buckets. Least overhead, no extra cost. Correct.", "B": "NAT gateway incurs per-GB cost and security groups cannot restrict traffic to only company-owned S3 buckets by account.", "C": "Gateway endpoint is correct, but adding a Deny condition with org/account condition key is more complex than a simple Allow policy in the instance profile. Higher configuration overhead than A.", "D": "NAT gateway costs money per GB processed and managing bucket policies across all buckets adds significant operational overhead.", "_summary": "S3 gateway endpoint (free, private) + IAM instance profile = secure, zero-overhead S3 access control"}, "160": {"A": "OpenSearch is a search/analytics engine — massively over-engineered and expensive for a 300 MB monthly backup use case.", "B": "S3 Glacier retrieval takes minutes to hours (Expedited: 1-5 min, Standard: 3-5 hr). Fails the millisecond-access requirement.", "C": "S3 Standard provides millisecond GET latency, costs ~$0.023/GB/month (300 MB ≈ $0.007/month), and lifecycle policies can delete after 30 days. Correct.", "D": "RDS for PostgreSQL requires instance hours, storage, and backups — expensive infrastructure for simple JSON file DR at 300 MB/month.", "_summary": "300 MB + ms access + 30-day retention → S3 Standard with lifecycle rule"}, "155": {"A": "DataSync is a data migration/transfer service, not a CDN. Does not cache content or reduce latency for global users.", "B": "Global Accelerator optimizes routing to origin but does not cache content at edge — each request still hits the origin S3/ALB.", "C": "CloudFront is a CDN that caches S3 content at 450+ edge locations globally, supports signed URLs/cookies for confidential files, and reduces latency worldwide. Correct.", "D": "SQS is a message queue with no content delivery or caching capability whatsoever.", "_summary": "Global caching from S3 → CloudFront CDN with signed URLs for confidential content"}, "154": {"A": "Governance mode lets users with `s3:BypassGovernanceRetention` permission override lock — violates 'no user can delete/modify' requirement.", "B": "Compliance mode is unbreakable by any user including root; 365-day retention period enforces the 1-year minimum — correct.", "C": "IAM/bucket policy controls access but does NOT enforce immutability; privileged users or policy changes could still allow deletion.", "D": "Lambda hash-tracking only flags modified objects; does not prevent modification or deletion — no enforcement.", "_summary": "S3 Object Lock compliance mode = immutable retention no one can override"}, "152": {"A": "Systems Manager Session Manager manages EC2 instance shell access, not RDS start/stop — wrong service.", "B": "ElastiCache caches reads but RDS instance keeps running and billing — no cost reduction.", "C": "EC2 cron job adds EC2 instance cost and complexity; misses the direct RDS start/stop mechanism.", "D": "EventBridge scheduled rules trigger Lambda to call `StartDBInstance`/`StopDBInstance` RDS APIs on schedule — correct, serverless, no extra infra cost.", "_summary": "EventBridge + Lambda = native RDS start/stop scheduling, zero extra infra"}, "798": {"A": "Timestream is a time-series DB; reading partner list and looping HTTP calls in Lambda is custom heavy lifting.", "B": "SNS natively supports HTTP/HTTPS endpoint subscriptions; adding a partner = one `Subscribe` API call; publish user ID = fan-out to all — least effort, correct.", "C": "Step Functions task-per-partner requires state machine redeploy per new partner — high implementation overhead.", "D": "Kinesis requires custom consumer apps to read stream and push HTTP; not designed for HTTP fan-out.", "_summary": "SNS HTTP/HTTPS subscriptions = built-in fan-out to partner endpoints, zero custom glue"}, "631": {"A": "Neptune correct for graph relationships; Kinesis requires additional consumer infrastructure to process CDC — extra overhead.", "B": "Neptune handles graph traversal for relationship analysis and recommendations; Neptune Streams is its native change-capture feed, no extra infrastructure — correct.", "C": "QLDB is an immutable ledger (sequential audit log), not a graph DB; cannot efficiently model or query social relationships.", "D": "QLDB wrong for graph use case; Neptune Streams cannot tap QLDB changes — doubly wrong.", "_summary": "Neptune = graph DB for social relationships; Neptune Streams = native CDC, zero extra infra"}, "784": {"A": "Lambda lacks built-in job orchestration, retry-with-backoff, and sequential dependency management across multiple jobs.", "B": "Athena runs SQL on S3; not a general data preparation job runner; EventBridge alone can't manage inter-job dependencies.", "C": "Glue DataBrew handles data prep jobs; Step Functions provides built-in error handling, retry logic, state management, parallel branches, and sequential ordering — correct.", "D": "AWS Data Pipeline is legacy; 'once at midnight' does not satisfy regular parallel intervals or complex ordering.", "_summary": "Step Functions orchestrates DataBrew jobs with native retry, parallel, and sequential state management"}, "148": {"A": "Lambda already spans multiple AZs by default; multi-AZ deployment does not address message loss on transient failure.", "B": "More CPU/memory doesn't fix network connectivity failures.", "C": "SNS retry for Lambda invocations retries only ~3 times over a short window; intermittent network issues that exceed retry window still lose messages.", "D": "SQS as on-failure destination persists failed events durably; Lambda reprocesses from queue when connectivity restored — guarantees eventual processing, correct.", "_summary": "SQS DLQ/destination = durable buffer that survives transient Lambda failures"}, "147": {"A": "AWS Backup creates backup copies of S3 objects; does not transition storage classes — adds cost instead of reducing it.", "B": "S3 Lifecycle policies natively transition objects to Glacier Deep Archive after 30 days; no extra services, minimal cost for cold storage — correct.", "C": "CloudWatch Logs has no native Glacier Deep Archive transition; AWS Backup cannot move CWL directly to Glacier.", "D": "CloudWatch Logs cannot use S3 Lifecycle policies directly; would require an export step first — adds complexity.", "_summary": "S3 Lifecycle to Glacier Deep Archive = lowest-cost native tiering, no extra services"}, "964": {"A": "EC2 requires OS patching and capacity management; storing images in RDS is inefficient and costly.", "B": "DynamoDB is NoSQL — cannot maintain structured relational schemas as required.", "C": "EKS on EC2 has high operational overhead (node groups, upgrades); S3 Glacier Deep Archive is cold archival storage, wrong for actively served product images.", "D": "ECS Fargate removes server management entirely; RDS Multi-AZ preserves relational schemas; S3 is standard object storage for images — correct, least operational overhead.", "_summary": "Fargate + RDS Multi-AZ + S3 = serverless containers, managed relational DB, standard image storage"}, "99": {"A": "Storage Gateway supports NFS/SMB, not Lustre protocol. Wrong client support.", "B": "EC2 Windows file share is self-managed, not fully managed. Fails requirement.", "C": "EFS does not support Lustre protocol. Cannot serve Lustre clients.", "D": "FSx for Lustre is AWS-managed, natively speaks Lustre protocol. Direct fit.", "_summary": "FSx for Lustre = only AWS fully managed Lustre-compatible storage"}, "97": {"A": "EFS is NFS-based Linux storage; no native SMB or AD integration for Windows workloads.", "B": "Storage Gateway SMB share exists but is not designed for HA SharePoint-scale Windows file storage.", "C": "S3 cannot be natively mounted as a Windows SMB volume; no AD access control.", "D": "FSx for Windows File Server provides native SMB, full AD integration, Multi-AZ HA. Exact match.", "_summary": "FSx for Windows File Server = managed Windows SMB storage with AD auth"}, "95": {"A": "Multi-AZ standby is passive failover only; primary zone serves all traffic. No read separation.", "B": "Multi-AZ secondary is synchronous standby, not readable. RDS Multi-AZ does not expose replica for reads.", "C": "Read replicas correct direction but undersized replicas become bottleneck under heavy read load.", "D": "Read replicas with matching compute/storage handle read traffic at source-equivalent performance. Correct.", "_summary": "RDS read replicas (same size) separate read/write traffic; Multi-AZ standby is not readable"}, "94": {"A": "EMR is batch-oriented, over-engineered for single-file transforms; Aurora adds unnecessary ops overhead.", "B": "SQS + EC2 requires instance management, patching, scaling config — higher operational overhead.", "C": "S3 event → SQS → Lambda: fully serverless, auto-scales with demand, zero infrastructure management. Least ops overhead.", "D": "EventBridge + Kinesis + Lambda + Aurora is over-engineered; Kinesis adds cost and complexity for simple file processing.", "_summary": "S3→SQS→Lambda is minimum-ops serverless pipeline for event-driven file processing"}, "56": {"A": "Stage variables cannot remap the URL to a custom domain; ACM cert import alone does not configure custom domain.", "B": "Regional API Gateway ACM cert must be in same region as the API; us-east-1 ACM is only for edge-optimized APIs.", "C": "Regional endpoint + ACM cert in same region (ca-central-1) + attach to endpoint + Route 53 alias = correct full setup.", "D": "Regional API requires ACM cert in same region, not us-east-1; this would fail cert attachment to a regional endpoint.", "_summary": "Regional API Gateway custom domain needs ACM cert in same region; edge-optimized needs us-east-1"}, "216": {"A": "Creating new bucket and re-uploading all objects is high effort and operationally expensive at millions-object scale.", "B": "Enable default encryption (covers future objects) + S3 Inventory to list unencrypted + Batch Operations copy-in-place to encrypt existing. Least effort at scale.", "C": "SSE-KMS default encryption only encrypts new objects going forward; existing objects remain unencrypted. Versioning does not re-encrypt.", "D": "Manual console selection per object is impractical at millions of objects; not a viable approach.", "_summary": "S3 default encryption + Batch Operations copy = only scalable way to encrypt existing + future objects"}, "223": {"A": "IRSA (IAM Roles for Service Accounts) attaches IAM role to EKS pod — correct, no long-term credentials, least privilege. Required.", "B": "IAM users require static access keys; not attachable to pods natively and violates security best practices.", "C": "Network ACLs control subnet traffic but do not route DynamoDB traffic off-internet; VPC endpoint (D) is what keeps traffic private.", "D": "VPC Gateway Endpoint for DynamoDB routes traffic through AWS private network, never touches internet. Required.", "E": "Hardcoded access keys in code is a critical security anti-pattern; credentials leak via source control.", "_summary": "EKS→DynamoDB private: IRSA role (A) + VPC Gateway Endpoint (D)"}, "664": {"A": "Burstable unlimited (T-family) sustains 10x CPU spike without throttling credit exhaustion; scale-on-requests reacts to actual load spikes. Correct.", "B": "Compute optimized instances handle sustained high CPU but 10x burst spikes on T-series unlimited is more cost-effective; scale-on-requests is valid but instance type suboptimal for bursty pattern.", "C": "Schedule-based scaling requires predictable timing; the question implies unpredictable peaks (twice/month, no fixed schedule stated).", "D": "Elastic Beanstalk does not offer 'predictive metrics' scaling as a native option; burstable unlimited is still correct instance choice but scaling mechanism is invalid.", "_summary": "Burstable unlimited handles sudden 10x CPU spikes without throttling; request-based scaling reacts dynamically"}, "890": {"A": "Glacier Instant Retrieval gives millisecond access but has higher per-GB retrieval cost than Standard-IA; also minimum 90-day storage charge adds cost for files moved at day 30.", "B": "One Zone-IA saves cost but stores data in single AZ — files that cannot be recreated must not use single-AZ storage due to data-loss risk.", "C": "Standard-IA provides millisecond retrieval (satisfies 'immediately accessible'), multi-AZ durability (protects irreplaceable files), and lower storage cost vs Standard after 30 days. Lifecycle deletes at 4 years exactly as required.", "D": "Moving to Glacier Flexible Retrieval at 4 years contradicts the requirement to DELETE files at 4 years; Flexible Retrieval also lacks immediate access.", "_summary": "irreplaceable+immediately accessible+rarely accessed → Standard-IA via Lifecycle"}, "887": {"A": "EC2 'Encryption by default' account-level setting forces all new EBS volumes to be encrypted and actively BLOCKS creation of unencrypted volumes — satisfies both requirements.", "B": "AWS Config with encrypted-volumes rule detects non-compliant volumes after creation (reactive) but cannot prevent unencrypted volume creation.", "C": "Systems Manager copying volumes to encrypted versions is a remediation workaround, not prevention; still allows unencrypted volumes to be created initially.", "D": "Migration Hub tracks migration progress; it has no capability to enforce EBS encryption or prevent unencrypted volume creation.", "_summary": "EBS default encryption = EC2 account-level setting, not Config/SSM/KMS alone"}, "870": {"A": "IAM policies grant permissions within an account; policies alone cannot grant cross-account access without a role-based trust relationship.", "B": "IAM role in Development account cannot grant access to Production account resources; trust relationship must be defined in the target (Production) account.", "C": "IAM role in Production account with trust policy referencing Development account is the standard cross-account pattern; developers in Dev assume this role to access Production.", "D": "IAM groups cannot be principals in cross-account trust policies; users in Dev account cannot be members of groups in Production account.", "_summary": "cross-account access = role in target account with trust policy pointing to source account"}, "869": {"A": "SQS FIFO queue provides exactly-once processing via deduplication IDs and message groups; Lambda scales automatically to absorb traffic surges without customer impact.", "B": "SNS standard topics deliver at-least-once (not exactly-once); no built-in surge buffering; direct application notification doesn't decouple processing load.", "C": "AppFlow is a SaaS-to-AWS data integration service, not designed for transactional order processing pipelines.", "D": "X-Ray is an observability/tracing tool; CloudWatch is for metrics and logs — neither functions as a message queue or guarantees exactly-once delivery.", "_summary": "exactly-once + surge handling = SQS FIFO + Lambda"}, "868": {"B": "S3 Storage Lens provides organization-wide analytics including versioning status across all buckets and regions — purpose-built for this visibility use case.", "C": "IAM Access Analyzer for S3 identifies buckets with public or cross-account access policies, not versioning configuration.", "D": "S3 Multi-Region Access Point routes requests to buckets across regions; it has no capability to audit or report versioning status.", "_summary": "cross-region S3 versioning audit = S3 Storage Lens"}, "864": {"A": "Second Aurora cluster requires manual data copying and application changes; expensive and operationally complex compared to native read replicas.", "B": "DAX (DynamoDB Accelerator) is a DynamoDB-specific cache and cannot front Aurora; this option is architecturally invalid.", "C": "Aurora read replica offloads read traffic to replica endpoint, relieving pressure on primary writer; application routes reads to replica endpoint and writes to cluster endpoint — native, cost-effective Aurora scaling pattern.", "D": "Redshift is an OLAP data warehouse for analytics workloads, not a drop-in replacement for Aurora OLTP; adds complexity and cost with no benefit here.", "_summary": "Aurora read scalability = read replica + split read/write endpoints"}, "124": {"A": "Spot Instances are up to 90% cheaper than On-Demand; stateless jobs that tolerate interruption are the ideal Spot use case; dynamic scaling available via Spot Fleet or ASG.", "B": "Reserved Instances require 1-3 year commitment at fixed capacity; cost savings only apply to steady-state predictable usage, not dynamic batch scaling.", "C": "On-Demand is full price with no interruption risk, but for interruptible stateless workloads this provides no cost advantage over Spot.", "D": "Lambda has a 15-minute maximum execution timeout; 60+ minute batch jobs cannot run on Lambda.", "_summary": "stateless interruptible batch = Spot Instances for max cost savings"}, "360": {"A": "X-API-Key is an authentication header; it controls access authorization but does not change network routing from internet to VPC-internal paths.", "B": "Interface endpoint (AWS PrivateLink) for API Gateway routes traffic to private APIs entirely within the VPC network; minimal code change — only the endpoint URL changes, keeping traffic off the internet.", "C": "Gateway endpoints only support S3 and DynamoDB; API Gateway is not a supported service for gateway endpoints.", "D": "Adding SQS between APIs changes the architecture to async and requires significant code changes — violates 'fewest changes to the code' constraint.", "_summary": "private API Gateway traffic within VPC = interface endpoint (PrivateLink)"}, "424": {"A": "Fargate backend costs more than Spot for variable short-lived workloads; not most cost-effective.", "B": "Reserved Instances lock in 24/7 frontend at lowest price; Spot Instances cheapest for interruptible, variable backend workloads. CORRECT.", "C": "Frontend runs 24/7 and cannot tolerate Spot interruptions; Spot wrong here.", "D": "Spot frontend still interruptible problem; Fargate backend more expensive than Spot.", "_summary": "Reserved=steady 24/7; Spot=cheap interruptible burst"}, "443": {"A": "S3 Transfer Acceleration uses CloudFront edge locations to speed up global uploads AND downloads — cost-effective, no servers to manage. CORRECT.", "B": "CacheControl headers control browser/CDN caching behavior; does nothing to accelerate upload latency for global users.", "C": "CloudFront accelerates downloads but not uploads; EC2+Auto Scaling adds cost and operational overhead vs S3.", "D": "ElastiCache caches DB query results, irrelevant to file upload/download latency for global users.", "_summary": "S3 Transfer Acceleration = CloudFront edge acceleration for both upload and download"}, "723": {"A": "EC2 instance can have only one IAM instance profile; attaching two roles is impossible.", "B": "IAM users cannot be attached to EC2 instances; SSM requires an IAM role on the instance, not a user credential.", "C": "Default Host Management Configuration in SSM auto-configures instances using a service-linked role without touching existing instance role or policies. CORRECT.", "D": "Removing existing policies breaks RDS connectivity since the role holds RDS access policies — disrupts running applications.", "_summary": "Default Host Management Config adds SSM without modifying existing IAM role"}, "381": {"A": "DocumentDB uses MongoDB-compatible API; migrating from PostgreSQL relational queries requires significant code rewrite.", "B": "Aurora PostgreSQL is wire-compatible with PostgreSQL; Aurora Replica handles read-only reporting queries without impacting primary writer. CORRECT.", "C": "RDS Multi-AZ standby is a failover target only — it does NOT serve read traffic; cannot route reporting queries to it.", "D": "DynamoDB is NoSQL; relational queries would require complete rewrite of reporting logic.", "_summary": "Aurora Replica = read offload with zero PostgreSQL code changes"}, "215": {"A": "500 Mbps over 1 month transfers ~162 TB max; 700 TB requires Snowball physical shipment. S3 Glacier Deep Archive = cheapest long-term storage. CORRECT.", "B": "VPN uses same 500 Mbps public internet — cannot transfer 700 TB in 1 month; same bandwidth bottleneck.", "C": "Direct Connect provisioning takes weeks; still bandwidth-limited; more expensive than Snowball+Deep Archive.", "D": "DataSync still uses internet bandwidth — same 500 Mbps bottleneck; cannot meet 1-month deadline for 700 TB.", "_summary": "700 TB over 500 Mbps = ~130 days; Snowball bypasses bandwidth constraint"}, "253": {"A": "Policy combination does not grant iam:DeleteUser permission.", "B": "Policy combination does not grant ds:DeleteDirectory permission.", "C": "Policy combination grants ec2:TerminateInstances (or equivalent EC2 delete action). CORRECT.", "D": "Policy combination does not grant logs:DeleteLogGroup permission.", "_summary": "Combined policies grant only EC2 instance deletion"}, "988": {"A": "Organizations tag policies define allowed tag key-value pairs (sensitive/nonsensitive) and enforce value compliance at the OU level. CORRECT.", "B": "SCPs can enforce conditions but tag policies are the right tool for defining and enforcing allowed tag values; SCP alone doesn't enumerate valid values.", "C": "Tag policies are compliance-reporting tools only — they cannot deny API actions like RunInstances; cannot prevent creation.", "D": "SCPs can deny ec2:RunInstances when required tag absent (aws:RequestTag condition) and deny ec2:DeleteTags — prevents both unwanted creation and tag deletion. CORRECT.", "E": "Config+Lambda is reactive (detects after creation); requirement is preventive; deleting resources is destructive not compliant.", "_summary": "Tag policy=enforce valid values; SCP=deny create-without-tag and deny tag deletion"}, "970": {"A": "BatchGetSecretValue is a Secrets Manager API — calling it against Parameter Store is wrong; API mismatch.", "B": "AWS Batch is a compute orchestration service for batch jobs, not a secrets retrieval mechanism; adds unnecessary operational overhead.", "C": "Same API mismatch (BatchGetSecretValue ≠ Parameter Store); AWS Batch still irrelevant overhead.", "D": "Secrets Manager is purpose-built for credentials; BatchGetSecretValue correctly retrieves multiple secrets in one API call; CloudFormation integration is native. CORRECT.", "_summary": "Secrets Manager+BatchGetSecretValue = purpose-built credential store, single API call, least overhead"}, "946": {"A": "Custom endpoint lets you specify exactly which Aurora Replicas to include — create one pointing to the 3 differently-sized replicas, and connections to that endpoint route only to those 3.", "B": "Cluster clone creates a separate independent cluster; doesn't distribute queries across a specific subset of the original cluster's replicas.", "C": "Instance endpoints connect to one specific node each — no automatic distribution across 3 nodes.", "D": "Reader endpoint distributes across ALL replicas in the cluster, not just the 3 with different specs — no way to restrict it to a subset.", "_summary": "Aurora custom endpoint = named subset of replicas for workload isolation"}, "893": {"A": "Control Tower provisions accounts with built-in guardrails (SCPs + detective controls automatically). RAM subnet sharing from a central networking account = least overhead for centralized networking.", "B": "Organizations alone has no automatic guardrails/security controls — you build all SCPs manually. Misses the 'automatic security controls' requirement.", "C": "Control Tower is correct for guardrails, but per-account VPCs + transit gateway attachments = more networking complexity and operational overhead than RAM subnet sharing.", "D": "Organizations without Control Tower means no automatic guardrails; transit gateway adds operational overhead over RAM sharing.", "_summary": "Control Tower = automatic guardrails; RAM subnet sharing = centralized networking, least overhead"}, "825": {"A": "SSE-S3 auto-rotates keys but AWS controls the schedule — not annually and you cannot configure the rotation period. Fails 'every year' requirement.", "B": "KMS CMK automatic rotation rotates the key material annually. You control the key, AWS handles rotation — meets 'automatically every year' with minimal overhead.", "C": "Manual rotation fails 'automatic' requirement.", "D": "Imported key material (BYOK) cannot have automatic rotation enabled in KMS — manual only.", "_summary": "KMS CMK automatic rotation = annual, AWS-managed; SSE-S3 rotation period is not user-controllable"}, "820": {"A": "Lambda max execution is 15 minutes — jobs up to 20 min will time out. Eliminates A.", "B": "AWS Batch scheduling policies don't directly map to cron expressions or one-time future events as cleanly as EventBridge Scheduler.", "C": "EventBridge Scheduler supports both recurring cron schedules and one-time future schedules. Fargate runs containers with no execution time limit — handles the 20-min jobs. Minimal refactoring: just containerize.", "D": "Step Functions Wait state works but is over-engineered for simple cron jobs — higher refactoring effort, more complexity.", "_summary": "EventBridge Scheduler handles cron + one-time future events; Fargate removes Lambda's 15-min limit"}, "793": {"A": "AWS Config rules evaluate compliance but cannot cancel a KMS deletion in real time — Config is reactive/periodic, not synchronous with API calls.", "B": "Lambda + CloudWatch alarm achieves the goal but is more complex to build and maintain than SSM Automation.", "C": "KMS deletion is always a scheduled operation (min 7-day pending window). EventBridge catches ScheduleKeyDeletion API call, SSM Automation runs CancelKeyDeletion, EventBridge also triggers SNS notification — prevention + notification in one rule, least custom code.", "D": "CloudTrail+CloudWatch approach only notifies, does not cancel the deletion — fails the prevention requirement.", "_summary": "KMS deletion is always pending (cancellable); EventBridge+SSM Automation cancels it; SNS notifies — no Lambda needed"}, "789": {"A": "Proactive controls in Control Tower use CloudFormation hooks — they intercept and block stack deployments BEFORE resources are created. Directly prevents IAM inline policies, wildcard statements, and EC2 public IPs at deploy time.", "B": "Detective controls find violations after deployment — resources already exist. Does not prevent deployment.", "C": "Config rules detect non-compliance post-deployment; deleting via SSM is reactive cleanup, not prevention.", "D": "SCPs deny specific IAM API actions but cannot inspect CloudFormation template contents (e.g., inline policy body or '*' in a statement) before provisioning.", "_summary": "Proactive controls = CloudFormation hooks that block non-compliant deployments pre-creation"}, "719": {"A": "EFS supports NFS only — no SMB support. Fails multi-protocol requirement for Windows clients.", "B": "FSx for ONTAP natively supports both SMB and NFS from a single file system. Auto tiering policy automatically moves infrequently accessed data to a lower-cost capacity pool. Least overhead: one service, both protocols, built-in tiering.", "C": "S3 File Gateway provides SMB+NFS but introduces a gateway appliance to manage and is more complex than native FSx ONTAP.", "D": "FSx for OpenZFS supports NFS but not SMB natively — fails Windows SMB requirement.", "_summary": "FSx for ONTAP = only AWS service with both SMB+NFS + built-in auto tiering in one managed service"}, "603": {"A": "Map state Inline mode caps at 40 concurrent iterations and stores all execution history in the parent — not suitable for thousands of items.", "B": "Distributed Map mode runs each iteration as a child execution, supports up to 10,000 concurrent executions, reads directly from S3, fully serverless — purpose-built for large-scale parallel processing.", "C": "Glue requires configuring DPU capacity, job scripts, and crawler setup — more operational overhead than Distributed Map.", "D": "Multiple Lambda functions require custom orchestration/fan-out logic — not operationally efficient at scale.", "_summary": "Step Functions Distributed Map = serverless fan-out for thousands of S3 items, no infra to manage"}, "407": {"A": "DataSync transfers data between storage systems — not a Lustre-protocol mountable filesystem.", "B": "Storage Gateway file gateway exposes NFS/SMB shares, not Lustre protocol.", "C": "EFS uses NFSv4 protocol only; it cannot be configured to support the Lustre client protocol.", "D": "FSx for Lustre is AWS's fully managed Lustre filesystem — supports native Lustre clients, zero infra to manage.", "_summary": "FSx for Lustre = only AWS managed service with native Lustre client support"}, "41": {"A": "Auto Scaling reduces overload but still requires managing EC2 for data ingestion — doesn't eliminate the bottleneck.", "B": "AppFlow is a fully managed SaaS-to-S3 integration service; removes EC2 entirely from the ingestion path. S3 event notification → SNS handles upload alerts. Least overhead.", "C": "EventBridge rules per SaaS source adds per-source config overhead; S3 bucket cannot be an EventBridge rule target for raw data delivery.", "D": "ECS still requires container/task management; CloudWatch Container Insights doesn't emit S3 upload completion events to SNS.", "_summary": "AppFlow = managed SaaS connector, eliminates EC2 data ingestion overhead"}, "40": {"A": "Firehose → S3 is fully managed, serverless, highly available, handles 500M small records/day cheaply. S3 Lifecycle to Glacier at 14 days is native and zero-overhead. Correct.", "B": "EC2 behind ELB requires managing instances — violates 'no additional infrastructure' requirement.", "C": "OpenSearch is expensive for raw storage; manual daily snapshots add operational burden.", "D": "SQS max retention is 14 days — data at day 14 risks loss; consumer-driven archiving logic adds significant operational complexity.", "_summary": "Firehose + S3 + Lifecycle = serverless ingest + tiered storage with zero infra management"}, "39": {"A": "Provisioned IOPS SSD directly increases storage throughput and IOPS ceiling — fixes the diagnosed storage performance bottleneck for high-write workloads.", "B": "Memory-optimized instance expands buffer pool but doesn't fix the underlying storage I/O saturation.", "C": "Burstable instances (T-class) are worse for sustained high-write workloads — IOPS credits exhaust, degrading performance further.", "D": "Read replicas offload SELECT queries; Multi-AZ doesn't increase write IOPS on the primary. Neither addresses insert latency.", "_summary": "gp2 saturates at 3000 IOPS; Provisioned IOPS SSD removes that ceiling"}, "38": {"A": "Replicating S3 to every region is costly and complex; requires managing replication + routing per region.", "B": "Global Accelerator routes TCP/UDP to AWS edge but does not cache static content — latency improves slightly but cost is higher than CloudFront for static sites.", "C": "CloudFront caches content at 400+ edge locations worldwide, dramatically cuts latency for static assets, and is cheaper than Accelerator for this use case. Correct.", "D": "S3 Transfer Acceleration speeds up data uploads into S3 — has no effect on download/read latency for website visitors.", "_summary": "CloudFront = CDN caching for static S3 sites; most cost-effective global latency fix"}, "37": {"A": "EC2 serial console is for emergency/out-of-band access only — not designed for routine remote administration.", "B": "Session Manager over IAM role: no open ports, no key pairs, no bastion, full audit trail in CloudTrail — native AWS, Well-Architected, least overhead. Correct.", "C": "Bastion host requires provisioning, patching, key management, and security group rules — high operational overhead.", "D": "Site-to-Site VPN requires customer gateway hardware/config on-premises and ongoing tunnel maintenance — significant overhead.", "_summary": "SSM Session Manager = keyless, portless remote admin via IAM; AWS Well-Architected preferred pattern"}, "35": {"A": "GuardDuty detects threats via log analysis — does not block or mitigate DDoS traffic.", "B": "Inspector scans EC2 for vulnerabilities — unrelated to DDoS mitigation.", "C": "Shield Standard (free tier) provides only basic L3/L4 protection; company uses third-party DNS so Route 53 isn't in the architecture — assigning Shield to Route 53 is irrelevant here.", "D": "Shield Advanced provides enhanced DDoS mitigation, 24/7 DRT support, and cost protection. Assigning it to the ELB (the actual ingress point) is correct since DNS is third-party. Correct.", "_summary": "Shield Advanced on ELB = L3-L7 DDoS protection at the load balancer ingress"}, "34": {"A": "Reversed — CloudTrail records API calls; Config tracks resource configuration changes.", "B": "AWS Config records configuration state and changes over time; AWS CloudTrail records API call history with who/when/what. Both requirements met. Correct.", "C": "CloudWatch handles metrics and logs — it does not record API call history; that's CloudTrail's job.", "D": "CloudTrail records API calls (correct for second requirement) but does not track resource configuration changes — that's Config's job.", "_summary": "Config = config change history; CloudTrail = API call audit log"}, "599": {"A": "Correct. Customer must supply facility power and network uplink to Outposts racks — AWS only manages what's inside the rack.", "B": "Incorrect. AWS owns the hypervisor, storage systems, and service software running on Outposts — not the customer.", "C": "Correct. Physical security and badge/access controls of the on-prem data center are entirely the customer's responsibility.", "D": "Incorrect. AWS is responsible for availability of hardware components within the Outposts racks (servers, NICs, power supplies inside the unit).", "E": "Incorrect. AWS dispatches field technicians for physical maintenance of Outposts hardware.", "F": "Correct. Outposts has finite capacity; the customer must provision enough ECS capacity to absorb failures and maintenance — AWS doesn't auto-scale Outposts hardware.", "_summary": "Outposts shared responsibility: customer owns facility (power, network, physical security) and capacity planning; AWS owns everything inside the rack"}, "587": {"A": "Incorrect. GWLB is for routing traffic to security appliances, not for auth; it has no built-in authorization layer.", "B": "Incorrect. Kinesis Data Streams works but requires consumers to pull and process data; no native Lambda authorizer integration at the stream level.", "C": "Correct. API Gateway scales automatically for spiky traffic, Lambda authorizer handles the auth step, and Kinesis Data Firehose buffers and delivers directly to S3 with no consumer code needed.", "D": "Incorrect. Same GWLB problem as A — wrong service for this ingestion + auth pattern regardless of where Lambda is placed.", "_summary": "API Gateway + Kinesis Firehose + Lambda authorizer is the canonical serverless ingest-with-auth pattern for unpredictable web traffic"}, "535": {"A": "Incorrect. Secrets Manager stores secrets externally in its own service — secrets are not encrypted inside the Kubernetes etcd store itself.", "B": "Correct. EKS supports KMS envelope encryption of Kubernetes Secrets at rest in etcd; enabling it on the cluster satisfies the requirement directly.", "C": "Incorrect. EBS CSI driver provides persistent volumes for pods — completely unrelated to encrypting etcd secrets.", "D": "Incorrect. Default EBS volume encryption encrypts block storage, not etcd key-value data.", "_summary": "EKS KMS secrets encryption encrypts Kubernetes Secret objects inside etcd using a customer-managed KMS key"}, "368": {"A": "Correct. IAM account password policy is a single account-wide setting that enforces complexity and rotation for all IAM users.", "B": "Incorrect. IAM has no per-user password policy — only one account-level policy exists.", "C": "Incorrect. Third-party tooling is unnecessary overhead; native IAM capability covers this fully.", "D": "Incorrect. CloudWatch events cannot enforce or set password policies; no such enforcement mechanism exists via events.", "_summary": "IAM account password policy is the single control point for complexity and rotation requirements across all users"}, "366": {"A": "Incorrect. Caching and throttling manage performance and rate limits, not subscription entitlements.", "B": "Incorrect. WAF filters web exploits and IPs, not subscription status — it has no awareness of user plans.", "C": "Incorrect. Fine-grained DynamoDB IAM permissions require per-user policy management, which is high operational overhead.", "D": "Correct. API Gateway usage plans paired with API keys natively model subscription tiers, enforcing access and quotas with zero custom code.", "_summary": "API Gateway usage plans + API keys are the native low-overhead mechanism for tiered subscription access control"}, "984": {"A": "Correct. CloudFront's global edge network caches and accelerates both static and dynamic content, reducing origin load at lowest marginal cost per request at scale.", "B": "Incorrect. Route 53 geo-routing directs users to nearest region but adds no caching layer — origin still handles every request, no cost reduction.", "C": "Incorrect. S3 static hosting cannot run a dynamic application backed by EC2/Lambda/DynamoDB.", "D": "Incorrect. Direct Connect is private on-prem-to-AWS connectivity, not a CDN for end-user content delivery.", "_summary": "CloudFront with ALB origin is the standard pattern to globally accelerate a regional web application cost-effectively"}, "643": {"A": "Correct. S3 stores logs cheaply; Athena is serverless SQL on S3 — pay only per query, ideal for infrequent ad-hoc analysis of large log volumes.", "B": "Incorrect. RDS requires a continuously running instance; expensive for weekly queries on tens-of-GB log data.", "C": "Incorrect. OpenSearch requires a running cluster, is expensive at sustained scale, and does not support standard SQL.", "D": "Incorrect. EMR is powerful but requires cluster provisioning and management overhead; costlier than Athena for intermittent use.", "_summary": "S3 + Athena is the canonical cost-effective serverless SQL pattern for infrequent log analytics"}, "315": {"A": "Incorrect. AWS Shield is a DDoS protection service — it does not scan for application or OS-level vulnerabilities.", "B": "Incorrect. Macie discovers sensitive data in S3; it does not scan EC2 instances for software vulnerabilities.", "C": "Incorrect. GuardDuty detects threats via log analysis and behavior, but does not actively scan for CVE-level vulnerabilities on instances.", "D": "Correct. Amazon Inspector is purpose-built for active vulnerability scanning of EC2 instances and container images; its agent reports CVEs, network exposure, and software findings.", "_summary": "Amazon Inspector is the AWS-native vulnerability scanner for EC2 — deploy agent, findings auto-reported, Lambda automates distribution"}, "986": {"A": "NFS on EC2 = single point of failure, manually managed, not HA; EBS can't be shared across instances anyway.", "B": "FSx for Windows uses SMB protocol — these are Linux instances; also single-AZ as stated.", "C": "Two EBS volumes on one instance still can't be shared across Auto Scaling group members.", "D": "EFS is managed multi-AZ NFS storage, natively mountable on Linux, no app code changes needed. Correct.", "_summary": "EFS = managed shared NFS for Linux EC2 across AZs"}, "187": {"A": "RDS Multi-AZ uses synchronous replication with automatic failover — HA with zero manual intervention. Correct.", "B": "Read replicas use async replication and require manual promotion; not automatic HA for writes.", "C": "EC2-based Docker cluster requires manual cluster management and scaling — contradicts 'least manual intervention'.", "D": "ECS Fargate is serverless containers — AWS manages underlying infrastructure, truly elastic. Correct.", "E": "ECS EC2 launch type requires managing and patching EC2 instances — more operational overhead than Fargate.", "_summary": "RDS Multi-AZ + ECS Fargate = HA with minimal ops"}, "186": {"A": "Storage Gateway volume gateway presents iSCSI block storage, not a shared Windows SMB file system.", "B": "FSx for Windows File Server is native SMB/NTFS, supports multi-AZ, mounts directly on Windows EC2. Correct.", "C": "EFS uses NFSv4 — not natively compatible with Windows without extra NFS client setup; not the right tool.", "D": "EBS cannot be simultaneously attached to multiple instances (standard volumes); inherently single-instance.", "_summary": "FSx for Windows = only AWS-managed SMB share for Windows instances"}, "182": {"A": "Standard RDS Multi-AZ has one primary + one standby (two nodes), not three; '3 nodes in 3 AZs' misrepresents standard RDS behavior.", "B": "RDS MySQL Multi-AZ replicates synchronously to standby in separate AZ — automatic failover, data on at least two nodes. Correct.", "C": "RDS read replicas use asynchronous replication — can lose transactions; not synchronous.", "D": "Lambda is not designed for synchronous DB replication; overly complex, unreliable, high operational overhead.", "_summary": "RDS Multi-AZ = synchronous replication, automatic failover"}, "180": {"A": "WAF cannot attach directly to NLB — WAF supports ALB, API Gateway, CloudFront, and AppSync only.", "B": "Shield Advanced integrates with NLB to detect and mitigate sophisticated DDoS attacks with dedicated response team. Correct.", "C": "WAF on API Gateway filters SQL injection and other Layer 7 exploits at the API entry point. Correct.", "D": "GuardDuty is threat detection/intel, not active DDoS mitigation; Shield Standard is automatic but only covers basic volumetric attacks.", "E": "Shield Standard is free and automatic but provides no advanced DDoS mitigation or SRT access.", "_summary": "WAF (L7 exploits on API GW) + Shield Advanced (DDoS on NLB)"}, "178": {"A": "AWS Backup natively supports cross-region copy for both EC2 (AMI/EBS) and RDS in a single policy — least overhead. Correct.", "B": "DLM only manages EBS snapshots; cannot handle RDS backups, so incomplete for this requirement.", "C": "AMI copy is manual; RDS read replica is for read scaling not backup, and doesn't replace cross-region snapshots.", "D": "Multi-step chain (EBS snapshots → copy, RDS snapshots → S3 export → CRR) is high operational complexity.", "_summary": "AWS Backup = single service for cross-region EC2+RDS backup"}, "175": {"A": "Provisioned concurrency reduces cold starts but doesn't reduce open DB connections; global database adds multi-region complexity irrelevant to connection exhaustion.", "B": "RDS Proxy pools and multiplexes Lambda connections to Aurora, directly solving connection exhaustion; only endpoint change needed in Lambda. Correct.", "C": "Read replicas handle reads, not writes; routing orders to a read replica in another region is architecturally wrong and introduces latency.", "D": "Migrating to DynamoDB requires significant application rewrites — contradicts 'least possible changes'.", "_summary": "RDS Proxy = connection pooling between Lambda and Aurora"}, "171": {"A": "Single EC2 instance is not elastic — fixed capacity, manual scaling, no burst handling.", "B": "API Gateway + Lambda is fully serverless and auto-scales to any concurrency with no capacity planning. Correct.", "C": "Two fixed EC2 instances behind ALB has hard capacity ceiling — not elastic for holiday surges.", "D": "API Gateway routing to EC2 still bottlenecks on the EC2 tier; EC2 doesn't auto-scale without ASG, and adds unnecessary hop.", "_summary": "API GW + Lambda = serverless elastic scaling for spiky workloads"}, "169": {"A": "Amazon Inspector scans EC2/container workloads for vulnerabilities — has no DDoS mitigation capability.", "B": "Macie is a data privacy service that classifies S3 data — irrelevant to DDoS or ALB traffic.", "C": "Shield Advanced provides enhanced DDoS protection for ALB, CloudFront, Route 53, and EIPs, including 24/7 DRT access and cost protection.", "D": "GuardDuty detects threats via log analysis but is passive monitoring — it does not block or absorb DDoS traffic.", "_summary": "Shield Advanced = only AWS service that actively mitigates DDoS against ALB"}, "168": {"A": "ACLs are S3/VPC-network constructs — they cannot restrict IAM actions or service access org-wide.", "B": "Security groups are EC2 network controls — cannot enforce IAM-level access restrictions across accounts.", "C": "Cross-account roles in every account require per-account maintenance — fails the single-point-of-control requirement and doesn't scale.", "D": "SCPs attached to root OU apply to all accounts and OUs in the org; single place to maintain, hierarchically enforced, cannot be overridden by member accounts.", "_summary": "SCPs on root OU = org-wide permission guardrails from one place"}, "166": {"A": "Presigned URLs grant time-limited access to S3 objects — adds complexity, doesn't cache or accelerate global delivery.", "B": "Cross-region replication duplicates S3 objects to other regions but provides no CDN caching or edge serving — high cost, low latency benefit.", "C": "Route 53 geoproximity routes DNS to the nearest region but doesn't cache content — users still fetch from S3 origin each time.", "D": "CloudFront caches static content at 400+ edge locations globally, reduces S3 origin load, handles millions of requests with low latency.", "_summary": "CloudFront CDN = global static content delivery at scale from S3"}, "164": {"A": "Self-managed Redis on EC2 adds operational overhead — provisioning, patching, HA setup — violates operational efficiency.", "B": "Kinesis targets high-throughput streaming analytics; default retention is 24h (max 7 days), lacks native DLQ semantics for failed-message isolation.", "C": "SQS supports up to 14-day message retention (covers 2-day processing window), decouples sender/processor, and DLQ captures failed messages without blocking the main queue.", "D": "SNS is push-based fan-out — it does not persist or retry messages, so failed processing causes permanent message loss.", "_summary": "SQS + DLQ = managed async decoupling with failure isolation"}, "163": {"A": "ECS Fargate = serverless container orchestration; no EC2 fleet to manage, built-in HA across AZs, target tracking handles scale automatically — lowest operational overhead.", "B": "ECS EC2 launch type requires managing the underlying EC2 instances (patching, capacity) — more overhead than Fargate for same functionality.", "C": "Self-hosted container registry on EC2 plus manual EC2 spreading = high operational overhead, no managed orchestration.", "D": "AMI-based EC2 Auto Scaling is not container orchestration — requires embedding container runtime in AMI, adds complexity, and loses container portability benefits.", "_summary": "ECS Fargate = serverless containers, HA, auto-scale, minimal ops"}, "162": {"A": "FSx for Lustre is a POSIX-compliant parallel file system built for Linux HPC; native S3 integration lets it import/export datasets to S3 as persistent storage — exact fit.", "B": "FSx for Windows File Server uses SMB/NTFS — incompatible with Linux HPC workloads and Lustre-style parallel access patterns.", "C": "S3 Glacier is archival (retrieval hours/days) — unusable as active processing storage; EBS cannot be attached to hundreds of instances simultaneously.", "D": "EBS volumes are single-instance block storage by design (Multi-Attach only for io1/io2 with cluster-aware filesystems) — cannot serve hundreds of Spot instances concurrently.", "_summary": "FSx for Lustre + S3 = HPC parallel FS with durable persistent backend"}, "161": {"A": "Multiple EC2 instances require fleet management (patching, scaling policy, SSH access) — higher operational overhead than serverless alternatives.", "B": "S3 event notification triggers Lambda per-object as documents arrive; Lambda scales to thousands of concurrent executions automatically; Aurora is managed relational DB — fully serverless, zero fleet management.", "C": "EBS Multi-Attach is limited to io1/io2 volumes with cluster-aware filesystems — not a general shared storage solution; EC2 fleet still adds operational burden.", "D": "SQS + ECS EC2 launch type still requires managing underlying EC2 capacity — more overhead than Lambda; EC2 launch type adds scaling lag.", "_summary": "S3 trigger → Lambda → Aurora = serverless pipeline, scales to demand"}, "611": {"A": "Kinesis Data Streams buffers incoming records durably; Lambda consumers process asynchronously — decouples ingestion from processing, absorbs traffic spikes without dropping requests.", "B": "API Gateway usage plans add quota/throttling — this limits the vendor further (more 429s/503s), it does not increase processing capacity or buffer spikes.", "C": "SNS is push-only fan-out with no durable buffering; spikes still overwhelm downstream EC2s; Auto Scaling helps eventually but has launch lag and doesn't prevent in-burst 503s.", "D": "Repackaging as ECS EC2 containers still has the same compute scaling lag problem; it doesn't decouple ingestion from processing or buffer bursts.", "_summary": "Kinesis + Lambda = durable ingestion buffer that absorbs traffic spikes"}, "610": {"A": "Interface VPC endpoint for EC2 does not exist as a service; also Site-to-Site VPN traverses public internet, violating compliance.", "B": "Gateway VPC endpoint keeps EC2-to-S3 traffic inside the AWS backbone (no public internet). Direct Connect provides a dedicated private link from on-prem to VPC. Both requirements satisfied.", "C": "Transit Gateway connects VPCs/networks together, not VPCs to S3 buckets directly. VPN still routes over public internet.", "D": "NAT gateways route S3-bound traffic over public internet, directly violating the compliance requirement.", "_summary": "Gateway VPC endpoint = private S3 access; Direct Connect = private on-prem link"}, "696": {"A": "ACM certificates are for TLS/SSL on endpoints, not for encrypting data at rest in S3. Wrong service.", "B": "Separate KMS keys per customer is correct, but denying in the S3 bucket policy is insufficient — the KMS key policy still governs who can call kms:Decrypt; a bucket policy deny cannot override KMS access.", "C": "KMS key policy is authoritative for key usage. Denying all principals except the customer IAM role inside each KMS key policy means even the AWS account root and company employees cannot decrypt. Per-customer key = per-customer isolation.", "D": "ACM certificates cannot encrypt S3 data at rest. Public certificate policies do not control S3 data access.", "_summary": "KMS key policy (not S3 bucket policy) is the authoritative gate for decryption; per-customer key = true isolation"}, "974": {"A": "CloudFront requires ACM certificates provisioned in us-east-1 regardless of origin region. Correct.", "B": "CloudFront only accepts ACM certs from us-east-1; a eu-west-1 cert cannot be attached to a CloudFront distribution.", "C": "S3 Transfer Acceleration enables fast direct uploads bypassing CloudFront entirely — does not satisfy the CloudFront upload path requirement.", "D": "Origin Access Control (OAC) lets CloudFront authenticate to S3, enabling S3 to accept PUT/POST from CloudFront and block direct uploads. Correct.", "E": "S3 static website endpoints do not support HTTPS and cannot be used with OAC; object uploads via CloudFront are not supported through a website endpoint.", "_summary": "CloudFront cert must be in us-east-1; OAC enables authenticated uploads from CloudFront to S3"}, "953": {"A": "Source images used twice/year → Deep Archive (lowest cost, batch retrieval acceptable). Premium AI images need instant access → Standard. Non-premium every 6 hours → Standard-IA (infrequent enough, retrieval delay tolerable). Best cost fit.", "B": "Glacier Flexible Retrieval for premium AI images fails — retrieval takes minutes to hours; premium users require immediate downloads.", "C": "One Zone-IA for irreplaceable source training data risks permanent loss if that AZ fails; durability trade-off not justified.", "D": "One Zone-IA durability risk for source images plus Glacier for all AI images breaks the premium anytime-access requirement.", "_summary": "Access frequency drives tier: twice/year = Deep Archive; anytime = Standard; every 6h = Standard-IA"}, "700": {"A": "With Global Accelerator as public-facing entry, internal NLBs work as regional endpoints. NLBs natively support TCP and UDP, meeting the protocol requirement.", "B": "ALBs are Layer 7 (HTTP/HTTPS only) and do not support UDP. Fails the TCP+UDP requirement.", "C": "Global Accelerator provides static anycast IPs, routes users to the nearest healthy regional endpoint over the AWS backbone, and supports TCP/UDP. Directly addresses latency and availability.", "D": "Route 53 geolocation routing relies on DNS TTL-based steering — slower failover and higher latency than Global Accelerator anycast.", "E": "CloudFront handles HTTP/HTTPS only, not raw TCP/UDP.", "_summary": "Global Accelerator (anycast, TCP/UDP) + NLBs (TCP/UDP support) = low-latency HA for non-HTTP protocols"}, "941": {"A": "Attaching policy to node IAM role shares permissions across all pods on that node — not granular, violates IRSA least-privilege intent.", "B": "Kubernetes network policies control pod networking traffic, not AWS IAM permissions on AWS services.", "C": "IRSA maps a distinct IAM role to each individual service account; modifying a single cluster-level IAM role defeats per-SA granularity.", "D": "Annotating a Kubernetes service account with the IAM role ARN is the core IRSA mechanism — the kubelet injects a projected token the pod uses to assume that specific role.", "E": "The IAM role trust policy must reference the EKS OIDC provider so AWS STS can validate the projected service account token and allow role assumption. Required prerequisite.", "_summary": "IRSA requires OIDC trust relationship on IAM role (E) + service account annotation with role ARN (D)"}, "249": {"A": "Storage Gateway volume gateway presents iSCSI block storage, not SMB file shares. Wrong gateway type.", "B": "Tape gateway emulates virtual tape libraries for backup/archival. No SMB file sharing.", "C": "Self-managed EC2 Windows file server is not fully managed — OS patching, HA, and backups are customer responsibility.", "D": "FSx for Windows File Server is fully managed, natively supports SMB protocol with AD integration, DFS, and Windows ACLs. Correct.", "_summary": "FSx for Windows File Server = fully managed native SMB; volume/tape gateways serve different protocols/use cases"}, "137": {"A": "Forwarding to all org users violates the 'limited to account administrators' requirement and creates noise.", "B": "Distribution list for root email ensures admins receive root-level alerts. Organizations alternate contacts (billing, security, operations) add additional admin-targeted notification paths without credential sharing. Meets both requirements.", "C": "Single administrator = single point of failure, same miss-risk as the original problem.", "D": "AWS requires a unique email address per account; sharing one root email across all accounts is not possible.", "_summary": "Root email as admin distribution list + Organizations alternate contacts = admin-scoped redundant notification coverage"}, "1006": {"A": "Changing to instance-type target group can help SSM automation documents interoperate with ALB deregistration, but the AWSEC2-PatchLoadBalancerInstance document supports both types — not the root fix.", "B": "Errors are occurring; the existing document is not optimized for this scenario and ignores the deregistration requirement entirely.", "C": "AWSEC2-PatchLoadBalancerInstance is an AWS-provided Automation document purpose-built to deregister instances from an ALB, apply patches, then re-register — directly resolves the errors.", "D": "Maintenance Windows provides the scheduling and execution framework to orchestrate removal-from-service and patching steps automatically, preventing manual timing errors.", "E": "State Manager enforces desired configuration continuously, not event-driven patch workflows; ALB health checks re-route traffic but do not safely drain/deregister instances before patching.", "_summary": "AWSEC2-PatchLoadBalancerInstance doc + Maintenance Windows = safe deregister-patch-reregister cycle"}, "150": {"A": "Composite alarms combine multiple alarms with AND/OR logic — alarm only fires when BOTH CPU>50% AND high read IOPS are simultaneously in ALARM, eliminating single-metric false positives.", "B": "Dashboards are visualization only; they require human observation and cannot send automated alerts or reduce false alarms.", "C": "Synthetics canaries test application endpoints synthetically (HTTP checks), not infrastructure metrics like CPU or disk IOPS.", "D": "A single CloudWatch alarm cannot natively express AND logic across two independent metrics; metric math can combine values but cannot enforce simultaneous threshold breach semantics cleanly.", "_summary": "Composite alarms apply AND logic across CPU + disk IOPS to eliminate single-metric false positives"}, "911": {"A": "EMR is a big-data cluster framework — massive overkill and continuous cost for 150 photo/day thumbnail generation; polling every minute adds unnecessary latency and waste.", "B": "Always-on EC2 incurs 24/7 compute costs regardless of upload activity; polling every minute still lags real-time uploads and wastes resources for a low-volume workload.", "C": "S3 event notification triggers Lambda immediately on each upload; Lambda is pay-per-invocation with no idle cost — ideal for 150 events/day, event-driven, and operationally simple.", "D": "S3 Storage Lens is an analytics and metrics service for bucket-level insights; it cannot trigger Lambda on individual object uploads.", "_summary": "S3 event notification + Lambda = event-driven, zero-idle-cost thumbnail generation"}, "884": {"A": "Web tier must accept HTTPS traffic originating from the ALB; referencing the ALB security group (not a CIDR) is the correct, least-privilege approach.", "B": "Outbound to 0.0.0.0/0 from the web tier bypasses the private-subnet isolation goal; outbound should target the application tier SG specifically.", "C": "Database tier only needs to accept SQL Server port (1433) from the application tier SG — correct least-privilege rule for the DB layer.", "D": "Database tier has no reason to initiate outbound connections to the web tier; this rule inverts the traffic flow and violates least-privilege.", "E": "Application tier receives HTTPS calls from the web tier; allowing inbound from the web tier SG is the correct scoped rule.", "F": "Application tier sends queries to the DB tier, not back to the web tier; outbound SQL Server traffic should target the DB SG, not the web SG.", "_summary": "Three-tier SG rules: ALB→Web (A), Web→App (E), App→DB (C) — each inbound rule references upstream tier's SG"}, "945": {"A": "NLB with interface VPC endpoints provides connectivity but lacks transparent bump-in-the-wire inspection; traffic is load-balanced to targets, not invisibly redirected through an appliance.", "B": "ALB operates at Layer 7 and lives in application accounts — it cannot centralize inspection in the networking account or handle non-HTTP protocols transparently.", "C": "GWLB is purpose-built for transparent network appliance insertion; GWLB endpoints (PrivateLink-based) in application accounts redirect traffic to the GWLB in the networking account, which forwards to the appliance and back — the canonical centralized inspection pattern.", "D": "An interface VPC endpoint alone connects to a PrivateLink service but does not provide transparent inspection; the full GWLB architecture (option C) is required for that.", "_summary": "GWLB + GWLB endpoints = transparent centralized security appliance inspection across accounts"}, "740": {"A": "S3 Inventory reports can filter by encryption status to list unencrypted objects; S3 Batch Operations natively supports SSE-C re-encryption at scale; S3 default encryption with SSE-C covers all future uploads — complete solution.", "B": "Storage Lens provides aggregate analytics, not a per-object encryption inventory; SSE-KMS uses AWS-managed or CMK keys, not customer-provided keys (SSE-C).", "C": "AWS usage reports are billing/cost data, not per-object encryption metadata; AWS Batch is general compute, not an S3 object operation service; SSE-KMS ≠ SSE-C.", "D": "AWS usage reports cannot enumerate unencrypted S3 objects; setting default encryption only protects future uploads, leaving existing unencrypted objects untouched.", "_summary": "S3 Inventory (filter unencrypted) → Batch Operations (SSE-C) → default encryption (SSE-C) covers past and future"}, "715": {"A": "AWS Budgets natively supports Savings Plans coverage budgets with configurable percentage thresholds and email/SNS alerts — no custom code, managed service, operationally simplest.", "B": "Custom Lambda + SES requires writing, deploying, and maintaining code to pull coverage data and send emails — significantly more operational overhead than a native Budgets alert.", "C": "Budgets Reports deliver scheduled snapshots of budget data via email but are not threshold-triggered; they will not fire specifically when coverage drops below a threshold.", "D": "Savings Plans alert subscriptions exist but are limited in scope and configurability; AWS Budgets provides richer coverage-threshold alerting with more notification options.", "_summary": "AWS Budgets coverage threshold alert = zero-code, native Savings Plans monitoring"}, "711": {"A": "Adding reader nodes is useful, but the EventBridge+Lambda portion only logs state change events — it contributes nothing to scalability or reducing timeouts under load.", "B": "Zero-downtime restart (ZDR) prevents engine-version-upgrade restarts from causing downtime; it does not address read/write saturation or connection timeout issues under heavy load.", "C": "Additional Aurora reader instances absorb read load; RDS Proxy pools and multiplexes database connections, directly preventing the connection exhaustion that causes timeouts during traffic spikes — least downtime because no primary engine change is required.", "D": "Replicating to ElastiCache via DMS is complex, has replication lag, and write-around caching doesn't reduce write pressure on Aurora; operational complexity is high with no guarantee of resolving connection timeouts.", "_summary": "Aurora readers + RDS Proxy connection pooling = read scale-out + timeout elimination with no downtime"}, "993": {"A": "Auto Scaling group manages instance count/health but has no effect on data transfer pricing between instances.", "B": "Same Region reduces cross-region egress costs but EC2-to-EC2 traffic crossing AZs still incurs $0.01/GB each way.", "C": "EC2-to-EC2 data transfer within the same AZ is free; this eliminates cross-AZ transfer charges entirely, the dominant cost for inter-instance batch traffic.", "D": "Multiple AZs guarantees cross-AZ transfer charges on every byte moved between instances.", "_summary": "intra-AZ EC2 traffic is free; cross-AZ is not"}, "436": {"A": "Reserved pricing cuts DB instance cost ~40-72% vs on-demand, and vertically scaling the single instance (scale-up) handles more workload without adding new infrastructure — satisfies both constraints.", "B": "Multi-AZ adds a standby for HA/failover, not for throughput; it doubles instance cost without improving performance.", "C": "Adding a second instance contradicts 'without adding infrastructure'; also reserved pricing doesn't justify the extra resource.", "D": "On-demand is more expensive than reserved; does nothing to handle the increased workload.", "_summary": "vertical scale-up + reserved pricing = more capacity, lower cost, no new infra"}, "303": {"A": "EC2 Auto Scaling targets EC2 instances, not Fargate tasks; Fargate has no underlying EC2 fleet to scale.", "B": "Custom Lambda-based scaling is non-standard and overly complex; Application Auto Scaling already provides this natively.", "C": "EC2 Auto Scaling simple scaling policies apply to EC2, not ECS Fargate services.", "D": "AWS Application Auto Scaling is the correct service for ECS Fargate task scaling; target tracking policies automatically adjust task count based on CPU/memory metrics without over-provisioning.", "_summary": "Fargate task scaling = Application Auto Scaling, not EC2 Auto Scaling"}, "966": {"A": "Interface VPC endpoints restrict network path to AWS services but cannot enforce per-team IAM boundaries or block IMDSv2 access on EC2 instances.", "B": "EMR runtime roles let each submitted job assume a distinct IAM role scoped to that team's permissions; they also bypass EC2 instance profile credentials (and thus IMDSv2) for workload access — exactly what's needed.", "C": "A single EC2 instance profile applies to all jobs on the cluster equally; no per-team isolation, and workloads can still reach IMDSv2.", "D": "Setting EnableApplicationScopedIAMRole=false disables application-level role isolation, which is the opposite of the requirement.", "_summary": "EMR runtime roles = per-job IAM isolation + IMDSv2 bypass for workloads"}, "954": {"A": "Lambda cannot hold 1 GB model data in memory persistently across invocations; cold starts reload from S3 each time, making latency unpredictable; NLB cannot auto-scale Lambda functions.", "B": "ALB targets ECS synchronously; the API is asynchronous — no queue buffers burst batches, so traffic spikes hit ECS directly and slow scale-out causes dropped requests.", "C": "Lambda vCPUs cannot be manually scaled; concurrency is the knob, not vCPUs. More critically, Lambda's ephemeral execution model means 1 GB model reload on every cold start, which is cost-prohibitive and slow.", "D": "SQS decouples asynchronous requests; ECS containers load the 1 GB model once at startup and keep it in memory; Application Auto Scaling on queue depth scales both cluster capacity and service task count — handles bursts and scales to zero during idle periods.", "_summary": "async = SQS; stateful 1 GB in-memory model = ECS containers, not Lambda"}, "950": {"A": "Direct Connect provides private connectivity but no encryption by default; traffic is not encrypted at the network or session layer without adding VPN on top.", "B": "IAM IP-based restrictions are identity controls, not network-layer encryption; they do not establish an encrypted tunnel between the corporate network and VPC.", "C": "Site-to-Site VPN uses IPsec (network layer) for encryption in transit; route tables + security groups + NACLs provide granular security controls preventing unrestricted access — meets all stated requirements.", "D": "Transit Gateway alone provides routing but no encryption; it would need a VPN attachment to encrypt traffic, making it more complex without adding value over direct Site-to-Site VPN.", "_summary": "VPN = IPsec network-layer encryption + SG/NACL security controls"}, "934": {"A": "FSx for NetApp ONTAP natively supports both NFS (v3/v4) and SMB (including cross-protocol access to the same files), and supports Multi-AZ deployment for AZ-level redundancy — satisfies every requirement.", "B": "EC2-hosted file servers are not a managed AWS storage service and require the company to manage OS, patching, and HA themselves.", "C": "FSx for ONTAP alone handles both protocols; adding FSx for Lustre is unnecessary and Lustre does not support SMB.", "D": "S3 File Gateway exposes S3 via NFS/SMB but does not provide native cross-protocol file sharing semantics and is not designed as an AZ-redundant managed file server replacement.", "_summary": "FSx for NetApp ONTAP = only AWS managed storage with simultaneous NFS+SMB on same data"}, "919": {"A": "A single io1 volume is hard-capped at 64,000 IOPS even on Nitro instances; LVM striping across multiple io1 volumes aggregates their IOPS, breaking through the per-volume ceiling to match on-prem performance.", "B": "64,000 IOPS is the absolute maximum for a single io1 volume; AWS does not allow provisioning beyond this limit on one volume.", "C": "io1 IOPS are provisioned independently of size; doubling volume size without increasing provisioned IOPS does nothing for throughput.", "D": "Switching to a storage-optimized instance changes to local NVMe (non-persistent), which is inappropriate for a database; the bottleneck is per-volume IOPS cap, not instance type.", "_summary": "io1 single-volume IOPS cap = 64K; LVM stripe multiple volumes to exceed it"}, "906": {"A": "Denying snapshot deletion via IAM prevents future accidents but blocks legitimate cleanup entirely and requires ongoing IAM policy maintenance — doesn't restore accidentally deleted data.", "B": "Cross-region copy adds redundancy but doesn't protect against deletion of the original; the copy persists but this adds S3 storage cost and scripting complexity.", "C": "Recycle Bin retention rules are the native AWS solution for exactly this scenario — deleted snapshots land in Recycle Bin for the retention window and can be recovered; zero code, one console rule.", "D": "EBS snapshots are already backed by S3 internally; copying to S3 Standard-IA requires custom scripting/Lambda and doesn't integrate with snapshot restore workflows.", "_summary": "EBS Recycle Bin: native soft-delete for snapshots, least effort"}, "84": {"A": "Spot Instances can be interrupted with 2-minute notice — unacceptable for 24/7 production SQL Server; Reserved for dev/test wastes money on hours where instances are stopped.", "B": "Reserved Instances are optimal for 24/7 predictable production workloads (up to 72% savings); On-Demand for dev/test means you only pay for actual running hours after automation stops idle instances — no wasted reservation commitment.", "C": "Spot Blocks were deprecated by AWS in 2021 and no longer purchasable; production on interruptible compute is architecturally unsound regardless.", "D": "On-Demand for production forfeits Reserved pricing on a 24/7 workload — highest cost option for production; Spot Blocks also deprecated.", "_summary": "Reserved for 24/7 prod + On-Demand for stoppable dev/test = cost-optimal split"}, "130": {"A": "Simple scaling reacts to a single threshold breach and adds/removes fixed capacity; it overshoots and undershoots, not suited for maintaining a specific utilization target.", "B": "Target tracking scales the group continuously to keep CPU at the specified target (40%); ASG automatically calculates required capacity and adjusts — purpose-built for this use case.", "C": "Lambda updating desired capacity is a custom re-implementation of target tracking with more operational overhead and latency.", "D": "Scheduled scaling requires knowing the load pattern in advance; it can't react to unpredictable traffic spikes to maintain 40% CPU.", "_summary": "Target tracking policy: native ASG feature to maintain specific CPU utilization"}, "712": {"A": "Outbound endpoint enables EC2 instances inside the VPC to forward DNS queries for on-premises domain names to on-premises DNS resolvers — correct direction (VPC → on-prem).", "B": "Inbound endpoint does the reverse: lets on-premises resolvers query Route 53 private hosted zones; doesn't help VPC instances resolve on-premises names.", "C": "Private hosted zone would require manually creating and maintaining records for every on-premises service — doesn't dynamically reflect on-premises DNS state.", "D": "Public hosted zone exposes service records on the internet, violating the security requirement.", "_summary": "Outbound Resolver endpoint + forwarding rule: VPC-to-on-premises private DNS resolution"}, "260": {"A": "AD Connector bridges to AD but mapping AD groups to IAM groups doesn't control FSx file/folder access — FSx uses NTFS ACLs enforced via AD, not IAM.", "B": "Resource tags + IAM groups control AWS API access, not SMB file-system permissions; NTFS ACL enforcement is entirely outside IAM scope.", "C": "IAM service-linked roles govern what FSx can do in the AWS control plane (e.g., create ENIs), not who can read/write files.", "D": "FSx for Windows File Server natively supports joining to an existing on-premises AD domain; once joined, existing AD users/groups and NTFS permissions control SMB access with no changes to the AD structure.", "_summary": "FSx joins on-premises AD directly; NTFS ACLs enforce existing AD group permissions"}, "511": {"A": "Provisioned Aurora runs 24/7 and bills continuously regardless of use; dev environments active only 4 hours/day pay for 20 idle hours — inefficient.", "B": "RDS Single-AZ runs continuously too; manual stop/start is possible but adds operational overhead and instances restart automatically after 7 days.", "C": "Aurora Serverless On-Demand (Serverless v1 can pause to zero; v2 scales to minimum ACUs) charges only for actual compute consumed; idle dev environments incur minimal or no cost — most cost-effective for 50%-utilization workloads.", "D": "S3 Object Select is a query feature on S3 objects, not a relational database engine; cannot run a PostgreSQL schema.", "_summary": "Aurora Serverless On-Demand: pay-per-use billing ideal for intermittent dev databases"}, "811": {"A": "Public RDS endpoint routes traffic over the internet — explicitly violates the no-internet-exposure requirement.", "B": "Grafana workspace inside a VPC with a private RDS endpoint keeps all data traffic on the AWS private network; no internet path exists between Grafana and RDS.", "C": "PrivateLink exposes services from one VPC/account to another via endpoint, but Managed Grafana without a VPC attachment cannot use PrivateLink to reach a private RDS instance — architecturally incorrect.", "D": "Even with Grafana in a VPC, a public RDS endpoint still routes traffic through the internet; the VPC placement of Grafana alone doesn't secure the RDS connection.", "_summary": "Managed Grafana in VPC + private RDS endpoint: fully private data path"}, "75": {"A": "API Gateway + Lambda eliminates EC2 management; SQS decouples tiers and acts as a buffer so no transactions are dropped when a downstream tier is overloaded — serverless, fully managed, most operationally efficient.", "B": "Right-sizing EC2 addresses capacity but not the drop problem; when the tier hits its new ceiling transactions still drop — treats symptom not cause.", "C": "SNS is push-based pub/sub with no buffering; if a subscriber is overloaded messages are dropped or lost — does not solve the dropped-transaction problem.", "D": "SQS on EC2 Auto Scaling groups does decouple tiers correctly, but managing EC2 instances, patching, and scaling policies adds operational overhead compared to the serverless option A.", "_summary": "SQS as inter-tier buffer prevents dropped transactions; Lambda+API GW eliminates EC2 ops overhead"}, "79": {"A": "On-demand scales instantly with zero cost when idle — perfect for unpredictable spikes on a table unused most mornings.", "B": "GSI affects query patterns, not capacity scaling or cost for unpredictable traffic.", "C": "Auto scaling has a lag of several minutes — cannot react fast enough to sudden spikes.", "D": "Global tables add multi-region replication cost; irrelevant to the single-region capacity/cost problem.", "_summary": "On-demand mode = instant scale + pay-per-request; beats provisioned+auto scaling when traffic is bursty and idle periods are long"}, "520": {"A": "Provisioned+auto scaling lags on sudden changes; for truly unpredictable traffic on-demand avoids both over-provisioning cost and scale-lag risk.", "B": "On-demand+Standard is correct: instant scaling, Standard class optimized for moderate-to-high request rates (lower per-request price than Standard-IA).", "C": "Standard-IA has lower storage cost but higher per-request cost — worse for moderate-to-high throughput, more expensive overall.", "D": "On-demand is correct but Standard-IA charges more per read/write operation, making it costlier than Standard at high throughput.", "_summary": "Standard-IA saves on storage not on I/O — for high-throughput on-demand, Standard class is cheaper"}, "183": {"A": "Fully serverless stack (Lambda+API GW+S3+DynamoDB on-demand+CloudFront) — zero patching, instant scaling for both compute and DB reads/writes.", "B": "Aurora auto scaling reacts in minutes; DynamoDB on-demand scales in seconds — Aurora fails the 'as quickly as possible' read/write scaling requirement.", "C": "EC2 requires OS patching; provisioned DynamoDB write capacity doesn't scale instantly.", "D": "EC2 requires OS patching; fails the no-maintenance requirement.", "_summary": "DynamoDB on-demand + serverless compute = fastest possible read/write scaling with zero server maintenance"}, "697": {"A": "ASG has no internet-facing DNS endpoint; instances remain unreachable from internet regardless of Auto Scaling.", "B": "Internet-facing ALB sits in public subnet, accepts inbound traffic on 80/443, forwards to private-subnet targets — standard inbound pattern for private instances.", "C": "NAT gateway provides outbound internet access for private instances, not inbound; also NAT in a private subnet with EIP doesn't create an inbound path.", "D": "Private subnet instances have no public IP assigned by default; security group rules are irrelevant when there's no route from internet to the instance.", "_summary": "Private subnet + public ALB = correct inbound pattern; NAT is outbound only"}, "93": {"A": "mysqldump reads the entire production DB, causing the same heavy-read latency that already impacts users.", "B": "Aurora Fast Clone uses copy-on-write — creates staging DB almost instantly with no I/O impact on production; staging is immediately usable.", "C": "RDS Multi-AZ standby is for failover only, not readable or usable as a staging environment.", "D": "mysqldump on RDS still causes the same production latency problem; no improvement.", "_summary": "Aurora database cloning is near-instant and copy-on-write — zero production impact, staging ready immediately"}, "1013": {"A": "Scheduled Reserved Instances cover a fixed recurring time window (e.g., 12h every Sunday) at discount; Standard RIs match predictable 24/7 Mon-Sat usage optimally.", "B": "Convertible RIs are billed for full 1- or 3-year term regardless of when instances run — paying for a full week of capacity for 12h/week Sunday use is wasteful.", "C": "Spot can be interrupted; requirement explicitly states Sunday instances cannot tolerate interruptions.", "D": "Spot violates the no-interruption requirement; Convertible gives less discount than Standard for constant predictable usage.", "_summary": "Scheduled RIs fit fixed recurring partial-week windows; Standard RIs are cheapest for constant 24/7 workloads"}, "1010": {"A": "AWS SCT converts database schemas — not used for VM lift-and-shift migrations.", "B": "AWS Application Migration Service (MGN) is the primary lift-and-shift tool; Replication Agent installed on source VMs starts continuous block-level replication.", "C": "After initial replication completes, launching test instances for acceptance testing is the standard MGN workflow step before cutover.", "D": "Stopping source VMs and launching the cutover instance is the final MGN step that completes the migration.", "E": "App2Container containerizes existing apps — not a VM migration tool.", "F": "DMS migrates databases, not virtual machines.", "_summary": "MGN workflow: install agent → replicate → test → cutover; SCT/DMS/A2C are for databases and containers, not VM lift-and-shift"}, "999": {"A": "Redshift is an OLAP data warehouse — over-engineered for a product catalog; adds cost and operational complexity without addressing cache-miss-driven CPU spikes.", "B": "ElastiCache Redis with lazy loading caches catalog query results; repeated searches hit cache instead of DB, directly eliminating the CPU spike on RDS.", "C": "Adding EC2 web servers increases concurrent DB connections and worsens DB CPU — the bottleneck is at the database layer, not the web tier.", "D": "Multi-AZ standby is not readable; throttling queries degrades UX without solving root cause; neither action reduces DB CPU from read-heavy catalog queries.", "_summary": "Cache infrequently-changing read-heavy data in ElastiCache to offload RDS CPU — lazy loading is the correct population strategy"}, "994": {"A": "Secrets Manager has native RDS/Aurora rotation built-in — create secret, attach to cluster, set 14-day schedule, done. Zero custom Lambda needed.", "B": "Parameter Store SecureString stores creds securely but has no built-in rotation engine; requires writing and maintaining a custom Lambda rotator.", "C": "EFS-backed credential file plus Lambda rotator is high-ops: mount management, file permissions, custom rotation code — not fit-for-purpose.", "D": "S3 credential file plus Lambda rotator works but forces regular file downloads and custom rotation code; far more moving parts than Secrets Manager.", "_summary": "Secrets Manager = purpose-built credential rotation for RDS/Aurora with native scheduler"}, "909": {"A": "Cross-Region replica solves the read-offload problem but adds cross-region data transfer cost — unnecessary when reports run in same region.", "B": "Multi-AZ standby is a hot-failover replica only; it is NOT readable. Routing reports there is not supported.", "C": "DMS logical replication adds significant cost and complexity for a use case a simple read replica handles natively.", "D": "Same-region read replica offloads reporting queries from the primary at lowest possible cost; no extra data transfer fees, minimal setup.", "_summary": "RDS read replica in same region = cheapest way to offload read-heavy reporting workloads"}, "969": {"A": "App2Container automates containerization of existing ASP.NET/Linux apps; ECS on Fargate removes all EC2 and cluster node management — minimum ops overhead.", "B": "ECS on EC2 requires managing EC2 instances, patching, capacity — more operational burden than Fargate for same container workload.", "C": "App Runner is a self-contained managed container platform; it does not deploy into ECS Fargate. Premise is architecturally wrong.", "D": "App Runner does not deploy into EKS; it runs its own managed runtime. EKS on EC2 also adds heavy cluster management overhead.", "_summary": "App2Container + ECS Fargate = modernize-and-containerize path with least ops overhead"}, "963": {"A": "SNS is pub/sub; it does not durably store messages — if no subscriber processes immediately, jobs are lost. CPU scaling also imprecise for queue-depth workloads.", "B": "SQS provides durable job storage, but network usage is a poor proxy for queue depth and doesn't reflect actual processing backlog.", "C": "SQS durably stores jobs; Auto Scaling on ApproximateNumberOfMessagesVisible (queue depth) is the canonical AWS pattern for parallel, loosely-coupled processing.", "D": "SNS has no durable message retention. 'Number of messages published' is not an Auto Scaling metric — SNS topics don't expose queue-depth-style CloudWatch metrics.", "_summary": "SQS + ASG scaling on queue depth = standard loosely-coupled parallel processing pattern"}, "957": {"A": "VPN to each individual VPC bypasses Transit Gateway, negates its hub-spoke benefit, and doesn't guarantee single-digit latency.", "B": "A Direct Connect gateway associated with the Transit Gateway lets a single DX connection reach all attached VPCs — required for TGW-based DX integration.", "C": "Site-to-Site VPN over a DX gateway still uses IPsec tunneling; VPN latency is not deterministic and won't reliably achieve single-digit ms.", "D": "A physical Direct Connect connection with a transit VIF to a DX gateway provides the dedicated, low-latency private link required. This is the DX physical layer.", "E": "VPN to Transit Gateway provides connectivity but VPN encryption overhead and internet routing cannot guarantee single-digit latency.", "_summary": "Direct Connect (D) + DX gateway associated with TGW (B) = low-latency hybrid with Transit Gateway"}, "871": {"A": "Cognito handles serverless auth with low-latency login; Lambda@Edge runs authorization checks at CloudFront edge nodes globally; CloudFront delivers content worldwide. All serverless.", "B": "AD for auth requires managed directory infrastructure — not serverless; ALB is regional, not global like CloudFront.", "C": "S3 Transfer Acceleration optimizes large-file uploads, not web application delivery; Lambda (regional) for authorization adds latency vs Lambda@Edge.", "D": "AD is not serverless; Elastic Beanstalk is regional and not a global delivery mechanism.", "_summary": "Cognito + Lambda@Edge + CloudFront = serverless auth with global low-latency delivery"}, "92": {"A": "VPC gateway endpoint for S3 routes traffic through AWS private network without internet gateway, NAT, or public IPs — secure and free within same region.", "B": "Making S3 objects public destroys the security requirement; any actor on the internet could access the data.", "C": "Bucket policy scoped to the VPC (using aws:sourceVpc or VPC endpoint condition) enforces that only traffic from that VPC can read the bucket.", "D": "IAM user credentials embedded or copied to EC2 instances is an antipattern — credentials can be leaked; IAM roles are the correct approach.", "E": "NAT instance routes S3 traffic over the internet path, adding cost and attack surface; a gateway endpoint is better in every dimension.", "_summary": "VPC gateway endpoint + VPC-scoped bucket policy = private, credential-free S3 access from EC2"}, "951": {"A": "KMS manages cryptographic keys, not application credentials — you cannot store a username/password in KMS as a secret.", "B": "Local encrypted storage with a cron job is brittle, not cloud-managed, and creates operational burden for rotation.", "C": "Secrets Manager stores database credentials, natively integrates with RDS MySQL for automatic rotation via managed Lambda, and requires only an SDK call change in the app.", "D": "Parameter Store SecureString can store creds but has no built-in RDS rotation engine; 'rotation schedule in RDS using Parameter Store' is not a supported native feature.", "_summary": "Secrets Manager = purpose-built credential store with native RDS MySQL auto-rotation"}, "947": {"A": "Parameter Store lacks native automatic rotation for RDS credentials — requires custom Lambda rotation code, adding operational overhead.", "B": "Secrets Manager has built-in automatic rotation natively integrated with RDS PostgreSQL — zero custom code needed. Least operational overhead.", "C": "Lambda env var rotation requires writing and scheduling a custom rotation Lambda — high operational overhead.", "D": "KMS stores encryption keys, not credentials. Key rotation rotates key material, not the actual DB password — wrong service for credential storage.", "_summary": "Secrets Manager = native RDS credential rotation; Parameter Store requires DIY rotation"}, "940": {"A": "On-Demand RDS is full price; Compute Savings Plans cover EC2/Lambda/Fargate but not RDS — wrong product for RDS savings.", "B": "1yr No Upfront gives smallest discount tier; EC2 Instance Savings Plan 1yr No Upfront similarly minimal savings for long-running stable workloads.", "C": "1yr Partial Upfront better than B but 1yr term limits discount depth; long-running workloads justify longer commitment.", "D": "3yr All Upfront maximizes discount on both RDS Reserved Instances (~40%+ off) and EC2 Savings Plans — highest savings for stable long-running workloads.", "_summary": "Long-running = 3yr All Upfront; maximum commitment = maximum discount"}, "90": {"A": "Multi-AZ improves HA and failover, not read throughput — the script and dev tasks still compete on same primary instance.", "B": "Read replica offloads all SELECT queries to a separate instance — script hits replica, primary free for dev tasks. Least overhead: no code beyond connection string change.", "C": "Manual export by devs daily is high operational burden and doesn't solve the performance contention problem.", "D": "ElastiCache caches specific query results but requires cache invalidation logic, connection pooling changes, and doesn't fully separate read load — more overhead than a read replica.", "_summary": "Read replica = separate read endpoint; eliminates script vs dev contention with minimal ops"}, "89": {"A": "Versioning preserves all object versions. MFA Delete requires MFA token to permanently delete versions or suspend versioning — prevents accidental or unauthorized deletion at S3 level.", "B": "MFA on IAM login protects account access but once authenticated, user can still delete objects — doesn't protect at object level.", "C": "S3 Lifecycle policies apply to objects, not IAM users, and cannot deny specific actions based on calendar dates — technically invalid construct.", "D": "KMS encryption protects confidentiality, not durability. Revoking KMS key access prevents reading, not deleting — wrong control for this threat.", "_summary": "MFA Delete = requires second factor to permanently remove S3 object versions"}, "85": {"A": "S3 Object Lock enforces WORM (Write Once Read Many) at object level in Compliance mode — physically prevents deletion/modification for retention period. Meets regulatory immutability.", "B": "Lifecycle policies transition or expire objects — they do not prevent modification or deletion, opposite of requirement.", "C": "Versioning preserves history but ACL read-only is not immutable — bucket owner can override ACL and delete. Does not satisfy regulatory requirement.", "D": "EFS read-only mount is a client-side control — remounting read-write bypasses it. No storage-level immutability enforcement.", "_summary": "S3 Object Lock Compliance mode = true WORM; only correct immutability control"}, "927": {"A": "AWS Config tracks configuration compliance and drift — no DDoS detection capability and no proactive engagement feature.", "B": "WAF provides Layer 7 filtering and can rate-limit, but has no proactive engagement (no DRT access) and is not a managed DDoS solution by itself.", "C": "GuardDuty detects threats via logs/DNS/VPC flow — not DDoS-specific, no proactive engagement, and S3 access logs is not the right GuardDuty data source for this.", "D": "Shield Advanced includes 24/7 DDoS Response Team (DRT) proactive engagement, cost protection, and supports Route 53 + ALB as protected resources — exact match for requirement.", "_summary": "Shield Advanced = only AWS service with proactive DRT engagement for DDoS"}, "426": {"A": "DataSync efficiently migrates large on-prem file data to S3. CloudTrail data events log S3 object-level API calls (GetObject/PutObject/DeleteObject) = audit at all data levels. Correct combo.", "B": "Snowcone is a physical edge device suited for disconnected/remote scenarios, not standard on-prem migration. CloudTrail management events log control-plane only (bucket creation, policy) — misses data-level audit.", "C": "S3 Transfer Acceleration accelerates client uploads over internet, not a bulk migration tool for existing on-prem data. CloudTrail data events are correct but wrong migration method.", "D": "Storage Gateway provides ongoing hybrid connectivity, not a migration service. CloudTrail management events miss data-level audit — fails the 'all levels' requirement.", "_summary": "DataSync = migration tool; CloudTrail data events = object-level audit trail"}, "76": {"A": "DataSync is purpose-built for large S3 transfers but public internet is variable, unreliable, and insufficiently secure for sensitive data.", "B": "DataSync over Direct Connect gives dedicated private bandwidth — consistent throughput, no internet exposure, most reliable and secure for 10TB/day sensitive data. Correct answer.", "C": "DMS migrates relational databases — wrong tool for JSON files on a SAN filesystem.", "D": "DMS wrong tool regardless of network path; Direct Connect would be correct network but DMS cannot migrate filesystem data.", "_summary": "DataSync = file transfer tool; Direct Connect = private reliable network; together = most reliable secure transfer"}, "71": {"A": "Global tables replicate mutations in near-real-time — data corruption replicates too; solves region failure, not corruption.", "B": "PITR gives continuous, second-level restore points for up to 35 days; RPO 15 min and RTO 1 hour both satisfied. Correct.", "C": "Daily Glacier export gives 24-hour RPO at best; Glacier retrieval adds hours — fails both targets.", "D": "DynamoDB is not EBS-backed; EBS snapshots have no mechanism to capture or restore a DynamoDB table.", "_summary": "PITR is the only option that meets sub-hour RPO+RTO for DynamoDB data corruption"}, "913": {"A": "Shared role with full access violates least privilege on two counts: over-permissioned and non-isolated.", "B": "Bucket policy on VPC endpoint IP blocks network path, not function identity; Lambda VPC endpoint IPs are shared and don't distinguish individual functions.", "C": "One execution role per function, each scoped to only needed S3 actions — textbook least privilege. Correct.", "D": "S3 bucket policies grant access to IAM principals (roles/users), not Lambda function ARNs directly; function ARNs are not IAM principals.", "_summary": "Separate execution roles per Lambda = least-privilege identity-based isolation"}, "908": {"A": "SSM Agent + instance profile + Identity Center = no open ports, centralized federated access, full audit trail via Session Manager. Most secure. Correct.", "B": "Local IAM users per account instead of Identity Center — fragmented credential management, harder to revoke, no centralized SSO.", "C": "Open SSH port 22 expands attack surface; IP-allowlisting is weak compared to SSM; long-term SSH keys are a liability.", "D": "Bastion host adds infrastructure to manage and an exposed public entry point; local IAM users per account remain fragmented.", "_summary": "SSM Session Manager + IAM Identity Center eliminates SSH exposure and centralizes access management"}, "772": {"A": "ECS + Fargate: AWS manages the compute plane; per-service auto-scaling built in; zero EC2 overhead. Correct.", "B": "EKS + Fargate: Kubernetes control plane managed by AWS, compute via Fargate — no node group to patch or scale. Correct.", "C": "Lambda runs function code, not persistent Docker containers; API Gateway + Lambda is not a container hosting solution.", "D": "ECS + EC2 worker nodes: company must patch, scale, and maintain the EC2 fleet — added operational overhead.", "E": "EKS + EC2 worker nodes: same problem as D; node groups require lifecycle management.", "_summary": "Fargate (with ECS or EKS) removes EC2 infrastructure management while enabling per-service scaling"}, "765": {"A": "Instance profiles attach to EC2 instances; irrelevant to granting an external company cross-account SQS access.", "B": "IAM policies in the dev account govern identities within that account only; cannot directly authorize an external account's principals without a resource-based policy.", "C": "SQS resource-based access policy can explicitly name the external account's principal, enabling cross-account polling without role assumption. Correct.", "D": "SNS access policies govern SNS topics, not SQS queues; wrong service entirely.", "_summary": "SQS access (resource-based) policy is the direct mechanism for cross-account queue access"}, "749": {"A": "CloudFront distributions don't have NACLs — NACLs are VPC-subnet constructs; no such option exists on CloudFront.", "B": "WAF already sits in front of CloudFront; adding an IP match condition blocks the IP at the edge before it reaches the origin. Correct.", "C": "Traffic arrives at EC2 subnets sourced from ALB IPs, not the malicious IP; NACL on EC2 subnets won't see the original IP.", "D": "Security groups have no deny rules, only allows; also, traffic source at EC2 level is the ALB, not the external IP.", "_summary": "WAF IP match condition blocks at edge; downstream controls never see the original source IP through CloudFront+ALB"}, "746": {"A": "Enhanced networking (SR-IOV/ENA) cuts CPU overhead for packet processing, lowering latency and jitter on inter-node traffic. Correct.", "B": "Separate accounts adds no networking benefit; cross-account traffic still traverses the same physical fabric.", "C": "Cluster placement group packs instances onto low-latency, high-bandwidth hardware in the same AZ — directly minimizes inter-node RTT. Correct.", "D": "Additional ENIs provide more network paths but don't reduce latency between nodes.", "E": "EBS-optimized instances dedicate bandwidth to EBS I/O; no effect on inter-instance network latency.", "_summary": "Cluster placement group (physical proximity) + enhanced networking (SR-IOV) together achieve minimum inter-node latency"}, "780": {"A": "Cross-account IAM role with trust policy for vendor's role — vendor assumes role via STS, no long-term credentials, least privilege, fully auditable. Correct.", "B": "IAM user with password = long-term static credential; less secure and harder to rotate than role assumption.", "C": "IAM groups cannot contain principals from external accounts; cross-account group membership is not supported.", "D": "Permission boundary limits maximum permissions but still requires a long-term IAM user credential — not more secure than role assumption.", "_summary": "Cross-account role trust is the standard, credential-free mechanism for granting external AWS account access"}, "779": {"A": "OS-level read-only mount enforces nothing at IAM layer; EC2 instance can remount rw or use another client. Question requires IAM control.", "B": "EFS resource-based policy supports `elasticfilesystem:ClientWrite` deny. Attaching this denial to instance IAM roles via the EFS file system policy is the correct IAM-layer enforcement — centralized, cannot be bypassed by remounting.", "C": "Identity policies attach to IAM principals, not to EFS itself. Phrasing 'for the EFS file system' is wrong; you'd need to modify every EC2 role individually. Less centralized than resource policy on B.", "D": "POSIX permissions are OS-level, not IAM. Access points solve path/uid enforcement, not IAM write prevention.", "_summary": "EFS resource policy with ClientWrite deny = IAM-layer write protection"}, "900": {"A": "ECS Anywhere uses EXTERNAL launch type, runs on-premises VMs/bare-metal. Fargate handles cloud containers. Correct split for hybrid.", "B": "ALB operates at Layer 7, designed for HTTP/HTTPS. Correct choice when question specifies HTTP traffic.", "C": "NLB is Layer 4 (TCP/UDP). Technically works but not optimal for HTTP — ALB is the right answer when HTTP is specified.", "D": "Fargate is AWS-managed serverless compute; cannot run on-premises. Invalid for on-prem containers.", "E": "ECS Anywhere uses EXTERNAL launch type, not Fargate launch type, on-premises. Fargate cannot run off-AWS infrastructure.", "_summary": "ECS Anywhere (EXTERNAL) = on-prem; Fargate = cloud; ALB = HTTP LB"}, "899": {"A": "VPN tunnels don't provide inter-app-VPC connectivity; managing software VPN at 100+ scale is high overhead.", "B": "VPC peering not transitive — 100 apps need ~5000 peer connections for full mesh. Operationally unscalable.", "C": "Direct Connect is on-premises-to-AWS, not VPC-to-VPC routing. Wrong tool entirely.", "D": "Transit gateway is hub-and-spoke: attach each VPC once, all can route to each other and shared services. Adding VPC #101 = one attachment. Least overhead at scale.", "_summary": "Transit gateway = transitive hub; scales to 100s of VPCs with single attachment per VPC"}, "898": {"A": "Lake Formation + Glue requires defining crawlers, catalog, schemas, permissions — significant setup effort.", "B": "Lambda collecting CSVs requires writing code, scheduling, handling formats per source — development effort.", "C": "Amazon Security Lake is purpose-built: auto-ingests AWS sources (GuardDuty, CloudTrail, Security Hub) normalized to OCSF, stores in S3. Zero custom code. Least effort by design.", "D": "AWS DMS is a database migration tool, not a security data aggregator. Wrong service entirely.", "_summary": "Security Lake = zero-code centralized security data lake with native AWS source integration"}, "896": {"A": "Read replica can be promoted but lacks automated managed failover; replication lag may exceed 5-min RPO and promotion is manual.", "B": "Aurora Global Database replicates with <1s lag and managed failover automates promotion within RTO—meets RPO/RTO with minimal config. CORRECT.", "C": "'Cross-Region Replication' is not a distinct Aurora cluster feature; would require custom tooling and more config than Global Database.", "D": "DMS adds high operational overhead for continuous sync and adds complexity vs native Aurora replication.", "_summary": "Aurora Global Database + managed failover = native low-lag DR with automated promotion"}, "895": {"A": "Volume Gateway is block storage (iSCSI protocol), not SMB file shares; File Gateway supports SMB but this option names Volume Gateway.", "B": "Tape Gateway is for backup tape emulation to S3/Glacier—no SMB file access use case.", "C": "Self-managed EC2 Windows file server requires patching, OS maintenance, HA setup—highest admin overhead.", "D": "FSx for Windows File Server is fully managed native SMB; no EC2 to manage, built-in HA and backups. CORRECT.", "_summary": "FSx for Windows = fully managed SMB, zero OS overhead"}, "891": {"A": "Regional endpoints route over public internet, so public network congestion not eliminated; also requires app-side routing logic.", "B": "S3 MRAP doesn't have per-region global endpoints; active-passive means manual failover intervention—contradicts least-management goal.", "C": "'Cross-account' replication is wrong framing; regional endpoints still traverse public internet, no congestion mitigation.", "D": "MRAP single global endpoint routes traffic over AWS network (not public internet) to nearest bucket; CRR keeps buckets in sync; active-active with automatic failover. CORRECT.", "_summary": "S3 MRAP active-active routes over AWS backbone to nearest bucket, CRR syncs data"}, "886": {"A": "SCT converts database schema/objects, not application-level SQL queries—rewriting app queries is out of SCT scope.", "B": "Babelfish lets Aurora PostgreSQL accept T-SQL and SQL Server wire protocol, so apps connect unchanged. CORRECT.", "C": "SCT converts schema, DMS migrates data—standard two-tool migration path. CORRECT.", "D": "RDS Proxy handles connection pooling/resilience but does nothing for SQL Server-to-PostgreSQL dialect compatibility.", "E": "DMS migrates data rows, not application source code SQL; it cannot rewrite queries in app code.", "_summary": "Babelfish = T-SQL compatibility layer; SCT+DMS = schema+data migration"}, "724": {"A": "Memory-based scaling requires custom metric configuration and manual setup—more overhead than native Cluster Autoscaler.", "B": "Kubernetes Cluster Autoscaler watches for unschedulable pods and scales the underlying node group automatically—least admin overhead. CORRECT.", "C": "Custom Lambda solution requires building, testing, and maintaining scaling logic—high overhead.", "D": "EKS node groups already back onto ASGs, but ASG alone doesn't know about Kubernetes pod-scheduling pressure; Cluster Autoscaler is the bridge.", "_summary": "Cluster Autoscaler = native K8s node scaling triggered by unschedulable pods"}, "59": {"A": "Data Pipeline is batch-oriented and largely deprecated; EMR startup latency and batch model ill-suited for continuous 30TB/day clickstream.", "B": "EC2-based processing is undifferentiated heavy lifting—doesn't scale elegantly to 30TB/day clickstream without significant custom engineering.", "C": "CloudFront is a CDN for content delivery, not a clickstream ingestion mechanism; Lambda concurrency/timeout limits don't suit 30TB/day.", "D": "Kinesis Data Streams ingests real-time high-volume streams; Firehose delivers to S3 without custom code; Redshift analyzes at scale. CORRECT.", "_summary": "Kinesis Streams→Firehose→S3→Redshift = canonical streaming analytics pipeline"}, "57": {"A": "Comprehend is NLP/text analysis—cannot inspect image pixels for inappropriate visual content.", "B": "Rekognition Content Moderation API detects inappropriate images natively with confidence scores; Amazon A2I handles human review of low-confidence results—zero ML development needed. CORRECT.", "C": "SageMaker requires building, training, and deploying a custom model—significant development effort.", "D": "Custom Fargate ML model is maximum development effort and operational overhead.", "_summary": "Rekognition Content Moderation = managed inappropriate image detection, no model training"}, "305": {"A": "DataSync is a data-transfer/sync service, not a mountable SMB file share.", "B": "EC2 Windows file server requires managing OS, patches, HA—not fully managed.", "C": "FSx for Windows File Server is fully managed, natively supports SMB, no infrastructure to maintain. CORRECT.", "D": "S3 has no native SMB protocol support; mounting via third-party tools is not fully managed and adds complexity.", "_summary": "FSx for Windows = only fully managed AWS service with native SMB"}, "875": {"A": "NAT gateway routes traffic through AWS internet gateway to public S3 endpoints — data still traverses public internet, violates regulatory requirement.", "B": "Storage Gateway is a hybrid storage appliance for on-premises integration — wrong tool, adds cost and complexity.", "C": "Interface endpoint (PrivateLink) works but costs ~$0.01/hr per AZ plus per-GB data processing fees — functional but not most cost-effective.", "D": "Gateway endpoint is free, routes S3 traffic privately through AWS network via route table entry — meets regulatory requirement at zero extra cost.", "_summary": "S3 gateway endpoint = free private S3 access; interface endpoint costs money"}, "874": {"A": "Pre-deployed ASG+ELB in DR region means no spin-up delay; DynamoDB global table replicates in near-real-time; DNS health-check failover triggers immediately — warm standby, minimal downtime.", "B": "CloudFormation must launch EC2 instances and create DynamoDB tables at failover time — cold standby, significant downtime during provisioning.", "C": "CloudFormation still must launch EC2+ELB at failover time even though DynamoDB global table is pre-replicated — EC2 provisioning time still causes downtime.", "D": "10-minute CloudWatch evaluation period adds mandatory delay before Lambda triggers Route 53 update — slower failover than DNS health-check in option A.", "_summary": "Warm standby (pre-deployed) + DNS health-check = least downtime for DR"}, "872": {"A": "Updating IAM policies across each account individually requires touching every account — high operational overhead.", "B": "AWS Resource Access Manager shares resources between accounts; it cannot enforce instance-type restrictions.", "C": "Creating deny roles per account and managing developer group bindings in each account = high overhead across multiple accounts.", "D": "Single SCP at Organizations level propagates to all member accounts automatically — one policy change enforces restriction everywhere with zero per-account work.", "_summary": "SCP in AWS Organizations = enforce guardrails across all accounts from one place"}, "738": {"A": "CloudFront is optimized for content delivery (downloads) not uploads — using it as upload accelerator is the wrong pattern.", "B": "S3 Transfer Acceleration routes uploads through CloudFront edge locations to reach S3 faster — purpose-built for global upload latency reduction.", "C": "Uploading to EC2 then copying to S3 adds a hop and operational complexity — no latency benefit.", "D": "CloudFront distributions don't accelerate uploads; placing S3 in the nearest region already handles the 90% same-region case but doesn't solve global upload latency.", "_summary": "S3 Transfer Acceleration uses edge locations to minimize upload latency globally"}, "114": {"A": "Lambda scales automatically for compute, but storing photos in DynamoDB is wrong — DynamoDB is not designed for binary large objects, has 400KB item size limit.", "B": "Kinesis Data Firehose is a streaming data delivery service — not designed to process images or handle metadata, wrong tool entirely.", "C": "Lambda auto-scales for variable concurrent load; S3 is correct for binary image storage; DynamoDB handles structured metadata — proper decoupled architecture.", "D": "Fixed 3 EC2 instances cannot scale for highly variable concurrent users; EBS io2 volumes are expensive and solve the wrong problem.", "_summary": "Lambda+S3+DynamoDB = scalable serverless image processing pattern"}, "989": {"A": "AWS Backup can manage RDS retention but adds another service layer and cost — native RDS retention setting already handles automated backups.", "B": "Disabling and recreating automated backups destroys existing backup history unnecessarily — disruptive and wrong approach.", "C": "Native RDS backup retention period set to 30 days handles automated backups directly; manual backups require manual deletion since RDS has no auto-expiry for them — simplest, no extra service cost.", "D": "Disabling automated backups then using CloudFormation to manage deletion is needlessly complex — CloudFormation is not a backup lifecycle tool.", "_summary": "RDS native 30-day retention + manual cleanup of manual snapshots = simplest cost-effective solution"}, "983": {"A": "Separate DX connection per account = high cost (DX is expensive) and high provisioning overhead.", "B": "VPC endpoints are for AWS-managed services (S3, DynamoDB, etc.) — cannot proxy traffic to on-premises directory/DNS servers.", "C": "VPN per account = multiple tunnels to manage, inconsistent latency, higher ongoing overhead than Transit Gateway.", "D": "Transit Gateway can be shared across accounts via Resource Access Manager; attach the DX gateway once — all accounts route on-premises traffic through single hub, minimal per-account config.", "_summary": "Transit Gateway + shared DX = hub-and-spoke for multi-account on-premises connectivity"}, "126": {"A": "Transitioning to Deep Archive immediately means first 2 years of data require 12-hour retrieval — violates high availability requirement.", "B": "Standard storage for first 2 years satisfies immediate retrieval requirement; Lifecycle rule moves objects to Deep Archive after 2 years at ~$0.00099/GB/month — cheapest long-term storage.", "C": "S3 Intelligent-Tiering charges per-object monitoring fees and doesn't guarantee Deep Archive placement on a predictable schedule — more expensive than a simple lifecycle rule for a known access pattern.", "D": "One Zone-IA immediately loses high availability (single AZ) and is not appropriate for the first 2 years where high availability is required.", "_summary": "Lifecycle: Standard 2yr → Glacier Deep Archive = meets availability + 25yr retention cheaply"}, "844": {"A": "EFS uses NFS protocol, not SMB — on-prem Windows app cannot mount it without code changes.", "B": "FSx for Windows File Server supports SMB but lives fully in AWS; moving the share there requires reconfiguring the app servers and doesn't transparently copy files from on-prem.", "C": "Snowball is a one-time physical bulk-transfer device, not a continuous file-copy solution.", "D": "Storage Gateway File Gateway exposes an SMB endpoint on-prem, transparently syncs writes to S3 over the existing VPN — zero code changes, persistent low-latency local access.", "_summary": "Storage Gateway File Gateway = SMB on-prem + async copy to S3 over VPN"}, "915": {"A": "S3+CloudFront optimizes static asset delivery but has no in-memory compute for real-time leaderboard aggregation.", "B": "Multi-region EC2 with Route 53 geolocation works but carries high operational overhead — patching, scaling, data-sync between regions.", "C": "ElastiCache for Redis supports sorted sets (perfect for rankings), sub-millisecond reads, AND persistence (RDB/AOF snapshots to disk) so data survives restarts — fully managed, least overhead.", "D": "Memcached is purely in-memory with no persistence; data is lost on restart, failing the durability requirement.", "_summary": "Redis = in-memory speed + disk persistence; Memcached has no persistence"}, "112": {"A": "Fargate runs containers as-is with zero code changes, serverless scaling, ALB handles distribution — lowest operational overhead for a containerized workload.", "B": "Two fixed EC2 instances cannot handle growing requests elastically and require OS/patch management.", "C": "Lambda requires rewriting the app to fit the event-driven function model — violates 'minimum code changes'.", "D": "ParallelCluster is for HPC/MPI scientific workloads, not general web serving; gross over-engineering here.", "_summary": "Fargate lifts containers to AWS with no code changes and no server management"}, "111": {"A": "Self-managed second ActiveMQ node and manually replicated MySQL on EC2 — high operational burden, no automatic failover.", "B": "Amazon MQ active/standby handles broker HA, but MySQL stays on EC2 with manual replication — single point of failure remains.", "C": "Adds managed RDS Multi-AZ for MySQL, but consumer EC2 is a fixed additional instance — no automatic scaling or failover for the processing tier.", "D": "Amazon MQ active/standby (broker HA) + Auto Scaling group for consumers across AZs (processing HA) + RDS Multi-AZ (database HA) — all three layers fully managed and highly available.", "_summary": "True HA needs managed HA at every tier: broker, compute, and database"}, "912": {"A": "CLI script on EC2 is not serverless; also doesn't scale well across millions of objects in Glacier Deep Archive.", "B": "AWS Batch provisions EC2/Fargate compute — not cleanly serverless and adds orchestration overhead.", "C": "Glue is an ETL tool optimized for data transformation, not object-level S3 deletion at scale.", "D": "S3 Inventory lists all objects with metadata; S3 Batch Operations invokes Lambda at scale (millions of objects) to filter the retained subset and delete the rest — fully serverless, no servers to manage.", "_summary": "S3 Inventory + S3 Batch Operations + Lambda = serverless mass-delete pipeline"}, "106": {"A": "SSE-C requires the caller to supply the key on every request; AWS never stores it, so there is no CloudTrail key-usage audit log.", "B": "SSE-S3 uses AWS-owned keys; no customer visibility into key usage, no audit log accessible to the customer.", "C": "SSE-KMS with manual rotation meets encryption and CloudTrail audit requirements but requires a manual key-rotation workflow each year — less efficient.", "D": "SSE-KMS with automatic rotation enables CloudTrail logging of every key use and rotates the key material annually with a single setting — fully compliant and zero manual effort.", "_summary": "SSE-KMS = KMS CloudTrail audit + automatic annual rotation with one toggle"}, "981": {"A": "Creating standalone IAM roles alongside IAM Identity Center duplicates identity infrastructure and increases management overhead rather than using Identity Center natively.", "B": "IAM Identity Center permission sets are the native mechanism for granting granular access; assigning teams to groups with permission sets scales cleanly and requires no per-user IAM management — least overhead.", "C": "Individual IAM users are the old model; IAM Identity Center already centralizes identities, making per-user IAM users redundant and violating least-privilege hygiene at scale.", "D": "Separate AWS accounts per team adds significant overhead (account vending, cross-account role maintenance, billing consolidation) far beyond what the use case requires.", "_summary": "IAM Identity Center permission sets + groups = native least-privilege with minimal ops"}, "104": {"A": "Shield Advanced provides L3/4/7 DDoS mitigation with 24/7 DRT support, attack diagnostics, and cost protection — directly addresses large-scale volumetric attacks.", "B": "GuardDuty is a threat-detection service; it raises findings but does NOT automatically block traffic or IPs.", "C": "CloudFront distributes traffic to 400+ edge locations, absorbs volumetric DDoS at the edge before it reaches origin EC2 instances, and hides origin IPs — natural DDoS absorber that pairs with Shield.", "D": "VPC NACLs have a hard limit (default 20, max 40 entries per ACL); thousands of attacker IPs overflow this instantly, and Lambda-driven NACL updates add latency without solving the scale problem.", "E": "Spot Instances can be interrupted by AWS at any time, making them unsuitable for a website where downtime is unacceptable; scaling up also just absorbs attack traffic at cost rather than mitigating it.", "_summary": "Shield Advanced stops DDoS; CloudFront absorbs volumetric traffic at edge before origin"}, "979": {"A": "Provisioned IOPS is highest-cost RDS storage tier; overkill for variable read-heavy workload — not cost-optimized.", "B": "Aurora Serverless v2 scales ACUs up/down based on actual load; pay only for consumed capacity — ideal for variable workloads at lowest cost.", "C": "DynamoDB is NoSQL key-value/document; question requires relational database — wrong engine type.", "D": "Magnetic storage is legacy, poor performance; application-level read replica management adds cost and complexity without matching Serverless cost efficiency.", "_summary": "Aurora Serverless auto-scales = cheapest fit for variable relational workload"}, "972": {"A": "FSx for Windows File Server provides SMB file protocol, not block storage; fails the iSCSI/block requirement.", "B": "EBS volumes are AZ-locked; application-level replication is high implementation effort and error-prone.", "C": "FSx for NetApp ONTAP Multi-AZ natively exposes iSCSI (block) protocol, spans AZs built-in, active/standby failover automatic — least effort.", "D": "EBS has no native cross-AZ replication feature; manual replication setup is high effort and io2 doesn't change that constraint.", "_summary": "FSx ONTAP Multi-AZ = only AWS managed block storage (iSCSI) with native multi-AZ, minimal setup"}, "707": {"A": "CloudTrail captures API management calls, not HTTP traffic patterns hitting the ALB — wrong data source.", "B": "ALB access logs contain per-request details (IP, URI, latency, status); S3+Athena enables SQL queries at scale — operationally efficient.", "C": "Manually opening text files doesn't scale; same data source as B but zero operational efficiency.", "D": "EMR cannot directly query an ALB; ALBs expose no queryable endpoint — technically invalid approach.", "_summary": "ALB access logs → S3 → Athena = standard efficient traffic analysis pattern"}, "691": {"A": "Storage Gateway Volume Gateway presents iSCSI block volumes per-host; not designed for concurrent multi-instance shared access across AZs.", "B": "EFS is a shared POSIX file system accessible from multiple EC2 instances across AZs; provides strong read-after-write consistency.", "C": "EBS volumes are AZ-scoped and cannot be concurrently mounted by instances in different AZs.", "D": "DataSync is a migration/sync tool, not a real-time shared storage solution for live application use.", "E": "S3 has strong read-after-write consistency since 2020; Cache-Control:no-cache on CloudFront bypasses edge cache so clients always fetch latest content.", "_summary": "EFS (multi-AZ shared mount) and S3+CloudFront no-cache (strong consistency) both meet shared+consistent requirements"}, "856": {"A": "Migrating all data to a public bucket exposes everything — violates least-privilege and is excessive.", "B": "Making entire bucket public exposes all operations data, not just the one report — security violation.", "C": "Creating IAM user adds permanent credentials risk; manual revocation after 7 days is operational burden and error-prone.", "D": "Presigned URL scopes access to one specific object, expires automatically at set time (up to 7 days for STS-based), no new users/credentials needed — most efficient.", "_summary": "Presigned URL = time-limited, object-scoped access with zero IAM overhead"}, "855": {"A": "ACM private certificates come from Private CA which has an associated cost; also not appropriate for public-facing CloudFront distributions.", "B": "CloudFront requires custom SSL/TLS certificates to be provisioned in us-east-1 specifically — wrong region.", "C": "ACM public certificates are free; CloudFront mandates the cert reside in us-east-1 — both conditions satisfied.", "D": "Public cert is free and correct type, but us-west-1 is wrong region; CloudFront will not find it.", "_summary": "CloudFront custom SSL = ACM public cert (free) in us-east-1 only"}, "1016": {"A": "S3 interface endpoint (PrivateLink) costs ~$0.01/AZ/hour plus data processing fees — more expensive than gateway endpoint.", "B": "S3 gateway endpoint is free, traffic routes through AWS backbone (not internet), only requires route table entry — most cost-effective solution.", "C": "NAT gateway routes traffic through the internet gateway path; S3 bucket policy on NAT EIP doesn't prevent internet traversal and adds NAT data charges.", "D": "Second NAT gateway adds cost and still routes externally; doesn't satisfy the no-internet-traffic requirement.", "_summary": "S3 gateway endpoint = free, private routing, zero internet traversal"}, "997": {"A": "Spot Instances can be interrupted mid-operation; unsuitable for databases requiring durability and availability.", "B": "RDS on-demand with GP SSD and automatic backups is valid but costs more than Aurora Serverless for low/variable traffic since you pay for provisioned instance size continuously.", "C": "Aurora Serverless scales to zero when idle, charges per ACU-second, includes automated backups to S3 — lowest cost for new app with uncertain/variable traffic.", "D": "Self-managed NoSQL on EC2 requires operational effort for patching/backups; NoSQL doesn't fit structured relational requirements; Reserved Instances require upfront commitment.", "_summary": "Aurora Serverless = pay-per-use scaling with built-in backups, cheapest for variable new-app traffic"}, "932": {"A": "Transit Gateway manages inter-VPC and on-premises routing; it cannot assign pods to custom subnets inside an EKS cluster.", "B": "Direct Connect links on-premises networks to AWS; it has no role in assigning VPC subnets to pods already inside AWS.", "C": "VPC CNI plugin is the AWS-native EKS network plugin; its custom networking feature lets you specify secondary subnets for pods while keeping all traffic inside the VPC.", "D": "Pod anti-affinity rules influence scheduling decisions (which node a pod lands on) but do not control subnet assignment or enforce network security between pods.", "_summary": "VPC CNI plugin custom networking = correct tool for pod subnet assignment in EKS"}, "937": {"A": "Cost and Usage Report surfaces raw billing data; it does not generate rightsizing or optimization recommendations for EC2, ASG, or EBS.", "B": "CloudWatch billing alerts threshold-monitor spend; they do not analyze resource utilization to recommend optimizations.", "C": "Compute Optimizer natively supports EC2 instances, Auto Scaling groups, and EBS volumes in a single service — one configuration covers all three, maximum operational efficiency.", "D": "Compute Optimizer already covers EBS volumes and ASGs; adding a separate CUR search is redundant work and lower efficiency.", "_summary": "Compute Optimizer covers EC2 + ASG + EBS rightsizing in one place"}, "938": {"A": "S3 is object storage accessed over HTTPS APIs, not a high-performance shared file system, and data traverses outside the VPC unless a gateway endpoint is used.", "B": "S3 cannot be natively mounted as a block/NFS volume; third-party FUSE drivers exist but are not AWS-managed and are not high-performing.", "C": "EBS volumes are tied to a single AZ and can only attach to one instance at a time (Multi-Attach is limited to io1/io2, single AZ — does not span AZs).", "D": "EFS is a managed NFS file system that mounts concurrently across unlimited EC2 instances in multiple AZs within the VPC, purpose-built for this pattern.", "_summary": "EFS = shared NFS across multi-AZ EC2; EBS cannot span AZs or instances"}, "133": {"A": "EC2 gives OS access and allows any Oracle version, but manually configuring cross-region replication is high operational overhead — fails 'minimize overhead' requirement.", "B": "RDS for Oracle is fully managed but locks you out of the underlying OS — fails the OS access requirement.", "C": "RDS Custom for Oracle provides a managed service (lower overhead than EC2) while granting OS-level access; cross-region read replicas satisfy DR with AWS-managed replication.", "D": "RDS for Oracle Multi-AZ deploys a standby in a second AZ (same region, not cross-region DR) and still provides no OS access — fails both DR scope and OS access requirements.", "_summary": "RDS Custom = managed Oracle + OS access; the only option satisfying all three constraints"}, "632": {"A": "S3 Glacier is archival with retrieval times of minutes to hours — incompatible with hourly modification and analysis of active data.", "B": "EBS volumes are bound to a single AZ and attach to one EC2 instance at a time; shared access across multiple instances in multiple AZs is not supported.", "C": "EFS auto-scales, supports concurrent NFS mounts from many EC2 instances across multiple AZs, and grows elastically — matches all stated requirements.", "D": "EBS Provisioned IOPS Multi-Attach is restricted to a single AZ and only io1/io2 volumes; it cannot serve instances spread across multiple AZs.", "_summary": "EFS = concurrent multi-AZ NFS; only option that satisfies multi-instance multi-AZ shared writes"}, "843": {"A": "Two fixed EC2 instances behind an ALB is not scalable; RDS read replicas handle read scaling but do not provide HA for write traffic — not a proper Multi-AZ configuration.", "B": "Cross-region DB replication on self-managed EC2 introduces high administrative overhead for patching, failover, and replication management.", "C": "Auto Scaling group handles demand spikes; ALB distributes traffic; RDS Multi-AZ provides synchronous standby with automatic failover — fully managed, highly available, scales automatically.", "D": "Fixed three EC2 instances do not autoscale; self-managed DB across three AZs on EC2 carries heavy admin overhead for failover and replication.", "_summary": "ASG + ALB + RDS Multi-AZ = HA + scalability with least admin overhead"}, "842": {"A": "The legacy 'EFS-to-EFS backup solution' relied on DataSync scripts — not a native managed backup service and more complex to operate than AWS Backup.", "B": "Scripting nightly copies to S3 and enabling CRR is not a fully managed approach; it requires maintaining and monitoring custom scripts.", "C": "VPC peering plus rsync is entirely self-managed — high operational overhead, no SLA, not an AWS managed service.", "D": "AWS Backup natively supports EFS with cross-region replication rules; one backup plan covers scheduling, retention, and cross-region copy with zero custom code — most cost-effective managed path.", "_summary": "AWS Backup = single managed service for EFS cross-region replication"}, "625": {"A": "CloudFront has built-in geographic restrictions that enforce content rights at the CDN edge; WAF adds fine-grained geo-based allow/deny rules — together they enforce distribution rights before content is served.", "B": "ALB with WAF can apply geo rules but ALBs are regional; placing WAF only at load balancers skips CDN-layer enforcement and does not address content caching or distribution rights globally.", "C": "Route 53 geolocation routing directs DNS queries to different endpoints but can be bypassed by using alternative resolvers — it does not enforce content access restrictions.", "D": "Geoproximity routing minimizes latency by routing to the nearest resource; it has no concept of content rights or geographic restrictions.", "_summary": "CloudFront geo-restriction + WAF = content rights enforced at CDN edge globally"}, "624": {"A": "Creates second identity for each user — violates 'no new identity' requirement. IAM users are separate from AD.", "B": "Cognito user pool creates net-new identities. Does not federate existing AD credentials.", "C": "Cross-account roles solve multi-account delegation, not identity federation. Users still need separate AWS credentials.", "D": "SAML 2.0 federation lets AD users authenticate with existing credentials via AD FS. Roles map to AD groups, no new identity needed. Correct.", "_summary": "SAML 2.0 federation bridges on-premises AD to AWS IAM roles without duplicate identities"}, "1005": {"A": "API Gateway → SQS buffers spikes. Lambda polls SQS, calls Comprehend (correct NLP service for sentiment), saves to DynamoDB. TTL=365 days handles retention. Fully serverless, scales to thousands/hour. Correct.", "B": "EC2-hosted API is a scaling bottleneck. Not serverless. Less scalable than A.", "C": "Rekognition analyzes images/video — wrong service for text sentiment. Eliminates this option entirely.", "D": "Lex is a conversational chatbot builder, not a sentiment analysis service. Wrong tool.", "_summary": "Comprehend = sentiment on text; Lex = chatbots; Rekognition = image/video"}, "770": {"A": "On-Demand for constant production is expensive vs Savings Plans. Dedicated Hosts for nonproduction weekends-only is nonsensical and costly.", "B": "RI for nonproduction wastes money — you pay for reserved capacity whether instances run or not. Shutting down nonprod doesn't reduce RI cost.", "C": "Compute Savings Plans suit constant production (high utilization maximizes discount). On-Demand for intermittent nonprod means you pay only when running. Correct.", "D": "Dedicated Hosts for production is expensive overkill. EC2 Instance Savings Plans for intermittent nonprod = paying for unused commitment.", "_summary": "Constant usage → Savings Plans/RI; intermittent usage → On-Demand (shut down = no charge)"}, "833": {"A": "Extra transformer Lambda knows the data format of every validation step — creates coupling. Adds operational overhead.", "B": "SNS filtering decides IF message reaches subscriber, not HOW to reshape payload. Cannot trim event data per subscriber.", "C": "EventBridge input transformer rewrites the event payload per rule target — sends only required fields to each Lambda. Rules decouple producers from consumers. Correct.", "D": "Synchronous parallel invocations from a coordinator Lambda are tightly coupled. Single SQS queue creates a bottleneck.", "_summary": "EventBridge input transformer = per-target payload shaping; SNS filtering = attribute-based routing only"}, "826": {"A": "Creates a new AWS Managed AD — new identity store, doesn't reuse existing on-premises AD. Users would be duplicated.", "B": "IAM Identity Center + two-way forest trust through AWS Managed AD bridges on-premises AD to IAM Identity Center. Users and groups still managed on-premises. SSO spans all AWS accounts in Organizations. Correct.", "C": "Directory Service trust alone gives resource access but not SSO across AWS accounts — IAM Identity Center is required for that.", "D": "Self-hosted IdP on EC2 is unnecessary complexity when AWS Directory Service + IAM Identity Center handles this natively.", "_summary": "IAM Identity Center + Managed AD forest trust = SSO across accounts while keeping on-premises AD as source of truth"}, "824": {"A": "Redshift is an analytics data warehouse, not a transactional MySQL-compatible OLTP database. Wrong service.", "B": "No Auto Scaling group mentioned — app tier lacks auto-scaling. RDS MySQL Multi-AZ is valid but app layer doesn't auto-scale.", "C": "ASG + ALB gives app-tier HA and auto-scaling. Aurora Serverless v2 is MySQL-compatible and auto-scales database compute capacity. Correct.", "D": "ElastiCache for Redis is a cache/key-value store, not a MySQL-compatible relational database.", "_summary": "Aurora Serverless = MySQL-compatible DB that auto-scales; ASG+ALB = auto-scaling app tier"}, "823": {"A": "NLB operates at Layer 4 (TCP/UDP) — no HTTP query string awareness. Cannot route by query parameters.", "B": "Gateway Load Balancer is for inline virtual appliances (firewalls, IDS). Does not serve application traffic or do path/query routing.", "C": "ALB operates at Layer 7 — supports query string condition rules in listener rules. ACM certificate provides TLS termination. Correct.", "D": "NLB has no query string routing capability regardless of certificate method.", "_summary": "ALB = Layer 7 routing (query strings, paths, headers); NLB = Layer 4 only; GWLB = virtual appliance bump-in-the-wire"}, "821": {"A": "VPN connects on-premises networks to AWS VPCs — cannot establish VPN to a SaaS like Salesforce. Glue DataBrew is data prep, not Salesforce ETL.", "B": "Direct Connect is for on-premises data center to AWS — not for SaaS-to-AWS connectivity.", "C": "AppFlow natively integrates with Salesforce as a source. AWS PrivateLink endpoint for AppFlow keeps data off public internet. Least development effort. Correct.", "D": "VPC peering is between two VPCs — Salesforce is a SaaS, not a VPC. Cannot peer with it.", "_summary": "AppFlow = native Salesforce connector; PrivateLink = private data path; Direct Connect/VPN do not apply to SaaS"}, "819": {"A": "Lambda+DocumentDB adds a second database engine and custom filtering logic — high operational overhead with no benefit over a simple S3 pointer pattern.", "B": "DynamoDB item size hard limit is 400 KB; 700 KB exceeds it. Storing large blobs in S3 and keeping the S3 URL as a DynamoDB attribute is the canonical AWS pattern — no size violation, no extra infrastructure.", "C": "Splitting items on the same partition key creates a hot partition and throttling risk; BatchWriteItem still enforces the 400 KB per-item limit, so the root problem is unsolved.", "D": "gzip cannot guarantee 700 KB compresses below 400 KB, and adding compression/decompression logic in Lambda is fragile and operationally costly for an unreliable gain.", "_summary": "DynamoDB 400 KB item limit → store large objects in S3, keep S3 URL attribute in DynamoDB"}, "812": {"A": "Glue Studio visual canvas supports no-code ETL but lacks built-in data profiling and the shareable 'recipe' concept; sharing is via Glue jobs (code artifacts), not step-by-step recipes.", "B": "EMR Serverless is a code-based Spark/Hive execution engine — writing transformation code is required, violating the no-code requirement.", "C": "AWS Glue DataBrew is purpose-built for no-code data preparation; it natively provides data profiling, data lineage, and transformation steps packaged as reusable recipes that are shareable across teams.", "D": "Athena requires writing SQL — not no-code; also has no built-in data profiling or lineage tracking.", "_summary": "DataBrew = no-code prep + data profiling + data lineage + shareable recipes"}, "810": {"A": "AWS Hosted Connection Direct Connect requires physical cross-connect provisioning at a colo facility — impossible without an existing internet or Direct Connect path, and VPC peering alone cannot bridge the connectivity gap.", "B": "Client VPN connects end-user devices to a VPC, not VPC-to-VPC; it also requires a client-side internet connection, which the company explicitly does not have.", "C": "AWS PrivateLink backed by an NLB endpoint service enables cross-account private service access without an internet gateway, Direct Connect, or VPN — the vendor exposes the NLB as an endpoint service; the company creates an interface VPC endpoint pointing to it.", "D": "Transit Gateway attachments and VPC peering both require a routable network path between the accounts; without IGW, DX, or VPN, TGW cannot establish cross-account connectivity, and stacking TGW on top of peering is redundant.", "_summary": "PrivateLink = cross-account private service access, zero need for IGW/DX/VPN"}, "809": {"A": "EventBridge natively captures AWS Batch job state-change events including SUCCEEDED. API Destinations support HTTP endpoints with connection objects storing Basic auth credentials — fully serverless, no Lambda required.", "B": "EventBridge Scheduler is time-based (cron/rate expressions), not event-driven; it cannot match 'Batch job SUCCEEDED' events — wrong service entirely.", "C": "AWS Batch does not publish events to API Gateway natively; Batch automatically emits state-change events to EventBridge, so this requires custom instrumentation inside the job.", "D": "Same fundamental flaw as C — Batch does not push to API Gateway — plus an unnecessary Lambda hop when EventBridge API Destinations already handle authenticated HTTP calls directly.", "_summary": "EventBridge API Destinations = serverless HTTP call with auth credentials, no Lambda needed"}, "805": {"A": "AWS Local Zones are AWS-owned infrastructure in metropolitan areas near cities — not inside a customer's data center; data leaves the customer's facility, violating the compliance requirement.", "B": "AWS Snowmobile is a petabyte-scale physical data migration service — not a compute platform and incapable of running EKS workloads.", "C": "AWS Outposts rack delivers AWS-managed compute, storage, and networking hardware physically inside the customer's on-premises data center, supporting EKS and other AWS managed services with data never leaving the facility.", "D": "Snowball Edge targets edge compute and offline/bandwidth-limited environments — it is not designed for production EKS clusters or ongoing managed-service operations.", "_summary": "Outposts rack = AWS infrastructure physically in customer DC, EKS supported, data stays on-prem"}, "534": {"A": "Objects land in S3 Standard by default; transitioning to Standard at day 30 is a no-op — no cheaper storage tier is applied for the 30–90 day backup window, so this is not cost-effective.", "B": "Scheduling both a Glacier transition and an expiration action at day 90 is contradictory — S3 lifecycle processes expiration before transition on the same day, so objects never reach Glacier; Standard-IA also carries a 30-day minimum storage charge.", "C": "Objects begin in S3 Standard (highly available, frequent access, days 0–30), transition to Glacier Flexible Retrieval at day 30 (cheap archive for backup days 30–90), expire at day 90 — matches all three requirements at minimum cost.", "D": "S3 One Zone-IA stores data in a single AZ and is not highly available; it also suffers the same contradictory same-day Glacier-transition-plus-expiration issue as B.", "_summary": "Standard (0–30 days) → Glacier Flexible Retrieval (30–90 days) → expire at 90 days"}, "533": {"A": "Amazon Macie is purpose-built for discovering PII in S3 objects; its findings use the SensitiveData finding type. EventBridge routes findings to SNS, which pushes email/SMS alerts to the security team — correct full chain.", "B": "Amazon GuardDuty detects security threats (malicious IPs, anomalous API calls, credential compromise) — it does not scan S3 object contents for PII; wrong service.", "C": "Macie correctly identifies PII, but SQS is a pull-based queue requiring a consumer to poll — it does not push notifications to a security team; SNS is the correct notification primitive.", "D": "GuardDuty does not detect PII in S3 objects, and SQS is not an appropriate security-team alerting mechanism — two wrong choices compounded.", "_summary": "Macie detects PII in S3 → EventBridge SensitiveData finding → SNS for team push notification"}, "532": {"A": "A single wildcard Route 53 record (*.example.com → API Gateway endpoint) covers all customers with one DNS entry — operationally efficient; correct step 1 of 3.", "B": "For a regional API Gateway, the ACM certificate must reside in the same AWS Region as the API. A certificate in a different region cannot be attached to a regional custom domain — incorrect.", "C": "Creating a separate Route 53 hosted zone per customer is operationally expensive and does not scale; one hosted zone with a wildcard record handles all customers.", "D": "An ACM wildcard certificate in the same Region as the regional API Gateway is required to enable HTTPS on the custom domain — correct step 2 of 3.", "E": "Creating separate API endpoints per customer defeats operational efficiency; a single API with stage variables or path-based routing serves all customers from one endpoint.", "F": "A custom domain name must be created in API Gateway and linked to the ACM certificate before API Gateway can serve traffic under the custom domain — required step 3 of 3.", "_summary": "Correct three: A (wildcard Route 53) + D (same-region ACM cert) + F (API GW custom domain); hint 'AD' is incomplete — F is also required"}, "516": {"A": "ALB+ECS runs containers that need cluster/task management — more overhead than serverless.", "B": "API Gateway+Lambda with provisioned concurrency pre-warms execution environments, eliminating cold starts for consistent low latency at peak load. Fully managed — least overhead.", "C": "ALB+EKS adds Kubernetes control plane management — highest operational overhead of all options.", "D": "Reserved concurrency reserves Lambda capacity quota but does NOT pre-warm environments — cold starts still occur, latency inconsistent under burst.", "_summary": "Provisioned concurrency = warm Lambda = no cold starts; reserved concurrency only caps concurrency"}, "494": {"A": "EC2 resource-based policies exist but the scenario describes an IAM role issue; no evidence of a resource policy deny here.", "B": "IAM policies attached to roles don't need a Principal field — the role itself is the principal.", "C": "ec2:TerminateInstances is a single action; the policy likely includes it or the error would differ.", "D": "IAM Condition with aws:SourceIp restricts calls to 192.0.2.0/24 or 203.0.113.0/24. CLI call from admin's workstation outside those CIDRs triggers implicit deny — hence 403.", "_summary": "Condition key aws:SourceIp denies requests not originating from allowed CIDRs"}, "479": {"A": "Systems Manager handles configuration/patching/runbooks — not IaC infrastructure provisioning.", "B": "CloudFormation templates codify the prototype, enabling repeatable automated deploys across AZs for both dev and prod. Correct tool.", "C": "AWS Config records configuration state and compliance — it does not provision infrastructure.", "D": "Elastic Beanstalk deploys applications with managed platforms; it does not template arbitrary VPC/ALB/RDS/ASG topologies.", "_summary": "CloudFormation = IaC for repeatable, automated, multi-AZ infrastructure deployment"}, "849": {"A": "Third-party software + Storage Gateway tape VTL adds licensing and operational complexity — opposite of native/centralized.", "B": "AWS Backup natively integrates with EC2, RDS, and DynamoDB; provides centralized policy, scheduling, monitoring, and compliance — exactly what's asked.", "C": "AWS Config tracks resource configuration history and compliance rules — not a backup solution.", "D": "Systems Manager State Manager enforces configuration state on EC2 — not a backup service.", "_summary": "AWS Backup = native centralized backup for EC2+RDS+DynamoDB with policy-driven automation"}, "848": {"A": "Standard RDS for Oracle is fully managed with no OS/DB privileged access — cannot install or configure third-party features requiring elevated privileges.", "B": "RDS Custom for Oracle grants OS and database-level access, supports BYOL, and allows customizing the environment for third-party features needing privileged access. Most cost-effective path.", "C": "DynamoDB is a NoSQL service — Oracle-specific features and schema cannot migrate there; DMS cannot bridge that gap.", "D": "Migrating to PostgreSQL requires engine rewrite plus application code changes — highest effort and cost, and loses Oracle-specific features.", "_summary": "RDS Custom = managed Oracle with privileged access; required for third-party Oracle features"}, "847": {"A": "Secrets Manager has native RDS integration for automatic rotation — rotates the password in both the secret and the database with zero custom code. Least overhead.", "B": "SSM Parameter Store has no native automatic rotation for RDS database passwords — rotation requires external automation.", "C": "SSM Parameter Store + custom Lambda works but requires writing and maintaining rotation logic — more overhead than Secrets Manager.", "D": "KMS manages encryption keys, not database credentials. Rotating a KMS key does not change the RDS database password.", "_summary": "Secrets Manager = built-in RDS password rotation with no code required"}, "860": {"A": "S3 Gateway endpoint routes traffic through AWS backbone at zero cost (no hourly fee, no data processing charge) — eliminates internet egress and NAT costs entirely.", "B": "NAT gateway charges $0.045/GB data processing; all S3 traffic flows through it — expensive at scale.", "C": "PrivateLink interface endpoint for S3 incurs hourly endpoint charges plus per-GB data processing fees — more expensive than gateway endpoint.", "D": "One NAT gateway per AZ improves resilience but still incurs NAT data processing charges on all S3 traffic — not cost-minimized.", "_summary": "S3 Gateway endpoint is free and private — cheapest path for EC2-to-S3 in same region"}, "752": {"A": "Lambda is serverless — zero infrastructure management for compute. Correct pick for least overhead.", "B": "EC2 requires provisioning, patching, scaling — more operational burden.", "C": "SNS is at-least-once delivery; it does NOT guarantee exactly-once — fails the core messaging requirement.", "D": "SQS FIFO queues provide exactly-once processing via deduplication IDs — matches the exactly-once guarantee requirement.", "E": "EKS requires managing Kubernetes nodes and control plane — significant infrastructure overhead.", "_summary": "Lambda (serverless compute) + SQS FIFO (exactly-once) = least overhead with delivery guarantee"}, "652": {"A": "Long-running cluster runs 24/7; paying for idle 18h/day makes it costlier than transient despite correct On-Demand/Spot node split.", "B": "Transient cluster terminates after 6h job (pay only when running); On-Demand primary/core protect HDFS data from Spot interruption; Spot task nodes cut compute cost — optimal balance.", "C": "Core nodes hold HDFS blocks; putting them on Spot risks data loss on interruption — violates the no-data-loss requirement.", "D": "Long-running raises cost over transient; also core nodes on Spot risk HDFS data loss.", "_summary": "EMR: transient=cost, On-Demand core=data safety, Spot task=savings"}, "585": {"A": "On-Demand instances available in normal conditions but AWS does not contractually guarantee capacity; during large failover events capacity can be exhausted.", "B": "Savings Plans provide billing discounts, not capacity guarantees — no reserved physical slots.", "C": "Regional Reserved Instances give billing priority but do NOT reserve capacity in a specific AZ; only Zonal RIs carry a capacity reservation, and the question says 'regional'.", "D": "Capacity Reservations explicitly hold EC2 capacity in a target AZ regardless of overall demand — the only construct that guarantees availability at failover time.", "_summary": "Capacity Reservation = only EC2 construct that guarantees physical capacity"}, "372": {"A": "Storing binary images inside Oracle RDS rows is expensive and slow; Oracle licensing adds cost; doesn't scale well for burst update rate.", "B": "S3 stores large binaries cheaply; DynamoDB with geographic code as partition key handles tens of thousands of writes/min elastically with no schema constraints — ideal key-value pattern.", "C": "DynamoDB item limit is 400 KB; high-res GIS images far exceed this, making direct image storage impossible; DAX adds cost without solving the size problem.", "D": "S3 is correct for images but Oracle RDS is expensive, less scalable for rapid key-value bursts, and adds licensing overhead versus DynamoDB.", "_summary": "S3 for blobs + DynamoDB for key→URL mapping = scalable, cost-effective migration from Oracle"}, "353": {"A": "Multi-AZ RDS MySQL with io2 Block Express is HA/fault-tolerant but io2 is expensive; for 1000 IOPS peak (2000 needed headroom) gp2 already covers it at lower cost.", "B": "gp2 on 1 TB delivers 3000 IOPS baseline (3 IOPS/GB) — exceeds the 2000 IOPS headroom requirement; Multi-AZ gives HA/fault tolerance; fully managed RDS eliminates self-managed overhead; cheapest qualifying option.", "C": "S3 Intelligent-Tiering is object storage, irrelevant to a relational database IOPS requirement.", "D": "Active-passive EC2 MySQL is not fully managed, requires manual failover logic, and incurs higher operational overhead — contradicts all stated requirements.", "_summary": "gp2 at 1TB = 3000 IOPS baseline, covers 2x headroom cheaper than io2; Multi-AZ = HA"}, "121": {"A": "AWS procedure for encrypting an existing RDS instance: snapshot → encrypt the copy → restore as new encrypted instance; all subsequent snapshots inherit encryption — correct and complete.", "B": "You cannot toggle encryption on a live RDS instance; attaching an encrypted EBS volume externally does not encrypt the RDS instance or its automated snapshots.", "C": "Snapshots cannot be restored 'to an existing DB instance' by overwriting; restoration always creates a new instance, and the phrasing implies the old unencrypted instance remains.", "D": "Copying snapshots to an encrypted S3 bucket does not encrypt the RDS instance itself or its future native snapshots.", "_summary": "RDS encryption: encrypt snapshot copy → restore new instance; encryption immutable post-creation"}, "858": {"A": "Two connections only from the primary DC; the secondary DC provides no redundancy path — primary DC or its local fiber is still a single point of failure.", "B": "Single connection from each DC to one DX location on the same device; one device failure or one DX location outage kills both paths.", "C": "Two connections from each DC (4 total) terminating at two separate DX locations on separate devices — eliminates failure of any single DC, fiber segment, DX location, or device; matches AWS maximum-resiliency blueprint.", "D": "Single connection from each DC to one DX location; one DX location outage breaks both paths despite separate devices.", "_summary": "Max DX resiliency: 2 connections × 2 DCs × 2 DX locations × 2 devices = no single point of failure"}, "854": {"A": "CloudFormation parameters for DB credentials mean static secrets in plaintext or in template history — not secure, high operational burden for rotation.", "B": "Parameter Store improves secret storage but credentials are still static; rotation requires manual update and re-deployment — more effort than IAM auth.", "C": "IAM database authentication lets the EC2 instance role generate short-lived auth tokens; no static password exists, tokens auto-expire, and no rotation workflow is needed — least operational effort.", "D": "IAM users are for human identities; EC2 workloads should use IAM roles; associating an IAM user with an instance is not a supported pattern and is an anti-pattern.", "_summary": "Aurora IAM DB auth + EC2 instance role = zero static credentials, no rotation ops"}, "853": {"A": "GuardDuty analyzes VPC Flow Logs, CloudTrail, and DNS to detect runtime threats; EventBridge routes findings to Lambda which dynamically tightens WAF rules — full automated detect-and-respond loop.", "B": "Firewall Manager centrally manages WAF/security group policies across accounts; it does not perform threat detection or generate findings to act on.", "C": "Inspector performs vulnerability scanning (CVEs, misconfigurations) on EC2/containers — not runtime behavioral threat detection; it cannot update WAF rules.", "D": "Macie discovers and classifies sensitive data in S3; it does not detect network/API-level threats against a web application.", "_summary": "GuardDuty=runtime threat detection; EventBridge+Lambda=automated WAF response"}, "438": {"A": "Read replica gives auditor live DB access over network — not their own copy, not cross-account isolated, poor for audit use case.", "B": "Exporting to S3 text files loses encryption-at-rest guarantees of RDS; sharing IAM user keys is anti-pattern (keys can be leaked/reused).", "C": "Copying snapshot to S3 loses RDS snapshot format; sharing IAM user keys is insecure — keys are long-term credentials the auditor could misuse.", "D": "RDS encrypted snapshots can be shared cross-account natively; auditor restores into their own account; KMS key policy grants them decryption — data stays encrypted in transit and at rest, auditor gets isolated copy.", "_summary": "Cross-account RDS snapshot share + KMS key policy = secure isolated copy"}, "425": {"A": "gp2 IOPS tied to volume size (3 IOPS/GB, max 16,000) — to hit 15,000 IOPS you need ~5TB provisioned even if you don't need that storage; not independent.", "B": "io2 supports up to 64,000 IOPS and higher durability than io1, but costs significantly more per IOPS — overkill for 15,000 IOPS requirement.", "C": "gp3 decouples IOPS from capacity: baseline 3,000 IOPS free, up to 16,000 IOPS provisionable independently of storage size, at lower cost than io1/io2 — exactly matches requirement.", "D": "io1 also decouples IOPS from capacity but costs more per provisioned IOPS than gp3 — no advantage over gp3 at 15,000 IOPS.", "_summary": "gp3 = independent IOPS+capacity provisioning at lowest cost up to 16,000 IOPS"}, "814": {"A": "ECS removes Kubernetes overhead, but SQS uses its own protocol (not AMQP) — migrating message protocol adds re-engineering work, not least overhead.", "B": "EKS preserves Kubernetes workload with minimal container refactoring; Amazon MQ supports AMQP natively — application message code unchanged, least operational overhead.", "C": "Raw EC2 requires managing OS, patching, scaling manually — higher operational overhead than managed container service.", "D": "Lambda has execution time limits and cold-start concerns for long-running container workloads; SQS doesn't speak AMQP — double mismatch.", "_summary": "EKS (K8s-compatible) + Amazon MQ (AMQP-native) = minimal migration friction"}, "115": {"A": "NAT gateway still routes traffic over internet — traffic exits VPC to public AWS endpoints, does not satisfy private-route requirement.", "B": "Security group restricting to S3 prefix list controls which traffic is allowed but doesn't change the routing path — traffic still goes via internet gateway.", "C": "VPC Gateway Endpoint for S3 keeps traffic on AWS private network entirely; moving instances to private subnets + endpoint route table entry satisfies private-route requirement without internet exposure.", "D": "Removing the IGW breaks all internet access for the instances; Direct Connect is for on-premises connectivity, not intra-AWS S3 access — wrong tool and destructive.", "_summary": "VPC Gateway Endpoint routes S3 traffic privately within AWS backbone"}, "237": {"A": "VPC peering is a direct, private, encrypted network path between two VPCs across accounts; no single point of failure, no bandwidth bottleneck — AWS manages the fabric.", "B": "VPC gateway endpoints are for AWS services (S3, DynamoDB) only — cannot be used to reach EC2 instances in another VPC.", "C": "Virtual private gateway is for VPN/Direct Connect connectivity to on-premises networks, not VPC-to-VPC peering.", "D": "Private VIF is a Direct Connect concept for on-premises-to-AWS connectivity — not applicable for VPC-to-VPC access between AWS accounts.", "_summary": "VPC peering = private cross-account VPC connectivity, no SPOF, no bandwidth cap"}, "229": {"A": "Aurora Serverless (v1/v2) auto-scales compute capacity up/down; Aurora MySQL is drop-in compatible with MySQL — minimal schema changes, managed replication, high durability via 6-way storage replication.", "B": "Aurora Serverless for PostgreSQL requires database engine migration from MySQL — additional effort beyond what's necessary; PostgreSQL is not MySQL-compatible.", "C": "Larger EC2 instances don't solve scaling elasticity — still manual vertical scaling, no managed replication, doesn't simplify operations.", "D": "EC2 Auto Scaling adds/removes instances but MySQL replication must still be managed manually — doesn't reduce operational burden on database tier.", "_summary": "Aurora Serverless MySQL = auto-scaling compute + managed replication, MySQL-compatible"}, "224": {"A": "Failover routing is active-passive — sends traffic to primary only unless it fails; doesn't distribute traffic to all running instances randomly.", "B": "Weighted routing sends proportional traffic by assigned weights — not random equal distribution, and requires manual weight configuration per instance.", "C": "Multivalue answer routing returns multiple healthy IPs and clients select randomly — achieves random distribution across all running instances.", "D": "2+1 AZ split means losing the 2-instance AZ drops capacity by 67% — unbalanced; not truly fault tolerant at equal distribution.", "E": "2+2 across two AZs = balanced HA; losing one AZ still leaves 50% capacity running — proper fault-tolerant spread for multivalue routing.", "_summary": "Route 53 multivalue (random distribution) + balanced 2+2 AZ spread = HA + random traffic"}, "222": {"A": "IAM role with cross-account trust policy is the AWS-recommended pattern for granting external account access — no long-term credentials, vendor's tool assumes the role via STS, least privilege, auditable.", "B": "IAM user with password creates long-term credentials in your account — violates least privilege and credential management best practices; passwords are for console humans, not tools.", "C": "You cannot add IAM users from external accounts to your account's IAM groups — IAM groups only contain users within the same account.", "D": "\"AWS account\" is not a valid identity provider type in IAM — IAM identity providers are for SAML/OIDC federation, not cross-account AWS access.", "_summary": "Cross-account IAM role trust = correct pattern for external AWS account tool access"}, "221": {"A": "EBS is single-instance block storage; no concurrent multi-instance access and prohibitively expensive for 7-year archival.", "B": "EFS provides shared file access but costs ~3× S3; not cost-effective for long-term log retention at scale.", "C": "Instance store is ephemeral; data is lost on stop/terminate; fails the retention requirement entirely.", "D": "S3 is durable object storage with native concurrent access, lifecycle rules to Glacier tiers for pennies per GB, and no infrastructure to manage — cheapest 7-year archival option.", "_summary": "S3 + lifecycle tiering = cheapest durable concurrent-access long-term storage"}, "726": {"A": "Multi-AZ improves availability failover, not read/write throughput; the bottleneck is performance, not availability.", "B": "OpenSearch is a search/analytics engine, not optimized for high-frequency geospatial key-value updates; migration adds complexity without solving the root problem.", "C": "DAX is DynamoDB-only; it cannot be placed in front of RDS PostgreSQL — technically incompatible.", "D": "ElastiCache for Redis supports native geospatial commands (GEOADD, GEORADIUS), absorbs high-frequency reads/writes as a caching layer in front of RDS, and scales horizontally.", "_summary": "Redis for geospatial caching in front of RDS; DAX is DynamoDB-only and cannot proxy RDS"}, "456": {"A": "Running a full duplicate EC2 fleet in the second region incurs continuous compute costs — not cost-effective for backup.", "B": "Manual EBS snapshot copy works but lacks centralized scheduling, retention policies, and cross-region management that AWS Backup provides.", "C": "AWS Backup provides managed cross-region backup with centralized policy and scheduling; no duplicate running instances; meets all requirements at lowest operational and dollar cost.", "D": "Running a similar EC2 fleet plus DataSync transfers doubles compute spend; not a backup strategy, it's a hot standby.", "_summary": "AWS Backup cross-region = managed, centralized, no duplicate running instances = most cost-effective"}, "601": {"A": "Snapshot restore requires stopping writes before the snapshot to avoid data loss, then a full restore window — both downtime and data loss risk are higher.", "B": "Aurora read replica of RDS PostgreSQL replicates continuously; promote with a brief cutover = minimal downtime and near-zero data loss; fully managed, least operational overhead.", "C": "S3 import requires first exporting data to S3, multiple manual steps, and a maintenance window — high overhead.", "D": "pg_dump is an offline export; application must pause writes or accept data loss during the dump period — high overhead and downtime.", "_summary": "Aurora read replica from RDS = live replication then promote = lowest downtime migration path"}, "598": {"A": "S3 File Gateway presents an SMB share on-premises and writes files directly to S3; exactly matches the devices' SMB output — correct ingestion layer.", "B": "FSx File Gateway routes SMB to FSx for Windows File Server; unnecessary cost and complexity when the target is S3 for SQL analysis.", "C": "Glue crawler inspects S3 CSV files and registers schema in the Data Catalog, which Athena requires to run SQL queries — correct catalog layer.", "D": "EMR requires provisioning a cluster; expensive and over-engineered for periodic ad-hoc queries; not cost-effective.", "E": "Redshift is a provisioned data warehouse; significant cluster cost for periodic CSV queries when serverless Athena exists.", "F": "Athena is serverless SQL on S3; pay-per-query with no cluster to manage; ideal for periodic analyst queries — correct query layer. Correct three: A + C + F.", "_summary": "S3 File Gateway (ingest) + Glue crawler (catalog) + Athena (serverless SQL) = cheapest stack; voted hint AC is incomplete — F is the third correct choice"}, "583": {"A": "NFS staging + DataSync still pushes 5 PB over a 1 Gbps link — takes ~460 days, well beyond the 6-month window.", "B": "Writing directly to Glacier Deep Archive over the network hits the same 1 Gbps ceiling; 5 PB cannot transfer in 6 months regardless of destination.", "C": "Snowball devices with Tape Gateway copy physical tapes to virtual tapes offline, then ship to AWS physically, bypassing the bandwidth constraint entirely; a lifecycle policy then moves data to Glacier Deep Archive for cheapest long-term storage.", "D": "On-premises Tape Gateway streams data over the internet/Direct Connect; same bandwidth bottleneck as all network options — infeasible for 5 PB in 6 months.", "_summary": "5 PB + 1 Gbps + 6 months = network is impossible; Snowball physical shipment is the only viable path"}, "477": {"A": "This option likely scopes the allow statement to the bucket ARN only — object-level actions require the object ARN (bucket/*), so DeleteObject still fails.", "B": "This option likely grants DeleteObject on the bucket ARN (arn:aws:s3:::bucket) rather than the objects ARN — S3 silently requires the /* suffix for object operations.", "C": "This option likely adds overly broad permissions violating the stated least-privilege requirement; not the minimal correct fix.", "D": "Adds s3:DeleteObject scoped to the object ARN (arn:aws:s3:::bucket/*) — S3 separates bucket-level actions (ListBucket on bucket ARN) from object-level actions (DeleteObject on bucket/* ARN); this is the precise minimal addition.", "_summary": "S3 object actions need ARN ending /* ; bucket ARN alone never authorizes DeleteObject/GetObject/PutObject"}, "240": {"A": "Visualization on-premises queries pull 50 MB result sets out over internet egress on every query — highest-cost path.", "B": "Visualization in same region keeps 50 MB within AWS (free intra-region transfer); but users receive 500 KB pages over internet egress — moderate cost.", "C": "Visualization on-premises pulls 50 MB per query via Direct Connect — lower rate than internet but still charges per GB on large result volumes.", "D": "Visualization in same region eliminates the 50 MB egress entirely (free intra-region); users receive only 500 KB pages via Direct Connect at the lower Direct Connect rate — smallest chargeable data volume at cheapest per-GB rate.", "_summary": "Co-locate viz tool with DW to make 50 MB free; serve small 500 KB pages via Direct Connect for lowest net egress cost"}, "527": {"A": "ASGs are regional — cannot extend single ASG across regions. Wrong architecture for compute tier despite correct Aurora global DB mention.", "B": "Cross-region Aurora Replica has higher lag (~seconds) than Aurora Global Database (<1s RPO). Less fault-tolerant than Global DB; promotion process is manual and slower.", "C": "DMS is a migration tool, not a continuous replication solution for fault tolerance. Ongoing CDC via DMS is fragile compared to Aurora native global replication.", "D": "Correct. Aurora Global Database provides <1s cross-region replication and fast promoted secondaries. Separate compute stacks per region + Route 53 failover = proper multi-region active-passive.", "_summary": "Aurora Global Database vs cross-region replica; ASGs are regional constructs"}, "519": {"A": "CloudFormation gives templates but no governance layer, no self-service portal, no approval workflow — just IaC files.", "B": "Correct. Service Catalog is purpose-built: admin creates Products, customers self-service from a Portfolio with IAM controls and versioning.", "C": "Systems Manager manages existing AWS resources operationally; no catalog/self-service product concept.", "D": "Config tracks configuration compliance; not a deployment or self-service tool.", "_summary": "Service Catalog = centrally governed self-service product catalog"}, "452": {"A": "Fargate works but has per-second billing plus task startup overhead. More cost than Lambda for a 10s/hr workload.", "B": "Correct. Lambda billed only during 10s execution per hour = near-zero cost. EventBridge scheduled rule triggers exactly on interval. No idle infrastructure.", "C": "EC2 still running 24/7; container only saves compute inside the instance. Full instance cost persists.", "D": "EC2 stop/start has 1-minute minimum billing plus startup latency. Operationally complex and costlier than Lambda.", "_summary": "Lambda + EventBridge is optimal for short-duration scheduled jobs"}, "580": {"A": "FSx for Lustre is high-performance parallel FS for HPC workloads — expensive overkill for simple lift-and-shift.", "B": "GP2 is older generation: 3 IOPS/GB scaling, same price tier but worse baseline than GP3. Functionally fine but not most cost-effective.", "C": "FSx for OpenZFS is costlier than EBS and adds unnecessary complexity for locally-attached storage equivalent.", "D": "Correct. GP3 is 20% cheaper per GB than GP2, delivers 3000 IOPS/125 MBps baseline regardless of size, and is the direct EBS replacement for locally-attached latency-sensitive workloads.", "_summary": "GP3 supersedes GP2: cheaper, better baseline, no size-IOPS coupling"}, "862": {"A": "'Client-side encryption with S3 managed key' is contradictory — S3 managed keys (SSE-S3) are server-side. Data arrives at AWS unencrypted.", "B": "SSE-KMS encrypts at rest inside S3 but AWS receives plaintext over TLS. Data is accessible to AWS infrastructure before encryption — violates the third-party access requirement.", "C": "DSSE-KMS adds a second layer of server-side encryption but is still server-side. Same third-party exposure problem as B.", "D": "Correct. Client-side encryption with KMS: application encrypts locally before transmission. Data is ciphertext when it leaves the app — no third party (including AWS) sees plaintext.", "_summary": "Client-side encryption = only option guaranteeing pre-transmission encryption"}, "136": {"A": "Correct. DMS ongoing replication task (CDC mode) keeps source and target continuously synchronized during cutover window.", "B": "Backup file not required — DMS full-load + CDC reads directly from live source. Unnecessary step.", "C": "Correct. DMS replication instance is the compute resource that runs replication tasks — mandatory prerequisite.", "D": "SCT is for heterogeneous migrations (e.g., Oracle→Aurora). PostgreSQL→Aurora PostgreSQL is homogeneous; schema conversion not required.", "E": "EventBridge has no role in DMS replication setup or monitoring sync state — not a standard requirement.", "_summary": "DMS live migration requires replication instance (C) + ongoing CDC task (A)"}, "690": {"A": "S3 access points manage permissions/network access, not throughput.", "B": "Splitting across buckets adds complexity with no throughput benefit per-object; S3 per-prefix scaling is automatic since 2018.", "C": "Correct. Multipart upload parallelizes large-file uploads across multiple parts simultaneously, maximizing upload throughput.", "D": "Correct. Byte-range fetches parallelize downloads by requesting different object segments concurrently, maximizing download throughput.", "E": "Random prefixes were a pre-2018 workaround for partition hotspots; S3 now auto-scales per prefix — irrelevant for throughput today.", "_summary": "Multipart upload (C) scales upload throughput; byte-range fetch (D) scales download throughput"}, "412": {"A": "GuardDuty is threat detection, not access-control enforcement. Reactive Lambda remediation means objects are briefly public before fix.", "B": "Trusted Advisor is advisory + manual — no automated prevention. Unacceptable for 'must remain private' requirement.", "C": "AWS RAM manages cross-account resource sharing, not S3 public access controls. Wrong service entirely.", "D": "Correct. S3 Block Public Access at account level is a hard preventive control. SCP via AWS Organizations prevents any IAM principal from disabling it — proactive, not reactive, with zero exposure window.", "_summary": "Block Public Access + SCP = preventive account-wide control; all other options are reactive"}, "404": {"A": "Wrong. Timeout controls max execution duration per invocation, not whether invocations are accepted. Throttled/dropped triggers are lost before Lambda even starts.", "B": "Wrong. S3 replication copies objects to another bucket but does not queue processing requests or prevent dropped Lambda invocations during bursts.", "C": "Wrong. Lambda already scales horizontally to thousands of concurrent instances automatically; adding one more function does not help with throttling from burst S3 events.", "D": "Correct. SQS decouples ingestion from processing. Burst S3 events write to queue; Lambda polls at sustainable rate. No events lost — SQS persists messages until successfully processed.", "_summary": "SQS buffer prevents event loss when Lambda is throttled during traffic spikes"}, "383": {"A": "Correct. Dedicated Hosts expose physical socket and core counts required by socket/core licensing models. Reserved pricing (1- or 3-year) lowers cost. BYOL with this license type requires Host-level visibility, not just instance isolation.", "B": "Wrong. Dedicated On-Demand Hosts also expose socket/core topology for BYOL, but on-demand pricing is significantly more expensive than Reserved for predictable workloads.", "C": "Wrong. Dedicated Reserved Instances guarantee dedicated hardware but do not provide visibility into physical sockets/cores — cannot apply per-socket/per-core BYOL licenses on Dedicated Instances.", "D": "Wrong. Dedicated On-Demand Instances: same problem as C (no socket/core visibility) plus highest cost tier.", "_summary": "Socket/core BYOL licensing requires Dedicated Hosts (not Instances) for physical topology visibility; Reserved cuts cost"}, "367": {"A": "Correct. NLB operates at L4 and supports UDP, so it can front on-premises UDP servers via IP targets. Global Accelerator routes over AWS backbone using anycast, improving latency and availability globally.", "B": "Wrong. ALB is an L7 HTTP/HTTPS load balancer — does not support UDP traffic at all. Fails for a UDP-based application.", "C": "Wrong. CloudFront is an HTTP/HTTPS CDN; does not support UDP. Using CloudFront in front of NLBs for a UDP application is architecturally invalid.", "D": "Wrong. Two errors: ALB does not support UDP, and CloudFront does not support UDP. Both components incompatible with UDP application.", "_summary": "UDP needs NLB (L4); Global Accelerator provides anycast + AWS backbone performance; CloudFront and ALB incompatible with UDP"}, "354": {"A": "Wrong. Reducing Lambda concurrency limits throughput but does not fix timeouts — fewer requests served, not fewer failures.", "B": "Correct. RDS Proxy maintains a persistent connection pool between Lambda and RDS. Lambda connects to the proxy instantly rather than opening a new DB connection each time. Eliminates connection exhaustion on spikes with no code changes.", "C": "Wrong. Upsizing the DB instance increases max_connections somewhat, but Lambda can scale to thousands of concurrent executions — a larger instance still gets overwhelmed. Treats symptom, not cause.", "D": "Wrong. Migrating from PostgreSQL to DynamoDB requires substantial code rewrites (different query model, no SQL). Violates the least-change requirement.", "_summary": "RDS Proxy pools Lambda-to-RDS connections, eliminating connection exhaustion during Lambda concurrency spikes with no code changes"}, "349": {"A": "Aurora/RDS won't let you create an unencrypted copy of an encrypted snapshot — encryption cannot be stripped at copy time.", "B": "Correct. Share encrypted snapshot cross-account by (1) granting the target account access via CMK key policy and (2) sharing the snapshot. Both steps required; this option does both.", "C": "AWS managed keys cannot have their key policies modified to add external accounts — only customer managed keys allow that. Also key aliases can't grant cross-account access.", "D": "Aurora snapshots aren't directly downloadable as files; this workflow doesn't exist for Aurora.", "_summary": "Cross-account encrypted Aurora snapshot sharing: grant CMK key policy access + share snapshot"}, "339": {"A": "KMS stores encryption keys, not credentials. You'd still need to put DB credentials somewhere; KMS alone can't solve this.", "B": "Works but requires writing and maintaining a custom Lambda rotation function — more programming effort than C.", "C": "Correct. Secrets Manager has native built-in RDS rotation integration — no Lambda code to write. Minimum effort: store secret, point app at Secrets Manager, enable rotation schedule.", "D": "Parameter Store has no native RDS credential rotation. Custom rotation logic required — more effort, not less.", "_summary": "Secrets Manager + native RDS rotation = least-code credential management"}, "337": {"A": "Correct. Aurora Replicas share the same underlying storage cluster as the primary — replication lag is typically single-digit milliseconds, far under 1 s. Aurora MySQL is fully MySQL-compatible so stored procedures run unchanged; Auto Scaling handles traffic spikes.", "B": "ElastiCache requires app-side cache-check logic (code change) and stored procedures → Lambda is a major rewrite. Violates both constraints.", "C": "Self-managed MySQL on EC2 increases operational overhead and doesn't fundamentally solve storage-layer replication lag.", "D": "DynamoDB is a NoSQL key-value store; migrating from relational MySQL with stored procedures is a complete rewrite. Violates 'minimize code changes'.", "_summary": "Aurora shared-storage architecture eliminates replication lag; Aurora Replicas stay sub-second by design"}, "334": {"A": "Correct. AWS Transfer Family natively supports SFTP, integrates directly with on-premises AD for authentication, and serves S3 as the backend. Zero app changes, minimal ops.", "B": "AWS DMS migrates databases, not file systems. Wrong service category entirely.", "C": "DataSync moves data; it's not an SFTP endpoint and doesn't give users interactive file access.", "D": "Windows EC2 + custom SFTP server has high operational overhead (OS patching, SFTP software, IAM wiring). Violates least-overhead constraint.", "_summary": "Transfer Family = managed SFTP + S3 backend + AD auth, no app changes"}, "332": {"A": "Public subnet exposes file server to internet — wrong security posture for confidential files.", "B": "Correct. FSx for Windows File Server supports SMB/AD natively; integrating with on-premises AD preserves existing auth. Client VPN provides encrypted tunnel so remote employees access files securely without exposing FSx publicly.", "C": "S3 doesn't speak SMB or support Windows AD file-share semantics. Signed URLs are temporary HTTP links, not a file-server replacement.", "D": "Public VPC endpoint is a security red flag for confidential data. S3 also doesn't replace Windows file server behavior.", "_summary": "FSx for Windows + AD integration + Client VPN = secure, capacity-scalable Windows file access"}, "558": {"A": "Transit Gateway charges $0.05/hr per attachment plus per-GB processing fees — more expensive than peering for two VPCs in the same account/region.", "B": "Site-to-Site VPN is designed for on-premises↔AWS connectivity, has hourly tunnel charges, and adds unnecessary complexity for intra-region VPC traffic.", "C": "Correct. VPC peering within the same region and same account has no data-transfer charge within the same AZ ($0.01/GB cross-AZ). No hourly fees. Cheapest possible option for same-region VPC connectivity.", "D": "Direct Connect is for on-premises to AWS. It cannot directly connect two VPCs and requires costly port/circuit fees.", "_summary": "Same-region VPC peering = $0 data transfer (same AZ) — cheapest intra-region VPC option"}, "552": {"A": "Reserved Instances lock to a specific instance type and family — can't freely change family every 2-3 months. 3-year term compounds inflexibility.", "B": "Correct. Compute Savings Plans apply across any EC2 instance type, family, OS, and region. Changing instance family has zero plan-impact. 1-year term is shortest commitment. No Upfront minimizes cash outlay.", "C": "Standard RIs lock to instance family; Convertible RIs allow exchanges but with process friction. All Upfront requires large cash commitment.", "D": "EC2 Instance Savings Plans are family-specific (e.g., locked to m5 in us-east-1) — changing family breaks the discount. Less flexible than Compute Savings Plans.", "_summary": "Compute Savings Plan = instance-family-agnostic discount; right tool when type/family changes frequently"}, "301": {"A": "Snowcone max capacity is 8 TB — cannot fit 30 TB in a single device.", "B": "FSx File Gateway provides on-premises SMB/NFS access to S3; it's an access layer, not a migration tool for FSx.", "C": "Correct. DataSync supports Windows SMB file servers as source and FSx for Windows as destination. Critical: DataSync has built-in bandwidth throttling schedules, satisfying the shared-link constraint. It parallelizes transfers to maximize throughput within that budget.", "D": "Transfer Family is a managed SFTP/FTPS server endpoint — not a bulk migration engine for moving data between file systems.", "_summary": "DataSync: Windows SMB→FSx migration with bandwidth throttling to protect shared 1 Gbps link"}, "288": {"A": "S3 lacks POSIX/NFS interface — mounting requires app changes or an NFS gateway layer, violating the no-change constraint.", "B": "CloudFront+S3 is a CDN solution, not a shared filesystem mount; app would need rewrite to use S3 APIs.", "C": "EFS exposes NFSv4 — Linux EC2 can mount it natively, zero app changes, multi-instance concurrent access. Correct.", "D": "EBS is block storage attached to one instance at a time (Multi-Attach only on io1/io2, same AZ); cannot be shared across a web server group.", "_summary": "EFS = NFS mount for shared Linux file access, no app changes"}, "287": {"A": "FSx File Gateway sits on premises to cache FSx data locally — no value for EC2-to-EC2 file sharing already in AWS.", "B": "FSx for Windows File Server is SMB-native, AD-integrated, Windows-compatible; SQL Server stays on EC2 so native backups and Data Quality Services are fully supported. Correct.", "C": "RDS SQL Server strips DBA-level control: native backup/restore and Data Quality Services not available. EFS is NFS, not SMB, so Windows clients cannot use it natively.", "D": "RDS same problem as C. EBS io2 cannot be attached to multiple instances simultaneously for cross-tier file sharing.", "_summary": "EC2 SQL Server + FSx for Windows FS = full SQL Server feature access + SMB file sharing"}, "284": {"A": "Athena can query Cost and Usage Reports but requires CUR export setup first — more setup, not most efficient for an ad-hoc grouped report.", "B": "Cost Explorer has built-in grouping by user/tag, downloadable CSV, no additional infrastructure needed. Correct.", "C": "Billing dashboard shows totals and line items but not grouped per-IAM-user; requires manual slicing.", "D": "AWS Budgets with SES sends alerts when thresholds hit — not a line-item report by user.", "_summary": "Cost Explorer = quickest path to user-grouped billing report"}, "283": {"A": "Lambda cannot run a Windows desktop GUI app; Lambda has no persistent NFS/SMB mount support.", "B": "FSx File Gateway is for on-premises clients to access FSx — not designed for EC2 workloads already in AWS. ECS is also unsuitable for a Windows desktop app.", "C": "SQS is a message queue, not a filesystem; simulation app writes to NFS share — switching to SQS requires code changes.", "D": "FSx for NetApp ONTAP supports NFS (for Linux simulation) and SMB (for Windows visualization) concurrently on the same volume, eliminating duplication with zero app changes. Correct.", "_summary": "FSx ONTAP = single storage serving NFS + SMB simultaneously"}, "274": {"A": "AMIs to secondary region is correct strategy, but Lambda+custom scripts is bespoke and harder to maintain than managed IaC.", "B": "AMIs copied to secondary region preserve data at rest; CloudFormation automates infra deployment on failover. No resources running until needed — fewest resources, RTO well under 4 hours. Correct.", "C": "Active EC2 in secondary region = warm standby — meets RTO but uses resources continuously, violating fewest-resources constraint.", "D": "Secondary AZ ≠ DR region; AZ redundancy is HA, not disaster recovery from a regional failure.", "_summary": "Backup-restore with AMI + CloudFormation = low-cost DR under 4 hr RTO"}, "265": {"A": "EC2 in public subnets are directly internet-reachable even if behind ALB — unnecessarily broad attack surface.", "B": "Using EC2 instances directly as CloudFront origin forces those instances to be publicly accessible; skips ALB layer, less secure and less scalable.", "C": "CloudFront at edge (lowest latency), ALB in public subnet terminates HTTPS, EC2 in private subnets never exposed to internet. Layered security + edge delivery. Correct.", "D": "EC2 in public subnets same problem as A; using EC2 directly as CF origin same problem as B.", "_summary": "CloudFront → public ALB → private EC2 = edge delivery + defense in depth"}, "263": {"A": "ECS cluster is the required control-plane foundation for running ECS services — must be provisioned first. Correct (pair with D).", "B": "Self-managed Kubernetes control plane on EC2 = managing additional infrastructure, violates the constraint.", "C": "ECS with EC2 launch type still requires managing the underlying EC2 instances — not serverless.", "D": "Fargate launch type removes all node/instance management; AWS scales tasks automatically. No infrastructure to manage. Correct (pair with A).", "E": "Self-managed Kubernetes worker nodes on EC2 = managing EC2 + Kubernetes — maximum operational overhead.", "_summary": "ECS cluster + Fargate = serverless containers, zero node management"}, "259": {"A": "AWS Backup supports RDS, enforces retention policies up to years, centrally managed, snapshots are consistent and directly restorable. Correct.", "B": "RDS automated backup retention max is 35 days — cannot reach 2 years natively. DLM manages EBS snapshots, not RDS.", "C": "CloudWatch Logs stores log streams, not database snapshots; cannot be used to restore an RDS instance.", "D": "DMS CDC streams change events to S3 — not full consistent snapshots; cannot restore a point-in-time RDS instance directly from CDC data.", "_summary": "AWS Backup vault = only managed way to retain RDS backups beyond 35-day native limit"}, "220": {"A": "Glue is an ETL service for batch data jobs — wrong tool for API compute, and always-on cost regardless of invocations.", "B": "Lambda is pay-per-invocation, scales to zero between requests, and supports async invocation via SQS/SNS — perfect fit for spiky variable traffic at lowest cost.", "C": "EKS worker nodes run continuously; idle hours still bill EC2 compute — too expensive for near-zero traffic periods.", "D": "EC2 in ECS charges even when idle; no scale-to-zero — defeats cost goal for highly variable load.", "_summary": "Scale-to-zero serverless (Lambda) wins for spiky async workloads"}, "206": {"A": "Lambda polling CloudTrail logs requires scheduled queries or stream logic — high complexity and lag, not event-driven.", "B": "CloudTrail→S3→SNS→Athena is a multi-service chain requiring table setup and query logic — high operational overhead.", "C": "EventBridge natively captures any CloudTrail API call as an event; rule targets SNS directly — zero custom code, lowest overhead.", "D": "SQS FIFO→Lambda→SNS adds three hops where EventBridge+SNS does the same in one rule.", "_summary": "EventBridge rules on CloudTrail API events = native, zero-code alerting"}, "704": {"A": "ALB operates at Layer 7 (HTTP/HTTPS only) — does not support UDP traffic at all.", "B": "Gateway Load Balancer is for inline third-party virtual appliances (IDS/IPS/firewalls), not for distributing game traffic to EC2 targets.", "C": "NLB operates at Layer 4, supports UDP natively, handles millions of requests per second, and delivers ultra-low latency — exact fit.", "D": "Duplicating servers across Regions solves geographic distribution, not load balancing UDP traffic at scale — wrong problem.", "_summary": "NLB is the only AWS LB with UDP support and millions-RPS ultra-low latency"}, "777": {"A": "AMI launch permissions accept OU ARNs when accounts are in AWS Organizations — grants the entire development OU access to launch the AMI.", "B": "Organizations root ARN grants every OU in the org access — overly broad, violates least-privilege.", "C": "KMS key policy must explicitly allow the development OU's principals to use the key for decryption; without this, EC2 can't decrypt the snapshot even with launch permission.", "D": "Account-level ARN works but targets individual accounts, not the OU as a whole — does not scale across the development OU without listing every account.", "E": "Recreating the KMS key invalidates all existing encrypted snapshots/volumes relying on the old key — destructive and unnecessary.", "_summary": "Share KMS-encrypted AMIs to OU: launch permission on OU ARN + KMS key policy for OU"}, "776": {"A": "Aurora with read replicas still has RDS-level latency (single-digit ms) — does not meet sub-millisecond requirement.", "B": "DynamoDB global tables solve multi-region replication but require schema redesign from relational model — different requirement set.", "C": "ElastiCache for Redis supports persistence (RDB snapshots), replication (primary+replicas), and delivers sub-millisecond reads — satisfies all three stated requirements as a cache layer in front of RDS.", "D": "ElastiCache for Memcached has no snapshot support and no replication — explicitly fails two of the stated requirements.", "_summary": "Redis layer covers all three: snapshots + replication + sub-ms latency; Memcached lacks both first two"}, "487": {"A": "FSx family products (Windows File Server, Lustre, NetApp ONTAP) all have minimum capacity requirements, and FSx for Windows does not mount natively on Linux via NFS without extra config.", "B": "EBS Multi-Attach is block storage, limited to a single AZ, and restricted to Nitro EC2 instances — not a file system, not cross-AZ, not on-premises.", "C": "EFS uses NFSv4 (native Linux protocol), has no minimum storage requirement, scales automatically, is Multi-AZ by default, and is accessible from on-premises over Site-to-Site VPN — all requirements satisfied.", "D": "Single mount target = single AZ = not highly available; access points control NFS path permissions, not availability — fails the HA requirement.", "_summary": "EFS: NFS-native, no minimum size, Multi-AZ HA, VPN-accessible from on-premises"}, "766": {"A": "Bastion in a private subnet is unreachable from the internet; ec2:CreateVpnConnection is an unrelated permission — architecturally broken.", "B": "Site-to-Site VPN covers corporate office but remote developers need a separate client VPN solution — incomplete and costly to operate.", "C": "Public bastion works but requires a running EC2 instance (cost), key management, and security group maintenance — higher cost and overhead than D.", "D": "SSM Session Manager requires no open ports, no bastion EC2, works from anywhere with internet/SSM endpoint access, and the AmazonSSMManagedInstanceCore policy is free — most cost-effective secure access.", "_summary": "SSM Session Manager: no bastion, no open SSH ports, works remote+office, zero extra cost"}, "760": {"A": "Lambda cannot mount S3 as a POSIX filesystem; this is not a supported integration pattern.", "B": "Lambda cannot attach EBS volumes — EBS requires a running EC2 instance as the compute layer.", "C": "ECS Fargate is fully serverless (no EC2 management), and EFS provides elastic shared storage well above 50 GB — serverless + persistent large storage, least overhead.", "D": "ECS with EC2 launch type requires provisioning and managing EC2 instances — not serverless, violates the requirement.", "_summary": "Fargate + EFS = serverless containers with scalable file storage; EC2 launch type breaks serverless constraint"}, "756": {"A": "S3 Object Lambda intercepts GET requests and runs Lambda inline — PII redacted on-the-fly, no copy, scales automatically with S3 demand. Correct.", "B": "EC2 batch job copies+redacts to second bucket — works but requires managing EC2 scheduling and capacity. More overhead.", "C": "EC2 web app redacts on download — same EC2 management burden plus manual workflow. Even more overhead.", "D": "Lambda extracts non-PII into DynamoDB — changes data format entirely (text files → DB rows), lossy, and forces provider to query DB instead of reading files. Wrong shape.", "_summary": "S3 Object Lambda: serverless inline redaction on GET, zero extra storage"}, "948": {"A": "Multi-AZ DMS gives HA failover but provisions fixed capacity — doesn't auto-scale with varying load. Wrong axis.", "B": "DMS Serverless auto-analyzes workload and scales replication capacity up/down dynamically — only allocates what's needed. Correct.", "C": "EC2 Auto Scaling does not manage DMS replication instances — DMS instances are not EC2 ASG targets. Invalid mechanism.", "D": "DMS does not run on ECS/Fargate — this is not how DMS infrastructure works. Fabricated option.", "_summary": "DMS Serverless: elastic capacity, no fixed provisioning"}, "439": {"A": "VPCs support adding secondary IPv4 CIDR blocks — new subnets in same VPC, no cross-VPC routing, no peering setup. Least overhead. Correct.", "B": "VPC peering + second VPC works but requires new VPC, peering connection, and route table updates in both VPCs. More overhead.", "C": "Transit Gateway adds another managed service plus second VPC — most capable but most overhead and cost for this simple problem.", "D": "Site-to-Site VPN over EC2 is the highest operational burden: EC2 instance, VPN config, route management. Worst choice.", "_summary": "Add secondary CIDR to existing VPC — no new VPC, no peering required"}, "406": {"A": "NACLs are stateless — denying outbound 3306 breaks DB→web response traffic. Also NACLs apply to subnet, not to specific instances. Incorrect.", "B": "Allowing traffic from subnet CIDR permits any future instance in that subnet to reach DB — not just web servers. Less precise, not best practice.", "C": "SG rule allowing 0.0.0.0/0 on 443 for web servers — correct way to expose web tier to internet. Correct.", "D": "Referencing web servers' SG as source on port 3306 — most precise, only web server instances can reach DB regardless of subnet. Correct.", "E": "SGs are allow-only; deny rules don't exist on security groups (that's NACLs). Default-deny is implicit — explicit deny rule is invalid and unnecessary.", "_summary": "SG reference (not CIDR) for DB access + allow 443 from internet on web SG"}, "165": {"A": "WAF has no ARN that S3 bucket policies can use as a principal — traffic flows client→CloudFront→S3, not through WAF at the S3 level. Invalid.", "B": "CloudFront doesn't forward to WAF as a proxy step — WAF is attached to the distribution and inspects inline. Description of flow is wrong.", "C": "S3 is a public service, not inside a VPC — security groups don't apply to S3 endpoints. Invalid.", "D": "OAI locks S3 to CloudFront-only access (no direct S3 URL bypass); WAF on distribution inspects every request before origin fetch. Correct.", "_summary": "OAI forces all traffic through CloudFront where WAF sits — no S3 bypass possible"}, "244": {"A": "Both EC2 instances in same AZ — single AZ = not HA. ALB in one AZ also not redundant. Fails HA requirement.", "B": "Aurora read replica in same AZ as EC2 — DB tier still single-AZ. Same HA failure.", "C": "Aurora cross-AZ replica + ASG + ALB across two AZs — web and DB tiers both multi-AZ. Scales automatically. Correct.", "D": "DB on EC2 with S3 backups — unmanaged DB, no HA for DB tier, S3 backups don't provide failover. ASG helps web tier but DB is still SPOF.", "_summary": "Separate managed multi-AZ DB + multi-AZ ASG = full HA and elasticity"}, "243": {"A": "Storage Gateway file gateway caches S3 objects locally as NFS/SMB shares — on-prem file-based apps see low-latency local cache, backed by read-only S3 bucket. Correct.", "B": "DataSync is a migration/sync tool, not a live access layer — moves data on schedule, doesn't present files for ongoing application use.", "C": "Volume gateway exposes iSCSI block volumes — not file protocol, wrong fit for file-based applications reading S3 objects.", "D": "EFS on-prem mount requires Direct Connect or VPN and doesn't map to an S3 bucket — wrong service, higher complexity, not backed by existing S3 data.", "_summary": "File gateway: local NFS/SMB cache in front of S3, minimum latency for on-prem apps"}, "822": {"A": "S3 Intelligent-Tiering auto-moves objects between frequent/infrequent/archive tiers — far cheaper than EFS per GB, no retrieval delay for active tiers. App update needed but cost savings large. Correct.", "B": "FSx for Windows uses SMB/CIFS — EC2 Linux instances use NFS, not CIFS. Wrong OS protocol. Also more expensive than S3.", "C": "FSx for OpenZFS is a managed file system — still per-GB file system pricing, not significantly cheaper than EFS for this workload.", "D": "S3 Glacier Flexible Retrieval has minutes-to-hours retrieval latency — indexing application needs files on demand, can't wait for Glacier restores. Wrong tier for active use.", "_summary": "S3 Intelligent-Tiering beats EFS cost; app must switch to S3 API"}, "816": {"A": "AWS DMS migrates databases, not files; wrong service for SFTP file transfer to S3.", "B": "AWS Transfer Family provides managed SFTP/FTPS/FTP endpoints that land files directly in S3 — purpose-built, zero server management.", "C": "EC2 SFTP server works but requires OS patching, HA setup, scaling — not managed, high overhead.", "D": "S3 File Gateway uses SMB protocol, not SFTP; wrong protocol for legacy SFTP vendors.", "_summary": "AWS Transfer Family = managed SFTP → S3 with no servers"}, "592": {"A": "Public bucket exposes copyrighted content to anyone; no geo-restriction; MFA doesn't block countries.", "B": "Per-customer IAM users don't scale and provide no geo-restriction or CDN performance.", "C": "Deploying EC2+ALB per country is expensive, complex, no built-in geo-blocking; highest cost option.", "D": "CloudFront geo-restriction blocks specific countries at edge; signed URLs enforce per-customer access; S3+CloudFront is cheapest at scale for static content.", "_summary": "CloudFront geo-restriction + signed URLs = access control + global performance + low cost"}, "590": {"A": "Read replica accepts read traffic; reporting queries offload from primary DB, preserving daily workload performance on primary.", "B": "Restoring a backup is manual and produces stale data; operational overhead high, not near-real-time.", "C": "S3 export+Athena adds ETL complexity and latency; data currency issues for monthly reports.", "D": "Upsizing for a monthly peak wastes money 29 days/month and doesn't isolate report query impact.", "_summary": "Read replica isolates reporting load from OLTP primary"}, "686": {"A": "VPC peering has no transitive routing; mesh grows as O(n²); VPN per-site multiplies connections.", "B": "EC2-based VPN software not managed; single point of failure; patching/scaling burden stays with you.", "C": "Transit Gateway is a managed regional hub — attach VPCs and VPN connections once; new accounts/VPCs join by adding one attachment, routing handled centrally.", "D": "Direct Connect is expensive per-location; VPC peering still can't transit, so mesh problem remains.", "_summary": "Transit Gateway = hub-and-spoke managed routing for many VPCs + on-premises"}, "907": {"A": "VPC endpoint routes internal VPC traffic to S3 privately; doesn't grant CloudFormation (control plane) access to a private bucket object for template retrieval.", "B": "API Gateway proxy to S3 is non-standard, adds latency and complexity; not a CloudFormation-native pattern.", "C": "Presigned URL grants time-limited, request-scoped access to a private S3 object; CloudFormation accepts presigned URLs as template source; no bucket policy changes needed.", "D": "Making object public then re-blocking is error-prone, violates least-privilege, and risks exposure window.", "_summary": "Presigned URL = temporary scoped access to private S3 template, least privilege"}, "827": {"A": "Aurora Standard charges per I/O operation; under high sustained traffic I/O costs grow unboundedly, making it expensive at scale.", "B": "Provisioned IOPS is an EBS/RDS storage type, not an Aurora storage configuration; this option doesn't exist for Aurora.", "C": "General Purpose (gp2/gp3) is EBS terminology; Aurora doesn't offer this as a named storage tier.", "D": "Aurora I/O-Optimized bundles I/O into storage pricing — no per-request I/O charges; cost-effective when I/O spend would exceed ~25% of total Aurora cost, which is expected under large traffic.", "_summary": "Aurora I/O-Optimized eliminates per-I/O charges for high-throughput workloads"}, "894": {"A": "S3 static hosting eliminates EC2/ALB costs entirely; CloudFront caches at edge globally, reduces origin hits and data transfer cost — cheapest architecture for static content.", "B": "ElastiCache is an in-memory cache for application data (Redis/Memcached); it cannot serve or cache S3 static websites.", "C": "Amplify can host static sites but routing through an ALB adds unnecessary cost and latency; ALB is redundant here.", "D": "Caching an Amplify site via EC2 is backwards — EC2 is the expensive component being replaced, not a caching layer.", "_summary": "S3 + CloudFront = cheapest static website hosting with global edge caching"}, "480": {"A": "KMS manages encryption keys; does not control network routing or prevent traffic from traversing the internet.", "B": "S3 Gateway VPC endpoint routes traffic from EC2 to S3 through AWS private network via route table entries; traffic never leaves AWS backbone or hits public internet.", "C": "Private subnet keeps EC2 off the public internet but without a VPC endpoint, S3 API calls still route through the public S3 endpoints via a NAT gateway or internet gateway.", "D": "Virtual private gateway terminates VPN/Direct Connect from on-premises; irrelevant for EC2-to-S3 traffic within AWS.", "_summary": "S3 Gateway VPC endpoint keeps EC2→S3 traffic on AWS private network"}, "51": {"A": "Kinesis Data Firehose streams data to S3/Redshift/etc — no scheduling or email capability; wrong tool for this job.", "B": "SES sends formatted HTML email to multiple recipients — exactly what's needed for the report delivery step.", "C": "Glue is ETL for large-scale data transformation jobs, not for querying a REST API; Lambda is the right compute here.", "D": "EventBridge cron triggers Lambda on a schedule; Lambda can call the REST API, build HTML, and invoke SES — correct orchestration layer.", "E": "SNS email notifications send plain text/JSON, cannot format HTML reports; also adds unnecessary S3 hop.", "_summary": "Scheduled EventBridge→Lambda queries API and formats HTML; SES delivers HTML email"}, "488": {"A": "This grants billing access to IAM users; the requirement is to DENY access, and IAM policies can't restrict root anyway.", "B": "IAM identity-based deny policies have no effect on root users — root bypasses all IAM policies by design.", "C": "SCPs override even root users of member accounts (not the management account); attaching a deny SCP at the root OU blocks billing access organization-wide including root. Correct.", "D": "Switching to consolidated billing removes SCP capability entirely — the opposite of what's needed.", "_summary": "Only SCPs can restrict root users of member accounts; attach deny SCP at root OU"}, "457": {"A": "DataSync moves data between storage systems (NFS, S3, etc.) and has no AS2 protocol support.", "B": "AppFlow integrates SaaS applications (Salesforce, Marketo); no AS2 support and not designed for B2B file transfer.", "C": "AWS Transfer Family natively supports AS2 protocol for B2B trading-partner transfers; Lambda custom IdP connector handles third-party identity providers. Correct.", "D": "Storage Gateway is hybrid cloud storage (NFS/SMB/iSCSI); no AS2 support; Cognito identity pools are for app-user federation, not custom IdP auth for Transfer Family.", "_summary": "Transfer Family = only AWS service with AS2; Lambda handles custom IdP authentication"}, "695": {"A": "ElastiCache reduces load but provides zero observability into performance bottlenecks or inter-service call behavior.", "B": "Container Insights collects EKS cluster/pod/node metrics; X-Ray traces distributed requests across microservices — together they cover both metrics and tracing for full observability. Correct.", "C": "CloudTrail records AWS API control-plane calls, not application-level microservice interactions or latency.", "D": "Trusted Advisor checks account-level best practices (cost, security, limits) — not application performance observability.", "_summary": "Container Insights (metrics) + X-Ray (distributed tracing) = EKS observability stack"}, "694": {"A": "Sticky sessions tie users to one instance — breaks HA; Aurora is relational, not ideal for session/cart key-value data.", "B": "ElastiCache for Redis caches the monthly catalog (low write, high read) and persists shopping cart/session data with TTL; Redis survives disconnect/reconnect via persistent sessions. Correct.", "C": "OpenSearch is a search/analytics engine, not a caching or session store; high cost and operational overhead for this use case.", "D": "EBS is attached to a single EC2 instance — no horizontal scaling, single point of failure, not suitable for distributed session state.", "_summary": "Redis caches static catalog + stores durable session/cart data with persistence across disconnects"}, "693": {"A": "NLB is layer-4 and adds no benefit over ALB for HTTP workloads; self-managing NoSQL replication across AZs is high operational overhead.", "B": "NLB is wrong for web app traffic (ALB handles HTTP/HTTPS better); DynamoDB migration is correct but pairing with NLB makes this answer wrong.", "C": "Multi-AZ Auto Scaling achieves HA, but self-managing embedded NoSQL replication across AZs is complex and high operational overhead.", "D": "Multi-AZ Auto Scaling gives HA across three AZs; migrating to DynamoDB (managed, eventually consistent, serverless) eliminates replication management entirely — least operational overhead. Correct.", "_summary": "Multi-AZ ASG + managed DynamoDB = HA with eventual consistency and zero replication ops"}, "688": {"A": "Creating users per-account duplicates identities; IAM Identity Center is designed for central single-identity management — this defeats the purpose.", "B": "Attaching managed policies to individual users instead of groups doesn't scale; new hires require per-user policy assignments.", "C": "Centralized users, role-based groups, permission sets (reusable IAM policy bundles) assigned to accounts — onboarding a new hire = add to group only. Least overhead. Correct.", "D": "Per-user permission sets and per-account assignments create N×M management complexity; adding IAM permissions inside accounts breaks central governance.", "_summary": "IAM Identity Center: users → groups → permission sets → accounts is the scalable least-overhead pattern"}, "682": {"A": "AWS Config rule (encrypted-volumes) detects noncompliant EBS; SSM Automation remediates automatically — native, managed, least overhead. Correct.", "B": "KMS manages keys but doesn't detect unencrypted volumes; Lambda+EventBridge solution requires custom code to build and maintain.", "C": "Macie detects sensitive data in S3 objects — it has no visibility into EBS volume encryption status.", "D": "Inspector scans for software vulnerabilities and CVEs — it does not evaluate EBS encryption compliance.", "_summary": "AWS Config detects unencrypted EBS; SSM Automation auto-remediates — no custom code needed"}, "304": {"A": "DataSync purpose-built for NFS-to-NFS cross-region transfers; scheduled tasks, managed service, zero server overhead.", "B": "Snowball physical device — requires shipping, weeks of latency, no periodic automation.", "C": "SFTP on EC2 requires you manage server, transfers, scheduling, certs — high overhead.", "D": "DMS migrates databases (structured data), not NFS file system data.", "_summary": "DataSync = managed NFS/cross-region periodic sync"}, "655": {"A": "NLB operates L4 — no WAF support (WAF requires L7), no sticky sessions via cookies.", "B": "GWLB routes traffic to security appliances (firewalls) — not a public web endpoint.", "C": "ALB operates L7 — supports WAF association, sticky sessions (cookie-based), public internet-facing.", "D": "Elastic IPs on EC2 + second target group adds complexity without WAF or sticky session handling.", "E": "WAF web ACL must be associated with ALB to inspect HTTP traffic — required step.", "_summary": "ALB = only LB type supporting both WAF + sticky sessions"}, "641": {"A": "Kinesis + EMR: streaming pipeline overkill for once-monthly batch query; high cost, high ops.", "B": "CUR to S3 + Athena: serverless, pay-per-query, no infrastructure; ideal for periodic ad-hoc analysis on management account consolidated report.", "C": "CUR per member account duplicates data; Redshift requires cluster provisioning — more cost/ops.", "D": "Per-member CUR + Kinesis + QuickSight: streaming ingestion unnecessary for monthly cadence; QuickSight alone doesn't query raw CUR well.", "_summary": "CUR → S3 → Athena = serverless cost analysis pattern"}, "619": {"A": "IAM policy on root user has no effect — root user bypasses IAM policies by design.", "B": "Creating a trail with org option enabled from developer account still lets that developer delete/modify it.", "C": "SCP applies at the OU/account level in Organizations and restricts even root users within member accounts — correct way to enforce immutable controls.", "D": "Service-linked roles for CloudTrail don't support conditional enforcement preventing modifications from within the account.", "_summary": "SCPs restrict root users in member accounts — IAM policies do not"}, "602": {"A": "Manual snapshots + CloudFormation = some automation but requires per-instance effort; not least effort at scale.", "B": "Elastic Beanstalk manages app environments, not DR restore of arbitrary EC2 fleets.", "C": "AWS Backup centralizes policy-driven backup across all EC2/EBS; single backup plan covers entire fleet, CLI/API allows parallel bulk restore — least effort at scale.", "D": "Custom Lambda for snapshots + AMI copies + restore logic = high development and maintenance overhead.", "_summary": "AWS Backup = centralized EC2/EBS DR with least operational effort"}, "325": {"A": "Cognito identity pool exchanges JWT for temporary AWS credentials via IAM role assumption — correct mechanism to grant S3 access to authenticated users.", "B": "S3 ACLs grant access to AWS principals/accounts, not to Cognito-authenticated end users presenting JWTs.", "C": "Eventual consistency is not the issue; permissions are the stated problem.", "D": "Custom attribute mappings in identity pools don't grant S3 permissions — IAM role assumption does.", "_summary": "Cognito identity pool → IAM role assumption → S3 access"}, "574": {"A": "Aurora Serverless v2 scales to zero (or near-zero) when idle — only pay during 2-hour weekly window; most cost-effective for intermittent workloads.", "B": "Aurora provisioned cluster charges continuously regardless of usage — no cost benefit for 2h/week.", "C": "EC2 Reserved Instance charges 24/7 for 1–3 year term — worst fit for 2h/week usage.", "D": "ECS MySQL containers don't pause billing automatically and add operational complexity vs managed RDS.", "_summary": "Aurora Serverless v2 = pay-per-use, idle cost near zero"}, "554": {"A": "SAP apps also have high memory utilization per the data — compute optimized (CPU-focused) undersupplies memory for the app tier.", "B": "Storage optimized (I/O-heavy) wrong for memory-bound workloads.", "C": "Both SAP application and database show high memory utilization — memory optimized (R/X/z families) correct for both tiers.", "D": "HPC optimized (hpc6a/7g) targets tightly-coupled parallel compute, not general SAP app memory needs.", "_summary": "Memory optimized instances for high-RAM SAP app + DB tiers"}, "345": {"A": "Cognito handles serverless auth scaling to any user count at low cost; Lambda@Edge runs authorization logic at CloudFront edge PoPs, giving lowest possible login latency; CloudFront serves content globally — all three requirements met serverlessly.", "B": "Directory Service for Managed AD requires dedicated domain controllers — not serverless, not cost-effective for <100 users; ALB is regional, not a global CDN.", "C": "S3 Transfer Acceleration optimizes uploads to S3, not global web app delivery; regional Lambda adds latency vs Lambda@Edge; Cognito part is correct but overall solution fails global low-latency requirement.", "D": "Directory Service again kills serverless requirement; Elastic Beanstalk is a managed EC2 platform, not serverless and not a global CDN.", "_summary": "Serverless global auth: Cognito + Lambda@Edge + CloudFront"}, "455": {"A": "AWS Budgets is configured under the Billing & Cost Management console/Billing dashboard — Cost and Usage Reports is a separate data export service, wrong location.", "B": "Correct location: budgets are created and managed in the Billing dashboard of each account.", "C": "Budget actions require an IAM role (not user) so Budgets can assume it to execute the action on your behalf.", "D": "Correct: IAM role grants Budgets the permissions needed to execute budget actions (attach SCP, apply IAM policy, etc.).", "E": "'Config rule' is an AWS Config concept unrelated to budget actions; budget actions attach IAM policies or SCPs, not config rules.", "F": "Correct: budget action can attach an SCP to the account when threshold is breached, blocking provisioning — requires the role from D. Full answer is B+D+F.", "_summary": "AWS Budgets actions: Billing dashboard + IAM role + SCP action"}, "800": {"A": "DataSync copies data to a new EFS — doesn't provide live cross-account access; adds cost and data lag as source grows.", "B": "VPC peering lets the primary-account Lambda (in its VPC) reach the EFS mount target IP in the secondary-account VPC; secondary-account EFS resource policy grants cross-account mount access — cost-effective, serverless, scales automatically.", "C": "Proxy Lambda in secondary account adds latency, complexity, and double invocation cost; not cost-effective.", "D": "Lambda layers max 250 MB unzipped — unsuitable for a file system of arbitrary size; layers are for code/libraries, not live file storage.", "_summary": "Cross-account EFS access via VPC peering + EFS resource policy"}, "795": {"A": "Global Accelerator custom routing directs traffic to specific EC2 endpoints by client IP — a routing feature, not an HPC networking or storage optimizer.", "B": "FSx for Lustre scratch configuration gives maximum throughput/IOPS with no durability overhead — the standard HPC parallel file system choice on AWS.", "C": "CloudFront is a CDN for HTTP content delivery — irrelevant to tightly coupled HPC inter-node communication or storage.", "D": "EFA (Elastic Fabric Adapter) bypasses the OS kernel for MPI traffic, providing RDMA-like latency between EC2 instances — the canonical HPC networking solution on AWS.", "E": "Elastic Beanstalk is a PaaS deployment abstraction — adds no HPC networking or storage capability.", "_summary": "HPC on AWS: FSx for Lustre (storage) + EFA (low-latency networking)"}, "794": {"A": "On-Demand EC2 running continuously for a week to handle <10 min tasks wastes ~10,000 min of billed compute for maybe a dozen report runs.", "B": "Lambda charges only for the milliseconds the function runs; EventBridge triggers on demand; 15-min max timeout easily covers <10 min reports; zero idle cost — optimal for infrequent short tasks.", "C": "ECS containers have cold-start and task-provisioning overhead; billed per vCPU/memory-second of task runtime including startup, not just computation; more expensive and slower to start than Lambda.", "D": "Spot Instances running continuously risk interruption mid-report and still waste ~10,000 min of compute for a few short runs.", "_summary": "Infrequent <10 min tasks: Lambda is cheapest — pay per execution, no idle cost"}, "788": {"A": "Migrating 10 TB into Aurora via DMS incurs migration time, DMS replication instance cost, and ongoing Aurora cluster cost — massively over-engineered for occasional queries.", "B": "Redshift Spectrum can query S3 directly but still requires a running Redshift cluster with a base hourly cost even when idle — not cost-effective for occasional use.", "C": "Glue crawler catalogs the Parquet schema; Athena queries S3 directly, charges $5/TB scanned; Parquet columnar format drastically reduces data scanned — no cluster, no idle cost, lowest TCO for occasional SQL.", "D": "EMR cluster provisioning takes minutes, requires ongoing instance costs, and introduces Spark SQL complexity — overkill for simple occasional SQL on static data.", "_summary": "Occasional SQL on S3 Parquet: Glue catalog + Athena — serverless, pay-per-query"}, "336": {"A": "Secrets Manager has a native Lambda rotation function for Aurora/RDS; configuring a 14-day rotation schedule is a few console clicks; KMS encrypts the secret at rest — fully managed, zero custom code, least operational effort.", "B": "Parameter Store lacks native Aurora rotation; requires writing and maintaining a custom Lambda that calls both Parameter Store and Aurora APIs — more operational burden than A.", "C": "EFS mount on every EC2 instance, Lambda writing credentials to a file, filesystem permission management — high complexity and operational overhead.", "D": "Periodic S3 download risks stale credentials between rotation and next poll; Lambda still needs to update Aurora password and re-upload file — operational overhead similar to C.", "_summary": "DB credential rotation with least effort: Secrets Manager native Aurora rotation"}, "545": {"A": "Latency routing picks the lowest-latency healthy endpoint — it does not fail over to a backup when the primary is down; both records would share traffic normally.", "B": "Active-passive failover: Route 53 health-checks the ALB; when unhealthy, DNS resolves to the S3-hosted static error page. Minimal new infrastructure — just an S3 bucket with static hosting.", "C": "Active-active serves traffic to both ALB and EC2 simultaneously under normal conditions — not a failover pattern; also adds an EC2 instance (infrastructure overhead).", "D": "Multivalue routing distributes traffic across multiple healthy endpoints — returns up to 8 random healthy records, not a clean primary-to-backup failover for an error page.", "_summary": "DNS failover to S3 static page: Route 53 active-passive + health check on ALB"}, "563": {"A": "CloudWatch Container Insights monitors EKS metrics/logs but cannot register or display on-prem Kubernetes clusters as connected workloads.", "B": "EKS Connector is purpose-built to register any conformant Kubernetes cluster (on-prem, other clouds) into the EKS console for unified visibility — zero extra infra.", "C": "Systems Manager manages EC2/hybrid nodes but has no native Kubernetes cluster topology or workload view.", "D": "EKS Anywhere deploys EKS software on-prem; it's a runtime, not a multi-cluster aggregation plane.", "_summary": "EKS Connector registers external K8s clusters into EKS console"}, "271": {"A": "Raising minimum keeps instances running 24/7, wastes cost; does not eliminate the 1-hour scale-up lag.", "B": "Higher max allows more instances but does not pre-provision them; lag remains.", "C": "Scheduled scaling fires before 1 AM, pre-warms to peak capacity so batch starts immediately; ASG still scales down when jobs finish — cost-effective.", "D": "Larger scale steps still react after CloudWatch alarm fires; 1-hour convergence lag shrinks but is not eliminated.", "_summary": "Scheduled scaling pre-provisions known peak capacity before fixed-time batch"}, "916": {"A": "S3 is object storage, not a key-management service; no per-customer key isolation or audit trail from KMS.", "B": "Hardware security appliance (CloudHSM-style) provides isolation but requires provisioning, patching, and HA management — high operational overhead.", "C": "Single KMS key encrypts all customers' data under the same key material, violating 'encrypted separately' compliance requirement.", "D": "One CMK per customer enforces cryptographic isolation; key policies grant granular access per customer; CloudTrail logs all key usage automatically — all managed by KMS.", "_summary": "Separate KMS CMKs per customer = cryptographic isolation with minimal ops"}, "105": {"A": "Execution role controls what Lambda calls outbound; lambda:InvokeFunction on an execution role with wildcard principal is architecturally wrong and overly permissive.", "B": "Execution role with lambda.amazonaws.com principal grants Lambda permissions to call other services, not permissions for EventBridge to invoke Lambda.", "C": "Resource-based policy is correct mechanism, but lambda:* grants all Lambda actions — violates least privilege.", "D": "Resource-based policy on the function grants events.amazonaws.com permission to call only lambda:InvokeFunction — correct mechanism, minimal scope.", "_summary": "EventBridge invokes Lambda via resource-based policy scoped to InvokeFunction"}, "484": {"A": "AWS Organizations with all features enabled is prerequisite for IAM Identity Center and SCPs; creates the account hierarchy.", "B": "Cognito is for app-level user pools, not corporate directory federation into AWS accounts; wrong tool for this use case.", "C": "SCPs don't authenticate users; 'adding IAM Identity Center to Directory Service' is not how integration works — reversed relationship.", "D": "AWS Organizations has no built-in auth mechanism that connects directly to Directory Service; this is not a real configuration path.", "E": "IAM Identity Center integrates natively with AD (via AWS Managed AD or AD Connector) or external SAML IdPs, providing SSO across all org accounts from corporate credentials.", "_summary": "Organizations (all features) + IAM Identity Center + corporate directory = centralized SSO"}, "228": {"A": "Larger instance alleviates pressure temporarily but does not decouple ingestion from DB writes or prevent loss during traffic spikes.", "B": "Multi-AZ adds standby for HA failover; writes still go to one primary, so connection/throughput problem persists.", "C": "SQS buffers bursts durably (no data loss), Lambda polls at controlled concurrency (fewer simultaneous DB connections), and scales naturally with queue depth.", "D": "SNS delivers to subscribers immediately; if Lambda is throttled or errors, messages are not re-queued — data loss risk; SNS is fan-out, not a durable buffer.", "_summary": "SQS decouples write bursts from RDS, ensuring durability and connection control"}, "203": {"A": "DAX accelerates DynamoDB reads via in-memory cache; does not affect SQS processing throughput or invitation sending speed.", "B": "API Gateway fronts the intake web app; the bottleneck is the back-end invitation-sending application consuming SQS.", "C": "CloudFront caches static/dynamic web content; irrelevant to back-end queue processing latency.", "D": "Auto Scaling the invitation application on SQS queue depth directly matches processing capacity to backlog, draining the queue faster as it grows.", "_summary": "Scale the consumer application to SQS queue depth to drain invitation backlog"}, "365": {"A": "Read replicas replicate writes in near-real-time including accidental changes; no independent point-in-time rollback capability.", "B": "Manual snapshots capture state at trigger time only; cannot restore to an arbitrary 5-minute window without pre-existing snapshot at that moment.", "C": "Automated backups enable RDS Point-in-Time Recovery using transaction logs; restore to any second within the retention window (up to 35 days).", "D": "Multi-AZ provides failover for hardware/AZ failure; the standby mirrors all writes including accidental ones — no protection against logical data corruption.", "_summary": "Automated backups enable PITR to any second within retention window"}, "673": {"A": "DataSync is a migration/sync tool, not a caching gateway — it doesn't provide local SMB access for recent files or seamlessly tiered retrieval for older ones.", "B": "S3 File Gateway presents SMB shares backed by S3 with local cache for hot data; Glacier Deep Archive standard retrieval is 12 h, well within the 24-hour SLA for cold data. Correct.", "C": "FSx File Gateway caches FSx for Windows File Server data — it has no S3 Lifecycle policy integration; you can't transition FSx data to S3 Glacier this way.", "D": "Per-user direct S3 access bypasses the SMB server entirely and requires per-user config changes; Glacier Flexible Retrieval does meet 24 h but the architecture doesn't preserve the file-server access model.", "_summary": "S3 File Gateway = SMB-compatible tiered storage; Glacier Deep Archive retrieval <= 12 h standard"}, "398": {"A": "100 Mbps = ~12.5 MB/s; 2 weeks max throughput ≈ 15 TB — far below 600 TB. HTTPS upload is irrelevant when bandwidth is the bottleneck.", "B": "VPN tunnels over the same 100 Mbps internet link; throughput unchanged, still only ~15 TB in 2 weeks.", "C": "Snowball Edge Storage Optimized holds 80 TB usable; ~8 devices cover 600 TB via physical shipment, bypassing internet bandwidth entirely. AES-256 encryption built in. Correct.", "D": "10 Gbps Direct Connect provisioning takes weeks just to order — not available within the 2-week deadline, and cost is high.", "_summary": "When internet bandwidth can't move data in time, Snowball physical transfer is the answer"}, "399": {"A": "CloudFront caching with 24-hour TTL would serve stale stock prices; caching doesn't block floods, it only reduces origin hits for cacheable content.", "B": "Regional WAF rate-based rule counts requests per IP and automatically blocks offenders — direct integration with API Gateway stage, no custom code, minimal overhead. Correct.", "C": "CloudWatch alerts only notify; no automatic blocking occurs. Operational staff still must respond manually.", "D": "Lambda@Edge with custom rate-limiting logic requires writing and maintaining IP-tracking code — far higher operational overhead than a native WAF rule.", "_summary": "WAF rate-based rules are the managed, zero-code solution for HTTP flood protection on API Gateway"}, "197": {"A": "Rewriting .NET Framework app as Lambda .NET Core functions requires significant refactoring — violates 'minimize development changes.'", "B": "Elastic Beanstalk .NET platform on Windows Server AMI, Multi-AZ = lift-and-shift with HA and no code changes. Correct.", "C": "Moving to Amazon Linux forces .NET Framework → .NET Core port; not minimal change. EC2 alone also requires manual HA setup.", "D": "Oracle relational schema to DynamoDB NoSQL is a full re-architecture of data access — major development changes required.", "E": "DMS supports Oracle → Oracle on RDS homogeneous migration with schema intact; Multi-AZ RDS provides HA with no application changes. Correct.", "_summary": "Minimize change = Beanstalk (.NET platform) + Oracle RDS Multi-AZ; avoid schema/runtime rewrites"}, "567": {"A": "API Gateway + Lambda + DynamoDB = fully serverless, fully managed, scales to sensor load, no servers to patch; loosely coupled for future component additions. Correct.", "B": "EC2 in Auto Scaling requires patching, AMI management, and OS-level ops; S3 is object storage, not a queryable database for per-tenant aggregation.", "C": "SQL Server Express on EC2 is self-managed — OS, DB engine, backups all manual; contradicts 'managed services when possible.'", "D": "EFS is a shared file system, not a database; EC2 Auto Scaling still adds operational burden.", "_summary": "Fully managed serverless stack (API GW + Lambda + DynamoDB) minimizes ops and enables independent component extension"}, "684": {"A": "CloudFront edge locations serve cached content — they can't run stateful compute workloads, and 'deploy in eu-central-1' still violates the regulatory restriction.", "B": "AWS Local Zones are AWS infrastructure physically placed near a specific city, extending the VPC; they satisfy both the geographic regulatory restriction and single-digit ms latency. Correct.", "C": "CloudFront regional edge caches are also just CDN nodes — same problem as A, and the apps still run in eu-central-1.", "D": "Wavelength Zones embed AWS compute inside 5G carrier networks for ultra-low latency to mobile devices — wrong use case for a general regulated-location web workload.", "_summary": "Local Zones = AWS compute physically outside the parent Region, satisfying geo-regulatory + latency requirements"}, "403": {"A": "Lambda resource policies (function policies) control who can invoke the function — they don't grant the function outbound permissions to call S3.", "B": "Hardcoding IAM user long-term credentials in Lambda code is a security anti-pattern; credentials can leak and don't rotate automatically.", "C": "Creating another IAM user and embedding static credentials in Lambda is the same anti-pattern as B — no improvement.", "D": "IAM execution role grants Lambda temporary STS credentials via AssumeRole at runtime — AWS best practice, no static credentials, least privilege. Correct.", "_summary": "Lambda permissions to AWS services always via execution role, never embedded static credentials"}, "415": {"A": "S3 Intelligent-Tiering automatically monitors access frequency and moves objects across tiers with no retrieval fees — ideal when access patterns are unknown. One Lifecycle rule per bucket, zero ongoing ops. Correct.", "B": "Storage class analysis generates a recommendation report, but an admin must then manually review and trigger transitions — high operational overhead at petabyte scale.", "C": "Glacier Instant Retrieval suits known-infrequent data; forcing all objects there when some may be frequently accessed incurs unnecessary retrieval charges.", "D": "One Zone-IA sacrifices AZ redundancy and charges retrieval fees; wrong fit for unknown access patterns where some data may be hot.", "_summary": "Unknown access patterns → S3 Intelligent-Tiering; it self-optimizes cost automatically with no manual analysis"}, "385": {"A": "SG for web servers correct tool, but 0.0.0.0/0 on 443 violates least-privilege — web servers should only accept from LB SG.", "B": "NACLs can't reference SGs as sources; they're CIDR-only and stateless — wrong tool for instance-level least-privilege.", "C": "SG referencing another SG as source is the AWS least-privilege pattern: web servers allow 443 only from LB SG, MySQL allows 3306 only from web SG.", "D": "NACLs can't use SG as source and operate at subnet level — can't enforce instance-level isolation required here.", "_summary": "SG-to-SG reference = correct least-privilege pattern; NACLs can't reference SGs"}, "299": {"A": "FSx ONTAP with tiering=ALL moves data to S3 automatically — adds retrieval latency, violates sub-ms requirement.", "B": "FSx for Lustre SSD persistent delivers sub-ms latency and scales to 1000 MB/s per TiB; S3 import/export handles initial data load — meets 6 GBps at 8 TB scale.", "C": "FSx for Lustre HDD persistent has latencies in the single-digit ms range, not sub-ms — fails the latency requirement.", "D": "FSx ONTAP NONE keeps data on SSD but ONTAP is not optimized for parallel HPC workloads; Lustre's parallel architecture outperforms it at this throughput target.", "_summary": "FSx Lustre SSD = sub-ms latency + massive parallel throughput for HPC"}, "327": {"A": "AWS Network Firewall supports domain-list rule groups that filter outbound traffic by FQDN/URL — the only AWS-native way to do URL-based egress filtering at scale.", "B": "WAF inspects inbound HTTP/HTTPS on ALB/CloudFront; it has no mechanism for filtering outbound EC2 traffic.", "C": "Security groups filter by IP/port only — no URL or domain awareness; can't enforce named-repo policy.", "D": "ALB is an inbound load balancer; routing outbound traffic through it is architecturally backwards and ALB has no outbound URL-filtering capability.", "_summary": "Network Firewall domain-list rules = only AWS service that filters outbound traffic by URL/FQDN"}, "741": {"A": "Route 53 public hosted zone is correct for internet-facing domains; importing a zone file migrates all records rapidly from any DNS provider.", "B": "Private hosted zone is VPC-internal only — not resolvable from public internet; wrong for a public website.", "C": "Directory Service is for AD/LDAP identity, not DNS hosting; zone transfer to Directory Service is not a supported DNS migration pattern.", "D": "Route 53 Resolver inbound endpoints forward on-prem DNS queries into a VPC — that's for hybrid DNS resolution, not for hosting/migrating a public domain.", "_summary": "Route 53 public hosted zone + zone file import = fastest DNS migration path"}, "499": {"A": "Dedicated connections can't be shared between accounts directly; sharing a 1 Gbps connection doesn't reduce the port-hour cost for the original account.", "B": "200 Mbps is not an available dedicated connection size (dedicated = 1/10/100 Gbps only); can't order it in the console.", "C": "Ordering a hosted connection through a partner then sharing it still leaves the original account paying for a 1 Gbps dedicated port.", "D": "Direct Connect Partners offer hosted connections down to 50 Mbps; a 200 Mbps hosted connection costs far less than a 1 Gbps dedicated port and matches actual ~100 Mbps utilization.", "_summary": "Hosted connection via DX Partner = right-size bandwidth below 1 Gbps dedicated minimum"}, "485": {"A": "S3 Glacier Expedited retrieval delivers data in 1–5 minutes — exactly meets the 5-minute SLA at lowest archival storage cost vs IA tiers.", "B": "Glacier Standard retrieval takes 3–5 hours — violates the 5-minute availability requirement.", "C": "S3 Standard-IA provides immediate retrieval but is significantly more expensive per GB than Glacier for rarely-accessed archives.", "D": "S3 One Zone-IA provides immediate retrieval but costs more than Glacier and sacrifices multi-AZ durability — overkill for cost-minimization.", "_summary": "Glacier Expedited = cheapest archive tier that hits 5-min restore SLA"}, "466": {"A": "Multi-AZ Auto Scaling group spreads stateless EC2 across AZs; ALB routes across them — together they fix the single-AZ failure domain. RDS is already Multi-AZ.", "B": "Cross-region snapshots are a DR strategy, not HA; doesn't address EC2 single-AZ exposure and adds RPO/RTO lag.", "C": "Latency-based routing routes geographically; it doesn't distribute across AZs in the same region or provide EC2 failover.", "D": "Multi-AZ ALB alone doesn't help if EC2 instances stay in one AZ; need Auto Scaling across AZs for actual compute HA.", "_summary": "Stateless EC2 HA = Multi-AZ ASG + ALB; RDS Multi-AZ already done"}, "658": {"A": "Cluster placement group packs EC2 onto same physical rack for lowest inter-instance network latency — critical for tightly-coupled HPC.", "B": "Partition placement group distributes across isolated hardware for fault tolerance (Kafka/HDFS pattern), not minimum latency.", "C": "FSx for Lustre is a high-performance parallel FS but supports POSIX/NFS only — no SMB; fails the multi-protocol requirement.", "D": "FSx for OpenZFS supports NFS only — no SMB; fails multi-protocol requirement.", "E": "FSx for NetApp ONTAP natively supports both NFS and SMB simultaneously on the same file system — the only FSx option meeting the multi-protocol requirement.", "_summary": "HPC multi-protocol (NFS+SMB) = FSx ONTAP; low inter-node latency = cluster placement group"}, "621": {"A": "S3 Cross-Region Replication (CRR) automatically copies new objects to a destination bucket in another region — native managed feature, zero custom code, least operational effort.", "B": "CORS controls browser cross-origin HTTP requests; has nothing to do with replicating object data between regions.", "C": "Lifecycle rules transition objects between storage classes or expire them; they cannot copy data to a different bucket or region.", "D": "Lambda-based copy works but requires writing/maintaining function code, IAM wiring, and event notification config — far more operational effort than CRR.", "_summary": "S3 CRR = managed cross-region copy; CORS/Lifecycle/Lambda all wrong tool or more effort"}, "616": {"A": "Macie specializes in S3 data classification/sensitive-data detection, not broad threat detection across account workloads; reporting to Config is also wrong pattern.", "B": "Inspector does vulnerability scanning of EC2/containers/Lambda; not designed for malicious-activity/threat detection; CloudTrail is a log store not a findings dashboard.", "C": "GuardDuty does continuous ML-based threat detection across CloudTrail, VPC Flow Logs, DNS, and S3 data-plane events; Security Hub aggregates findings and provides a unified dashboard — perfect fit.", "D": "AWS Config tracks resource configuration compliance, not malicious behavior or threat patterns; EventBridge is an event bus, not a security dashboard.", "_summary": "GuardDuty = threat detection; Security Hub = findings aggregation + dashboard"}, "606": {"A": "S3 Glacier requires retrieval time (minutes to hours) — violates 'readily available at any time' requirement.", "B": "S3 Standard-IA keeps objects in multiple AZs (durable), retrieval is immediate, and costs less than Standard for infrequently accessed data — matches all constraints after 30-day transition.", "C": "S3 One Zone-IA stores data in a single AZ; one AZ failure destroys objects — does not maximize durability, violating an explicit requirement.", "D": "Intelligent-Tiering adds a monthly monitoring fee per object and cannot be lifecycle-transitioned to Standard-IA (you can't mix IT with a subsequent IA lifecycle transition usefully); also over-engineered when access pattern is already known.", "_summary": "Standard→Standard-IA lifecycle: durable, immediately accessible, cheapest for known 30-day access cliff"}, "118": {"A": "EBS volumes are tied to a single AZ and max out at 64 TiB per volume; 900 TB across multi-AZ EC2 would require massive volume management overhead and cost.", "B": "EFS scales automatically and works across AZs, but costs ~3× more than S3 per GB — 900 TB on EFS is extremely expensive for static text documents.", "C": "OpenSearch is a search/analytics engine, not object storage; storing 900 TB of raw documents there is architecturally wrong and prohibitively costly.", "D": "S3 scales infinitely, is multi-AZ durable by default, costs ~$0.023/GB-month (Standard), and serves objects directly to EC2 or browsers — cheapest and most scalable option for static document storage at 900 TB.", "_summary": "S3 = infinite scale, lowest cost/GB, natively multi-AZ — only viable option at 900 TB"}, "262": {"A": "VPC peering is cheapest same-region option; security groups can reference SGs across peered VPCs, so the ElastiCache SG rule allowing the app SG is valid and sufficient.", "B": "Transit VPC adds EC2 routing instances and cost; overkill for two VPCs and not MOST cost-effective.", "C": "Peering connections have no security groups — you attach rules to the ElastiCache cluster's SG, not the peering object; this option is architecturally invalid.", "D": "Transit VPC is expensive, and like C, a Transit VPC has no security group to attach rules to; double-wrong.", "_summary": "VPC peering = cheapest 2-VPC link; SG rules attach to resource SGs, not the peering connection"}, "205": {"A": "Lightsail is a managed server — requires patching, single instance, higher cost than S3 for purely static content; not most cost-effective or resilient.", "B": "ASG + ALB + EC2 is massive overkill for static documents; expensive and unnecessary compute for content that never executes server-side.", "C": "Private S3 + CloudFront OAI is the canonical pattern: no servers, 11-nines durability, infinite scale, OAI locks bucket to CloudFront only; AWS CLI replaces SFTP cleanly.", "D": "AWS Transfer Family (SFTP) charges per-hour endpoint + data fees making it expensive; public bucket is less secure; Transfer Family adds cost with no benefit S3 static hosting doesn't already provide.", "_summary": "Static site on S3 + CloudFront OAI = cheapest, most resilient origin; no servers needed"}, "384": {"A": "S3 is object storage, not POSIX-compliant — no file-system semantics, no seek/append/locking; eliminates this option regardless of lifecycle.", "B": "Same disqualifier as A — S3 is not POSIX-compliant; Standard-IA lifecycle is irrelevant when the base requirement fails.", "C": "EFS Standard is POSIX-compliant, replicates across multiple AZs (maximum durability + HA), mountable by all EC2 instances simultaneously; EFS lifecycle to Standard-IA cuts cost after 30 days.", "D": "EFS One Zone stores data in a single AZ — violates both 'highly available' and 'maximum data durability' requirements; cheaper but wrong tier for the stated constraints.", "_summary": "POSIX + multi-AZ + shareable = EFS Standard; lifecycle to EFS-IA covers the cost requirement"}, "350": {"A": "Multi-AZ converts the instance to synchronous standby replication with automatic failover — directly satisfies 'high availability and automatic recovery'.", "B": "Restoring a snapshot creates an independent standalone instance with no automated failover link to the original; doesn't meet automatic recovery requirement.", "C": "Read replicas offload read-heavy report queries from the primary, eliminating the contention that delays customer transactions; SQL Server on RDS supports read replicas.", "D": "RDS Custom provides OS/engine-level access — neither addresses HA nor report-query isolation; adds complexity without solving either requirement.", "E": "RDS Proxy provides connection pooling/multiplexing; it does not schedule or isolate report workloads, and maintenance windows control patching, not query routing.", "_summary": "Multi-AZ = HA/failover; read replica = report offload — two independent solutions for two independent problems"}, "370": {"A": "NAT instance in public subnet routes correctly but requires manual patching, scaling, HA failover — not managed, fails 'minimize operational maintenance'.", "B": "NAT device must sit in public subnet to reach internet; placing NAT instance in private subnet breaks outbound path entirely.", "C": "NAT gateway is fully AWS-managed (auto-scales, no patching), must be in public subnet — correct placement and satisfies managed requirement.", "D": "NAT gateway in private subnet cannot reach internet; NAT gateways require a public subnet with IGW route to function.", "_summary": "NAT gateway (managed) must live in public subnet; NAT instance (unmanaged) fails operational requirement"}, "357": {"A": "S3 for static files + CloudFront edge caching reduces latency and offloads EC2 — correct, highly available by design.", "B": "ElastiCache is in-memory app cache (Redis/Memcached), not an edge CDN; wrong tool for static asset delivery.", "C": "EFS uses NFS protocol — not natively mountable on Windows Server EC2 instances without third-party drivers; wrong OS compatibility.", "D": "FSx for Windows File Server uses SMB protocol, natively supported by Windows Server; shared file system across multiple EC2 instances for server-side code.", "E": "gp2 EBS is single-instance block storage; cannot be simultaneously mounted across multiple EC2 instances (multi-attach requires io1/io2, not gp2).", "_summary": "Windows EC2 needs FSx for Windows (SMB) for shared code; CloudFront+S3 for static assets"}, "356": {"A": "S3 Glacier Deep Archive retrieval takes 12 hours minimum — violates 'immediately accessible' requirement.", "B": "S3 Standard-IA retains same 11-9s durability and multi-AZ resiliency as Standard, immediate retrieval, lower per-GB cost — matches all constraints.", "C": "S3 One Zone-IA stores data in single AZ; loses the 'same high availability and resiliency' guarantee compared to Standard.", "D": "Moving all data to One Zone-IA immediately sacrifices resiliency for 100% of data unnecessarily, not just the 75% rarely accessed after 30 days.", "_summary": "Standard-IA = same HA/durability as Standard, immediate access, lower cost for infrequent data"}, "352": {"A": "Transit Gateway inter-region peering routes VPC-to-VPC traffic, not end-user traffic; does nothing to reduce last-mile latency for players.", "B": "Global Accelerator uses anycast IPs and AWS global backbone, routes UDP traffic to nearest edge, minimizes latency and packet loss — designed exactly for this use case.", "C": "CloudFront is HTTP/HTTPS CDN only; UDP protocol not supported on CloudFront distributions.", "D": "VPC peering optimizes inter-VPC routing but not end-user ingress; doesn't reduce internet path latency for players, and mesh of 8 regions = complex maintenance.", "_summary": "Global Accelerator provides anycast + AWS backbone for UDP gaming traffic across regions"}};
